UPDATE words SET meaning='보존하다, 저장하다', example_zh='这些老照片要好好保存，以后可以留作纪念。', example_ko='이 오래된 사진들은 잘 보존해야 해, 나중에 기념으로 남길 수 있어.', example_pinyin='zhè xiē lǎo zhào piān yào hǎo hǎo bǎo cún ， yǐ hòu kě yǐ liú zuò jì niàn 。' WHERE chinese='保存' AND pinyin='bǎo cún' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보류하다, 남겨두다', example_zh='对于这个方案，我想保留意见，先观察一段时间。', example_ko='이 방안에 대해 나는 의견을 유보하고 먼저 잠시 관찰하고 싶어.', example_pinyin='duì yú zhè ge fāng àn ， wǒ xiǎng bǎo liú yì jiàn ， xiān guān chá yī duàn shí jiān 。' WHERE chinese='保留' AND pinyin='bǎo liú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보험; 안전하다', example_zh='出门旅游最好买一份旅游保险，以防万一。', example_ko='외출 여행 시 만일을 대비해 여행보험에 가입하는 게 좋아.', example_pinyin='chū mén lǚ yóu zuì hǎo mǎi yī fèn lǚ yóu bǎo xiǎn ， yǐ fáng wàn yī 。' WHERE chinese='保险' AND pinyin='bǎo xiǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보고하다; 보고서', example_zh='他向领导汇报了最新的项目进展报告。', example_ko='그는 리더에게 최신 프로젝트 진행 보고서를 보고했어.', example_pinyin='tā xiàng lǐng dǎo huì bào le zuì xīn de xiàng mù jìn zhǎn bào gào 。' WHERE chinese='报告' AND pinyin='bào gào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비관적이다, 비관주의', example_zh='不要太悲观，事情总会有转机的，坚持下去。', example_ko='너무 비관적으로 생각하지 마, 상황은 언젠가 나아질 거야, 버텨.', example_pinyin='bú yào tài bēi guān ， shì qíng zǒng huì yǒu zhuǎn jī de ， jiān chí xià qù 。' WHERE chinese='悲观' AND pinyin='bēi guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이불', example_zh='冬天要盖厚一点的被子，不然容易着凉。', example_ko='겨울에는 두꺼운 이불을 덮어야 해, 안 그러면 감기 걸리기 쉬워.', example_pinyin='dōng tiān yào gài hòu yì diǎn de bèi zi ， bù rán róng yì zháo liáng 。' WHERE chinese='被子' AND pinyin='bèi zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='등지다; 외우다; 등', example_zh='他把课文背得很熟，老师叫他当众朗读。', example_ko='그는 본문을 완벽히 외워서 선생님이 모두 앞에서 낭독하라고 했어.', example_pinyin='tā bǎ kè wén bèi dé hěn shú ， lǎo shī jiào tā dāng zhòng lǎng dú 。' WHERE chinese='背' AND pinyin='bèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='배경', example_zh='了解历史背景对理解这篇文章很重要。', example_ko='역사적 배경을 이해하는 게 이 글을 이해하는 데 중요해.', example_pinyin='liǎo jiě lì shǐ bèi jǐng duì lǐ jiě zhè piān wén zhāng hěn zhòng yào 。' WHERE chinese='背景' AND pinyin='bèi jǐng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='학사 (대학교)', example_zh='他本科毕业后继续读了研究生，现在在读博士。', example_ko='그는 학사 졸업 후 대학원에 진학해서 지금 박사 과정을 밟고 있어.', example_pinyin='tā běn kē bì yè hòu jì xù dú le yán jiū shēng ， xiàn zài zài dú bó shì 。' WHERE chinese='本科' AND pinyin='běn kē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='능력, 재능', example_zh='她有很强的语言本领，会说四门外语。', example_ko='그녀는 언어 능력이 뛰어나서 외국어를 네 개나 할 수 있어.', example_pinyin='tā yǒu hěn qiáng de yǔ yán běn lǐng ， huì shuō sì mén wài yǔ 。' WHERE chinese='本领' AND pinyin='běn lǐng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='본질, 본성', example_zh='事物的本质往往不是一眼就能看出来的。', example_ko='사물의 본질은 대개 한눈에 알아볼 수 있는 게 아니야.', example_pinyin='shì wù de běn zhì wǎng wǎng bú shì yī yǎn jiù néng kàn chū lái de 。' WHERE chinese='本质' AND pinyin='běn zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비율, 비례', example_zh='男女生比例差不多，班级氛围很好。', example_ko='남녀 비율이 비슷해서 반 분위기가 정말 좋아.', example_pinyin='nán nǚ shēng bǐ lì chà bu duō ， bān jí fēn wéi hěn hǎo 。' WHERE chinese='比例' AND pinyin='bǐ lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='예를 들어', example_zh='有些习惯很难改，比如睡前玩手机这个坏习惯。', example_ko='어떤 습관은 바꾸기 어려워, 예를 들어 자기 전에 스마트폰 보는 나쁜 습관처럼.', example_pinyin='yǒu xiē xí guàn hěn nán gǎi ， bǐ rú shuì qián wán shǒu jī zhè ge huài xí guàn 。' WHERE chinese='比如' AND pinyin='bǐ rú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서로, 상대방', example_zh='我们认识多年，彼此了解很深。', example_ko='우리는 여러 해 알고 지내서 서로를 깊이 이해해.', example_pinyin='wǒ men rèn shí duō nián ， bǐ cǐ liǎo jiě hěn shēn 。' WHERE chinese='彼此' AND pinyin='bǐ cǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='필연적이다, 당연하다', example_zh='付出努力，成功是必然的结果。', example_ko='노력을 기울이면 성공은 필연적인 결과야.', example_pinyin='fù chū nǔ lì ， chéng gōng shì bì rán de jié guǒ 。' WHERE chinese='必然' AND pinyin='bì rán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반드시 필요하다, 필수의', example_zh='维生素是身体必需的营养素，不能缺少。', example_ko='비타민은 몸에 반드시 필요한 영양소야, 부족하면 안 돼.', example_pinyin='wéi shēng sù shì shēn tǐ bì xū de yíng yǎng sù ， bù néng quē shǎo 。' WHERE chinese='必需' AND pinyin='bì xū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='필요하다, 필요성', example_zh='有没有必要参加那个会议，再想想吧。', example_ko='그 회의에 참석할 필요가 있는지 다시 생각해봐.', example_pinyin='yǒu méi yǒu bì yào cān jiā nà ge huì yì ， zài xiǎng xiǎng ba 。' WHERE chinese='必要' AND pinyin='bì yào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어쨌든, 결국', example_zh='他毕竟是你的老师，要对他表示尊重。', example_ko='어쨌든 그는 네 선생님이야, 존중을 표해야 해.', example_pinyin='tā bì jìng shì nǐ de lǎo shī ， yào duì tā biǎo shì zūn zhòng 。' WHERE chinese='毕竟' AND pinyin='bì jìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='피하다, 방지하다', example_zh='出行前查好天气，避免被雨淋湿。', example_ko='출발 전에 날씨를 미리 확인해서 비에 젖지 않도록 해.', example_pinyin='chū xíng qián chá hǎo tiān qì ， bì miǎn bèi yǔ lín shī 。' WHERE chinese='避免' AND pinyin='bì miǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='폭죽', example_zh='春节放鞭炮是中国的传统习俗，热闹极了。', example_ko='춘절에 폭죽을 터뜨리는 건 중국의 전통 풍습이야, 정말 시끌벅적해.', example_pinyin='chūn jié fàng biān pào shì zhōng guó de chuán tǒng xí sú ， rè nào jí le 。' WHERE chinese='鞭炮' AND pinyin='biān pào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='편집하다, 편집자', example_zh='她是一名出版社编辑，负责审核书稿内容。', example_ko='그녀는 출판사 편집자야, 원고 내용 검토를 담당하고 있어.', example_pinyin='tā shì yī míng chū bǎn shè biān jí ， fù zé shěn hé shū gǎo nèi róng 。' WHERE chinese='编辑' AND pinyin='biān jí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='곧, 그렇다면; 편리하다', example_zh='你不舒服就便早点回家休息吧。', example_ko='불편하면 그냥 일찍 집에 가서 쉬어.', example_pinyin='nǐ bù shū fú jiù biàn zǎo diǎn huí jiā xiū xī ba 。' WHERE chinese='便' AND pinyin='biàn' AND hsk_level IN (3,5,6);
