UPDATE words SET meaning='표정, 얼굴 표현', example_zh='她笑着说没事，但表情出卖了她的真实感受。', example_ko='그녀는 웃으며 괜찮다고 했지만 표정이 진짜 감정을 드러냈어.', example_pinyin='tā xiào zhe shuō méi shì ， dàn biǎo qíng chū mài le tā de zhēn shí gǎn shòu 。' WHERE chinese='表情' AND pinyin='biǎo qíng' AND hsk_level IN (3,5,6);
