UPDATE words SET meaning='유리', example_zh='小心，地上有碎玻璃，不要踩到。', example_ko='조심해, 바닥에 유리 조각이 있어, 밟지 마.', example_pinyin='xiǎo xīn ， dì shàng yǒu suì bō lí ， bú yào cǎi dào 。' WHERE chinese='玻璃' AND pinyin='bō li' AND hsk_level IN (3,5,6);
