UPDATE words SET meaning='목', example_zh='他喝水太急，呛到了，一直揉脖子。', example_ko='그가 물을 너무 급하게 마셔서 사레들려서 계속 목을 만지고 있어.', example_pinyin='tā hē shuǐ tài jí ， qiàng dào le ， yì zhí róu bó zi 。' WHERE chinese='脖子' AND pinyin='bó zi' AND hsk_level IN (3,5,6);
