UPDATE words SET meaning='끊임없이, 계속해서', example_zh='她不断地练习，终于把这首曲子弹得很好了。', example_ko='그녀는 끊임없이 연습해서 결국 이 곡을 잘 연주하게 됐어.', example_pinyin='tā bù duàn dì liàn xí ， zhōng yú bǎ zhè shǒu qǔ zi dàn dé hěn hǎo le 。' WHERE chinese='不断' AND pinyin='bù duàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반드시 그렇지는 않다', example_zh='贵的东西不见得好，价格和质量不总是成比例的。', example_ko='비싼 게 반드시 좋은 건 아니야, 가격과 품질이 항상 비례하는 건 아니거든.', example_pinyin='guì de dōng xī bú jiàn de hǎo ， jià gé hé zhì liàng bù zǒng shì chéng bǐ lì de 。' WHERE chinese='不见得' AND pinyin='bù jiàn de' AND hsk_level IN (3,5,6);
