UPDATE words SET meaning='괜찮다, 별일 아니다', example_zh='摔了一跤，没受伤，不要紧，大家别担心。', example_ko='넘어졌는데 다친 게 없어, 괜찮아, 다들 걱정 마.', example_pinyin='shuāi le yī jiāo ， méi shòu shāng ， bú yào jǐn ， dà jiā bié dān xīn 。' WHERE chinese='不要紧' AND pinyin='bù yào jǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보충하다, 추가하다', example_zh='运动后要及时补充水分，防止脱水。', example_ko='운동 후에는 수분을 적시에 보충해서 탈수를 방지해야 해.', example_pinyin='yùn dòng hòu yào jí shí bǔ chōng shuǐ fèn ， fáng zhǐ tuō shuǐ 。' WHERE chinese='补充' AND pinyin='bǔ chōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='불안하다, 안절부절못하다', example_zh='考试前他总是感到不安，担心考不好。', example_ko='시험 전에 그는 항상 불안해해서 잘 못 볼까봐 걱정해.', example_pinyin='kǎo shì qián tā zǒng shì gǎn dào bù ān ， dān xīn kǎo bù hǎo 。' WHERE chinese='不安' AND pinyin='bù ān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대단하다, 엄청나다', example_zh='孩子发高烧，把父母急得不得了。', example_ko='아이가 고열이 나서 부모를 완전히 초조하게 만들었어.', example_pinyin='hái zi fā gāo shāo ， bǎ fù mǔ jí dé bù dé le 。' WHERE chinese='不得了' AND pinyin='bù dé liǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미안하다, 쑥스럽다', example_zh='迟到了，真的很不好意思，路上堵车了。', example_ko='늦었어, 정말 미안해, 길이 막혔어.', example_pinyin='chí dào le ， zhēn de hěn bù hǎo yì sī ， lù shàng dǔ chē le 。' WHERE chinese='不好意思' AND pinyin='bù hǎo yì si' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~하게 마련이다, 불가피하다', example_zh='第一次做新事情，不免会犯错，慢慢就好了。', example_ko='처음으로 새로운 일을 하면 실수하게 마련이야, 천천히 나아질 거야.', example_pinyin='dì yī cì zuò xīn shì qíng ， bù miǎn huì fàn cuò ， màn màn jiù hǎo le 。' WHERE chinese='不免' AND pinyin='bù miǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그렇지 않으면, 안 그러면', example_zh='赶紧出发，不然会赶不上最后一班地铁。', example_ko='빨리 출발해, 그렇지 않으면 마지막 지하철을 놓칠 거야.', example_pinyin='gǎn jǐn chū fā ， bù rán huì gǎn bù shàng zuì hòu yī bān dì tiě 。' WHERE chinese='不然' AND pinyin='bù rán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~만 못하다, ~하는 게 낫다', example_zh='与其一个人发愁，不如和朋友聊聊，说不定有办法。', example_ko='혼자 걱정하느니 친구랑 얘기해봐, 혹시 방법이 있을 수도 있으니까.', example_pinyin='yǔ qí yí gè rén fā chóu ， bù rú hé péng yǒu liáo liáo ， shuō bù dìng yǒu bàn fǎ 。' WHERE chinese='不如' AND pinyin='bù rú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부족하다, 불충분하다', example_zh='他的经验不足，所以这次项目出现了一些问题。', example_ko='그는 경험이 부족해서 이번 프로젝트에서 문제가 좀 생겼어.', example_pinyin='tā de jīng yàn bù zú ， suǒ yǐ zhè cì xiàng mù chū xiàn le yī xiē wèn tí 。' WHERE chinese='不足' AND pinyin='bù zú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='천, 직물', example_zh='这块布颜色很好看，可以做一条裙子。', example_ko='이 천은 색깔이 예뻐서 치마 하나 만들 수 있겠어.', example_pinyin='zhè kuài bù yán sè hěn hǎo kàn ， kě yǐ zuò yī tiáo qún zi 。' WHERE chinese='布' AND pinyin='bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='순서, 절차', example_zh='按照步骤来操作，就不会出错。', example_ko='절차에 따라 조작하면 실수하지 않을 거야.', example_pinyin='àn zhào bù zhòu lái cāo zuò ， jiù bú huì chū cuò 。' WHERE chinese='步骤' AND pinyin='bù zhòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부서, 부문', example_zh='公司各部门要加强协作，共同完成任务。', example_ko='회사 각 부서는 협력을 강화해서 함께 업무를 완수해야 해.', example_pinyin='gōng sī gè bù mén yào jiā qiáng xié zuò ， gòng tóng wán chéng rèn wù 。' WHERE chinese='部门' AND pinyin='bù mén' AND hsk_level IN (3,5,6);
