UPDATE words SET meaning='채택하다, 취하다', example_zh='政府采取了一系列措施来应对经济下滑。', example_ko='정부는 경기 하락에 대응하기 위해 일련의 조치를 취했어.', example_pinyin='zhèng fǔ cǎi qǔ le yī xì liè cuò shī lái yìng duì jīng jì xià huá 。' WHERE chinese='采取' AND pinyin='cǎi qǔ' AND hsk_level IN (3,5,6);
