UPDATE words SET meaning='참고하다, 참조하다', example_zh='写论文前最好先参考一些相关资料。', example_ko='논문 쓰기 전에 관련 자료를 먼저 참고하는 게 좋아.', example_pinyin='xiě lùn wén qián zuì hǎo xiān cān kǎo yī xiē xiāng guān zī liào 。' WHERE chinese='参考' AND pinyin='cān kǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='참여하다, 참가하다', example_zh='欢迎大家积极参与这次讨论，发表各自的看法。', example_ko='모두 적극적으로 이번 토론에 참여해서 각자의 의견을 발표해주세요.', example_pinyin='huān yíng dà jiā jī jí cān yù zhè cì tǎo lùn ， fā biǎo gè zì de kàn fǎ 。' WHERE chinese='参与' AND pinyin='cān yù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='식당, 레스토랑', example_zh='公司楼下有一家不错的餐厅，午饭经常去那里。', example_ko='회사 건물 아래에 괜찮은 식당이 있어서 점심을 자주 거기서 먹어.', example_pinyin='gōng sī lóu xià yǒu yī jiā bù cuò de cān tīng ， wǔ fàn jīng cháng qù nà lǐ 。' WHERE chinese='餐厅' AND pinyin='cān tīng' AND hsk_level IN (3,5,6);
