UPDATE words SET meaning='부끄럽다, 창피하다', example_zh='借了朋友钱又忘了还，真的很惭愧。', example_ko='친구한테 빌린 돈을 또 갚는 걸 잊어버렸어, 정말 창피해.', example_pinyin='jiè le péng yǒu qián yòu wàng le hái ， zhēn de hěn cán kuì 。' WHERE chinese='惭愧' AND pinyin='cán kuì' AND hsk_level IN (3,5,6);
