UPDATE words SET meaning='걱정하다, 신경 쓰다', example_zh='他什么事都爱操心，从不让自己清闲。', example_ko='그는 모든 일을 걱정하고 스스로를 한가하게 두는 법이 없어.', example_pinyin='tā shén me shì dōu ài cāo xīn ， cóng bù ràng zì jǐ qīng xián 。' WHERE chinese='操心' AND pinyin='cāo xīn' AND hsk_level IN (3,5,6);
