UPDATE words SET meaning='볶다', example_zh='她炒了一道番茄炒蛋，简单又好吃。', example_ko='그녀는 토마토달걀볶음을 만들었는데 간단하고 맛있어.', example_pinyin='tā chǎo le yī dào fān qié chǎo dàn ， jiǎn dān yòu hǎo chī 。' WHERE chinese='炒' AND pinyin='chǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='말다툼하다, 싸우다', example_zh='他们俩吵架了，好几天没说话。', example_ko='그들 둘이 싸워서 며칠 동안 말을 안 했어.', example_pinyin='tā men liǎ chǎo jià le ， hǎo jǐ tiān méi shuō huà 。' WHERE chinese='吵架' AND pinyin='chǎo jià' AND hsk_level IN (3,5,6);
