UPDATE words SET meaning='객차, 차량 칸', example_zh='请到3号车厢就坐，您的座位在那里。', example_ko='3번 객차로 가서 앉으세요, 자리가 거기 있어요.', example_pinyin='qǐng dào 3 hào chē xiāng jiù zuò ， nín de zuò wèi zài nà lǐ 。' WHERE chinese='车厢' AND pinyin='chē xiāng' AND hsk_level IN (3,5,6);
