UPDATE words SET meaning='~을 틈타, ~를 이용해', example_zh='趁现在有空，把这件事办了，免得以后麻烦。', example_ko='지금 시간 있을 때 이 일을 처리해둬, 나중에 번거로워지지 않게.', example_pinyin='chèn xiàn zài yǒu kòng ， bǎ zhè jiàn shì bàn le ， miǎn de yǐ hòu má fán 。' WHERE chinese='趁' AND pinyin='chèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부르다, 칭하다; 무게를 달다', example_zh='这个地方大家都称它为"小上海"。', example_ko='이 지역은 모두가 "작은 상하이"라고 불러.', example_pinyin='zhè ge dì fāng dà jiā dōu chēng tā wèi " xiǎo shàng hǎi "。' WHERE chinese='称' AND pinyin='chēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부르다, 호칭하다; 호칭', example_zh='中国人见面时的称呼很讲究，要根据关系来定。', example_ko='중국 사람들이 만날 때 호칭이 까다로워, 관계에 따라 정해야 해.', example_pinyin='zhōng guó rén jiàn miàn shí de chēng hū hěn jiǎng jiū ， yào gēn jù guān xì lái dìng 。' WHERE chinese='称呼' AND pinyin='chēng hu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='칭찬하다', example_zh='老师称赞他的作文写得有创意，叫他去参加比赛。', example_ko='선생님이 그의 작문이 창의적이라고 칭찬하며 대회에 나가게 했어.', example_pinyin='lǎo shī chēng zàn tā de zuò wén xiě dé yǒu chuàng yì ， jiào tā qù cān jiā bǐ sài 。' WHERE chinese='称赞' AND pinyin='chēng zàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='타다, 승차하다', example_zh='乘地铁上班比开车省时间，不用担心堵车。', example_ko='지하철로 출근하는 게 운전보다 시간을 아낄 수 있어, 막힐 걱정 없거든.', example_pinyin='chéng dì tiě shàng bān bǐ kāi chē shěng shí jiān ， bù yòng dān xīn dǔ chē 。' WHERE chinese='乘' AND pinyin='chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='담당하다, 맡다', example_zh='他承担了这次项目的主要责任，压力不小。', example_ko='그는 이번 프로젝트의 주요 책임을 맡아서 스트레스가 적지 않아.', example_pinyin='tā chéng dān le zhè cì xiàng mù dì zhǔ yào zé rèn ， yā lì bù xiǎo 。' WHERE chinese='承担' AND pinyin='chéng dān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인정하다, 승인하다', example_zh='他终于承认了自己的错误，向大家道歉。', example_ko='그는 결국 자신의 잘못을 인정하고 모두에게 사과했어.', example_pinyin='tā zhōng yú chéng rèn le zì jǐ de cuò wù ， xiàng dà jiā dào qiàn 。' WHERE chinese='承认' AND pinyin='chéng rèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감당하다, 견디다', example_zh='这么大的压力，她一个人很难承受，需要帮助。', example_ko='이렇게 큰 스트레스를 그녀 혼자 감당하기 힘들어, 도움이 필요해.', example_pinyin='zhè me dà de yā lì ， tā yí gè rén hěn nán chéng shòu ， xū yào bāng zhù 。' WHERE chinese='承受' AND pinyin='chéng shòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성분, 구성요소', example_zh='这种食品的成分表上没有防腐剂，比较健康。', example_ko='이 식품의 성분표에 방부제가 없어서 비교적 건강해.', example_pinyin='zhè zhǒng shí pǐn de chéng fèn biǎo shàng méi yǒu fáng fǔ jì ， bǐ jiào jiàn kāng 。' WHERE chinese='成分' AND pinyin='chéng fèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성과, 결실', example_zh='经过多年努力，他们的研究终于取得了重要成果。', example_ko='수년간의 노력 끝에 그들의 연구가 드디어 중요한 성과를 거뒀어.', example_pinyin='jīng guò duō nián nǔ lì ， tā men de yán jiū zhōng yú qǔ dé le zhòng yào chéng guǒ 。' WHERE chinese='成果' AND pinyin='chéng guǒ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성취, 업적', example_zh='他在音乐上的成就令人钦佩，获得了多项大奖。', example_ko='그가 음악에서 이룬 성취는 정말 대단해서 여러 큰 상을 받았어.', example_pinyin='tā zài yīn yuè shàng de chéng jiù lìng rén qīn pèi ， huò dé le duō xiàng dà jiǎng 。' WHERE chinese='成就' AND pinyin='chéng jiù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='설립하다, 창설하다', example_zh='这家公司成立于2005年，现在已发展成行业领头羊。', example_ko='이 회사는 2005년에 설립되어 지금은 업계 선두 기업으로 성장했어.', example_pinyin='zhè jiā gōng sī chéng lì yú 2005 nián ， xiàn zài yǐ fā zhǎn chéng háng yè lǐng tóu yáng 。' WHERE chinese='成立' AND pinyin='chéng lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성어, 사자성어', example_zh='中国成语大多来自古代故事，意义深刻。', example_ko='중국 성어는 대부분 고대 이야기에서 나온 거야, 의미가 깊어.', example_pinyin='zhōng guó chéng yǔ dà duō lái zì gǔ dài gù shì ， yì yì shēn kè 。' WHERE chinese='成语' AND pinyin='chéng yǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성장하다, 자라다', example_zh='孩子在爱的环境中成长，性格会更开朗。', example_ko='아이가 사랑 속에서 자라면 성격이 더 밝아질 거야.', example_pinyin='hái zi zài ài de huán jìng zhōng chéng zhǎng ， xìng gé huì gèng kāi lǎng 。' WHERE chinese='成长' AND pinyin='chéng zhǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정도, 수준', example_zh='他中文的程度已经很高了，基本上没有障碍。', example_ko='그의 중국어 수준은 이미 꽤 높아서 기본적으로 장벽이 없어.', example_pinyin='tā zhōng wén de chéng dù yǐ jīng hěn gāo le ， jī běn shàng méi yǒu zhàng ài 。' WHERE chinese='程度' AND pinyin='chéng dù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='프로그램, 순서', example_zh='软件出了问题，需要检查程序代码找出错误。', example_ko='소프트웨어에 문제가 생겨서 프로그램 코드를 검사해서 오류를 찾아야 해.', example_pinyin='ruǎn jiàn chū le wèn tí ， xū yào jiǎn chá chéng xù dài mǎ zhǎo chū cuò wù 。' WHERE chinese='程序' AND pinyin='chéng xù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성실하다, 진심 어리다', example_zh='他的道歉很诚恳，让人感受到了他的悔意。', example_ko='그의 사과가 정말 진심 어려서 그의 후회를 느낄 수 있었어.', example_pinyin='tā de dào qiàn hěn chéng kěn ， ràng rén gǎn shòu dào le tā de huǐ yì 。' WHERE chinese='诚恳' AND pinyin='chéng kěn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='손해 보다, 억울하게 당하다', example_zh='做生意要精明，不然容易吃亏，被人蒙骗。', example_ko='장사할 때 눈치 있어야 해, 안 그러면 손해 보고 속기 쉬워.', example_pinyin='zuò shēng yì yào jīng míng ， bù rán róng yì chī kuī ， bèi rén mēng piàn 。' WHERE chinese='吃亏' AND pinyin='chī kuī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지속하다, 계속되다', example_zh='这场雨持续了三天，造成了一些洪涝灾害。', example_ko='이 비는 사흘 동안 지속되어 일부 홍수 피해를 일으켰어.', example_pinyin='zhè chǎng yǔ chí xù le sān tiān ， zào chéng le yī xiē hóng lào zāi hài 。' WHERE chinese='持续' AND pinyin='chí xù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연못', example_zh='公园里有一个小池子，里面养了很多金鱼。', example_ko='공원에 작은 연못이 있는데 안에 금붕어가 많이 있어.', example_pinyin='gōng yuán lǐ yǒu yí gè xiǎo chí zi ， lǐ miàn yǎng le hěn duō jīn yú 。' WHERE chinese='池子' AND pinyin='chí zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자', example_zh='画直线要用尺子，不然画出来的线会歪。', example_ko='직선을 그을 때 자를 써야 해, 안 그러면 선이 삐뚤어져.', example_pinyin='huà zhí xiàn yào yòng chǐ zi ， bù rán huà chū lái de xiàn huì wāi 。' WHERE chinese='尺子' AND pinyin='chǐ zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='날개', example_zh='鸟受伤了，翅膀动不了，被好心人救下了。', example_ko='새가 다쳐서 날개를 움직이지 못했는데 마음씨 좋은 사람이 구해줬어.', example_pinyin='niǎo shòu shāng le ， chì bǎng dòng bù liǎo ， bèi hǎo xīn rén jiù xià le 。' WHERE chinese='翅膀' AND pinyin='chì bǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='달려들다, 씻다; 충돌하다', example_zh='他一冲动就说了不该说的话，后悔不已。', example_ko='그는 충동적으로 하지 말았어야 할 말을 해버려서 후회가 이만저만이 아니야.', example_pinyin='tā yī chōng dòng jiù shuō le bù gāi shuō de huà ， hòu huǐ bù yǐ 。' WHERE chinese='冲' AND pinyin='chōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='충전기', example_zh='手机没电了，我忘带充电器了，借一下吧。', example_ko='스마트폰 배터리가 떨어졌는데 충전기를 안 가져왔어, 빌려줘.', example_pinyin='shǒu jī méi diàn le ， wǒ wàng dài chōng diàn qì le ， jiè yī xià ba 。' WHERE chinese='充电器' AND pinyin='chōng diàn qì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='충분하다, 충분히', example_zh='这次时间充分，大家可以好好准备，不用急。', example_ko='이번에 시간이 충분하니 다들 잘 준비하면 돼, 서두를 필요 없어.', example_pinyin='zhè cì shí jiān chōng fèn ， dà jiā kě yǐ hǎo hǎo zhǔn bèi ， bù yòng jí 。' WHERE chinese='充分' AND pinyin='chōng fèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가득 차다, 넘치다', example_zh='她眼里充满了泪水，却一直忍着不哭。', example_ko='그녀의 눈에 눈물이 가득 찼지만 계속 참으며 울지 않았어.', example_pinyin='tā yǎn lǐ chōng mǎn le lèi shuǐ ， què yì zhí rěn zhe bù kū 。' WHERE chinese='充满' AND pinyin='chōng mǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반복하다, 되풀이하다', example_zh='不要重复同样的错误，这次要汲取教训。', example_ko='똑같은 실수를 반복하지 마, 이번에는 교훈을 얻어야 해.', example_pinyin='bú yào chóng fù tóng yàng de cuò wù ， zhè cì yào jí qǔ jiào xùn 。' WHERE chinese='重复' AND pinyin='chóng fù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반려동물', example_zh='她养了一只猫和一只狗，把它们当宠物来疼爱。', example_ko='그녀는 고양이 한 마리와 개 한 마리를 키우며 반려동물로 아끼고 있어.', example_pinyin='tā yǎng le yī zhī māo hé yī zhī gǒu ， bǎ tā men dāng chǒng wù lái téng ài 。' WHERE chinese='宠物' AND pinyin='chǒng wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서랍', example_zh='我把重要文件放在了书桌的抽屉里锁好了。', example_ko='중요한 서류를 책상 서랍에 넣어 잠궜어.', example_pinyin='wǒ bǎ zhòng yào wén jiàn fàng zài le shū zhuō de chōu tì lǐ suǒ hǎo le 。' WHERE chinese='抽屉' AND pinyin='chōu ti' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='추상적이다, 추상', example_zh='这个概念太抽象了，能不能举个例子来说明？', example_ko='이 개념이 너무 추상적이야, 예를 들어서 설명해줄 수 있어?', example_pinyin='zhè ge gài niàn tài chōu xiàng le ， néng bù néng jǔ gè lì zi lái shuō míng ？' WHERE chinese='抽象' AND pinyin='chōu xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='못생기다, 부끄럽다', example_zh='他觉得自己的字写得很丑，一直在练习书法。', example_ko='그는 자신의 글씨체가 못생겼다고 생각해서 계속 서예를 연습하고 있어.', example_pinyin='tā jué de zì jǐ de zì xiě dé hěn chǒu ， yì zhí zài liàn xí shū fǎ 。' WHERE chinese='丑' AND pinyin='chǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='냄새가 나다, 더럽다', example_zh='垃圾桶里的垃圾很臭，赶紧倒掉比较好。', example_ko='쓰레기통 안이 냄새나니 빨리 버리는 게 좋겠어.', example_pinyin='lā jī tǒng lǐ de lā jī hěn chòu ， gǎn jǐn dào diào bǐ jiào hǎo 。' WHERE chinese='臭' AND pinyin='chòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='출판하다, 발행하다', example_zh='她的第一本小说终于出版了，朋友们都很开心。', example_ko='그녀의 첫 번째 소설이 드디어 출판됐어, 친구들 모두 기뻐했어.', example_pinyin='tā de dì yī běn xiǎo shuō zhōng yú chū bǎn le ， péng yǒu men dōu hěn kāi xīn 。' WHERE chinese='出版' AND pinyin='chū bǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='출구, 수출', example_zh='地铁出口有很多指示牌，很容易找到。', example_ko='지하철 출구에 안내판이 많아서 찾기 쉬워.', example_pinyin='dì tiě chū kǒu yǒu hěn duō zhǐ shì pái ， hěn róng yì zhǎo dào 。' WHERE chinese='出口' AND pinyin='chū kǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뛰어나다, 훌륭하다', example_zh='他在这次演讲比赛中表现出色，获得了第一名。', example_ko='그는 이번 연설 대회에서 뛰어난 활약으로 1등을 차지했어.', example_pinyin='tā zài zhè cì yǎn jiǎng bǐ sài zhōng biǎo xiàn chū sè ， huò dé le dì yì míng 。' WHERE chinese='出色' AND pinyin='chū sè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='참석하다, 출석하다', example_zh='董事长亲自出席了开幕式，表示了对活动的重视。', example_ko='회장이 직접 개막식에 참석해서 행사에 대한 중시를 표했어.', example_pinyin='dǒng shì zhǎng qīn zì chū xí le kāi mù shì ， biǎo shì le duì huó dòng de zhòng shì 。' WHERE chinese='出席' AND pinyin='chū xí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='초급, 기초 단계', example_zh='他刚开始学汉语，现在还是初级水平，但进步很快。', example_ko='그는 막 중국어를 배우기 시작해서 지금 초급 수준이지만 빠르게 발전하고 있어.', example_pinyin='tā gāng kāi shǐ xué hàn yǔ ， xiàn zài hái shì chū jí shuǐ píng ， dàn jìn bù hěn kuài 。' WHERE chinese='初级' AND pinyin='chū jí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='외에, 제외하고', example_zh='除了周末，我每天都要上班，很少有空。', example_ko='주말 외에 나는 매일 출근해야 해서 시간이 거의 없어.', example_pinyin='chú le zhōu mò ， wǒ měi tiān dōu yào shàng bān ， hěn shǎo yǒu kōng 。' WHERE chinese='除' AND pinyin='chú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~이 아니라면, ~만 아니면', example_zh='除非你亲自去道歉，否则他不会原谅你的。', example_ko='네가 직접 가서 사과하지 않는 한 그는 너를 용서하지 않을 거야.', example_pinyin='chú fēi nǐ qīn zì qù dào qiàn ， fǒu zé tā bú huì yuán liàng nǐ de 。' WHERE chinese='除非' AND pinyin='chú fēi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='섣달그믐, 제야', example_zh='除夕那天全家人聚在一起吃团圆饭，看春晚。', example_ko='섣달그믐에 온 가족이 모여 단란한 식사를 하고 춘완을 봐.', example_pinyin='chú xī nà tiān quán jiā rén jù zài yì qǐ chī tuán yuán fàn ， kàn chūn wǎn 。' WHERE chinese='除夕' AND pinyin='chú xī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='처리하다, 다루다', example_zh='这个问题有点棘手，需要慎重处理。', example_ko='이 문제가 좀 골치 아파서 신중하게 처리해야 해.', example_pinyin='zhè ge wèn tí yǒu diǎn jí shǒu ， xū yào shèn zhòng chǔ lǐ 。' WHERE chinese='处理' AND pinyin='chǔ lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전파하다, 보급하다', example_zh='网络的发展使信息传播速度大幅提升。', example_ko='인터넷의 발전으로 정보 전파 속도가 크게 향상됐어.', example_pinyin='wǎng luò de fā zhǎn shǐ xìn xī chuán bō sù dù dà fú tí shēng 。' WHERE chinese='传播' AND pinyin='chuán bō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전달하다, 전하다', example_zh='请帮我把这封信传递给他，我自己没空去。', example_ko='이 편지를 그에게 전달해줘, 나는 직접 갈 시간이 없어.', example_pinyin='qǐng bāng wǒ bǎ zhè fēng xìn chuán dì gěi tā ， wǒ zì jǐ méi kòng qù 。' WHERE chinese='传递' AND pinyin='chuán dì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전염되다, 감염되다', example_zh='流感传染性很强，出门最好戴口罩预防。', example_ko='독감은 전염성이 강하니 외출할 때 마스크를 착용하면 예방에 좋아.', example_pinyin='liú gǎn chuán rǎn xìng hěn qiáng ， chū mén zuì hǎo dài kǒu zhào yù fáng 。' WHERE chinese='传染' AND pinyin='chuán rǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전설, 전해지다', example_zh='关于这座山，当地有很多神奇的传说。', example_ko='이 산에 대해 현지에 신기한 전설이 많이 있어.', example_pinyin='guān yú zhè zuò shān ， dāng dì yǒu hěn duō shén qí de chuán shuō 。' WHERE chinese='传说' AND pinyin='chuán shuō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전통', example_zh='中国有着悠久的文化传统，值得我们好好学习。', example_ko='중국은 유구한 문화 전통을 갖고 있어서 우리가 잘 배울 가치가 있어.', example_pinyin='zhōng guó yǒu zhe yōu jiǔ de wén huà chuán tǒng ， zhí de wǒ men hǎo hǎo xué xí 。' WHERE chinese='传统' AND pinyin='chuán tǒng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='커튼', example_zh='早上阳光太强，我把窗帘拉上，再睡一会儿。', example_ko='아침에 햇빛이 너무 강해서 커튼을 치고 좀 더 잤어.', example_pinyin='zǎo shàng yáng guāng tài qiáng ， wǒ bǎ chuāng lián lā shàng ， zài shuì yī huì er 。' WHERE chinese='窗帘' AND pinyin='chuāng lián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='달려들다, 거침없이 나아가다', example_zh='他不顾危险，闯入火场救出了被困的老人。', example_ko='그는 위험을 무릅쓰고 화재 현장으로 뛰어들어 갇혀 있던 노인을 구해냈어.', example_pinyin='tā bù gù wēi xiǎn ， chuǎng rù huǒ chǎng jiù chū le bèi kùn de lǎo rén 。' WHERE chinese='闯' AND pinyin='chuǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='창조하다, 만들어내다', example_zh='这位设计师创造了很多独特的作品，备受好评。', example_ko='이 디자이너는 독특한 작품을 많이 만들어내서 호평을 받고 있어.', example_pinyin='zhè wèi shè jì shī chuàng zào le hěn duō dú tè de zuò pǐn ， bèi shòu hǎo píng 。' WHERE chinese='创造' AND pinyin='chuàng zào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='불다; 뽐내다', example_zh='风吹来了，把桌上的纸吹到了地上。', example_ko='바람이 불어서 책상 위의 종이를 바닥으로 날려버렸어.', example_pinyin='fēng chuī lái le ， bǎ zhuō shàng de zhǐ chuī dào le dì shàng 。' WHERE chinese='吹' AND pinyin='chuī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='카세트 테이프', example_zh='以前用磁带听音乐，现在都用手机或电脑了。', example_ko='예전에는 카세트 테이프로 음악을 들었는데 지금은 모두 스마트폰이나 컴퓨터를 써.', example_pinyin='yǐ qián yòng cí dài tīng yīn yuè ， xiàn zài dōu yòng shǒu jī huò diàn nǎo le 。' WHERE chinese='磁带' AND pinyin='cí dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사직하다, 그만두다', example_zh='他觉得现在的工作不适合自己，决定辞职换行业。', example_ko='그는 현재 직업이 자신에게 맞지 않는다고 느껴서 그만두고 업종을 바꾸기로 했어.', example_pinyin='tā jué de xiàn zài de gōng zuò bú shì hé zì jǐ ， jué dìng cí zhí huàn háng yè 。' WHERE chinese='辞职' AND pinyin='cí zhí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이 외에, 그 밖에', example_zh='会英语，此外还会日语和法语，语言天赋不错。', example_ko='영어를 할 줄 알고 이 외에 일본어와 프랑스어도 할 수 있어, 언어 재능이 좋아.', example_pinyin='huì yīng yǔ ， cǐ wài hái huì rì yǔ hé fǎ yǔ ， yǔ yán tiān fù bù cuò 。' WHERE chinese='此外' AND pinyin='cǐ wài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자극하다; 흥미롭다', example_zh='这部电影情节很刺激，让人一直想知道结局。', example_ko='이 영화 줄거리가 정말 스릴 있어서 계속 결말이 궁금해져.', example_pinyin='zhè bù diàn yǐng qíng jié hěn cì jī ， ràng rén yì zhí xiǎng zhī dào jié jú 。' WHERE chinese='刺激' AND pinyin='cì jī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부차적이다, 이차적이다', example_zh='质量是主要的，价格是次要的，不要本末倒置。', example_ko='품질이 주요하고 가격은 부차적이야, 주객을 전도시키면 안 돼.', example_pinyin='zhì liàng shì zhǔ yào de ， jià gé shì cì yào de ， bú yào běn mò dào zhì 。' WHERE chinese='次要' AND pinyin='cì yào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='바쁘다, 서두르다', example_zh='他每天都很匆忙，根本没时间好好吃饭。', example_ko='그는 매일 바빠서 제대로 밥 먹을 시간이 없어.', example_pinyin='tā měi tiān dōu hěn cōng máng ， gēn běn méi shí jiān hǎo hǎo chī fàn 。' WHERE chinese='匆忙' AND pinyin='cōng máng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그때부터, 이후로', example_zh='从此以后，他再也没有回到那个城市。', example_ko='그때부터 그는 다시는 그 도시로 돌아가지 않았어.', example_pinyin='cóng cǐ yǐ hòu ， tā zài yě méi yǒu huí dào nà ge chéng shì 。' WHERE chinese='从此' AND pinyin='cóng cǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='따라서, 그리고', example_zh='技术不断进步，从而推动了整个行业的发展。', example_ko='기술이 끊임없이 발전해서 따라서 전체 업계의 발전을 촉진했어.', example_pinyin='jì shù bù duàn jìn bù ， cóng ér tuī dòng le zhěng gè háng yè de fā zhǎn 。' WHERE chinese='从而' AND pinyin='cóng ér' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='예전에, 옛날에', example_zh='从前，这里是一片荒地，如今已变成了繁华的城市。', example_ko='예전에 여기는 황무지였는데 지금은 번화한 도시로 변했어.', example_pinyin='cóng qián ， zhè lǐ shì yī piàn huāng dì ， rú jīn yǐ biàn chéng le fán huá de chéng shì 。' WHERE chinese='从前' AND pinyin='cóng qián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='종사하다, 일하다', example_zh='他从事教育工作二十年了，培养了很多优秀学生。', example_ko='그는 교육 일에 20년째 종사하며 우수한 학생을 많이 키워냈어.', example_pinyin='tā cóng shì jiào yù gōng zuò èr shí nián le ， péi yǎng le hěn duō yōu xiù xué shēng 。' WHERE chinese='从事' AND pinyin='cóng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='식초', example_zh='这道凉拌黄瓜加了一点醋，味道更爽口了。', example_ko='이 오이무침에 식초를 조금 넣었더니 맛이 더 시원해졌어.', example_pinyin='zhè dào liáng bàn huáng guā jiā le yì diǎn cù ， wèi dào gèng shuǎng kǒu le 。' WHERE chinese='醋' AND pinyin='cù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='촉진하다, 증진하다', example_zh='适量运动可以促进血液循环，有益健康。', example_ko='적당한 운동은 혈액순환을 촉진해서 건강에 도움이 돼.', example_pinyin='shì liàng yùn dòng kě yǐ cù jìn xuè yè xún huán ， yǒu yì jiàn kāng 。' WHERE chinese='促进' AND pinyin='cù jìn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='촉구하다, 하도록 하다', example_zh='这件事促使他重新思考自己的人生规划。', example_ko='이 일은 그로 하여금 자신의 인생 계획을 다시 생각하게 했어.', example_pinyin='zhè jiàn shì cù shǐ tā chóng xīn sī kǎo zì jǐ de rén shēng guī huà 。' WHERE chinese='促使' AND pinyin='cù shǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='재촉하다, 서두르게 하다', example_zh='快到截止日期了，领导一直在催，压力很大。', example_ko='마감이 다가와서 상사가 계속 재촉하고 있어, 스트레스가 심해.', example_pinyin='kuài dào jié zhǐ rì qī le ， lǐng dǎo yì zhí zài cuī ， yā lì hěn dà 。' WHERE chinese='催' AND pinyin='cuī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='저금하다; 존재하다', example_zh='每个月我都会存一部分工资，留作紧急备用。', example_ko='매달 월급의 일부를 저금해두는데 긴급 상황을 대비해서야.', example_pinyin='měi gè yuè wǒ dū huì cún yī bù fèn gōng zī ， liú zuò jǐn jí bèi yòng 。' WHERE chinese='存' AND pinyin='cún' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='존재하다, 있다', example_zh='这个问题一直存在，只是大家不愿意去面对。', example_ko='이 문제는 계속 존재했는데 다들 직면하기 싫어할 뿐이야.', example_pinyin='zhè ge wèn tí yì zhí cún zài ， zhǐ shì dà jiā bù yuàn yì qù miàn duì 。' WHERE chinese='存在' AND pinyin='cún zài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실수, 오류', example_zh='他检查了三遍，确认没有错误，才提交了作业。', example_ko='그는 세 번을 확인해서 오류가 없음을 확인한 후 과제를 제출했어.', example_pinyin='tā jiǎn chá le sān biàn ， què rèn méi yǒu cuò wù ， cái tí jiāo le zuò yè 。' WHERE chinese='错误' AND pinyin='cuò wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조치, 대책', example_zh='公司采取了有效措施，解决了员工反映的问题。', example_ko='회사는 효과적인 조치를 취해서 직원들이 반영한 문제를 해결했어.', example_pinyin='gōng sī cǎi qǔ le yǒu xiào cuò shī ， jiě jué le yuán gōng fǎn yìng de wèn tí 。' WHERE chinese='措施' AND pinyin='cuò shī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='응하다, 동의하다', example_zh='她答应帮我翻译这封信，明天就能完成。', example_ko='그녀가 이 편지를 번역해주기로 했어, 내일이면 완성된대.', example_pinyin='tā dā yìng bāng wǒ fān yì zhè fēng xìn ， míng tiān jiù néng wán chéng 。' WHERE chinese='答应' AND pinyin='dā ying' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='달성하다, 이르다', example_zh='经过努力，他终于达到了自己设定的目标。', example_ko='노력 끝에 그는 결국 스스로 설정한 목표에 도달했어.', example_pinyin='jīng guò nǔ lì ， tā zhōng yú dá dào le zì jǐ shè dìng de mù biāo 。' WHERE chinese='达到' AND pinyin='dá dào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아르바이트하다, 일하다', example_zh='大学期间他去超市打工，自己赚生活费。', example_ko='대학 다닐 때 그는 슈퍼마켓에서 아르바이트를 해서 스스로 생활비를 벌었어.', example_pinyin='dà xué qī jiān tā qù chāo shì dǎ gōng ， zì jǐ zhuàn shēng huó fèi 。' WHERE chinese='打工' AND pinyin='dǎ gōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교류하다, 거래하다', example_zh='他做生意多年，和很多行业的人都打过交道。', example_ko='그는 오랫동안 사업을 하면서 많은 업계 사람들과 거래해왔어.', example_pinyin='tā zuò shēng yì duō nián ， hé hěn duō háng yè de rén dōu dǎ guò jiāo dào 。' WHERE chinese='打交道' AND pinyin='dǎ jiāo dào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='재채기하다', example_zh='她一直打喷嚏，可能是过敏，也可能是感冒了。', example_ko='그녀가 계속 재채기를 하는데 알레르기일 수도 있고 감기일 수도 있어.', example_pinyin='tā yì zhí dǎ pēn tì ， kě néng shì guò mǐn ， yě kě néng shì gǎn mào le 。' WHERE chinese='打喷嚏' AND pinyin='dǎ pēn tì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수소문하다, 물어보다', example_zh='我去附近打听了一下，附近有一家新开的餐厅。', example_ko='근처를 수소문해봤더니 근처에 새로 문 연 식당이 있더라고.', example_pinyin='wǒ qù fù jìn dǎ tīng le yī xià ， fù jìn yǒu yī jiā xīn kāi de cān tīng 。' WHERE chinese='打听' AND pinyin='dǎ ting' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인사하다, 안부를 묻다', example_zh='路上碰到邻居，要主动打招呼，这是礼貌。', example_ko='길에서 이웃을 만나면 먼저 인사해야 해, 이게 예의야.', example_pinyin='lù shàng pèng dào lín jū ， yào zhǔ dòng dǎ zhāo hū ， zhè shì lǐ mào 。' WHERE chinese='打招呼' AND pinyin='dǎ zhāo hu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소탈하다, 후하다; 자연스럽다', example_zh='她为人大方，从不小气，朋友有困难都愿意帮。', example_ko='그녀는 소탈해서 인색하지 않고 친구가 어려움에 처하면 기꺼이 도와.', example_pinyin='tā wéi rén dà fāng ， cóng bù xiǎo qì ， péng yǒu yǒu kùn nán dōu yuàn yì bāng 。' WHERE chinese='大方' AND pinyin='dà fang' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='코끼리', example_zh='大象是陆地上最大的动物之一，鼻子很长。', example_ko='코끼리는 육지에서 가장 큰 동물 중 하나야, 코가 정말 길어.', example_pinyin='dà xiàng shì lù dì shàng zuì dà de dòng wù zhī yī ， bí zi hěn zhǎng 。' WHERE chinese='大象' AND pinyin='dà xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대형의, 대규모의', example_zh='这是一场大型音乐会，来了上万名观众。', example_ko='이건 대형 콘서트야, 만 명 이상의 관객이 왔어.', example_pinyin='zhè shì yī cháng dà xíng yīn yuè huì ， lái le shàng wàn míng guān zhòng 。' WHERE chinese='大型' AND pinyin='dà xíng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='멍하다, 바보같다', example_zh='他呆坐在那里，什么也没说，好像在想事情。', example_ko='그는 거기 멍하니 앉아서 아무 말도 안 했어, 뭔가 생각하는 것 같았어.', example_pinyin='tā dāi zuò zài nà lǐ ， shén me yě méi shuō ， hǎo xiàng zài xiǎng shì qíng 。' WHERE chinese='呆' AND pinyin='dāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대출, 융자', example_zh='他贷款买了房子，每个月要还银行一笔钱。', example_ko='그는 대출을 받아 집을 샀는데 매달 은행에 돈을 갚아야 해.', example_pinyin='tā dài kuǎn mǎi le fáng zi ， měi gè yuè yào hái yín háng yī bǐ qián 。' WHERE chinese='贷款' AND pinyin='dài kuǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대우, 처우', example_zh='这家公司待遇很好，有五险一金，还有年终奖。', example_ko='이 회사는 대우가 좋아, 사회보험과 주택공적금, 연말 보너스도 있어.', example_pinyin='zhè jiā gōng sī dài yù hěn hǎo ， yǒu wǔ xiǎn yī jīn ， hái yǒu nián zhōng jiǎng 。' WHERE chinese='待遇' AND pinyin='dài yù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='담임하다, 맡다', example_zh='他担任了公司副总经理一职，责任重大。', example_ko='그는 회사 부총경리직을 맡아서 책임이 막중해.', example_pinyin='tā dān rèn le gōng sī fù zǒng jīng lǐ yī zhí ， zé rèn zhòng dà 。' WHERE chinese='担任' AND pinyin='dān rèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단순하다, 순수하다', example_zh='她的想法很单纯，只是想帮助别人，没有其他目的。', example_ko='그녀의 생각은 정말 단순해서 그냥 다른 사람을 돕고 싶은 거야, 다른 목적 없어.', example_pinyin='tā de xiǎng fǎ hěn dān chún ， zhǐ shì xiǎng bāng zhù bié rén ， méi yǒu qí tā mù dì 。' WHERE chinese='单纯' AND pinyin='dān chún' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단조롭다, 지루하다', example_zh='每天做同样的事太单调了，需要尝试一些新鲜的东西。', example_ko='매일 똑같은 일을 하는 게 너무 단조로워서 새로운 걸 시도해봐야 해.', example_pinyin='měi tiān zuò tóng yàng de shì tài dān diào le ， xū yào cháng shì yī xiē xīn xiān de dōng xī 。' WHERE chinese='单调' AND pinyin='dān diào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='혼자, 단독으로', example_zh='他喜欢单独行动，不喜欢跟团旅游。', example_ko='그는 단독으로 행동하는 걸 좋아하고 단체 여행을 싫어해.', example_pinyin='tā xǐ huān dān dú xíng dòng ， bù xǐ huān gēn tuán lǚ yóu 。' WHERE chinese='单独' AND pinyin='dān dú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단위, 직장', example_zh='他在国家机关单位工作，待遇比较稳定。', example_ko='그는 국가기관 단위에서 일하는데 대우가 비교적 안정적이야.', example_pinyin='tā zài guó jiā jī guān dān wèi gōng zuò ， dài yù bǐ jiào wěn dìng 。' WHERE chinese='单位' AND pinyin='dān wèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단원, 유닛', example_zh='这本教材共有十个单元，每个单元有一个主题。', example_ko='이 교재는 총 10개 단원이 있는데 각 단원마다 하나의 주제가 있어.', example_pinyin='zhè běn jiào cái gòng yǒu shí gè dān yuán ， měi gè dān yuán yǒu yí gè zhǔ tí 。' WHERE chinese='单元' AND pinyin='dān yuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지체시키다, 방해하다', example_zh='不好意思，耽误你时间了，事情比较复杂。', example_ko='미안해, 시간을 뺏었어, 일이 좀 복잡했어.', example_pinyin='bù hǎo yì sī ， dān wù nǐ shí jiān le ， shì qíng bǐ jiào fù zá 。' WHERE chinese='耽误' AND pinyin='dān wu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='겁쟁이', example_zh='别做胆小鬼，要勇于尝试，失败了也没关系。', example_ko='겁쟁이처럼 굴지 마, 용감하게 시도해야 해, 실패해도 괜찮아.', example_pinyin='bié zuò dǎn xiǎo guǐ ， yào yǒng yú cháng shì ， shī bài le yě méi guān xì 。' WHERE chinese='胆小鬼' AND pinyin='dǎn xiǎo guǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연하다, 싱겁다; 옅다', example_zh='这个汤味道有点淡，能不能加点盐？', example_ko='이 국이 좀 싱거운데 소금 좀 더 넣을 수 있어?', example_pinyin='zhè ge tāng wèi dào yǒu diǎn dàn ， néng bù néng jiā diǎn yán ？' WHERE chinese='淡' AND pinyin='dàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='현대, 당대', example_zh='当代年轻人压力很大，要面对很多挑战。', example_ko='현대 젊은이들은 스트레스가 많아서 많은 도전을 직면해야 해.', example_pinyin='dāng dài nián qīng rén yā lì hěn dà ， yào miàn duì hěn duō tiǎo zhàn 。' WHERE chinese='当代' AND pinyin='dāng dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='막다, 가로막다', example_zh='他挡在门口，不让任何人进去。', example_ko='그가 입구를 막고 서서 아무도 들어오지 못하게 했어.', example_pinyin='tā dǎng zài mén kǒu ， bù ràng rèn hé rén jìn qù 。' WHERE chinese='挡' AND pinyin='dǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='섬', example_zh='这个岛上没有太多人，但风景非常美。', example_ko='이 섬에는 사람이 많지 않은데 경치가 정말 아름다워.', example_pinyin='zhè ge dǎo shàng méi yǒu tài duō rén ， dàn fēng jǐng fēi cháng měi 。' WHERE chinese='岛' AND pinyin='dǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운이 나쁘다, 재수없다', example_zh='今天真倒霉，先是下雨，后来手机又丢了。', example_ko='오늘 진짜 재수없어, 먼저 비가 오더니 나중에 스마트폰까지 잃어버렸어.', example_pinyin='jīn tiān zhēn dǎo méi ， xiān shì xià yǔ ， hòu lái shǒu jī yòu diū le 。' WHERE chinese='倒霉' AND pinyin='dǎo méi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감독, 연출하다', example_zh='这部电影由著名导演执导，视觉效果非常震撼。', example_ko='이 영화는 유명 감독이 연출했는데 시각 효과가 정말 대단해.', example_pinyin='zhè bù diàn yǐng yóu zhù míng dǎo yǎn zhí dǎo ， shì jué xiào guǒ fēi cháng zhèn hàn 。' WHERE chinese='导演' AND pinyin='dǎo yǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='야기하다, 초래하다', example_zh='长期压力会导致健康问题，要注意及时减压。', example_ko='장기적인 스트레스는 건강 문제를 야기할 수 있어서 제때 해소해야 해.', example_pinyin='cháng qī yā lì huì dǎo zhì jiàn kāng wèn tí ， yào zhù yì jí shí jiǎn yā 。' WHERE chinese='导致' AND pinyin='dǎo zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='거꾸로; 오히려', example_zh='你帮了他，他倒说你多管闲事，太过分了。', example_ko='네가 그를 도와줬는데 오히려 쓸데없이 참견했다고 하네, 너무해.', example_pinyin='nǐ bāng le tā ， tā dào shuō nǐ duō guǎn xián shì ， tài guò fèn le 。' WHERE chinese='倒' AND pinyin='dào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='도달하다, 도착하다', example_zh='飞机准时到达，旅客们下机后直接去取行李。', example_ko='비행기가 정시에 도착해서 승객들이 내린 후 바로 짐을 찾으러 갔어.', example_pinyin='fēi jī zhǔn shí dào dá ， lǚ kè men xià jī hòu zhí jiē qù qǔ xíng lǐ 。' WHERE chinese='到达' AND pinyin='dào dá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='도덕, 윤리', example_zh='做事要有道德底线，不能为了利益不择手段。', example_ko='일을 할 때 도덕적 마지노선이 있어야 해, 이익을 위해 수단 방법을 가리지 않으면 안 돼.', example_pinyin='zuò shì yào yǒu dào dé dǐ xiàn ， bù néng wèi le lì yì bù zé shǒu duàn 。' WHERE chinese='道德' AND pinyin='dào dé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이치, 도리', example_zh='他说的道理很对，我完全赞同他的看法。', example_ko='그가 말한 이치가 맞아, 나는 그의 생각에 완전히 동의해.', example_pinyin='tā shuō de dào lǐ hěn duì ， wǒ wán quán zàn tóng tā de kàn fǎ 。' WHERE chinese='道理' AND pinyin='dào li' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='탑승권, 보딩 패스', example_zh='登机前请出示登机牌，然后通过安检。', example_ko='탑승 전에 탑승권을 제시하고 보안 검사를 통과하세요.', example_pinyin='dēng jī qián qǐng chū shì dēng jī pái ， rán hòu tōng guò ān jiǎn 。' WHERE chinese='登机牌' AND pinyin='dēng jī pái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='등록하다, 기재하다', example_zh='来到酒店先去前台登记，然后才能拿房间钥匙。', example_ko='호텔에 도착하면 먼저 프런트에 가서 등록하고 나서 방 열쇠를 받아.', example_pinyin='lái dào jiǔ diàn xiān qù qián tái dēng jì ， rán hòu cái néng ná fáng jiān yào shi 。' WHERE chinese='登记' AND pinyin='dēng jì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기다리다', example_zh='他在咖啡厅等待朋友，一边喝咖啡一边看书。', example_ko='그는 카페에서 친구를 기다리면서 커피를 마시며 책을 읽었어.', example_pinyin='tā zài kā fēi tīng děng dài péng yǒu ， yī biān hē kā fēi yī biān kàn shū 。' WHERE chinese='等待' AND pinyin='děng dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기다리다 (공식적)', example_zh='贵宾已在会议室等候，请尽快前往。', example_ko='귀빈이 이미 회의실에서 기다리고 있으니 빨리 가주세요.', example_pinyin='guì bīn yǐ zài huì yì shì děng hòu ， qǐng jǐn kuài qián wǎng 。' WHERE chinese='等候' AND pinyin='děng hòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~과 같다, ~에 해당한다', example_zh='一公里等于一千米，这个换算要记住。', example_ko='1킬로미터는 1000미터와 같아, 이 환산은 기억해야 해.', example_pinyin='yī gōng lǐ děng yú yī qiān mǐ ， zhè ge huàn suàn yào jì zhù 。' WHERE chinese='等于' AND pinyin='děng yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='방울; 뚝뚝 떨어지다', example_zh='屋顶漏水了，一滴一滴地往下落，得赶紧修。', example_ko='지붕에서 물이 새서 한 방울씩 떨어지고 있어, 빨리 수리해야 해.', example_pinyin='wū dǐng lòu shuǐ le ， yī dī yī dī dì wǎng xià luò ， dé gǎn jǐn xiū 。' WHERE chinese='滴' AND pinyin='dī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정말로, 확실히', example_zh='他的话的确有道理，我们应该重新考虑这个方案。', example_ko='그가 하는 말이 정말로 일리가 있어, 우리 이 방안을 다시 생각해봐야 해.', example_pinyin='tā de huà dí què yǒu dào lǐ ， wǒ men yīng gāi chóng xīn kǎo lǜ zhè ge fāng àn 。' WHERE chinese='的确' AND pinyin='dí què' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='적, 원수', example_zh='在竞争激烈的商场上，今天的合作伙伴可能是明天的敌人。', example_ko='치열한 경쟁의 시장에서 오늘의 파트너가 내일의 경쟁자가 될 수 있어.', example_pinyin='zài jìng zhēng jī liè de shāng chǎng shàng ， jīn tiān de hé zuò huǒ bàn kě néng shì míng tiān de dí rén 。' WHERE chinese='敌人' AND pinyin='dí rén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='건네다, 넘겨주다', example_zh='他把文件递给了经理，等待下一步的指示。', example_ko='그는 서류를 매니저에게 건네고 다음 지시를 기다렸어.', example_pinyin='tā bǎ wén jiàn dì gěi le jīng lǐ ， děng dài xià yī bù de zhǐ shì 。' WHERE chinese='递' AND pinyin='dì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정통적이다, 순수하다', example_zh='这家餐厅的北京烤鸭味道很地道，很多老北京人都来吃。', example_ko='이 식당의 베이징 오리 요리는 정통 맛이라 베이징 토박이들도 많이 찾아와.', example_pinyin='zhè jiā cān tīng de běi jīng kǎo yā wèi dào hěn dì dào ， hěn duō lǎo běi jīng rén dōu lái chī 。' WHERE chinese='地道' AND pinyin='dì dao' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지리, 지역학', example_zh='学地理可以了解各国的地形、气候和文化。', example_ko='지리를 배우면 각국의 지형, 기후와 문화를 알 수 있어.', example_pinyin='xué dì lǐ kě yǐ liǎo jiě gè guó de dì xíng 、 qì hòu hé wén huà 。' WHERE chinese='地理' AND pinyin='dì lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지역, 지구', example_zh='这个地区经济发展很快，近几年变化很大。', example_ko='이 지역은 경제 발전이 빠르고 최근 몇 년간 변화가 많아.', example_pinyin='zhè ge dì qū jīng jì fā zhǎn hěn kuài ， jìn jǐ nián biàn huà hěn dà 。' WHERE chinese='地区' AND pinyin='dì qū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='카펫', example_zh='客厅铺了一块漂亮的地毯，让整个房间显得更温馨。', example_ko='거실에 예쁜 카펫을 깔았더니 방 전체가 더 아늑해 보여.', example_pinyin='kè tīng pù le yī kuài piào liàng de dì tǎn ， ràng zhěng gè fáng jiān xiǎn de gèng wēn xīn 。' WHERE chinese='地毯' AND pinyin='dì tǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지위, 위치', example_zh='他在公司里的地位很高，大家都很尊重他。', example_ko='그는 회사에서 지위가 높아서 모두가 그를 매우 존중해.', example_pinyin='tā zài gōng sī lǐ de dì wèi hěn gāo ， dà jiā dōu hěn zūn zhòng tā 。' WHERE chinese='地位' AND pinyin='dì wèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지진', example_zh='那次地震造成了很大的破坏，很多房子都倒塌了。', example_ko='그 지진이 큰 피해를 일으켰어, 많은 집이 무너졌어.', example_pinyin='nà cì dì zhèn zào chéng le hěn dà de pò huài ， hěn duō fáng zi dōu dǎo tā le 。' WHERE chinese='地震' AND pinyin='dì zhèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고개를 끄덕이다', example_zh='他听完我的建议，点了点头，表示同意。', example_ko='그는 내 제안을 다 듣고 고개를 끄덕이며 동의를 표했어.', example_pinyin='tā tīng wán wǒ de jiàn yì ， diǎn le diǎn tóu ， biǎo shì tóng yì 。' WHERE chinese='点头' AND pinyin='diǎn tóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='간식, 디저트', example_zh='下午茶时间，同事们一起吃点心，聊聊天。', example_ko='오후 티 타임에 동료들이 함께 간식을 먹으며 수다를 떨어.', example_pinyin='xià wǔ chá shí jiān ， tóng shì men yì qǐ chī diǎn xīn ， liáo liáo tiān 。' WHERE chinese='点心' AND pinyin='diǎn xin' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전지, 배터리', example_zh='遥控器的电池没电了，需要换新的。', example_ko='리모컨 배터리가 떨어졌어, 새것으로 교체해야 해.', example_pinyin='yáo kòng qì de diàn chí méi diàn le ， xū yào huàn xīn de 。' WHERE chinese='电池' AND pinyin='diàn chí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='라디오 방송국', example_zh='她在地方电台主持节目，声音很好听。', example_ko='그녀는 지방 라디오 방송국에서 프로그램을 진행하는데 목소리가 정말 좋아.', example_pinyin='tā zài dì fāng diàn tái zhǔ chí jié mù ， shēng yīn hěn hǎo tīng 。' WHERE chinese='电台' AND pinyin='diàn tái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='낚시하다', example_zh='周末他去河边钓鱼，放松心情，很舒服。', example_ko='주말에 그는 강가에 낚시하러 가서 마음을 풀어, 정말 편해.', example_pinyin='zhōu mò tā qù hé biān diào yú ， fàng sōng xīn qíng ， hěn shū fú 。' WHERE chinese='钓' AND pinyin='diào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='넷째 천간; 남자 이름', example_zh='他叫王丁，名字里有个丁字。', example_ko='그의 이름은 왕딩인데 이름에 丁자가 있어.', example_pinyin='tā jiào wáng dīng ， míng zì lǐ yǒu gè dīng zì 。' WHERE chinese='丁' AND pinyin='dīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정상, 꼭대기; 최고의; 버티다', example_zh='他顶着巨大压力，坚持把项目做完了。', example_ko='그는 엄청난 압박을 버티면서 프로젝트를 끝까지 완수했어.', example_pinyin='tā dǐng zhe jù dà yā lì ， jiān chí bǎ xiàng mù zuò wán le 。' WHERE chinese='顶' AND pinyin='dǐng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='얼다, 얼리다', example_zh='外面太冷，水管都冻住了，没有自来水用。', example_ko='밖이 너무 추워서 수도관이 다 얼어붙어서 수돗물을 쓸 수 없어.', example_pinyin='wài miàn tài lěng ， shuǐ guǎn dōu dòng zhù le ， méi yǒu zì lái shuǐ yòng 。' WHERE chinese='冻' AND pinyin='dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='굴, 구멍', example_zh='墙上有一个小洞，应该是鼠洞，要堵上。', example_ko='벽에 작은 구멍이 있는데 쥐구멍인 것 같아, 막아야 해.', example_pinyin='qiáng shàng yǒu yí gè xiǎo dòng ， yīng gāi shì shǔ dòng ， yào dǔ shàng 。' WHERE chinese='洞' AND pinyin='dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만화 영화, 애니메이션', example_zh='小时候他最喜欢看动画片，现在还经常回看。', example_ko='어릴 때 그는 만화 영화 보는 걸 가장 좋아했는데 지금도 가끔 다시 봐.', example_pinyin='xiǎo shí hòu tā zuì xǐ huān kàn dòng huà piàn ， xiàn zài hái jīng cháng huí kàn 。' WHERE chinese='动画片' AND pinyin='dòng huà piàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='우기다, 웃기다; 놀리다', example_zh='他讲的笑话太逗了，把大家都逗笑了。', example_ko='그가 한 농담이 너무 웃겨서 모두를 웃게 만들었어.', example_pinyin='tā jiǎng de xiào huà tài dòu le ， bǎ dà jiā dōu dòu xiào le 。' WHERE chinese='逗' AND pinyin='dòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='두부', example_zh='麻婆豆腐是很有名的川菜，又辣又香。', example_ko='마파두부는 매우 유명한 쓰촨 요리야, 맵고 향긋해.', example_pinyin='má pó dòu fǔ shì hěn yǒu míng de chuān cài ， yòu là yòu xiāng 。' WHERE chinese='豆腐' AND pinyin='dòu fu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='독립하다, 자립하다', example_zh='大学毕业后，她决定独立生活，不再依赖父母。', example_ko='대학 졸업 후 그녀는 독립적으로 살기로 결심하고 더 이상 부모에게 의존하지 않았어.', example_pinyin='dà xué bì yè hòu ， tā jué dìng dú lì shēng huó ， bù zài yī lài fù mǔ 。' WHERE chinese='独立' AND pinyin='dú lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='독특하다, 독창적이다', example_zh='他的设计风格很独特，很容易辨认出来。', example_ko='그의 디자인 스타일이 매우 독특해서 쉽게 알아볼 수 있어.', example_pinyin='tā de shè jì fēng gé hěn dú tè ， hěn róng yì biàn rèn chū lái 。' WHERE chinese='独特' AND pinyin='dú tè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보내다, 지내다', example_zh='今年暑假我们去海边度过了一段美好的时光。', example_ko='올 여름방학에 우리는 바닷가에서 아름다운 시간을 보냈어.', example_pinyin='jīn nián shǔ jià wǒ men qù hǎi biān dù guò le yī duàn měi hǎo de shí guāng 。' WHERE chinese='度过' AND pinyin='dù guò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='문자 메시지', example_zh='发了一条短信给他，但他没有回复，不知道看到没。', example_ko='그에게 문자를 보냈는데 답장이 없어, 봤는지 모르겠어.', example_pinyin='fā le yī tiáo duǎn xìn gěi tā ， dàn tā méi yǒu huí fù ， bù zhī dào kàn dào méi 。' WHERE chinese='短信' AND pinyin='duǎn xìn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쌓다; 더미', example_zh='桌上堆了一堆书，要整理一下了。', example_ko='책상 위에 책이 한 무더기 쌓여 있어서 정리해야 해.', example_pinyin='zhuō shàng duī le yī duī shū ， yào zhěng lǐ yī xià le 。' WHERE chinese='堆' AND pinyin='duī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대조하다, 비교하다', example_zh='把两份报告对比一下，看看有没有出入。', example_ko='두 보고서를 비교해봐, 차이가 있는지 없는지 확인해.', example_pinyin='bǎ liǎng fèn bào gào duì bǐ yī xià ， kàn kàn yǒu méi yǒu chū rù 。' WHERE chinese='对比' AND pinyin='duì bǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대하다, 처우하다', example_zh='对待工作要认真，不能马马虎虎，应付了事。', example_ko='일을 대할 때 진지해야 해, 대충대충 하면 안 돼.', example_pinyin='duì dài gōng zuò yào rèn zhēn ， bù néng mǎ mǎ hǔ hǔ ， yìng fù liǎo shì 。' WHERE chinese='对待' AND pinyin='duì dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상대방', example_zh='谈判时要了解对方的立场，才能找到合适的方案。', example_ko='협상할 때 상대방의 입장을 파악해야 적합한 방안을 찾을 수 있어.', example_pinyin='tán pàn shí yào liǎo jiě duì fāng de lì chǎng ， cái néng zhǎo dào hé shì de fāng àn 。' WHERE chinese='对方' AND pinyin='duì fāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='경쟁 상대, 라이벌', example_zh='他和对手之间竞争很激烈，两人旗鼓相当。', example_ko='그와 경쟁 상대 사이의 경쟁이 치열해, 두 사람이 막상막하야.', example_pinyin='tā hé duì shǒu zhī jiān jìng zhēng hěn jī liè ， liǎng rén qí gǔ xiāng dāng 。' WHERE chinese='对手' AND pinyin='duì shǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대상, 목표; 연인', example_zh='他还没有找到合适的对象，父母很着急。', example_ko='그는 아직 적합한 상대를 못 찾아서 부모님이 조급해하고 있어.', example_pinyin='tā hái méi yǒu zhǎo dào hé shì de duì xiàng ， fù mǔ hěn zháo jí 。' WHERE chinese='对象' AND pinyin='duì xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~에 대해, ~에 대하여', example_zh='对于这个问题，大家的意见不太一致。', example_ko='이 문제에 대해 모두의 의견이 그다지 일치하지 않아.', example_pinyin='duì yú zhè ge wèn tí ， dà jiā de yì jiàn bù tài yí zhì 。' WHERE chinese='对于' AND pinyin='duì yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='톤 (무게 단위)', example_zh='这批货物重达五吨，需要用大货车来运输。', example_ko='이 화물 무게가 5톤에 달해서 대형 트럭으로 운반해야 해.', example_pinyin='zhè pī huò wù zhòng dá wǔ dūn ， xū yào yòng dà huò chē lái yùn shū 。' WHERE chinese='吨' AND pinyin='dūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쪼그려 앉다', example_zh='他蹲在地上，仔细检查花圃里的植物。', example_ko='그는 바닥에 쪼그려 앉아서 화단의 식물을 꼼꼼히 점검했어.', example_pinyin='tā dūn zài dì shàng ， zǐ xì jiǎn chá huā pǔ lǐ de zhí wù 。' WHERE chinese='蹲' AND pinyin='dūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~덕분에', example_zh='多亏了你的帮助，这件事才顺利解决了。', example_ko='네 도움 덕분에 이 일이 순조롭게 해결됐어.', example_pinyin='duō kuī le nǐ de bāng zhù ， zhè jiàn shì cái shùn lì jiě jué le 。' WHERE chinese='多亏' AND pinyin='duō kuī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='여분이다, 쓸데없다', example_zh='这些材料是多余的，用不上，放在那里占地方。', example_ko='이 자료들은 여분이라 쓸 수 없어서 거기 놓여서 공간만 차지해.', example_pinyin='zhè xiē cái liào shì duō yú de ， yòng bù shàng ， fàng zài nà lǐ zhàn dì fāng 。' WHERE chinese='多余' AND pinyin='duō yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='숨다, 피하다', example_zh='小孩躲藏在桌子下面，等着大人来找她。', example_ko='아이가 탁자 밑에 숨어서 어른이 찾아오기를 기다렸어.', example_pinyin='xiǎo hái duǒ cáng zài zhuō zi xià miàn ， děng zhe dà rén lái zhǎo tā 。' WHERE chinese='躲藏' AND pinyin='duǒ cáng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='나쁘다, 열악하다', example_zh='那一带的环境条件恶劣，生活很艰苦。', example_ko='그 지역의 환경 조건이 열악해서 생활이 매우 힘들어.', example_pinyin='nà yī dài de huán jìng tiáo jiàn è liè ， shēng huó hěn jiān kǔ 。' WHERE chinese='恶劣' AND pinyin='è liè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='발표하다, 게재하다', example_zh='他在学术期刊上发表了一篇关于环境保护的论文。', example_ko='그는 학술 저널에 환경보호에 관한 논문을 발표했어.', example_pinyin='tā zài xué shù qī kān shàng fā biǎo le yī piān guān yú huán jìng bǎo hù de lùn wén 。' WHERE chinese='发表' AND pinyin='fā biǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='걱정하다, 근심하다', example_zh='她为孩子的成绩发愁，晚上都睡不好。', example_ko='그녀는 아이 성적을 걱정하느라 밤에 잠을 못 자.', example_pinyin='tā wèi hái zi de chéng jì fā chóu ， wǎn shàng dōu shuì bù hǎo 。' WHERE chinese='发愁' AND pinyin='fā chóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='발달하다, 선진적이다', example_zh='发达国家的教育体系比较完善，值得借鉴。', example_ko='선진국의 교육 체계가 비교적 잘 갖춰져 있어서 참고할 만해.', example_pinyin='fā dá guó jiā de jiào yù tǐ xì bǐ jiào wán shàn ， zhí de jiè jiàn 。' WHERE chinese='发达' AND pinyin='fā dá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='떨다, 전율하다', example_zh='天气太冷了，他冷得直发抖，赶紧回屋里取暖。', example_ko='날씨가 너무 추워서 그가 추위에 계속 떨었어, 얼른 방에 들어가서 몸을 녹였어.', example_pinyin='tiān qì tài lěng le ， tā lěng dé zhí fā dǒu ， gǎn jǐn huí wū lǐ qǔ nuǎn 。' WHERE chinese='发抖' AND pinyin='fā dǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='발휘하다, 발揮하다', example_zh='在关键时刻，他发挥出了自己最好的水平。', example_ko='결정적인 순간에 그는 자신의 최고 실력을 발휘했어.', example_pinyin='zài guān jiàn shí kè ， tā fā huī chū le zì jǐ zuì hǎo de shuǐ píng 。' WHERE chinese='发挥' AND pinyin='fā huī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='발명하다; 발명품', example_zh='爱迪生发明了电灯，改变了人类的生活方式。', example_ko='에디슨은 전구를 발명해서 인류의 생활 방식을 바꿨어.', example_pinyin='ài dí shēng fà míng liǎo diàn dēng ， gǎi biàn le rén lèi de shēng huó fāng shì 。' WHERE chinese='发明' AND pinyin='fā míng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영수증', example_zh='购物后记得要发票，以便报销或退换货。', example_ko='쇼핑 후 영수증을 챙겨야 해, 환급이나 교환 반품에 필요하거든.', example_pinyin='gòu wù hòu jì de yào fā piào ， yǐ biàn bào xiāo huò tuì huàn huò 。' WHERE chinese='发票' AND pinyin='fā piào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='발언하다; 발언', example_zh='会议上她发言很积极，提了好几个有建设性的意见。', example_ko='회의에서 그녀는 발언을 적극적으로 해서 건설적인 의견을 몇 가지 제시했어.', example_pinyin='huì yì shàng tā fā yán hěn jī jí ， tí le hǎo jǐ gè yǒu jiàn shè xìng de yì jiàn 。' WHERE chinese='发言' AND pinyin='fā yán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='벌금을 부과하다; 벌금', example_zh='随地吐痰会被罚款，这是维护公共卫生的规定。', example_ko='아무데나 침을 뱉으면 벌금을 맞아, 공중위생 유지를 위한 규정이야.', example_pinyin='suí dì tǔ tán huì bèi fá kuǎn ， zhè shì wéi hù gōng gòng wèi shēng de guī dìng 。' WHERE chinese='罚款' AND pinyin='fá kuǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='법원', example_zh='这场官司打了两年，最终由法院判决结果。', example_ko='이 소송은 2년이나 걸렸는데 결국 법원에서 판결을 내렸어.', example_pinyin='zhè chǎng guān sī dǎ le liǎng nián ， zuì zhōng yóu fǎ yuàn pàn jué jié guǒ 。' WHERE chinese='法院' AND pinyin='fǎ yuàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뒤집다, 번역하다', example_zh='他把书翻到了第五章，开始认真阅读。', example_ko='그는 책을 5장으로 펼쳐서 진지하게 읽기 시작했어.', example_pinyin='tā bǎ shū fān dào le dì wǔ zhāng ， kāi shǐ rèn zhēn yuè dú 。' WHERE chinese='翻' AND pinyin='fān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='번영하다, 번성하다', example_zh='改革开放后，这座城市的经济日益繁荣。', example_ko='개혁개방 이후 이 도시의 경제가 날로 번성해졌어.', example_pinyin='gǎi gé kāi fàng hòu ， zhè zuò chéng shì de jīng jì rì yì fán róng 。' WHERE chinese='繁荣' AND pinyin='fán róng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무릇, ~는 모두', example_zh='凡是参加活动的人，都可以获得一份纪念品。', example_ko='행사에 참가하는 사람은 모두 기념품을 받을 수 있어.', example_pinyin='fán shì cān jiā huó dòng de rén ， dōu kě yǐ huò dé yī fèn jì niàn pǐn 。' WHERE chinese='凡是' AND pinyin='fán shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오히려, 반대로', example_zh='他没有因失败而放弃，反而越挫越勇。', example_ko='그는 실패로 포기하기는커녕 오히려 좌절할수록 더 용감해졌어.', example_pinyin='tā méi yǒu yīn shī bài ér fàng qì ， fǎn ér yuè cuò yuè yǒng 。' WHERE chinese='反而' AND pinyin='fǎn ér' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반복적으로, 거듭', example_zh='这道题他反复做了好几遍，终于弄清楚了。', example_ko='이 문제를 그가 반복해서 여러 번 풀었더니 결국 이해했어.', example_pinyin='zhè dào tí tā fǎn fù zuò le hǎo jǐ biàn ， zhōng yú nòng qīng chǔ le 。' WHERE chinese='反复' AND pinyin='fǎn fù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반응; 반응하다', example_zh='她对花粉过敏，接触后会有强烈的反应。', example_ko='그녀는 꽃가루 알레르기가 있어서 접촉하면 강한 반응이 나타나.', example_pinyin='tā duì huā fěn guò mǐn ， jiē chù hòu huì yǒu qiáng liè de fǎn yìng 。' WHERE chinese='反应' AND pinyin='fǎn yìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어차피, 어쨌든', example_zh='反正已经迟到了，就别着急了，慢慢来吧。', example_ko='어차피 이미 늦었으니 서두르지 마, 천천히 와.', example_pinyin='fǎn zhèng yǐ jīng chí dào le ， jiù bié zháo jí le ， màn màn lái ba 。' WHERE chinese='反正' AND pinyin='fǎn zhèng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모, 방형; 방법', example_zh='他想了一个方法，解决了大家头疼的问题。', example_ko='그가 방법을 하나 생각해내서 모두를 골치 아프게 했던 문제를 해결했어.', example_pinyin='tā xiǎng le yí gè fāng fǎ ， jiě jué le dà jiā tóu téng de wèn tí 。' WHERE chinese='方' AND pinyin='fāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='방안, 계획', example_zh='团队提出了三个方案，领导选择了最可行的那个。', example_ko='팀에서 세 가지 방안을 제시했는데 리더가 가장 실행 가능한 것을 선택했어.', example_pinyin='tuán duì tí chū le sān gè fāng àn ， lǐng dǎo xuǎn zé le zuì kě xíng de nà ge 。' WHERE chinese='方案' AND pinyin='fāng àn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='방식, 방법', example_zh='他习惯用自己的方式解决问题，不喜欢按规定来。', example_ko='그는 자기 방식으로 문제를 해결하는 걸 좋아하고 규정대로 하는 걸 싫어해.', example_pinyin='tā xí guàn yòng zì jǐ de fāng shì jiě jué wèn tí ， bù xǐ huān àn guī dìng lái 。' WHERE chinese='方式' AND pinyin='fāng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='방해하다, 지장을 주다', example_zh='在图书馆大声说话会妨碍其他人学习，请保持安静。', example_ko='도서관에서 큰 소리로 말하면 다른 사람들 공부에 방해가 되니 조용히 해주세요.', example_pinyin='zài tú shū guǎn dà shēng shuō huà huì fáng ài qí tā rén xué xí ， qǐng bǎo chí ān jìng 。' WHERE chinese='妨碍' AND pinyin='fáng ài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집주인, 건물주', example_zh='房东突然提高了房租，他不得不另找地方住。', example_ko='집주인이 갑자기 월세를 올려서 그는 어쩔 수 없이 다른 곳을 찾아야 했어.', example_pinyin='fáng dōng tū rán tí gāo le fáng zū ， tā bù dé bù lìng zhǎo dì fāng zhù 。' WHERE chinese='房东' AND pinyin='fáng dōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='마치 ~같다, ~인 듯하다', example_zh='他仿佛没听见一样，继续走自己的路。', example_ko='그는 못 들은 것처럼 계속 자기 길을 걸어갔어.', example_pinyin='tā fǎng fú méi tīng jiàn yī yàng ， jì xù zǒu zì jǐ de lù 。' WHERE chinese='仿佛' AND pinyin='fǎng fú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='편히 쉬다, 긴장을 풀다', example_zh='忙了一整天，晚上要好好放松一下，听听音乐。', example_ko='하루 종일 바빴으니 저녁에 음악을 들으며 잘 쉬어야 해.', example_pinyin='máng le yī zhěng tiān ， wǎn shàng yào hǎo hǎo fàng sōng yī xià ， tīng tīng yīn yuè 。' WHERE chinese='放松' AND pinyin='fàng sōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~가 아니다, 비; 잘못이다', example_zh='这件事非你的错，是我没有说清楚。', example_ko='이 일은 네 잘못이 아니야, 내가 제대로 말하지 않은 거야.', example_pinyin='zhè jiàn shì fēi nǐ de cuò ， shì wǒ méi yǒu shuō qīng chǔ 。' WHERE chinese='非' AND pinyin='fēi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비누', example_zh='洗手时要用肥皂认真搓洗，才能去除细菌。', example_ko='손 씻을 때 비누로 꼼꼼히 문질러야 세균을 제거할 수 있어.', example_pinyin='xǐ shǒu shí yào yòng féi zào rèn zhēn cuō xǐ ， cái néng qù chú xì jūn 。' WHERE chinese='肥皂' AND pinyin='féi zào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='폐', example_zh='长期吸烟会严重损害肺部健康，要尽早戒烟。', example_ko='장기적인 흡연은 폐 건강을 심각하게 해쳐, 일찍 금연해야 해.', example_pinyin='cháng qī xī yān huì yán zhòng sǔn hài fèi bù jiàn kāng ， yào jǐn zǎo jiè yān 。' WHERE chinese='肺' AND pinyin='fèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='헛소리, 쓸데없는 말', example_zh='他说了很多废话，重点就是需要多一点时间。', example_ko='그가 헛소리를 많이 했는데 요점은 시간이 좀 더 필요하다는 거야.', example_pinyin='tā shuō le hěn duō fèi huà ， zhòng diǎn jiù shì xū yào duō yì diǎn shí jiān 。' WHERE chinese='废话' AND pinyin='fèi huà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비용, 경비', example_zh='这次旅行的费用超出了预算，下次要控制一下。', example_ko='이번 여행 비용이 예산을 초과했어, 다음엔 좀 조절해야 해.', example_pinyin='zhè cì lǚ xíng de fèi yòng chāo chū le yù suàn ， xià cì yào kòng zhì yī xià 。' WHERE chinese='费用' AND pinyin='fèi yòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='각각, 따로따로; 헤어지다', example_zh='毕业后大家各奔东西，分别在不同城市生活。', example_ko='졸업 후 다들 뿔뿔이 흩어져서 각각 다른 도시에서 살고 있어.', example_pinyin='bì yè hòu dà jiā gè bēn dōng xī ， fēn bié zài bù tóng chéng shì shēng huó 。' WHERE chinese='分别' AND pinyin='fēn bié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='분포하다, 퍼져 있다', example_zh='这种植物在全国各地都有分布，很常见。', example_ko='이 식물은 전국 각지에 분포하고 있어서 아주 흔해.', example_pinyin='zhè zhòng zhí wù zài quán guó gè dì dōu yǒu fēn bù ， hěn cháng jiàn 。' WHERE chinese='分布' AND pinyin='fēn bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='분배하다, 나누다', example_zh='工作要合理分配，不能让一个人承担太多。', example_ko='일을 합리적으로 분배해야 해, 한 사람이 너무 많이 떠맡으면 안 돼.', example_pinyin='gōng zuò yào hé lǐ fēn pèi ， bù néng ràng yí gè rén chéng dān tài duō 。' WHERE chinese='分配' AND pinyin='fēn pèi' AND hsk_level IN (3,5,6);
