UPDATE words SET meaning='고치다, 수정하다', example_zh='写完作文后要检查，把错别字改正过来。', example_ko='작문을 다 쓰고 나서 검사해서 오탈자를 고쳐야 해.', example_pinyin='xiě wán zuò wén hòu yào jiǎn chá ， bǎ cuò bié zì gǎi zhèng guò lái 。' WHERE chinese='改正' AND pinyin='gǎi zhèng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='덮다; 건물을 짓다', example_zh='他用被子把自己盖住，继续睡觉。', example_ko='그는 이불로 자신을 덮고 계속 잤어.', example_pinyin='tā yòng bèi zi bǎ zì jǐ gài zhù ， jì xù shuì jiào 。' WHERE chinese='盖' AND pinyin='gài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='개괄하다, 요약하다', example_zh='请用一句话概括这篇文章的主要内容。', example_ko='이 글의 주요 내용을 한 문장으로 요약해봐.', example_pinyin='qǐng yòng yī jù huà gài kuò zhè piān wén zhāng de zhǔ yào nèi róng 。' WHERE chinese='概括' AND pinyin='gài kuò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='개념', example_zh='这个概念比较抽象，需要举例来帮助理解。', example_ko='이 개념이 비교적 추상적이라 이해를 돕기 위해 예를 들어야 해.', example_pinyin='zhè ge gài niàn bǐ jiào chōu xiàng ， xū yào jǔ lì lái bāng zhù lǐ jiě 。' WHERE chinese='概念' AND pinyin='gài niàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='솔직하다, 간단명료하다', example_zh='他干脆地拒绝了那个要求，态度很坚决。', example_ko='그는 솔직하게 그 요청을 거절했어, 태도가 매우 단호했어.', example_pinyin='tā gān cuì dì jù jué le nà ge yāo qiú ， tài dù hěn jiān jué 。' WHERE chinese='干脆' AND pinyin='gān cuì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감격하다, 감사하다', example_zh='她帮了我很大的忙，我真的很感激她。', example_ko='그녀가 나를 크게 도와줘서 나는 정말로 그녀에게 감사해.', example_pinyin='tā bāng le wǒ hěn dà de máng ， wǒ zhēn de hěn gǎn jī tā 。' WHERE chinese='感激' AND pinyin='gǎn jī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='느끼다, 체감하다; 감각', example_zh='旅行时我感受到了不同文化的魅力，很有收获。', example_ko='여행하면서 나는 다양한 문화의 매력을 느꼈어, 많은 걸 얻었어.', example_pinyin='lǚ xíng shí wǒ gǎn shòu dào le bù tóng wén huà de mèi lì ， hěn yǒu shōu huò 。' WHERE chinese='感受' AND pinyin='gǎn shòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='느낌, 소감', example_zh='看完这部电影，你有什么感想，跟大家分享一下。', example_ko='이 영화를 다 보고 나서 어떤 느낌이 들었어, 모두와 나눠봐.', example_pinyin='kàn wán zhè bù diàn yǐng ， nǐ yǒu shén me gǎn xiǎng ， gēn dà jiā fēn xiǎng yī xià 。' WHERE chinese='感想' AND pinyin='gǎn xiǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서두르다', example_zh='快迟到了，赶紧出门，别磨蹭了。', example_ko='늦겠다, 서둘러서 나가, 꾸물거리지 마.', example_pinyin='kuài chí dào le ， gǎn jǐn chū mén ， bié mó cèng le 。' WHERE chinese='赶紧' AND pinyin='gǎn jǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='빨리 서두르다', example_zh='领导说文件要今天交，赶快整理好发过去。', example_ko='리더가 서류를 오늘까지 제출하라고 했어, 빨리 정리해서 보내.', example_pinyin='lǐng dǎo shuō wén jiàn yào jīn tiān jiāo ， gǎn kuài zhěng lǐ hǎo fā guò qù 。' WHERE chinese='赶快' AND pinyin='gǎn kuài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일하다', example_zh='他每天干活儿很卖力，老板非常欣赏他。', example_ko='그는 매일 일을 열심히 해서 사장이 그를 매우 높이 평가해.', example_pinyin='tā měi tiān gān huó er hěn mài lì ， lǎo bǎn fēi cháng xīn shǎng tā 。' WHERE chinese='干活儿' AND pinyin='gàn huó r' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='강철, 철강', example_zh='中国的钢铁产量多年来一直是世界第一。', example_ko='중국의 철강 생산량은 수년째 세계 1위를 유지하고 있어.', example_pinyin='zhōng guó de gāng tiě chǎn liàng duō nián lái yì zhí shì shì jiè dì yī 。' WHERE chinese='钢铁' AND pinyin='gāng tiě' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고급의, 고품질의', example_zh='他喜欢高档产品，认为质量好的东西才值得买。', example_ko='그는 고급 제품을 좋아해서 품질 좋은 것만 살 가치가 있다고 생각해.', example_pinyin='tā xǐ huān gāo dàng chǎn pǐn ， rèn wéi zhì liàng hǎo de dōng xī cái zhí de mǎi 。' WHERE chinese='高档' AND pinyin='gāo dàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고속의, 빠른', example_zh='高速公路行驶更快，但需要支付过路费。', example_ko='고속도로로 달리면 더 빠르지만 통행료를 내야 해.', example_pinyin='gāo sù gōng lù xíng shǐ gèng kuài ， dàn xū yào zhī fù guò lù fèi 。' WHERE chinese='高速' AND pinyin='gāo sù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='하다, 만들다 (구어)', example_zh='他搞不清楚这件事是怎么回事，很困惑。', example_ko='그는 이 일이 어떻게 된 건지 이해가 안 돼서 많이 혼란스러워.', example_pinyin='tā gǎo bù qīng chǔ zhè jiàn shì shì zěn me huí shì ， hěn kùn huò 。' WHERE chinese='搞' AND pinyin='gǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='작별하다, 고별하다', example_zh='离开故乡时，他和老朋友们一一告别。', example_ko='고향을 떠날 때 그는 옛 친구들과 하나하나 작별 인사를 나눴어.', example_pinyin='lí kāi gù xiāng shí ， tā hé lǎo péng yǒu men yī yī gào bié 。' WHERE chinese='告别' AND pinyin='gào bié' AND hsk_level IN (3,5,6);
