UPDATE words SET meaning='옆집, 이웃', example_zh='隔壁邻居很吵，经常晚上开派对，影响睡眠。', example_ko='옆집 이웃이 너무 시끄러워서 자주 밤에 파티를 열어서 수면을 방해해.', example_pinyin='gé bì lín jū hěn chǎo ， jīng cháng wǎn shàng kāi pài duì ， yǐng xiǎng shuì mián 。' WHERE chinese='隔壁' AND pinyin='gé bì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='특별히, 유달리', example_zh='今天天气格外晴朗，很适合出去郊游。', example_ko='오늘 날씨가 특별히 맑아서 교외 나들이 가기 좋아.', example_pinyin='jīn tiān tiān qì gé wài qíng lǎng ， hěn shì hé chū qù jiāo yóu 。' WHERE chinese='格外' AND pinyin='gé wài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='혁명, 혁명적이다', example_zh='工业革命彻底改变了人类的生产方式和生活方式。', example_ko='산업혁명은 인류의 생산 방식과 생활 방식을 완전히 바꿔놓았어.', example_pinyin='gōng yè gé mìng chè dǐ gǎi biàn le rén lèi de shēng chǎn fāng shì hé shēng huó fāng shì 。' WHERE chinese='革命' AND pinyin='gé mìng' AND hsk_level IN (3,5,6);
