UPDATE words SET meaning='개성, 성격', example_zh='她个性很强，从不轻易妥协，坚持自己的原则。', example_ko='그녀는 개성이 강해서 쉽게 타협하지 않고 자신의 원칙을 고수해.', example_pinyin='tā gè xìng hěn qiáng ， cóng bù qīng yì tuǒ xié ， jiān chí zì jǐ de yuán zé 。' WHERE chinese='个性' AND pinyin='gè xìng' AND hsk_level IN (3,5,6);
