UPDATE words SET meaning='근본적으로, 전혀', example_zh='他根本不知道这件事，不要怪他。', example_ko='그는 이 일을 전혀 몰랐어, 그를 탓하지 마.', example_pinyin='tā gēn běn bù zhī dào zhè jiàn shì ， bú yào guài tā 。' WHERE chinese='根本' AND pinyin='gēn běn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='더욱, 한층 더', example_zh='经过这次培训，他的技能更加熟练了。', example_ko='이번 교육을 통해 그의 기술이 더욱 능숙해졌어.', example_pinyin='jīng guò zhè cì péi xùn ， tā de jì néng gèng jiā shú liàn le 。' WHERE chinese='更加' AND pinyin='gèng jiā' AND hsk_level IN (3,5,6);
