UPDATE words SET meaning='공개하다, 공개적이다', example_zh='这次会议向公众公开，任何人都可以旁听。', example_ko='이번 회의는 대중에게 공개되어 누구나 방청할 수 있어.', example_pinyin='zhè cì huì yì xiàng gōng zhòng gōng kāi ， rèn hé rén dōu kě yǐ páng tīng 。' WHERE chinese='公开' AND pinyin='gōng kāi' AND hsk_level IN (3,5,6);
