UPDATE words SET meaning='공주', example_zh='故事里的公主被巫婆施了魔法，沉睡了一百年。', example_ko='이야기 속 공주는 마녀에게 마법에 걸려 100년 동안 잠들었어.', example_pinyin='gù shì lǐ de gōng zhǔ bèi wū pó shī le mó fǎ ， chén shuì le yì bǎi nián 。' WHERE chinese='公主' AND pinyin='gōng zhǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='공장', example_zh='他在工厂里工作了十年，熟悉各个生产流程。', example_ko='그는 공장에서 10년간 일해서 각 생산 공정에 익숙해.', example_pinyin='tā zài gōng chǎng lǐ gōng zuò le shí nián ， shú xī gè gè shēng chǎn liú chéng 。' WHERE chinese='工厂' AND pinyin='gōng chǎng' AND hsk_level IN (3,5,6);
