UPDATE words SET meaning='쿵후; 노력, 기술', example_zh='他从小学功夫，现在已经能打出漂亮的套路了。', example_ko='그는 어릴 때부터 쿵후를 배워서 지금은 멋진 동작을 구사할 수 있어.', example_pinyin='tā cóng xiǎo xué gōng fu ， xiàn zài yǐ jīng néng dǎ chū piào liàng de tào lù le 。' WHERE chinese='功夫' AND pinyin='gōng fu' AND hsk_level IN (3,5,6);
