UPDATE words SET meaning='기여하다; 기여, 공헌', example_zh='他为公司做出了很大贡献，受到了高度表彰。', example_ko='그는 회사에 크게 기여해서 높은 표창을 받았어.', example_pinyin='tā wèi gōng sī zuò chū le hěn dà gòng xiàn ， shòu dào le gāo dù biǎo zhāng 。' WHERE chinese='贡献' AND pinyin='gòng xiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소통하다, 의사소통하다', example_zh='多沟通可以减少误解，让合作更顺畅。', example_ko='소통을 많이 하면 오해를 줄이고 협력을 더 원활하게 할 수 있어.', example_pinyin='duō gōu tōng kě yǐ jiǎn shǎo wù jiě ， ràng hé zuò gèng shùn chàng 。' WHERE chinese='沟通' AND pinyin='gōu tōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구성하다, 이루다', example_zh='这栋楼由三个独立单元构成，每个单元有不同的功能。', example_ko='이 건물은 세 개의 독립 유닛으로 구성되어 있어서 각 유닛마다 다른 기능이 있어.', example_pinyin='zhè dòng lóu yóu sān gè dú lì dān yuán gòu chéng ， měi gè dān yuán yǒu bù tóng de gōng néng 。' WHERE chinese='构成' AND pinyin='gòu chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고모', example_zh='我姑姑住在上海，每年春节我们都会去看她。', example_ko='우리 고모는 상하이에 살아서 매년 춘절에 우리는 그녀를 보러 가.', example_pinyin='wǒ gū gū zhù zài shàng hǎi ， měi nián chūn jié wǒ men dū huì qù kàn tā 。' WHERE chinese='姑姑' AND pinyin='gū gu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='처녀, 소녀', example_zh='这个姑娘唱歌唱得非常好，大家都被她的声音折服了。', example_ko='이 아가씨는 노래를 정말 잘해서 다들 그녀의 목소리에 반했어.', example_pinyin='zhè ge gū niáng chàng gē chàng dé fēi cháng hǎo ， dà jiā dōu bèi tā de shēng yīn zhé fú le 。' WHERE chinese='姑娘' AND pinyin='gū niang' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고대', example_zh='中国古代有很多伟大的发明，对全人类都有贡献。', example_ko='중국 고대에는 위대한 발명이 많았어, 전 인류에게 기여했어.', example_pinyin='zhōng guó gǔ dài yǒu hěn duō wěi dà de fā míng ， duì quán rén lèi dōu yǒu gòng xiàn 。' WHERE chinese='古代' AND pinyin='gǔ dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고전적이다, 클래식', example_zh='他喜欢听古典音乐，认为那种音乐有一种沉静的美。', example_ko='그는 클래식 음악 듣는 걸 좋아해서 그 음악에 고요한 아름다움이 있다고 생각해.', example_pinyin='tā xǐ huān tīng gǔ diǎn yīn yuè ， rèn wéi nà zhǒng yīn yuè yǒu yī zhǒng chén jìng de měi 。' WHERE chinese='古典' AND pinyin='gǔ diǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오래되다, 고색창연하다', example_zh='这座古老的城市保留了很多历史建筑，值得游览。', example_ko='이 오래된 도시는 많은 역사 건물을 보존하고 있어서 둘러볼 만해.', example_pinyin='zhè zuò gǔ lǎo de chéng shì bǎo liú le hěn duō lì shǐ jiàn zhù ， zhí de yóu lǎn 。' WHERE chinese='古老' AND pinyin='gǔ lǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주식', example_zh='股票市场波动很大，投资前要做好充分的研究。', example_ko='주식 시장은 변동이 커서 투자 전에 충분한 조사를 해야 해.', example_pinyin='gǔ piào shì chǎng bō dòng hěn dà ， tóu zī qián yào zuò hǎo chōng fèn de yán jiū 。' WHERE chinese='股票' AND pinyin='gǔ piào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고무하다, 격려하다', example_zh='教练一番话鼓舞了队员们，大家信心倍增。', example_ko='코치의 한 마디가 팀원들을 고무시켜서 모두 자신감이 두 배로 늘었어.', example_pinyin='jiào liàn yī fān huà gǔ wǔ le duì yuán men ， dà jiā xìn xīn bèi zēng 。' WHERE chinese='鼓舞' AND pinyin='gǔ wǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뼈', example_zh='老人摔了一跤，骨头骨折了，需要手术治疗。', example_ko='노인이 넘어져서 뼈가 골절됐어, 수술 치료가 필요해.', example_pinyin='lǎo rén shuāi le yī jiāo ， gǔ tou gǔ zhé le ， xū yào shǒu shù zhì liáo 。' WHERE chinese='骨头' AND pinyin='gǔ tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고정하다, 정해두다', example_zh='每周三下午是固定的团队会议时间，不能随意更改。', example_ko='매주 수요일 오후는 정해진 팀 회의 시간이야, 함부로 변경할 수 없어.', example_pinyin='měi zhōu sān xià wǔ shì gù dìng de tuán duì huì yì shí jiān ， bù néng suí yì gēng gǎi 。' WHERE chinese='固定' AND pinyin='gù dìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고체', example_zh='水在零度以下会变成固体，也就是冰。', example_ko='물은 영하에서 고체로 변해, 즉 얼음이 되는 거야.', example_pinyin='shuǐ zài líng dù yǐ xià huì biàn chéng gù tǐ ， yě jiù shì bīng 。' WHERE chinese='固体' AND pinyin='gù tǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고용하다', example_zh='公司决定雇佣更多技术人员，以满足业务发展需求。', example_ko='회사는 업무 발전 수요를 충족하기 위해 기술 인력을 더 고용하기로 결정했어.', example_pinyin='gōng sī jué dìng gù yōng gèng duō jì shù rén yuán ， yǐ mǎn zú yè wù fā zhǎn xū qiú 。' WHERE chinese='雇佣' AND pinyin='gù yōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='등록하다; 등기', example_zh='看病前要先挂号，然后等医生叫到你的名字。', example_ko='진료 전에 먼저 등록해야 해, 그다음에 의사가 이름을 부를 때까지 기다려.', example_pinyin='kàn bìng qián yào xiān guà hào ， rán hòu děng yī shēng jiào dào nǐ de míng zì 。' WHERE chinese='挂号' AND pinyin='guà hào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='순하다, 말을 잘 듣다', example_zh='她的孩子特别乖，从不惹麻烦，大人都很喜欢他。', example_ko='그녀의 아이는 특히 순해서 말썽을 피우지 않아서 어른들이 모두 좋아해.', example_pinyin='tā de hái zi tè bié guāi ， cóng bù rě má fán ， dà rén dōu hěn xǐ huān tā 。' WHERE chinese='乖' AND pinyin='guāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모퉁이를 돌다, 방향을 바꾸다', example_zh='前面路口向右拐弯，然后直走就到了。', example_ko='앞 사거리에서 오른쪽으로 돌면 그냥 직진하면 돼.', example_pinyin='qián miàn lù kǒu xiàng yòu guǎi wān ， rán hòu zhí zǒu jiù dào le 。' WHERE chinese='拐弯' AND pinyin='guǎi wān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어쩐지, 그래서 그렇구나', example_zh='怪不得他今天不开心，原来是失恋了。', example_ko='어쩐지 그가 오늘 기분이 안 좋더라, 알고 보니 실연을 당했네.', example_pinyin='guài bù dé tā jīn tiān bù kāi xīn ， yuán lái shì shī liàn le 。' WHERE chinese='怪不得' AND pinyin='guài bu de' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='닫다, 폐쇄하다', example_zh='下班前要关闭电脑，把资料保存好再走。', example_ko='퇴근 전에 컴퓨터를 끄고 자료를 잘 저장하고 가야 해.', example_pinyin='xià bān qián yào guān bì diàn nǎo ， bǎ zī liào bǎo cún hǎo zài zǒu 。' WHERE chinese='关闭' AND pinyin='guān bì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='배려하다, 보살피다', example_zh='她非常关怀身边的人，总是默默帮助有困难的朋友。', example_ko='그녀는 주변 사람들을 정말 잘 보살피는데 항상 묵묵히 어려운 친구들을 도와.', example_pinyin='tā fēi cháng guān huái shēn biān de rén ， zǒng shì mò mò bāng zhù yǒu kùn nán de péng yǒu 。' WHERE chinese='关怀' AND pinyin='guān huái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='관리, 공무원', example_zh='他考上了公务员，成为了一名政府官员。', example_ko='그는 공무원 시험에 합격해서 정부 관리가 됐어.', example_pinyin='tā kǎo shàng le gōng wù yuán ， chéng wéi le yī míng zhèng fǔ guān yuán 。' WHERE chinese='官' AND pinyin='guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='관찰하다', example_zh='科学家通过观察自然现象，发现了新的规律。', example_ko='과학자는 자연 현상을 관찰해서 새로운 법칙을 발견했어.', example_pinyin='kē xué jiā tōng guò guān chá zì rán xiàn xiàng ， fā xiàn le xīn de guī lǜ 。' WHERE chinese='观察' AND pinyin='guān chá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='관점, 견해', example_zh='从不同的观点来看，这个问题有不同的答案。', example_ko='다른 관점에서 보면 이 문제는 다른 답이 나와.', example_pinyin='cóng bù tóng de guān diǎn lái kàn ， zhè ge wèn tí yǒu bù tóng de dá àn 。' WHERE chinese='观点' AND pinyin='guān diǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='관념, 사고방식', example_zh='年轻一代的观念更加开放，与上一代有很大差异。', example_ko='젊은 세대의 관념은 더욱 개방적이야, 윗세대와 큰 차이가 있어.', example_pinyin='nián qīng yí dài de guān niàn gèng jiā kāi fàng ， yǔ shàng yí dài yǒu hěn dà chā yì 。' WHERE chinese='观念' AND pinyin='guān niàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='관, 튜브', example_zh='水管漏水了，找人来修，否则浪费很多水。', example_ko='수도관이 새고 있어, 수리할 사람을 불러야 해, 안 그러면 물이 많이 낭비돼.', example_pinyin='shuǐ guǎn lòu shuǐ le ， zhǎo rén lái xiū ， fǒu zé làng fèi hěn duō shuǐ 。' WHERE chinese='管子' AND pinyin='guǎn zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='통조림, 깡통', example_zh='家里备了几罐头食品，以备不时之需。', example_ko='집에 통조림 몇 개를 비치해뒀어, 만일의 경우에 대비해서.', example_pinyin='jiā lǐ bèi le jǐ guàn tou shí pǐn ， yǐ bèi bù shí zhī xū 。' WHERE chinese='罐头' AND pinyin='guàn tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='챔피언, 우승자', example_zh='他们队赢得了这次比赛的冠军，队员们都激动不已。', example_ko='그들 팀이 이번 대회에서 우승을 차지해서 팀원들이 모두 감격했어.', example_pinyin='tā men duì yíng dé le zhè cì bǐ sài de guàn jūn ， duì yuán men dōu jī dòng bù yǐ 。' WHERE chinese='冠军' AND pinyin='guàn jūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='매끄럽다, 반질반질하다', example_zh='地板刚刚拖过，很光滑，走路要小心别滑倒。', example_ko='바닥을 방금 닦아서 매우 미끄러우니 걸을 때 미끄러지지 않도록 조심해.', example_pinyin='dì bǎn gāng gāng tuō guò ， hěn guāng huá ， zǒu lù yào xiǎo xīn bié huá dào 。' WHERE chinese='光滑' AND pinyin='guāng hua' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='왕림하다, 방문하다 (경어)', example_zh='欢迎光临，请问您需要什么？', example_ko='어서 오세요, 무엇이 필요하신가요?', example_pinyin='huān yíng guāng lín ， qǐng wèn nín xū yào shén me ？' WHERE chinese='光临' AND pinyin='guāng lín' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='밝다, 광명', example_zh='经历了那段艰难的时光后，他的未来充满了光明。', example_ko='그 힘든 시간을 겪은 후 그의 미래는 광명으로 가득 찼어.', example_pinyin='jīng lì le nà duàn jiān nán de shí guāng hòu ， tā de wèi lái chōng mǎn le guāng míng 。' WHERE chinese='光明' AND pinyin='guāng míng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='CD, 광디스크', example_zh='这张光盘里存有很多重要的照片和文件。', example_ko='이 CD에 중요한 사진과 서류가 많이 저장되어 있어.', example_pinyin='zhè zhāng guāng pán lǐ cún yǒu hěn duō zhòng yào de zhào piān hé wén jiàn 。' WHERE chinese='光盘' AND pinyin='guāng pán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영광스럽다, 명예롭다', example_zh='能代表国家参加比赛，他感到非常光荣。', example_ko='국가를 대표해서 대회에 참가할 수 있어서 그는 매우 영광스럽게 느꼈어.', example_pinyin='néng dài biǎo guó jiā cān jiā bǐ sài ， tā gǎn dào fēi cháng guāng róng 。' WHERE chinese='光荣' AND pinyin='guāng róng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='광장', example_zh='天安门广场是北京的地标，每天都有很多游客参观。', example_ko='천안문 광장은 베이징의 랜드마크야, 매일 많은 관광객이 방문해.', example_pinyin='tiān ān mén guǎng chǎng shì běi jīng de dì biāo ， měi tiān dōu yǒu hěn duō yóu kè cān guān 。' WHERE chinese='广场' AND pinyin='guǎng chǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='광대하다, 방대하다', example_zh='中国土地广大，各地的文化和风景差异很大。', example_ko='중국은 땅이 광대해서 각 지역의 문화와 경치 차이가 매우 커.', example_pinyin='zhōng guó tǔ dì guǎng dà ， gè dì de wén huà hé fēng jǐng chā yì hěn dà 。' WHERE chinese='广大' AND pinyin='guǎng dà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='광범위하다, 폭넓다', example_zh='他的知识面非常广泛，无论什么话题都能聊两句。', example_ko='그의 지식 범위는 매우 광범위해서 어떤 주제로도 한마디씩 할 수 있어.', example_pinyin='tā de zhī shí miàn fēi cháng guǎng fàn ， wú lùn shén me huà tí dōu néng liáo liǎng jù 。' WHERE chinese='广泛' AND pinyin='guǎng fàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='규범, 규칙; 예의 바르다', example_zh='在公共场所要守规矩，不能大声喧哗。', example_ko='공공장소에서는 규범을 지켜야 해, 큰 소리로 떠들면 안 돼.', example_pinyin='zài gōng gòng chǎng suǒ yào shǒu guī jǔ ， bù néng dà shēng xuān huá 。' WHERE chinese='规矩' AND pinyin='guī ju' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='규율, 법칙', example_zh='万物都有其运行规律，理解它们有助于科学进步。', example_ko='만물에는 각자의 운행 법칙이 있어서 이를 이해하면 과학 발전에 도움이 돼.', example_pinyin='wàn wù dōu yǒu qí yùn xíng guī lǜ ， lǐ jiě tā men yǒu zhù yú kē xué jìn bù 。' WHERE chinese='规律' AND pinyin='guī lǜ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='규모', example_zh='这次活动规模很大，吸引了来自全国的参与者。', example_ko='이번 행사는 규모가 커서 전국에서 참가자들을 끌어모았어.', example_pinyin='zhè cì huó dòng guī mó hěn dà ， xī yǐn le lái zì quán guó de cān yù zhě 。' WHERE chinese='规模' AND pinyin='guī mó' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='규칙', example_zh='游戏有自己的规则，参与者必须遵守。', example_ko='게임에는 자체 규칙이 있어서 참가자는 반드시 지켜야 해.', example_pinyin='yóu xì yǒu zì jǐ de guī zé ， cān yù zhě bì xū zūn shǒu 。' WHERE chinese='规则' AND pinyin='guī zé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='카운터, 계산대', example_zh='请到柜台办理手续，工作人员会帮你处理的。', example_ko='카운터에 가서 수속을 처리하세요, 담당자가 도와드릴 거예요.', example_pinyin='qǐng dào guì tái bàn lǐ shǒu xù ， gōng zuò rén yuán huì bāng nǐ chǔ lǐ de 。' WHERE chinese='柜台' AND pinyin='guì tái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구르다, 굴러가다', example_zh='皮球滚到了马路上，小朋友追过去把它捡起来。', example_ko='공이 도로로 굴러갔는데 아이가 뒤쫓아가서 주웠어.', example_pinyin='pí qiú gǔn dào le mǎ lù shàng ， xiǎo péng yǒu zhuī guò qù bǎ tā jiǎn qǐ lái 。' WHERE chinese='滚' AND pinyin='gǔn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='냄비, 솥', example_zh='妈妈在厨房用锅炖了一锅香喷喷的排骨汤。', example_ko='엄마가 주방에서 냄비로 향긋한 갈비탕을 끓이고 있어.', example_pinyin='mā mā zài chú fáng yòng guō dùn le yī guō xiāng pēn pēn de pái gǔ tāng 。' WHERE chinese='锅' AND pinyin='guō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='국적', example_zh='他持有两个国家的国籍，生活在两国之间。', example_ko='그는 두 나라의 국적을 갖고 있어서 두 나라 사이에서 생활해.', example_pinyin='tā chí yǒu liǎng gè guó jiā de guó jí ， shēng huó zài liǎng guó zhī jiān 。' WHERE chinese='国籍' AND pinyin='guó jí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='국경절, 국경일', example_zh='国庆节期间，全国各地都有庆祝活动和烟火表演。', example_ko='국경절 기간에 전국 각지에서 기념행사와 불꽃놀이가 있어.', example_pinyin='guó qìng jié qī jiān ， quán guó gè dì dōu yǒu qìng zhù huó dòng hé yān huǒ biǎo yǎn 。' WHERE chinese='国庆节' AND pinyin='Guó qìng jié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='열매, 결실', example_zh='秋天果实累累，农民们忙着收获，脸上都是笑容。', example_ko='가을에 열매가 풍성해서 농부들이 수확에 바쁘고 모두 환한 얼굴이야.', example_pinyin='qiū tiān guǒ shí lěi lěi ， nóng mín men máng zhe shōu huò ， liǎn shàng dōu shì xiào róng 。' WHERE chinese='果实' AND pinyin='guǒ shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지나치다, 과분하다', example_zh='批评可以，但不要过分，要顾及对方的感受。', example_ko='비판할 수는 있지만 지나치면 안 돼, 상대방의 감정을 배려해야 해.', example_pinyin='pī píng kě yǐ ， dàn bú yào guò fèn ， yào gù jí duì fāng de gǎn shòu 。' WHERE chinese='过分' AND pinyin='guò fèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='알레르기가 생기다', example_zh='她对海鲜过敏，吃了之后会起皮疹，非常难受。', example_ko='그녀는 해산물 알레르기가 있어서 먹으면 두드러기가 나서 매우 힘들어.', example_pinyin='tā duì hǎi xiān guò mǐn ， chī le zhī hòu huì qǐ pí zhěn ， fēi cháng nán shòu 。' WHERE chinese='过敏' AND pinyin='guò mǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유효기간이 지나다', example_zh='这瓶牛奶已经过期了，喝了可能会拉肚子。', example_ko='이 우유는 이미 유효기간이 지났어, 마시면 배탈이 날 수 있어.', example_pinyin='zhè píng niú nǎi yǐ jīng guò qī le ， hē le kě néng huì lā dù zi 。' WHERE chinese='过期' AND pinyin='guò qī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='하하 (웃음소리)', example_zh='他听到这个笑话，忍不住哈哈大笑起来。', example_ko='그는 이 농담을 듣고 참지 못하고 하하 크게 웃어버렸어.', example_pinyin='tā tīng dào zhè ge xiào huà ， rěn bú zhù hā hā dà xiào qǐ lái 。' WHERE chinese='哈' AND pinyin='hā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세관', example_zh='入境时需要通过海关检查，申报携带的物品。', example_ko='입국 시 세관 검사를 통과해야 하고 휴대품을 신고해야 해.', example_pinyin='rù jìng shí xū yào tōng guò hǎi guān jiǎn chá ， shēn bào xié dài de wù pǐn 。' WHERE chinese='海关' AND pinyin='hǎi guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='해산물', example_zh='在沿海城市，海鲜非常新鲜，价格也比内地便宜。', example_ko='해안 도시에서는 해산물이 매우 신선하고 내륙보다 가격도 저렴해.', example_pinyin='zài yán hǎi chéng shì ， hǎi xiān fēi cháng xīn xiān ， jià gé yě bǐ nèi dì pián yi 。' WHERE chinese='海鲜' AND pinyin='hǎi xiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소리치다, 외치다', example_zh='她在人群中喊了他的名字，但他没有听到。', example_ko='그녀는 군중 속에서 그의 이름을 소리쳤는데 그는 듣지 못했어.', example_pinyin='tā zài rén qún zhōng hǎn le tā de míng zì ， dàn tā méi yǒu tīng dào 。' WHERE chinese='喊' AND pinyin='hǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='업종, 업계', example_zh='他在IT行业工作了多年，积累了丰富的经验。', example_ko='그는 IT 업계에서 수년간 일해서 풍부한 경험을 쌓았어.', example_pinyin='tā zài IT háng yè gōng zuò le duō nián ， jī lěi le fēng fù de jīng yàn 。' WHERE chinese='行业' AND pinyin='háng yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='호화롭다, 럭셔리하다', example_zh='他们入住了一家豪华酒店，享受了一段难忘的旅程。', example_ko='그들은 호화 호텔에 투숙해서 잊을 수 없는 여행을 즐겼어.', example_pinyin='tā men rù zhù le yī jiā háo huá jiǔ diàn ， xiǎng shòu le yī duàn nán wàng de lǚ chéng 。' WHERE chinese='豪华' AND pinyin='háo huá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='호기심이 많다', example_zh='小孩子天生好奇，对新事物特别感兴趣。', example_ko='아이들은 선천적으로 호기심이 많아서 새로운 것에 특히 흥미를 느껴.', example_pinyin='xiǎo hái zi tiān shēng hào qí ， duì xīn shì wù tè bié gǎn xìng qù 。' WHERE chinese='好奇' AND pinyin='hào qí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평화, 화평', example_zh='世界和平是每个人共同的愿望，需要大家共同维护。', example_ko='세계 평화는 모든 사람의 공통된 소원이야, 다함께 지켜나가야 해.', example_pinyin='shì jiè hé píng shì měi gè rén gòng tóng de yuàn wàng ， xū yào dà jiā gòng tóng wéi hù 。' WHERE chinese='和平' AND pinyin='hé píng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무엇 하러, 왜', example_zh='既然你不喜欢，何必勉强自己去做？', example_ko='싫어한다면 무엇 하러 억지로 해? 굳이 할 필요 없잖아.', example_pinyin='jì rán nǐ bù xǐ huān ， hé bì miǎn qiǎng zì jǐ qù zuò ？' WHERE chinese='何必' AND pinyin='hé bì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='더구나, 하물며', example_zh='连我这个外国人都知道，何况是本地人呢？', example_ko='나 같은 외국인도 알고 있는데 현지인은 오죽하겠어.', example_pinyin='lián wǒ zhè ge wài guó rén dōu zhī dào ， hé kuàng shì běn dì rén ne ？' WHERE chinese='何况' AND pinyin='hé kuàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='합법적이다', example_zh='他的行为是合法的，没有违反任何法律规定。', example_ko='그의 행위는 합법적이야, 어떤 법 규정도 위반하지 않았어.', example_pinyin='tā de xíng wéi shì hé fǎ de ， méi yǒu wéi fǎn rèn hé fǎ lǜ guī dìng 。' WHERE chinese='合法' AND pinyin='hé fǎ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='합리적이다, 이치에 맞다', example_zh='这个价格非常合理，不贵也不便宜，刚好。', example_ko='이 가격은 매우 합리적이야, 비싸지도 저렴하지도 않고 딱 맞아.', example_pinyin='zhè ge jià gé fēi cháng hé lǐ ， bù guì yě bù biàn yí ， gāng hǎo 。' WHERE chinese='合理' AND pinyin='hé lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='계약, 합동', example_zh='签合同之前一定要仔细阅读每一条款。', example_ko='계약서에 서명하기 전에 반드시 모든 조항을 꼼꼼히 읽어야 해.', example_pinyin='qiān hé tóng zhī qián yí dìng yào zǐ xì yuè dú měi yī tiáo kuǎn 。' WHERE chinese='合同' AND pinyin='hé tong' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='함께 사진 찍다', example_zh='活动结束后，大家聚在一起合影留念。', example_ko='행사가 끝난 후 다들 모여서 함께 기념사진을 찍었어.', example_pinyin='huó dòng jié shù hòu ， dà jiā jù zài yì qǐ hé yǐng liú niàn 。' WHERE chinese='合影' AND pinyin='hé yǐng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='협력하다, 협동하다', example_zh='两家公司决定合作，共同开发新市场。', example_ko='두 회사가 협력하기로 결정하고 함께 새로운 시장을 개척하기로 했어.', example_pinyin='liǎng jiā gōng sī jué dìng hé zuò ， gòng tóng kāi fā xīn shì chǎng 。' WHERE chinese='合作' AND pinyin='hé zuò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='핵심', example_zh='学习要抓住核心内容，不能什么都学，要有重点。', example_ko='공부할 때 핵심 내용을 파악해야 해, 모든 걸 다 배울 수 없으니 중점이 있어야 해.', example_pinyin='xué xí yào zhuā zhù hé xīn nèi róng ， bù néng shén me dōu xué ， yào yǒu zhòng diǎn 。' WHERE chinese='核心' AND pinyin='hé xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미워하다, 증오하다', example_zh='他很恨那个背叛了他的朋友，再也不想见到对方。', example_ko='그는 자신을 배신한 친구를 몹시 미워해서 다시는 보고 싶지 않아.', example_pinyin='tā hěn hèn nà ge bèi pàn le tā de péng yǒu ， zài yě bù xiǎng jiàn dào duì fāng 。' WHERE chinese='恨' AND pinyin='hèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가로의, 수평의', example_zh='这幅画挂得不对，是横的，应该是竖的。', example_ko='이 그림이 잘못 걸렸어, 가로로 됐는데 세로여야 해.', example_pinyin='zhè fú huà guà dé bú duì ， shì héng de ， yīng gāi shì shù de 。' WHERE chinese='横' AND pinyin='héng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결과, 후과', example_zh='不考虑后果就行动，往往会带来很多麻烦。', example_ko='결과를 고려하지 않고 행동하면 많은 문제를 일으키기 쉬워.', example_pinyin='bù kǎo lǜ hòu guǒ jiù xíng dòng ， wǎng wǎng huì dài lái hěn duō má fán 。' WHERE chinese='后果' AND pinyin='hòu guǒ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무시하다, 등한시하다', example_zh='他忽视了身体发出的信号，结果病情越来越严重。', example_ko='그는 몸이 보내는 신호를 무시했다가 결국 병이 점점 더 심해졌어.', example_pinyin='tā hū shì le shēn tǐ fā chū de xìn hào ， jié guǒ bìng qíng yuè lái yuè yán zhòng 。' WHERE chinese='忽视' AND pinyin='hū shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='호흡하다', example_zh='在空气污染严重的地方，要减少户外活动，保护呼吸系统。', example_ko='공기오염이 심한 곳에서는 야외 활동을 줄이고 호흡기를 보호해야 해.', example_pinyin='zài kōng qì wū rǎn yán zhòng de dì fāng ， yào jiǎn shǎo hù wài huó dòng ， bǎo hù hū xī xì tǒng 。' WHERE chinese='呼吸' AND pinyin='hū xī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주전자', example_zh='水壶里的水开了，快去泡茶吧。', example_ko='주전자 물이 끓었어, 빨리 가서 차 우려봐.', example_pinyin='shuǐ hú lǐ de shuǐ kāi le ， kuài qù pào chá ba 。' WHERE chinese='壶' AND pinyin='hú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='나비', example_zh='花园里有很多色彩斑斓的蝴蝶，飞来飞去，很美。', example_ko='정원에 알록달록한 나비가 많이 날아다니고 있어, 정말 아름다워.', example_pinyin='huā yuán lǐ yǒu hěn duō sè cǎi bān lán de hú dié ， fēi lái fēi qù ， hěn měi 。' WHERE chinese='蝴蝶' AND pinyin='hú dié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='허튼소리하다, 말도 안 되다', example_zh='他在胡说，这件事根本不是那样，别相信他。', example_ko='그는 허튼소리를 하고 있어, 이 일은 전혀 그렇지 않아, 그를 믿지 마.', example_pinyin='tā zài hú shuō ， zhè jiàn shì gēn běn bú shì nà yàng ， bié xiāng xìn tā 。' WHERE chinese='胡说' AND pinyin='hú shuō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='골목', example_zh='北京的胡同文化是老北京的缩影，很有历史感。', example_ko='베이징의 골목 문화는 옛 베이징의 축소판이야, 역사감이 넘쳐.', example_pinyin='běi jīng de hú tòng wén huà shì lǎo běi jīng de suō yǐng ， hěn yǒu lì shǐ gǎn 。' WHERE chinese='胡同' AND pinyin='hú tòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수염', example_zh='他最近留起了胡须，看起来成熟了很多。', example_ko='그는 최근 수염을 기르기 시작해서 훨씬 성숙해 보여.', example_pinyin='tā zuì jìn liú qǐ le hú xū ， kàn qǐ lái chéng shú le hěn duō 。' WHERE chinese='胡须' AND pinyin='hú xū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='혼란스럽다, 어리둥절하다', example_zh='他被这么多选择弄得很糊涂，不知道该选哪个好。', example_ko='그는 이렇게 많은 선택지에 어리둥절해져서 어느 것을 골라야 할지 모르겠어.', example_pinyin='tā bèi zhè me duō xuǎn zé nòng dé hěn hú tú ， bù zhī dào gāi xuǎn nǎ ge hǎo 。' WHERE chinese='糊涂' AND pinyin='hú tu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='땅콩', example_zh='花生是一种营养丰富的食物，可以榨油，也可以直接吃。', example_ko='땅콩은 영양이 풍부한 식품이야, 기름을 짜거나 그냥 먹을 수도 있어.', example_pinyin='huā shēng shì yī zhǒng yíng yǎng fēng fù de shí wù ， kě yǐ zhà yóu ， yě kě yǐ zhí jiē chī 。' WHERE chinese='花生' AND pinyin='huā shēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='스케이트를 타다', example_zh='冬天他们去湖面上滑冰，非常开心。', example_ko='겨울에 그들은 호수 위에서 스케이트를 탔어, 정말 즐거웠어.', example_pinyin='dōng tiān tā men qù hú miàn shàng huá bīng ， fēi cháng kāi xīn 。' WHERE chinese='滑冰' AND pinyin='huá bīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보트를 타다', example_zh='夏天他喜欢去湖边划船，在水面上静静地漂流。', example_ko='여름에 그는 호숫가에 가서 보트를 타는 걸 좋아해, 수면 위에서 조용히 떠다녀.', example_pinyin='xià tiān tā xǐ huān qù hú biān huá chuán ， zài shuǐ miàn shàng jìng jìng dì piāo liú 。' WHERE chinese='划船' AND pinyin='huá chuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='화교', example_zh='他是一名华裔，虽然生活在海外，但始终保持着中国传统。', example_ko='그는 화교야, 해외에 살지만 항상 중국 전통을 유지하고 있어.', example_pinyin='tā shì yī míng huá yì ， suī rán shēng huó zài hǎi wài ， dàn shǐ zhōng bǎo chí zhe zhōng guó chuán tǒng 。' WHERE chinese='华裔' AND pinyin='Huá yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='화학', example_zh='化学实验需要严格遵守操作规程，避免发生事故。', example_ko='화학 실험은 운영 규정을 엄격히 지켜서 사고가 일어나지 않도록 해야 해.', example_pinyin='huà xué shí yàn xū yào yán gé zūn shǒu cāo zuò guī chéng ， bì miǎn fā shēng shì gù 。' WHERE chinese='化学' AND pinyin='huà xué' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='화제, 주제', example_zh='今天的话题是关于环境保护，大家有什么想法？', example_ko='오늘의 화제는 환경보호에 관한 거야, 다들 무슨 생각이 있어?', example_pinyin='jīn tiān de huà tí shì guān yú huán jìng bǎo hù ， dà jiā yǒu shén me xiǎng fǎ ？' WHERE chinese='话题' AND pinyin='huà tí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그리워하다, 회상하다', example_zh='她时常怀念小时候的快乐时光，觉得那是最美好的记忆。', example_ko='그녀는 어릴 때의 즐거운 시간을 자주 그리워해, 그게 가장 아름다운 추억이라고 느껴.', example_pinyin='tā shí cháng huái niàn xiǎo shí hòu de kuài lè shí guāng ， jué de nà shì zuì měi hǎo de jì yì 。' WHERE chinese='怀念' AND pinyin='huái niàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='완화하다, 해소하다', example_zh='听音乐能帮助缓解压力，让人放松下来。', example_ko='음악을 들으면 스트레스를 완화하는 데 도움이 되어 사람을 이완시켜줘.', example_pinyin='tīng yīn yuè néng bāng zhù huǎn jiě yā lì ， ràng rén fàng sōng xià lái 。' WHERE chinese='缓解' AND pinyin='huǎn jiě' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='환상, 상상하다', example_zh='他从小就有飞行员的幻想，后来真的实现了梦想。', example_ko='그는 어릴 때부터 비행사에 대한 환상을 갖고 있었는데 나중에 정말 꿈을 이뤘어.', example_pinyin='tā cóng xiǎo jiù yǒu fēi xíng yuán de huàn xiǎng ， hòu lái zhēn de shí xiàn le mèng xiǎng 。' WHERE chinese='幻想' AND pinyin='huàn xiǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='당황하다, 허둥대다', example_zh='突然停电，她有点慌张，赶紧找手电筒。', example_ko='갑자기 정전이 되자 그녀는 좀 당황해서 얼른 손전등을 찾았어.', example_pinyin='tū rán tíng diàn ， tā yǒu diǎn huāng zhāng ， gǎn jǐn zhǎo shǒu diàn tǒng 。' WHERE chinese='慌张' AND pinyin='huāng zhāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오이', example_zh='夏天吃黄瓜凉拌很爽口，而且热量低，很健康。', example_ko='여름에 오이를 무쳐서 먹으면 시원하고 열량도 낮아서 건강에 좋아.', example_pinyin='xià tiān chī huáng guā liáng bàn hěn shuǎng kǒu ， ér qiě rè liàng dī ， hěn jiàn kāng 。' WHERE chinese='黄瓜' AND pinyin='huáng guā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='금, 황금', example_zh='她买了一条黄金项链，作为自己的生日礼物。', example_ko='그녀는 황금 목걸이를 하나 사서 자신의 생일 선물로 했어.', example_pinyin='tā mǎi le yī tiáo huáng jīn xiàng liàn ， zuò wéi zì jǐ de shēng rì lǐ wù 。' WHERE chinese='黄金' AND pinyin='huáng jīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='황제', example_zh='秦始皇是中国历史上第一位统一全国的皇帝。', example_ko='진시황은 중국 역사상 전국을 최초로 통일한 황제야.', example_pinyin='qín shǐ huáng shì zhōng guó lì shǐ shàng dì yī wèi tǒng yī quán guó de huáng dì 。' WHERE chinese='皇帝' AND pinyin='huáng dì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='황후', example_zh='这部电视剧讲述了皇后与皇帝的宫廷故事，很受欢迎。', example_ko='이 TV 드라마는 황후와 황제의 궁중 이야기를 다루고 있어서 인기가 많아.', example_pinyin='zhè bù diàn shì jù jiǎng shù le huáng hòu yǔ huáng dì de gōng tíng gù shì ， hěn shòu huān yíng 。' WHERE chinese='皇后' AND pinyin='huáng hòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='회색; 재', example_zh='这件灰色的西服很低调，适合正式场合穿。', example_ko='이 회색 정장은 무난해서 공식 행사에 입기 좋아.', example_pinyin='zhè jiàn huī sè de xī fú hěn dī diào ， shì hé zhèng shì chǎng hé chuān 。' WHERE chinese='灰' AND pinyin='huī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='먼지, 티끌', example_zh='桌子上积了一层灰尘，需要擦一擦，保持整洁。', example_ko='책상 위에 먼지가 한 겹 쌓였어, 닦아서 깨끗하게 유지해야 해.', example_pinyin='zhuō zi shàng jī le yī céng huī chén ， xū yào cā yī cā ， bǎo chí zhěng jié 。' WHERE chinese='灰尘' AND pinyin='huī chén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='낙심하다, 의기소침하다', example_zh='虽然失败了，但不能灰心，要继续努力才行。', example_ko='비록 실패했지만 낙심하면 안 돼, 계속 노력해야 해.', example_pinyin='suī rán shī bài le ， dàn bù néng huī xīn ， yào jì xù nǔ lì cái xíng 。' WHERE chinese='灰心' AND pinyin='huī xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='흔들다, 휘두르다', example_zh='他挥了挥手，告别了送他的朋友们。', example_ko='그는 손을 흔들며 배웅 나온 친구들에게 작별을 고했어.', example_pinyin='tā huī le huī shǒu ， gào bié le sòng tā de péng yǒu men 。' WHERE chinese='挥' AND pinyin='huī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='회복하다, 되돌리다', example_zh='生病后要好好休息，身体才能尽快恢复。', example_ko='아프고 나서 잘 쉬어야 몸이 빨리 회복될 수 있어.', example_pinyin='shēng bìng hòu yào hǎo hǎo xiū xī ， shēn tǐ cái néng jǐn kuài huī fù 。' WHERE chinese='恢复' AND pinyin='huī fù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='환율', example_zh='出国前要关注一下汇率，换合适的外币。', example_ko='출국 전에 환율을 좀 확인해서 적합한 외화로 환전해야 해.', example_pinyin='chū guó qián yào guān zhù yī xià huì lǜ ， huàn hé shì de wài bì 。' WHERE chinese='汇率' AND pinyin='huì lǜ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결혼식', example_zh='他们的婚礼办得很隆重，请了很多亲朋好友。', example_ko='그들의 결혼식은 성대하게 열렸어, 친척과 친구들을 많이 초대했어.', example_pinyin='tā men de hūn lǐ bàn dé hěn lóng zhòng ， qǐng le hěn duō qīn péng hǎo yǒu 。' WHERE chinese='婚礼' AND pinyin='hūn lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결혼, 혼인', example_zh='婚姻需要双方共同经营，彼此理解和包容。', example_ko='결혼은 양쪽이 함께 가꿔나가야 해, 서로 이해하고 포용해야 해.', example_pinyin='hūn yīn xū yào shuāng fāng gòng tóng jīng yíng ， bǐ cǐ lǐ jiě hé bāo róng 。' WHERE chinese='婚姻' AND pinyin='hūn yīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='활발하다, 활기차다', example_zh='她在课堂上表现很活跃，经常主动提问。', example_ko='그녀는 수업 시간에 매우 활발해서 자주 먼저 질문해.', example_pinyin='tā zài kè táng shàng biǎo xiàn hěn huó yuè ， jīng cháng zhǔ dòng tí wèn 。' WHERE chinese='活跃' AND pinyin='huó yuè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성냥', example_zh='以前没有打火机，大家都用火柴来点火。', example_ko='예전에 라이터가 없어서 다들 성냥으로 불을 붙였어.', example_pinyin='yǐ qián méi yǒu dǎ huǒ jī ， dà jiā dōu yòng huǒ chái lái diǎn huǒ 。' WHERE chinese='火柴' AND pinyin='huǒ chái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='동료, 파트너', example_zh='他和伙伴们一起创业，经历了很多困难。', example_ko='그는 동료들과 함께 창업했는데 많은 어려움을 겪었어.', example_pinyin='tā hé huǒ bàn men yì qǐ chuàng yè ， jīng lì le hěn duō kùn nán 。' WHERE chinese='伙伴' AND pinyin='huǒ bàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기본적인, 기초의', example_zh='这些是基本知识，学好了才能进一步提高。', example_ko='이것들은 기본 지식이야, 잘 익혀야 한 단계 더 발전할 수 있어.', example_pinyin='zhè xiē shì jī běn zhī shí ， xué hǎo le cái néng jìn yí bù tí gāo 。' WHERE chinese='基本' AND pinyin='jī běn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기계', example_zh='工厂里的机器发出很大的噪音，工人都戴着耳塞。', example_ko='공장의 기계가 큰 소음을 내서 노동자들이 모두 귀마개를 하고 있어.', example_pinyin='gōng chǎng lǐ de jī qì fā chū hěn dà de zào yīn ， gōng rén dōu dài zhe ěr sāi 。' WHERE chinese='机器' AND pinyin='jī qì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='격렬하다, 치열하다', example_zh='两队之间的比赛非常激烈，观众都很紧张。', example_ko='두 팀의 경기가 매우 치열해서 관중들이 모두 긴장했어.', example_pinyin='liǎng duì zhī jiān de bǐ sài fēi cháng jī liè ， guān zhòng dōu hěn jǐn zhāng 。' WHERE chinese='激烈' AND pinyin='jī liè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='근육', example_zh='坚持运动可以增强肌肉，改善体型。', example_ko='운동을 꾸준히 하면 근육을 강화하고 체형을 개선할 수 있어.', example_pinyin='jiān chí yùn dòng kě yǐ zēng qiáng jī ròu ， gǎi shàn tǐ xíng 。' WHERE chinese='肌肉' AND pinyin='jī ròu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='합격하다', example_zh='这次考试他总算及格了，悬着的心终于放下了。', example_ko='이번 시험에서 그는 드디어 합격해서 조마조마했던 마음이 드디어 놓였어.', example_pinyin='zhè cì kǎo shì tā zǒng suàn jí gé le ， xuán zhe de xīn zhōng yú fàng xià le 。' WHERE chinese='及格' AND pinyin='jí gé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서둘러, 황급히', example_zh='听说妈妈生病了，他急忙赶去医院。', example_ko='엄마가 아프다는 말을 듣고 그는 서둘러 병원으로 달려갔어.', example_pinyin='tīng shuō mā mā shēng bìng le ， tā jí máng gǎn qù yī yuàn 。' WHERE chinese='急忙' AND pinyin='jí máng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집단, 단체', example_zh='集体活动需要大家相互配合，不能只顾自己。', example_ko='단체 활동은 모두가 서로 협력해야 해, 자기만 챙기면 안 돼.', example_pinyin='jí tǐ huó dòng xū yào dà jiā xiāng hù pèi hé ， bù néng zhǐ gù zì jǐ 。' WHERE chinese='集体' AND pinyin='jí tǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집중하다', example_zh='上课的时候要集中注意力，不要分心。', example_ko='수업 시간에는 집중해야 해, 딴생각하면 안 돼.', example_pinyin='shàng kè de shí hòu yào jí zhōng zhù yì lì ， bú yào fēn xīn 。' WHERE chinese='集中' AND pinyin='jí zhōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기록하다; 기록', example_zh='他把会议的主要内容都记录下来，方便之后查阅。', example_ko='그는 회의의 주요 내용을 모두 기록해뒀어, 나중에 확인하기 편하게.', example_pinyin='tā bǎ huì yì de zhǔ yào nèi róng dōu jì lù xià lái ， fāng biàn zhī hòu chá yuè 。' WHERE chinese='记录' AND pinyin='jì lù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기억, 기억하다', example_zh='她的记忆力很好，背过的东西很少会忘。', example_ko='그녀는 기억력이 좋아서 외운 것을 거의 잊지 않아.', example_pinyin='tā de jì yì lì hěn hǎo ， bèi guò de dōng xī hěn shǎo huì wàng 。' WHERE chinese='记忆' AND pinyin='jì yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='계산하다', example_zh='他计算了一下费用，发现已经超出了预算。', example_ko='그는 비용을 계산해봤더니 이미 예산을 초과했다는 걸 알았어.', example_pinyin='tā jì suàn le yī xià fèi yòng ， fā xiàn yǐ jīng chāo chū le yù suàn 。' WHERE chinese='计算' AND pinyin='jì suàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쓸쓸하다, 외롭다', example_zh='他一个人在外地工作，感到非常寂寞。', example_ko='그는 혼자 타지에서 일해서 매우 외롭게 느껴.', example_pinyin='tā yí gè rén zài wài dì gōng zuò ， gǎn dào fēi cháng jì mò 。' WHERE chinese='寂寞' AND pinyin='jì mò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='넥타이를 매다', example_zh='参加正式场合前，他仔细系好领带，整理好仪表。', example_ko='공식 행사에 참가하기 전 그는 넥타이를 꼼꼼히 매고 몸가짐을 가다듬었어.', example_pinyin='cān jiā zhèng shì chǎng hé qián ， tā zǐ xì jì hǎo lǐng dài ， zhěng lǐ hǎo yí biǎo 。' WHERE chinese='系领带' AND pinyin='jì lǐng dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='(공식) 기록', example_zh='他打破了百米短跑的世界纪录，成为历史上最快的人之一。', example_ko='그는 100미터 단거리 세계 기록을 경신해서 역사상 가장 빠른 사람 중 하나가 됐어.', example_pinyin='tā dǎ pò le bǎi mǐ duǎn pǎo de shì jiè jì lù ， chéng wéi lì shǐ shàng zuì kuài de rén zhī yī 。' WHERE chinese='纪录' AND pinyin='jì lù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='규율, 기강', example_zh='军队的纪律非常严格，任何人都不得违反。', example_ko='군대의 규율은 매우 엄격해서 누구도 위반할 수 없어.', example_pinyin='jūn duì de jì lǜ fēi cháng yán gé ， rèn hé rén dōu bù dé wéi fǎn 。' WHERE chinese='纪律' AND pinyin='jì lǜ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기념하다; 기념', example_zh='这枚纪念币是为庆祝建国70周年而发行的。', example_ko='이 기념 동전은 건국 70주년을 기념하기 위해 발행된 거야.', example_pinyin='zhè méi jì niàn bì shì wèi qìng zhù jiàn guó 70 zhōu nián ér fā xíng de 。' WHERE chinese='纪念' AND pinyin='jì niàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가정, 가족', example_zh='家庭和睦是幸福生活的基础，要珍惜家人。', example_ko='가정 화목은 행복한 삶의 기초야, 가족을 소중히 여겨야 해.', example_pinyin='jiā tíng hé mù shì xìng fú shēng huó de jī chǔ ， yào zhēn xī jiā rén 。' WHERE chinese='家庭' AND pinyin='jiā tíng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집안일', example_zh='他主动承担家务，减轻了妻子的负担。', example_ko='그는 집안일을 자진해서 맡아 아내의 부담을 덜어줬어.', example_pinyin='tā zhǔ dòng chéng dān jiā wù ， jiǎn qīng le qī zǐ de fù dān 。' WHERE chinese='家务' AND pinyin='jiā wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고향', example_zh='每年春节他都要回家乡和家人团聚。', example_ko='매년 춘절에 그는 고향에 돌아가서 가족과 함께해.', example_pinyin='měi nián chūn jié tā dōu yào huí jiā xiāng hé jiā rén tuán jù 。' WHERE chinese='家乡' AND pinyin='jiā xiāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='귀빈, 특별 손님', example_zh='今天的节目来了很多嘉宾，现场气氛非常热烈。', example_ko='오늘 프로그램에 귀빈이 많이 왔어, 현장 분위기가 매우 뜨거워.', example_pinyin='jīn tiān de jié mù lái le hěn duō jiā bīn ， xiàn chǎng qì fēn fēi cháng rè liè 。' WHERE chinese='嘉宾' AND pinyin='jiā bīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집게, 클립', example_zh='用夹子把这些文件夹在一起，不要散开。', example_ko='집게로 이 서류들을 묶어둬, 흩어지지 않게.', example_pinyin='yòng jiā zi bǎ zhè xiē wén jiàn jiā zài yì qǐ ， bú yào sàn kāi 。' WHERE chinese='夹子' AND pinyin='jiā zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='첫째, 갑', example_zh='按甲乙丙丁的顺序排列，甲排在第一位。', example_ko='갑을병정 순서로 나열하면 갑이 첫 번째야.', example_pinyin='àn jiǎ yǐ bǐng dīng de shùn xù pái liè ， jiǎ pái zài dì yī wèi 。' WHERE chinese='甲' AND pinyin='jiǎ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만약, 가령', example_zh='假如明天下雨，我们就改在室内举行活动。', example_ko='만약 내일 비가 오면 우리는 실내에서 활동을 진행하는 것으로 바꿔.', example_pinyin='jiǎ rú míng tiān xià yǔ ， wǒ men jiù gǎi zài shì nèi jǔ xíng huó dòng 。' WHERE chinese='假如' AND pinyin='jiǎ rú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~인 척하다, 가장하다', example_zh='他假装没看到我，低头走过去了。', example_ko='그는 나를 못 본 척하며 고개를 숙이고 지나쳐 버렸어.', example_pinyin='tā jiǎ zhuāng méi kàn dào wǒ ， dī tóu zǒu guò qù le 。' WHERE chinese='假装' AND pinyin='jiǎ zhuāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시집가다, 결혼하다(여성)', example_zh='她嫁给了一个善良的人，生活很幸福。', example_ko='그녀는 착한 사람에게 시집가서 행복하게 살고 있어.', example_pinyin='tā jià gěi le yí gè shàn liáng de rén ， shēng huó hěn xìng fú 。' WHERE chinese='嫁' AND pinyin='jià' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가치', example_zh='这幅画很有收藏价值，将来可能会升值。', example_ko='이 그림은 소장 가치가 높아서 나중에 가치가 오를 수도 있어.', example_pinyin='zhè fú huà hěn yǒu shōu cáng jià zhí ， jiāng lái kě néng huì shēng zhí 。' WHERE chinese='价值' AND pinyin='jià zhí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운전하다', example_zh='他拿到驾照后，每天开车上下班，很方便。', example_ko='그는 운전면허를 따고 나서 매일 운전해서 출퇴근해, 매우 편리해.', example_pinyin='tā ná dào jià zhào hòu ， měi tiān kāi chē shàng xià bān ， hěn fāng biàn 。' WHERE chinese='驾驶' AND pinyin='jià shǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지지다, 프라이하다', example_zh='她把鸡蛋煎得刚刚好，外焦里嫩，很香。', example_ko='그녀는 계란을 딱 알맞게 지져서 겉은 바삭하고 속은 부드러워, 정말 맛있어.', example_pinyin='tā bǎ jī dàn jiān dé gāng gāng hǎo ， wài jiāo lǐ nèn ， hěn xiāng 。' WHERE chinese='煎' AND pinyin='jiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어깨', example_zh='他背着沉重的书包，肩膀都酸了。', example_ko='그는 무거운 책가방을 메서 어깨가 다 결렸어.', example_pinyin='tā bèi zhe chén zhòng de shū bāo ， jiān bǎng dōu suān le 。' WHERE chinese='肩膀' AND pinyin='jiān bǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단호하다, 결연하다', example_zh='他坚决反对这个提案，态度非常明确。', example_ko='그는 이 제안에 단호하게 반대하며 태도가 매우 분명해.', example_pinyin='tā jiān jué fǎn duì zhè ge tí àn ， tài dù fēi cháng míng què 。' WHERE chinese='坚决' AND pinyin='jiān jué' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='굳세다, 강인하다', example_zh='她经历了很多磨难，但始终保持坚强的心态。', example_ko='그녀는 많은 고난을 겪었지만 항상 강인한 마음을 유지했어.', example_pinyin='tā jīng lì le hěn duō mó nàn ， dàn shǐ zhōng bǎo chí jiān qiáng de xīn tài 。' WHERE chinese='坚强' AND pinyin='jiān qiáng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='날카롭다, 예리하다', example_zh='他的问题非常尖锐，让对方一时无法回答。', example_ko='그의 질문은 매우 날카로워서 상대방이 순간 대답할 수가 없었어.', example_pinyin='tā de wèn tí fēi cháng jiān ruì ， ràng duì fāng yī shí wú fǎ huí dá 。' WHERE chinese='尖锐' AND pinyin='jiān ruì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어렵고 힘들다', example_zh='这项任务艰巨而复杂，需要团队共同完成。', example_ko='이 임무는 어렵고 복잡해서 팀이 함께 완수해야 해.', example_pinyin='zhè xiàng rèn wù jiān jù ér fù zá ， xū yào tuán duì gòng tóng wán chéng 。' WHERE chinese='艰巨' AND pinyin='jiān jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고생스럽다, 힘들다', example_zh='他小时候家里很穷，生活十分艰苦。', example_ko='그는 어릴 때 집이 가난해서 생활이 매우 고생스러웠어.', example_pinyin='tā xiǎo shí hòu jiā lǐ hěn qióng ， shēng huó shí fēn jiān kǔ 。' WHERE chinese='艰苦' AND pinyin='jiān kǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='줍다', example_zh='他在路边捡到了一个钱包，马上去警察局上交。', example_ko='그는 길가에서 지갑을 주웠는데 바로 경찰서에 가서 제출했어.', example_pinyin='tā zài lù biān jiǎn dào le yí gè qián bāo ， mǎ shàng qù jǐng chá jú shàng jiāo 。' WHERE chinese='捡' AND pinyin='jiǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가위', example_zh='用剪刀把这条线剪断，然后再重新接上。', example_ko='가위로 이 줄을 끊고 나서 다시 연결해.', example_pinyin='yòng jiǎn dāo bà zhè tiáo xiàn jiǎn duàn ， rán hòu zài chóng xīn jiē shàng 。' WHERE chinese='剪刀' AND pinyin='jiǎn dāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이력서', example_zh='他花了一个下午来整理自己的简历，准备投递工作。', example_ko='그는 오후 내내 이력서를 정리해서 취업 지원 준비를 했어.', example_pinyin='tā huā le yí gè xià wǔ lái zhěng lǐ zì jǐ de jiǎn lì ， zhǔn bèi tóu dì gōng zuò 。' WHERE chinese='简历' AND pinyin='jiǎn lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정말, 그야말로', example_zh='这道题简直太难了，我想了半天也没想出来。', example_ko='이 문제는 정말 너무 어려워서 한참 생각해도 못 풀겠어.', example_pinyin='zhè dào tí jiǎn zhí tài nán le ， wǒ xiǎng le bàn tiān yě méi xiǎng chū lái 。' WHERE chinese='简直' AND pinyin='jiǎn zhí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='헬스장, 피트니스 센터', example_zh='他每天下班后去健身房锻炼，坚持了一年多。', example_ko='그는 매일 퇴근 후 헬스장에 가서 운동하는데 1년 넘게 꾸준히 하고 있어.', example_pinyin='tā měi tiān xià bān hòu qù jiàn shēn fáng duàn liàn ， jiān chí le yī nián duō 。' WHERE chinese='健身房' AND pinyin='jiàn shēn fáng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세우다, 수립하다', example_zh='他们共同建立了一家公司，目标是做全国最好的品牌。', example_ko='그들은 함께 회사를 세웠는데 목표는 전국 최고의 브랜드가 되는 거야.', example_pinyin='tā men gòng tóng jiàn lì le yī jiā gōng sī ， mù biāo shì zuò quán guó zuì hǎo de pǐn pái 。' WHERE chinese='建立' AND pinyin='jiàn lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='건설하다, 구축하다', example_zh='政府投资建设新的高铁线路，方便市民出行。', example_ko='정부가 새로운 고속철도 노선 건설에 투자해서 시민들의 이동을 편리하게 해.', example_pinyin='zhèng fǔ tóu zī jiàn shè xīn de gāo tiě xiàn lù ， fāng biàn shì mín chū xíng 。' WHERE chinese='建设' AND pinyin='jiàn shè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='건의하다; 건의, 제안', example_zh='他向领导提出了几条改进工作流程的建议。', example_ko='그는 리더에게 업무 프로세스를 개선하는 몇 가지 제안을 했어.', example_pinyin='tā xiàng lǐng dǎo tí chū le jǐ tiáo gǎi jìn gōng zuò liú chéng de jiàn yì 。' WHERE chinese='建议' AND pinyin='jiàn yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='건물, 건축', example_zh='这栋建筑已有百年历史，是当地的文化遗产。', example_ko='이 건물은 100년의 역사가 있어서 현지의 문화유산이야.', example_pinyin='zhè dòng jiàn zhù yǐ yǒu bǎi nián lì shǐ ， shì dāng dì de wén huà yí chǎn 。' WHERE chinese='建筑' AND pinyin='jiàn zhù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='키보드', example_zh='他长时间用键盘打字，手腕有点酸痛。', example_ko='그는 오랫동안 키보드로 타이핑해서 손목이 좀 결리고 아파.', example_pinyin='tā zhǎng shí jiān yòng jiàn pán dǎ zì ， shǒu wàn yǒu diǎn suān tòng 。' WHERE chinese='键盘' AND pinyin='jiàn pán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='따지다, 중시하다', example_zh='她做事很讲究，对每个细节都非常在意。', example_ko='그녀는 일 처리가 까다로워서 모든 세부 사항에 매우 신경 써.', example_pinyin='tā zuò shì hěn jiǎng jiū ， duì měi gè xì jié dōu fēi cháng zài yì 。' WHERE chinese='讲究' AND pinyin='jiǎng jiu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='강연, 강좌', example_zh='他去大学听了一场关于人工智能的讲座，收获很多。', example_ko='그는 대학에 가서 인공지능에 관한 강연을 들었는데 많은 걸 얻었어.', example_pinyin='tā qù dà xué tīng le yī cháng guān yú rén gōng zhì néng de jiǎng zuò ， shōu huò hěn duō 。' WHERE chinese='讲座' AND pinyin='jiǎng zuò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='착륙하다', example_zh='飞机顺利降落，乘客们都松了一口气。', example_ko='비행기가 순조롭게 착륙하자 승객들이 모두 안도의 한숨을 내쉬었어.', example_pinyin='fēi jī shùn lì jiàng luò ， chéng kè men dōu sōng le yì kǒu qì 。' WHERE chinese='降落' AND pinyin='jiàng luò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='간장', example_zh='炒菜时加点酱油，颜色更好看，味道更鲜美。', example_ko='볶을 때 간장을 조금 넣으면 색이 더 예쁘고 맛이 더 감칠맛 있어.', example_pinyin='chǎo cài shí jiā diǎn jiàng yóu ， yán sè gèng hǎo kàn ， wèi dào gèng xiān měi 。' WHERE chinese='酱油' AND pinyin='jiàng yóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='물을 주다, 붓다', example_zh='她每天给阳台上的花浇水，花开得很茂盛。', example_ko='그녀는 매일 베란다 화분에 물을 줘서 꽃이 매우 잘 피어.', example_pinyin='tā měi tiān gěi yáng tái shàng de huā jiāo shuǐ ， huā kāi dé hěn mào shèng 。' WHERE chinese='浇' AND pinyin='jiāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교환하다', example_zh='两国代表团交换了礼品，表示了友好的诚意。', example_ko='양국 대표단이 선물을 교환하며 우호적인 성의를 표했어.', example_pinyin='liǎng guó dài biǎo tuán jiāo huàn le lǐ pǐn ， biǎo shì le yǒu hǎo de chéng yì 。' WHERE chinese='交换' AND pinyin='jiāo huàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교류하다; 사교', example_zh='他的社交能力很强，善于和不同的人交际。', example_ko='그는 사교 능력이 강해서 다양한 사람들과 잘 어울려.', example_pinyin='tā de shè jiāo néng lì hěn qiáng ， shàn yú hé bù tóng de rén jiāo jì 。' WHERE chinese='交际' AND pinyin='jiāo jì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교외 지역', example_zh='他们搬到郊区住了，环境更好，空气也更新鲜。', example_ko='그들은 교외로 이사해서 환경이 더 좋고 공기도 더 맑아.', example_pinyin='tā men bān dào jiāo qū zhù le ， huán jìng gèng hǎo ， kōng qì yě gēng xīn xiān 。' WHERE chinese='郊区' AND pinyin='jiāo qū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='풀, 접착제', example_zh='他用胶水把碎了的杯子粘起来，勉强还能用。', example_ko='그는 풀로 깨진 컵을 붙였는데 겨우 쓸 수는 있어.', example_pinyin='tā yòng jiāo shuǐ bǎ suì le de bēi zi zhān qǐ lái ， miǎn qiǎng hái néng yòng 。' WHERE chinese='胶水' AND pinyin='jiāo shuǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='각도, 관점', example_zh='从不同角度看这个问题，会得到不同的结论。', example_ko='다른 각도에서 이 문제를 보면 다른 결론을 얻을 수 있어.', example_pinyin='cóng bù tóng jiǎo dù kàn zhè ge wèn tí ， huì dé dào bù tóng de jié lùn 。' WHERE chinese='角度' AND pinyin='jiǎo dù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교활하다', example_zh='那只狐狸非常狡猾，总是能逃脱猎人的追捕。', example_ko='그 여우는 매우 교활해서 항상 사냥꾼의 추격을 피할 수 있어.', example_pinyin='nà zhǐ hú lí fēi cháng jiǎo huá ， zǒng shì néng táo tuō liè rén de zhuī bǔ 。' WHERE chinese='狡猾' AND pinyin='jiǎo huá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교재', example_zh='这本教材内容很丰富，适合中级水平的学习者使用。', example_ko='이 교재는 내용이 풍부해서 중급 수준의 학습자가 사용하기에 적합해.', example_pinyin='zhè běn jiào cái nèi róng hěn fēng fù ， shì hé zhōng jí shuǐ píng de xué xí zhě shǐ yòng 。' WHERE chinese='教材' AND pinyin='jiào cái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='코치, 트레이너', example_zh='他是国家队的教练，带领队伍取得了很好的成绩。', example_ko='그는 국가대표팀의 코치야, 팀을 이끌어 좋은 성적을 거뒀어.', example_pinyin='tā shì guó jiā duì de jiào liàn ， dài lǐng duì wǔ qǔ dé le hěn hǎo de chéng jì 。' WHERE chinese='教练' AND pinyin='jiào liàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교훈, 훈계', example_zh='这次失败给了我们深刻的教训，以后一定要更加谨慎。', example_ko='이번 실패는 우리에게 깊은 교훈을 줬어, 앞으로 더욱 신중해야 해.', example_pinyin='zhè cì shī bài gěi le wǒ men shēn kè de jiào xùn ， yǐ hòu yí dìng yào gèng jiā jǐn shèn 。' WHERE chinese='教训' AND pinyin='jiào xun' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='접촉하다, 닿다', example_zh='他第一次接触这种新技术，觉得非常新奇。', example_ko='그는 이 새로운 기술을 처음 접해서 매우 신기하게 느꼈어.', example_pinyin='tā dì yī cì jiē chù zhè zhǒng xīn jì shù ， jué de fēi cháng xīn qí 。' WHERE chinese='接触' AND pinyin='jiē chù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='접대하다, 응대하다', example_zh='他负责接待来访的外国代表团，表现非常专业。', example_ko='그는 방문한 외국 대표단 접대를 담당했는데 매우 전문적으로 처신했어.', example_pinyin='tā fù zé jiē dài lái fǎng de wài guó dài biǎo tuán ， biǎo xiàn fēi cháng zhuān yè 。' WHERE chinese='接待' AND pinyin='jiē dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가까워지다, 근접하다', example_zh='随着考试日期接近，同学们都开始紧张起来了。', example_ko='시험일이 가까워지면서 학생들이 모두 긴장하기 시작했어.', example_pinyin='suí zhe kǎo shì rì qī jiē jìn ， tóng xué men dōu kāi shǐ jǐn zhāng qǐ lái le 。' WHERE chinese='接近' AND pinyin='jiē jìn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이어서, 곧이어', example_zh='他先做完了第一道题，接着开始做第二道。', example_ko='그는 먼저 첫 번째 문제를 다 풀고 이어서 두 번째 문제를 풀기 시작했어.', example_pinyin='tā xiān zuò wán le dì yī dào tí ， jiē zhe kāi shǐ zuò dì èr dào 。' WHERE chinese='接着' AND pinyin='jiē zhe' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단계, 시기', example_zh='现在是项目的初期阶段，很多细节还需要确认。', example_ko='지금은 프로젝트의 초기 단계야, 많은 세부 사항을 아직 확인해야 해.', example_pinyin='xiàn zài shì xiàng mù dì chū qī jiē duàn ， hěn duō xì jié hái xū yào què rèn 。' WHERE chinese='阶段' AND pinyin='jiē duàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='튼튼하다, 견고하다', example_zh='这张桌子做工很结实，用了十年还跟新的一样。', example_ko='이 탁자는 만듦새가 튼튼해서 10년을 써도 새것 같아.', example_pinyin='zhè zhāng zhuō zi zuò gōng hěn jiē shí ， yòng le shí nián hái gēn xīn de yī yàng 。' WHERE chinese='结实' AND pinyin='jiē shi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='마디, 절; 명절 (양사)', example_zh='这首歌一共有三节，每节的旋律都很好听。', example_ko='이 노래는 총 세 절이 있는데 각 절의 멜로디가 모두 아름다워.', example_pinyin='zhè shǒu gē yī gòng yǒu sān jié ， měi jié de xuán lǜ dōu hěn hǎo tīng 。' WHERE chinese='节' AND pinyin='jié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='절약하다', example_zh='要节省用电，随手关灯是个好习惯。', example_ko='전기를 아껴야 해, 불 끄는 습관이 좋은 습관이야.', example_pinyin='yào jié shěng yòng diàn ， suí shǒu guān dēng shì gè hǎo xí guàn 。' WHERE chinese='节省' AND pinyin='jié shěng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구조, 구성', example_zh='这篇文章的结构很清晰，层次分明，逻辑严密。', example_ko='이 글의 구조가 매우 명확하고 층차가 분명하며 논리가 엄밀해.', example_pinyin='zhè piān wén zhāng de jié gòu hěn qīng xī ， céng cì fēn míng ， luó jí yán mì 。' WHERE chinese='结构' AND pinyin='jié gòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결합하다, 연결하다', example_zh='理论要和实践结合，光说不做是没有用的。', example_ko='이론과 실천을 결합해야 해, 말만 하고 실천하지 않으면 소용없어.', example_pinyin='lǐ lùn yào hé shí jiàn jié hé ， guāng shuō bù zuò shì méi yǒu yòng de 。' WHERE chinese='结合' AND pinyin='jié hé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결론', example_zh='讨论了很久，最终得出了一个大家都接受的结论。', example_ko='오랫동안 토론해서 결국 모두가 받아들이는 결론을 도출했어.', example_pinyin='tǎo lùn le hěn jiǔ ， zuì zhōng dé chū le yí gè dà jiā dōu jiē shòu de jié lùn 。' WHERE chinese='结论' AND pinyin='jié lùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='계산하다, 결제하다', example_zh='吃完饭后，他们喊服务员来结账，一起付了钱。', example_ko='식사를 마친 후 그들은 직원을 불러 계산하고 함께 돈을 냈어.', example_pinyin='chī wán fàn hòu ， tā men hǎn fú wù yuán lái jié zhàng ， yì qǐ fù le qián 。' WHERE chinese='结账' AND pinyin='jié zhàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='해방하다; 해방', example_zh='新中国成立后，人民从压迫中得到了解放。', example_ko='신중국 성립 후 인민은 억압에서 해방됐어.', example_pinyin='xīn zhōng guó chéng lì hòu ， rén mín cóng yā pò zhōng dé dào le jiě fàng 。' WHERE chinese='解放' AND pinyin='jiě fàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='해설자', example_zh='他担任了这次世界杯的解说员，声音浑厚，解说精彩。', example_ko='그는 이번 월드컵의 해설자를 맡았는데 목소리가 중후하고 해설이 훌륭해.', example_pinyin='tā dān rèn le zhè cì shì jiè bēi de jiě shuō yuán ， shēng yīn hún hòu ， jiě shuō jīng cǎi 。' WHERE chinese='解说员' AND pinyin='jiě shuō yuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='회, 기 (양사)', example_zh='这是第五届国际文化节，规模比往届更大。', example_ko='이번은 제5회 국제 문화 축제야, 규모가 지난 회보다 더 커.', example_pinyin='zhè shì dì wǔ jiè guó jì wén huà jié ， guī mó bǐ wǎng jiè gèng dà 。' WHERE chinese='届' AND pinyin='jiè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='핑계, 구실', example_zh='他总是找借口不来开会，领导对他很不满。', example_ko='그는 항상 핑계를 대고 회의에 오지 않아서 리더가 그에게 매우 불만이야.', example_pinyin='tā zǒng shì zhǎo jiè kǒu bù lái kāi huì ， lǐng dǎo duì tā hěn bù mǎn 。' WHERE chinese='借口' AND pinyin='jiè kǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='담배를 끊다', example_zh='医生建议他戒烟，否则对肺部伤害会越来越大。', example_ko='의사가 그에게 담배를 끊으라고 권유했어, 그러지 않으면 폐에 해가 점점 커진대.', example_pinyin='yī shēng jiàn yì tā jiè yān ， fǒu zé duì fèi bù shāng hài huì yuè lái yuè dà 。' WHERE chinese='戒烟' AND pinyin='jiè yān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반지', example_zh='他在纪念日给她买了一枚钻石戒指，她非常感动。', example_ko='그는 기념일에 다이아몬드 반지를 사줬는데 그녀가 매우 감동받았어.', example_pinyin='tā zài jì niàn rì gěi tā mǎi le yī méi zuàn shí jiè zhǐ ， tā fēi cháng gǎn dòng 。' WHERE chinese='戒指' AND pinyin='jiè zhi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='금속', example_zh='金属导热性强，所以金属餐具在热汤里会变烫。', example_ko='금속은 열전도성이 강해서 금속 식기는 뜨거운 국에서 뜨거워져.', example_pinyin='jīn shǔ dǎo rè xìng qiáng ， suǒ yǐ jīn shǔ cān jù zài rè tāng lǐ huì biàn tàng 。' WHERE chinese='金属' AND pinyin='jīn shǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='팽팽하다, 조이다; 급하다', example_zh='时间紧，任务重，大家要加快进度才行。', example_ko='시간이 촉박하고 임무가 무거우니 모두 진도를 서둘러야 해.', example_pinyin='shí jiān jǐn ， rèn wù zhòng ， dà jiā yào jiā kuài jìn dù cái xíng 。' WHERE chinese='紧' AND pinyin='jǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='긴급하다', example_zh='发生了紧急情况，所有人立刻停下工作应对。', example_ko='긴급 상황이 발생해서 모든 사람이 즉시 일을 멈추고 대응했어.', example_pinyin='fā shēng le jǐn jí qíng kuàng ， suǒ yǒu rén lì kè tíng xià gōng zuò yìng duì 。' WHERE chinese='紧急' AND pinyin='jǐn jí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가능한 한, 최대한', example_zh='尽量早点到，这样我们有更多时间准备。', example_ko='가능한 한 일찍 와, 그래야 우리가 준비할 시간이 더 많아.', example_pinyin='jǐn liàng zǎo diǎn dào ， zhè yàng wǒ men yǒu gèng duō shí jiān zhǔn bèi 。' WHERE chinese='尽量' AND pinyin='jǐn liàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신중하다', example_zh='做重大决定时一定要谨慎，不能草率了事。', example_ko='중요한 결정을 할 때는 반드시 신중해야 해, 경솔하게 처리하면 안 돼.', example_pinyin='zuò zhòng dà jué dìng shí yí dìng yào jǐn shèn ， bù néng cǎo shuài liǎo shì 。' WHERE chinese='谨慎' AND pinyin='jǐn shèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='진보하다, 발전하다; 진보', example_zh='他这学期进步很大，从班级末尾升到了前十名。', example_ko='그는 이번 학기에 크게 발전해서 반 꼴찌에서 상위 10위 안에 들었어.', example_pinyin='tā zhè xué qī jìn bù hěn dà ， cóng bān jí mò wěi shēng dào le qián shí míng 。' WHERE chinese='进步' AND pinyin='jìn bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수입하다; 수입', example_zh='这家超市进口了很多国外的商品，很受消费者欢迎。', example_ko='이 슈퍼마켓은 외국 상품을 많이 수입해서 소비자들에게 인기가 많아.', example_pinyin='zhè jiā chāo shì jìn kǒu le hěn duō guó wài de shāng pǐn ， hěn shòu xiāo fèi zhě huān yíng 。' WHERE chinese='进口' AND pinyin='jìn kǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='근대', example_zh='近代中国经历了很多变革，从封建社会走向现代化。', example_ko='근대 중국은 많은 변혁을 겪으며 봉건 사회에서 현대화로 나아갔어.', example_pinyin='jìn dài zhōng guó jīng lì le hěn duō biàn gé ， cóng fēng jiàn shè huì zǒu xiàng xiàn dài huà 。' WHERE chinese='近代' AND pinyin='jìn dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='최선을 다하다', example_zh='无论结果如何，只要尽力了，就不会后悔。', example_ko='결과가 어떻든 간에 최선을 다했다면 후회하지 않아.', example_pinyin='wú lùn jié guǒ rú hé ， zhǐ yào jìn lì le ， jiù bú huì hòu huǐ 。' WHERE chinese='尽力' AND pinyin='jìn lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='에너지, 활력', example_zh='他精力充沛，一天工作十几个小时都不觉得累。', example_ko='그는 에너지가 넘쳐서 하루에 십여 시간을 일해도 피곤함을 느끼지 않아.', example_pinyin='tā jīng lì chōng pèi ， yī tiān gōng zuò shí jǐ gè xiǎo shí dōu bù jué dé lèi 。' WHERE chinese='精力' AND pinyin='jīng lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고전적이다, 정통의', example_zh='这首曲子是音乐史上的经典之作，百听不厌。', example_ko='이 곡은 음악사의 고전 작품이야, 아무리 들어도 싫증이 안 나.', example_pinyin='zhè shǒu qǔ zi shì yīn yuè shǐ shàng de jīng diǎn zhī zuò ， bǎi tīng bù yàn 。' WHERE chinese='经典' AND pinyin='jīng diǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='경영하다, 운영하다', example_zh='他经营着一家小餐厅，生意做得还不错。', example_ko='그는 작은 식당을 경영하고 있는데 장사가 꽤 잘 돼.', example_pinyin='tā jīng yíng zhe yī jiā xiǎo cān tīng ， shēng yì zuò dé hái bú cuò 。' WHERE chinese='经营' AND pinyin='jīng yíng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='경치, 경관', example_zh='山上的景色太美了，让人忍不住多待一会儿。', example_ko='산 위의 경치가 너무 아름다워서 저절로 좀 더 있고 싶어져.', example_pinyin='shān shàng de jǐng sè tài měi le ， ràng rén rěn bú zhù duō dài yī huì er 。' WHERE chinese='景色' AND pinyin='jǐng sè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='공경하다', example_zh='他从小就非常敬爱老师和父母，经常主动帮助他们。', example_ko='그는 어릴 때부터 선생님과 부모님을 매우 공경해서 자주 먼저 도왔어.', example_pinyin='tā cóng xiǎo jiù fēi cháng jìng ài lǎo shī hé fù mǔ ， jīng cháng zhǔ dòng bāng zhù tā men 。' WHERE chinese='敬爱' AND pinyin='jìng ài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='바, 술집', example_zh='下班后同事们去酒吧聚了一聚，聊聊工作之外的话题。', example_ko='퇴근 후 동료들이 술집에서 모여 업무 외의 화제로 이야기를 나눴어.', example_pinyin='xià bān hòu tóng shì men qù jiǔ bā jù le yī jù ， liáo liáo gōng zuò zhī wài de huà tí 。' WHERE chinese='酒吧' AND pinyin='jiǔ bā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구하다, 구조하다', example_zh='消防员冒着生命危险冲入火场，救出了被困的居民。', example_ko='소방관이 생명의 위험을 무릅쓰고 화재 현장에 뛰어들어 갇혀 있던 주민을 구했어.', example_pinyin='xiāo fáng yuán mào zhe shēng mìng wēi xiǎn chōng rù huǒ chǎng ， jiù chū le bèi kùn de jū mín 。' WHERE chinese='救' AND pinyin='jiù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구급차', example_zh='发生事故后，路人立刻拨打了急救电话，救护车很快赶到了。', example_ko='사고가 발생하자 행인이 즉시 응급 전화를 걸었고 구급차가 빨리 도착했어.', example_pinyin='fā shēng shì gù hòu ， lù rén lì kè bō dǎ le jí jiù diàn huà ， jiù hù chē hěn kuài gǎn dào le 。' WHERE chinese='救护车' AND pinyin='jiù hù chē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='외삼촌', example_zh='我舅舅住在广州，每年暑假我都去他那里玩。', example_ko='우리 외삼촌은 광저우에 살아서 매년 여름방학에 나는 거기 가서 놀아.', example_pinyin='wǒ jiù jiù zhù zài guǎng zhōu ， měi nián shǔ jià wǒ dōu qù tā nà lǐ wán 。' WHERE chinese='舅舅' AND pinyin='jiù jiu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뜻밖에, 의외로', example_zh='他居然通过了那次面试，连他自己都没想到。', example_ko='그가 뜻밖에 그 면접을 통과했어, 그 자신도 생각지 못한 일이었어.', example_pinyin='tā jū rán tōng guò le nà cì miàn shì ， lián tā zì jǐ dōu méi xiǎng dào 。' WHERE chinese='居然' AND pinyin='jū rán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='귤', example_zh='冬天吃桔子对身体好，富含维生素C。', example_ko='겨울에 귤을 먹으면 몸에 좋아, 비타민C가 풍부해.', example_pinyin='dōng tiān chī jú zi duì shēn tǐ hǎo ， fù hán wéi shēng sù C。' WHERE chinese='桔子' AND pinyin='jú zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='들다, 들어 올리다; 예를 들다', example_zh='老师让大家举手发言，很多同学都积极响应。', example_ko='선생님이 손을 들고 발언하라고 했더니 많은 학생들이 적극적으로 응했어.', example_pinyin='lǎo shī ràng dà jiā jǔ shǒu fā yán ， hěn duō tóng xué dōu jī jí xiǎng yìng 。' WHERE chinese='举' AND pinyin='jǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='갖추다, 구비하다', example_zh='这名候选人具备了岗位所需的各种能力和经验。', example_ko='이 후보자는 직위에 필요한 다양한 능력과 경험을 갖추고 있어.', example_pinyin='zhè míng hòu xuǎn rén jù bèi le gǎng wèi suǒ xū de gè zhǒng néng lì hé jīng yàn 。' WHERE chinese='具备' AND pinyin='jù bèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구체적이다', example_zh='请把你的想法说得更具体一些，不要太笼统。', example_ko='생각을 좀 더 구체적으로 말해줘, 너무 막연하게 하지 말고.', example_pinyin='qǐng bǎ nǐ de xiǎng fǎ shuō dé gèng jù tǐ yī xiē ， bú yào tài lǒng tǒng 。' WHERE chinese='具体' AND pinyin='jù tǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='거대하다, 엄청나다', example_zh='这次地震造成了巨大的破坏，需要很长时间来重建。', example_ko='이번 지진이 엄청난 피해를 일으켜서 재건에 오랜 시간이 필요해.', example_pinyin='zhè cì dì zhèn zào chéng le jù dà de pò huài ， xū yào hěn zhǎng shí jiān lái chóng jiàn 。' WHERE chinese='巨大' AND pinyin='jù dà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모임, 파티', example_zh='他组织了一场同学聚会，大家聊了很多往日的故事。', example_ko='그는 동창 모임을 조직했는데 다들 과거 이야기를 많이 나눴어.', example_pinyin='tā zǔ zhī le yī cháng tóng xué jù huì ， dà jiā liáo le hěn duō wǎng rì de gù shì 。' WHERE chinese='聚会' AND pinyin='jù huì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='클럽', example_zh='他参加了一个摄影俱乐部，每周和成员们一起出去拍照。', example_ko='그는 사진 클럽에 가입해서 매주 회원들과 함께 외출해서 사진을 찍어.', example_pinyin='tā cān jiā le yí gè shè yǐng jù lè bù ， měi zhōu hé chéng yuán men yì qǐ chū qù pāi zhào 。' WHERE chinese='俱乐部' AND pinyin='jù lè bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~라고 하더라', example_zh='据说这家餐厅的招牌菜非常好吃，要提前预约。', example_ko='이 식당의 시그니처 메뉴가 매우 맛있다고 하더라, 미리 예약해야 한대.', example_pinyin='jù shuō zhè jiā cān tīng de zhāo pái cài fēi cháng hǎo chī ， yào tí qián yù yuē 。' WHERE chinese='据说' AND pinyin='jù shuō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기부하다, 헌납하다', example_zh='他每年都会捐出部分收入，帮助有困难的孩子上学。', example_ko='그는 매년 수입의 일부를 기부해서 어려운 아이들이 학교에 다닐 수 있게 도와.', example_pinyin='tā měi nián dū huì juān chū bù fèn shōu rù ， bāng zhù yǒu kùn nán de hái zi shàng xué 。' WHERE chinese='捐' AND pinyin='juān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='말다, 감다; 두루마리 (양사)', example_zh='老师卷起袖子，亲自动手帮学生修理机器。', example_ko='선생님은 소매를 걷어붙이고 직접 학생을 도와 기계를 수리했어.', example_pinyin='lǎo shī juǎn qǐ xiù zi ， qīn zì dòng shǒu bāng xué shēng xiū lǐ jī qì 。' WHERE chinese='卷' AND pinyin='juǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결승전', example_zh='他们队进入了决赛，全校师生都为他们加油。', example_ko='그들 팀이 결승전에 진출해서 전교 선생님과 학생들이 모두 응원했어.', example_pinyin='tā men duì jìn rù le jué sài ， quán xiào shī shēng dōu wèi tā men jiā yóu 。' WHERE chinese='决赛' AND pinyin='jué sài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결심, 결의', example_zh='他下定决心要减肥，开始坚持每天锻炼。', example_ko='그는 다이어트를 하기로 굳게 결심하고 매일 운동을 꾸준히 시작했어.', example_pinyin='tā xià dìng jué xīn yào jiǎn féi ， kāi shǐ jiān chí měi tiān duàn liàn 。' WHERE chinese='决心' AND pinyin='jué xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='절대적이다, 반드시', example_zh='这件事绝对不能泄露出去，要严格保密。', example_ko='이 일은 절대 새어나가면 안 돼, 철저하게 비밀을 지켜야 해.', example_pinyin='zhè jiàn shì jué duì bù néng xiè lòu chū qù ， yào yán gé bǎo mì 。' WHERE chinese='绝对' AND pinyin='jué duì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='역할, 배역', example_zh='他在这部电影里扮演了一个反派角色，演技非常出色。', example_ko='그는 이 영화에서 악당 역할을 맡았는데 연기가 매우 훌륭해.', example_pinyin='tā zài zhè bù diàn yǐng lǐ bàn yǎn le yí gè fǎn pài jué sè ， yǎn jì fēi cháng chū sè 。' WHERE chinese='角色' AND pinyin='jué sè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='군사, 군사의', example_zh='这个地区的军事部署非常严密，外人无法靠近。', example_ko='이 지역의 군사 배치가 매우 엄밀해서 외부인이 접근할 수 없어.', example_pinyin='zhè ge dì qū de jūn shì bù shǔ fēi cháng yán mì ， wài rén wú fǎ kào jìn 。' WHERE chinese='军事' AND pinyin='jūn shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='균일하다, 고르다', example_zh='要把颜料涂得均匀，这样颜色才会好看。', example_ko='물감을 균일하게 칠해야 해, 그래야 색이 예쁘게 나와.', example_pinyin='yào bǎ yán liào tú dé jūn yún ， zhè yàng yán sè cái huì hǎo kàn 。' WHERE chinese='均匀' AND pinyin='jūn yún' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='트럭', example_zh='工地上来了好几辆卡车，运来了大量建筑材料。', example_ko='공사 현장에 트럭이 몇 대 와서 건축 자재를 대량으로 실어왔어.', example_pinyin='gōng dì shàng lái le hǎo jǐ liàng kǎ chē ， yùn lái le dà liàng jiàn zhù cái liào 。' WHERE chinese='卡车' AND pinyin='kǎ chē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='개발하다', example_zh='公司正在开发一款新的手机应用，预计明年上线。', example_ko='회사에서 새로운 스마트폰 앱을 개발 중이야, 내년에 출시될 예정이야.', example_pinyin='gōng sī zhèng zài kāi fā yī kuǎn xīn de shǒu jī yìng yòng ， yù jì míng nián shàng xiàn 。' WHERE chinese='开发' AND pinyin='kāi fā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='개방하다; 개방적이다', example_zh='这个地区对外开放已有三十年，吸引了大量外资。', example_ko='이 지역은 대외 개방한 지 30년이 됐는데 대규모 외자를 유치했어.', example_pinyin='zhè ge dì qū duì wài kāi fàng yǐ yǒu sān shí nián ， xī yǐn le dà liàng wài zī 。' WHERE chinese='开放' AND pinyin='kāi fàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='개막식', example_zh='奥运会开幕式非常壮观，全球数十亿人收看了直播。', example_ko='올림픽 개막식은 매우 장관이어서 전 세계 수십억 명이 생방송을 시청했어.', example_pinyin='ào yùn huì kāi mù shì fēi cháng zhuàng guān ， quán qiú shù shí yì rén shōu kàn le zhí bō 。' WHERE chinese='开幕式' AND pinyin='kāi mù shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기쁘다, 즐겁다', example_zh='她今天特别开心，因为收到了很久没联系的老朋友的消息。', example_ko='그녀는 오늘 특히 기뻐, 오래 연락 못 한 옛 친구의 소식을 받아서야.', example_pinyin='tā jīn tiān tè bié kāi xīn ， yīn wèi shōu dào le hěn jiǔ méi lián xì de lǎo péng yǒu de xiāo xī 。' WHERE chinese='开心' AND pinyin='kāi xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='베다, 자르다', example_zh='他用斧头砍倒了一棵大树，准备做木材。', example_ko='그는 도끼로 큰 나무를 베어서 목재로 쓸 준비를 했어.', example_pinyin='tā yòng fǔ tóu kǎn dào le yī kē dà shù ， zhǔn bèi zuò mù cái 。' WHERE chinese='砍' AND pinyin='kǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무시하다, 얕보다', example_zh='不要看不起别人，每个人都有自己的长处。', example_ko='남을 얕보지 마, 모든 사람에게 자신의 장점이 있어.', example_pinyin='bú yào kàn bù qǐ bié rén ， měi gè rén dōu yǒu zì jǐ de cháng chù 。' WHERE chinese='看不起' AND pinyin='kàn bu qǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보아하니, ~인 것 같다', example_zh='看来今天的会议要延期了，负责人还没到。', example_ko='보아하니 오늘 회의가 연기될 것 같아, 담당자가 아직 안 왔어.', example_pinyin='kàn lái jīn tiān de huì yì yào yán qī le ， fù zé rén hái méi dào 。' WHERE chinese='看来' AND pinyin='kàn lai' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='항의하다; 항의', example_zh='市民们聚集在市政府门口，抗议新的税收政策。', example_ko='시민들이 시청 앞에 모여서 새 세금 정책에 항의했어.', example_pinyin='shì mín men jù jí zài shì zhèng fǔ mén kǒu ， kàng yì xīn de shuì shōu zhèng cè 。' WHERE chinese='抗议' AND pinyin='kàng yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='베이징 오리구이', example_zh='到北京一定要吃烤鸭，这是最有代表性的北京美食。', example_ko='베이징에 가면 반드시 오리구이를 먹어야 해, 가장 대표적인 베이징 음식이야.', example_pinyin='dào běi jīng yí dìng yào chī kǎo yā ， zhè shì zuì yǒu dài biǎo xìng de běi jīng měi shí 。' WHERE chinese='烤鸭' AND pinyin='kǎo yā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='알 (양사)', example_zh='她每天早上吃一颗鸡蛋和一片面包，作为早餐。', example_ko='그녀는 매일 아침 계란 한 알과 빵 한 조각을 먹어서 아침 식사로 해.', example_pinyin='tā měi tiān zǎo shàng chī yī kē jī dàn hé yī piàn miàn bāo ， zuò wéi zǎo cān 。' WHERE chinese='颗' AND pinyin='kē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~임을 알 수 있다', example_zh='由此可见，坚持努力才是成功的关键。', example_ko='이로써 알 수 있듯이 꾸준히 노력하는 것이 성공의 핵심이야.', example_pinyin='yóu cǐ kě jiàn ， jiān chí nǔ lì cái shì chéng gōng de guān jiàn 。' WHERE chinese='可见' AND pinyin='kě jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='믿을 만하다, 신뢰할 수 있다', example_zh='这家网站提供的信息很可靠，数据都有来源。', example_ko='이 웹사이트가 제공하는 정보는 믿을 만해, 데이터 모두 출처가 있어.', example_pinyin='zhè jiā wǎng zhàn tí gōng de xìn xī hěn kě kào ， shù jù dōu yǒu lái yuán 。' WHERE chinese='可靠' AND pinyin='kě kào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무섭다, 두렵다', example_zh='那部恐怖片真的很可怕，他看完后好几天做噩梦。', example_ko='그 공포 영화는 정말 무서웠어, 그는 다 보고 나서 며칠 동안 악몽을 꿨어.', example_pinyin='nà bù kǒng bù piàn zhēn de hěn kě pà ， tā kàn wán hòu hǎo jǐ tiān zuò è mèng 。' WHERE chinese='可怕' AND pinyin='kě pà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='각고하다, 열심히 하다', example_zh='他刻苦学习，终于考上了理想的大学。', example_ko='그는 각고하게 공부해서 결국 원하는 대학에 합격했어.', example_pinyin='tā kè kǔ xué xí ， zhōng yú kǎo shàng le lǐ xiǎng de dà xué 。' WHERE chinese='刻苦' AND pinyin='kè kǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='과정, 커리큘럼', example_zh='这门课程内容很丰富，学生们反映收获很大。', example_ko='이 과정은 내용이 풍부해서 학생들이 많은 걸 얻었다고 반응해.', example_pinyin='zhè mén kè chéng nèi róng hěn fēng fù ， xué shēng men fǎn yìng shōu huò hěn dà 。' WHERE chinese='课程' AND pinyin='kè chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그램 (무게 단위)', example_zh='这包零食净含量是200克，热量不低。', example_ko='이 과자 순 함량은 200그램이야, 열량이 낮지 않아.', example_pinyin='zhè bāo líng shí jìng hán liàng shì 200 kè ， rè liàng bù dī 。' WHERE chinese='克' AND pinyin='kè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='극복하다', example_zh='他克服了重重困难，最终完成了这次艰难的旅程。', example_ko='그는 수많은 어려움을 극복하고 결국 이 힘든 여정을 마쳤어.', example_pinyin='tā kè fú le chóng chóng kùn nán ， zuì zhōng wán chéng le zhè cì jiān nán de lǚ chéng 。' WHERE chinese='克服' AND pinyin='kè fú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='객관적이다', example_zh='评价一件事要客观，不能凭个人感情来判断。', example_ko='무언가를 평가할 때 객관적이어야 해, 개인 감정으로 판단하면 안 돼.', example_pinyin='píng jià yī jiàn shì yào kè guān ， bù néng píng gè rén gǎn qíng lái pàn duàn 。' WHERE chinese='客观' AND pinyin='kè guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='거실', example_zh='他们家的客厅布置得很温馨，经常在里面看电视。', example_ko='그들의 거실은 아늑하게 꾸며져 있어서 자주 거기서 TV를 봐.', example_pinyin='tā men jiā de kè tīng bù zhì dé hěn wēn xīn ， jīng cháng zài lǐ miàn kàn diàn shì 。' WHERE chinese='客厅' AND pinyin='kè tīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='공간', example_zh='这个房间空间不大，但装修得很合理，住着很舒服。', example_ko='이 방은 공간이 크지 않지만 인테리어가 합리적으로 되어 있어서 살기 편해.', example_pinyin='zhè ge fáng jiān kōng jiān bù dà ， dàn zhuāng xiū dé hěn hé lǐ ， zhù zhe hěn shū fú 。' WHERE chinese='空间' AND pinyin='kōng jiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='공포스럽다, 무섭다', example_zh='那部恐怖片的特效太好了，场景非常恐怖。', example_ko='그 공포 영화의 특수효과가 너무 좋아서 장면이 매우 공포스러워.', example_pinyin='nà bù kǒng bù piàn de tè xiào tài hǎo le ， chǎng jǐng fēi cháng kǒng bù 。' WHERE chinese='恐怖' AND pinyin='kǒng bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='한가하다, 여유가 있다', example_zh='周末他终于有空闲时间，去公园走了走。', example_ko='주말에 그는 드디어 여유 시간이 생겨서 공원에 가서 걸었어.', example_pinyin='zhōu mò tā zhōng yú yǒu kòng xián shí jiān ， qù gōng yuán zǒu le zǒu 。' WHERE chinese='空闲' AND pinyin='kòng xián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='통제하다, 조절하다', example_zh='他控制不住自己的情绪，在公开场合发了脾气。', example_ko='그는 감정을 억제하지 못해서 공개 장소에서 화를 냈어.', example_pinyin='tā kòng zhì bú zhù zì jǐ de qíng xù ， zài gōng kāi chǎng hé fā le pí qì 。' WHERE chinese='控制' AND pinyin='kòng zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='입맛, 맛', example_zh='这道菜很合我的口味，吃了一碗还想再来一碗。', example_ko='이 음식은 내 입맛에 딱 맞아서 한 그릇 먹고 또 먹고 싶어.', example_pinyin='zhè dào cài hěn hé wǒ de kǒu wèi ， chī le yī wǎn hái xiǎng zài lái yī wǎn 。' WHERE chinese='口味' AND pinyin='kǒu wèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='칭찬하다', example_zh='老师在课堂上夸了他的作文，他高兴了一整天。', example_ko='선생님이 수업 시간에 그의 작문을 칭찬해서 그는 하루 종일 기뻐했어.', example_pinyin='lǎo shī zài kè táng shàng kuā le tā de zuò wén ， tā gāo xìng le yī zhěng tiān 。' WHERE chinese='夸' AND pinyin='kuā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='회계', example_zh='她是公司的会计，负责管理财务账目。', example_ko='그녀는 회사의 회계야, 재무 장부 관리를 담당하고 있어.', example_pinyin='tā shì gōng sī de kuài jì ， fù zé guǎn lǐ cái wù zhàng mù 。' WHERE chinese='会计' AND pinyin='kuài jì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미네랄워터', example_zh='运动后要喝矿泉水补充水分，不要喝饮料。', example_ko='운동 후에는 미네랄워터를 마셔서 수분을 보충해야 해, 음료는 마시지 마.', example_pinyin='yùn dòng hòu yào hē kuàng quán shuǐ bǔ chōng shuǐ fèn ， bú yào hē yǐn liào 。' WHERE chinese='矿泉水' AND pinyin='kuàng quán shuǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고추', example_zh='她很能吃辣，每道菜都要加很多辣椒。', example_ko='그녀는 매운 걸 잘 먹어서 모든 요리에 고추를 많이 넣어.', example_pinyin='tā hěn néng chī là ， měi dào cài dōu yào jiā hěn duō là jiāo 。' WHERE chinese='辣椒' AND pinyin='là jiāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='양초', example_zh='停电了，他找出了几根蜡烛放在桌上，照亮了房间。', example_ko='정전이 돼서 그는 양초 몇 개를 찾아서 책상 위에 놓으니 방이 밝아졌어.', example_pinyin='tíng diàn le ， tā zhǎo chū le jǐ gēn là zhú fàng zài zhuō shàng ， zhào liàng le fáng jiān 。' WHERE chinese='蜡烛' AND pinyin='là zhú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~에서 오다, ~출신이다', example_zh='他来自农村，通过自己的努力考上了名校。', example_ko='그는 농촌 출신이야, 스스로의 노력으로 명문 대학에 합격했어.', example_pinyin='tā lái zì nóng cūn ， tōng guò zì jǐ de nǔ lì kǎo shàng le míng xiào 。' WHERE chinese='来自' AND pinyin='lái zì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='막다, 가로막다', example_zh='警察拦住了那辆超速的车，要求驾驶员出示证件。', example_ko='경찰이 과속하는 차를 세워서 운전자에게 신분증 제시를 요구했어.', example_pinyin='jǐng chá lán zhù le nà liàng chāo sù de chē ， yāo qiú jià shǐ yuán chū shì zhèng jiàn 。' WHERE chinese='拦' AND pinyin='lán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='썩다, 문드러지다', example_zh='水果放太久了，已经烂了，不能吃了。', example_ko='과일을 너무 오래 뒀더니 이미 썩었어, 먹으면 안 돼.', example_pinyin='shuǐ guǒ fàng tài jiǔ le ， yǐ jīng làn le ， bù néng chī le 。' WHERE chinese='烂' AND pinyin='làn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='늑대', example_zh='寓言故事里，狼总是被描写成贪婪而危险的动物。', example_ko='우화에서 늑대는 항상 탐욕스럽고 위험한 동물로 묘사돼.', example_pinyin='yù yán gù shì lǐ ， láng zǒng shì bèi miáo xiě chéng tān lán ér wēi xiǎn de dòng wù 。' WHERE chinese='狼' AND pinyin='láng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='노동하다; 노동', example_zh='劳动节是五月一日，是向全世界劳动者致敬的节日。', example_ko='노동절은 5월 1일이야, 전 세계 노동자에게 경의를 표하는 날이야.', example_pinyin='láo dòng jié shì wǔ yuè yī rì ， shì xiàng quán shì jiè láo dòng zhě zhì jìng de jié rì 。' WHERE chinese='劳动' AND pinyin='láo dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실례합니다 (부탁할 때)', example_zh='劳驾，请问去地铁站怎么走？', example_ko='실례합니다, 지하철역은 어떻게 가나요?', example_pinyin='láo jià ， qǐng wèn qù dì tiě zhàn zěn me zǒu ？' WHERE chinese='劳驾' AND pinyin='láo jià' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일반 시민, 서민', example_zh='政府出台的新政策主要是为了改善老百姓的生活。', example_ko='정부가 내놓은 새 정책은 주로 서민들의 생활 개선을 위한 거야.', example_pinyin='zhèng fǔ chū tái de xīn zhèng cè zhǔ yào shì wèi le gǎi shàn lǎo bǎi xìng de shēng huó 。' WHERE chinese='老百姓' AND pinyin='lǎo bǎi xìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사장, 보스', example_zh='他的老板非常好，从不加班，员工福利也很好。', example_ko='그의 사장은 매우 좋아서 야근을 절대 안 시키고 직원 복지도 매우 좋아.', example_pinyin='tā de lǎo bǎn fēi cháng hǎo ， cóng bù jiā bān ， yuán gōng fú lì yě hěn hǎo 。' WHERE chinese='老板' AND pinyin='lǎo bǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='솔직하다, 착실하다', example_zh='他为人老实，从不说谎，大家都很信任他。', example_ko='그는 사람이 솔직해서 거짓말을 하지 않아서 다들 그를 매우 신뢰해.', example_pinyin='tā wéi rén lǎo shí ， cóng bù shuō huǎng ， dà jiā dōu hěn xìn rèn tā 。' WHERE chinese='老实' AND pinyin='lǎo shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쥐', example_zh='老鼠偷吃了厨房里的食物，要赶紧买捕鼠夹。', example_ko='쥐가 주방의 음식을 훔쳐 먹었어, 빨리 쥐덫을 사야 해.', example_pinyin='lǎo shǔ tōu chī le chú fáng lǐ de shí wù ， yào gǎn jǐn mǎi bǔ shǔ jiā 。' WHERE chinese='老鼠' AND pinyin='lǎo shǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='외할머니', example_zh='他从小和姥姥住在一起，感情非常深厚。', example_ko='그는 어릴 때부터 외할머니와 함께 살아서 정이 매우 깊어.', example_pinyin='tā cóng xiǎo hé lǎo lao zhù zài yì qǐ ， gǎn qíng fēi cháng shēn hòu 。' WHERE chinese='姥姥' AND pinyin='lǎo lao' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='낙관적이다', example_zh='她很乐观，无论遇到什么困难都能保持积极的心态。', example_ko='그녀는 낙관적이어서 어떤 어려움을 만나도 긍정적인 마음을 유지할 수 있어.', example_pinyin='tā hěn lè guān ， wú lùn yù dào shén me kùn nán dōu néng bǎo chí jī jí de xīn tài 。' WHERE chinese='乐观' AND pinyin='lè guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='천둥', example_zh='外面打雷了，孩子被吓到了，赶紧跑进屋子里。', example_ko='밖에서 천둥이 쳐서 아이가 놀라서 얼른 집 안으로 뛰어 들어갔어.', example_pinyin='wài miàn dǎ léi le ， hái zi bèi xià dào le ， gǎn jǐn pǎo jìn wū zi lǐ 。' WHERE chinese='雷' AND pinyin='léi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유형, 종류', example_zh='这类问题在考试中经常出现，大家要多练习。', example_ko='이런 유형의 문제는 시험에서 자주 나와서 다들 많이 연습해야 해.', example_pinyin='zhè lèi wèn tí zài kǎo shì zhōng jīng cháng chū xiàn ， dà jiā yào duō liàn xí 。' WHERE chinese='类' AND pinyin='lèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='배', example_zh='他买了一袋梨，皮薄肉嫩，又甜又多汁。', example_ko='그는 배를 한 봉지 샀는데 껍질이 얇고 과육이 부드럽고 달콤하고 즙이 많아.', example_pinyin='tā mǎi le yī dài lí ， pí báo ròu nèn ， yòu tián yòu duō zhī 。' WHERE chinese='梨' AND pinyin='lí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이혼하다', example_zh='他们因为长期分居，最终决定离婚。', example_ko='그들은 오랫동안 별거해서 결국 이혼하기로 결정했어.', example_pinyin='tā men yīn wèi cháng qī fēn jū ， zuì zhōng jué dìng lí hūn 。' WHERE chinese='离婚' AND pinyin='lí hūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='센티미터', example_zh='他的身高是175厘米，在中国男生中属于中等身材。', example_ko='그의 키는 175센티미터야, 중국 남자 중에서는 보통 키에 속해.', example_pinyin='tā de shēn gāo shì 175 lí mǐ ， zài zhōng guó nán shēng zhōng shǔ yú zhōng děng shēn cái 。' WHERE chinese='厘米' AND pinyin='lí mǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일요일', example_zh='礼拜天我喜欢睡懒觉，然后出去散步吃饭。', example_ko='일요일에 나는 늦잠 자는 걸 좋아하고 그다음에 나가서 산책하고 밥 먹어.', example_pinyin='lǐ bài tiān wǒ xǐ huān shuì lǎn jiào ， rán hòu chū qù sàn bù chī fàn 。' WHERE chinese='礼拜天' AND pinyin='lǐ bài tiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이론', example_zh='学习时不能只注重理论，还要结合实际操作。', example_ko='공부할 때 이론만 중시해서는 안 되고 실제 운용과 결합해야 해.', example_pinyin='xué xí shí bù néng zhǐ zhù zhòng lǐ lùn ， hái yào jié hé shí jì cāo zuò 。' WHERE chinese='理论' AND pinyin='lǐ lùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이유, 까닭', example_zh='他没有说明理由就突然辞职了，大家都很疑惑。', example_ko='그는 이유도 말하지 않고 갑자기 사직해서 다들 매우 의아해했어.', example_pinyin='tā méi yǒu shuō míng lǐ yóu jiù tū rán cí zhí le ， dà jiā dōu hěn yí huò 。' WHERE chinese='理由' AND pinyin='lǐ yóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='알갱이 (양사)', example_zh='医生让他每天吃两粒维生素，增强免疫力。', example_ko='의사가 그에게 매일 비타민 두 알을 먹으라고 했어, 면역력을 강화하기 위해서.', example_pinyin='yī shēng ràng tā měi tiān chī liǎng lì wéi shēng sù ， zēng qiáng miǎn yì lì 。' WHERE chinese='粒' AND pinyin='lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세제곱, 입방', example_zh='这个游泳池的容积是一千立方米。', example_ko='이 수영장의 용적은 1000세제곱미터야.', example_pinyin='zhè ge yóu yǒng chí de róng jī shì yī qiān lì fāng mǐ 。' WHERE chinese='立方' AND pinyin='lì fāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='즉시, 당장', example_zh='听到警报声，大家立即停下工作，有序撤离。', example_ko='경보 소리를 듣고 모두 즉시 일을 멈추고 질서 있게 대피했어.', example_pinyin='tīng dào jǐng bào shēng ， dà jiā lì jí tíng xià gōng zuò ， yǒu xù chè lí 。' WHERE chinese='立即' AND pinyin='lì jí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='즉각, 곧바로', example_zh='他接到电话后立刻出门，连外套都没来得及穿。', example_ko='그는 전화를 받자마자 즉각 나갔는데 외투를 입을 틈도 없었어.', example_pinyin='tā jiē dào diàn huà hòu lì kè chū mén ， lián wài tào dōu méi lái de jí chuān 。' WHERE chinese='立刻' AND pinyin='lì kè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='힘, 역량', example_zh='团结的力量是无穷的，大家一起努力一定能成功。', example_ko='단결의 힘은 무한해서 다 함께 노력하면 반드시 성공할 수 있어.', example_pinyin='tuán jié de lì liàng shì wú qióng de ， dà jiā yì qǐ nǔ lì yí dìng néng chéng gōng 。' WHERE chinese='力量' AND pinyin='lì liang' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이익, 이윤', example_zh='这季度公司的利润比去年同期增长了20%。', example_ko='이번 분기 회사의 이윤이 작년 같은 시기보다 20% 성장했어.', example_pinyin='zhè jì dù gōng sī de lì rùn bǐ qù nián tóng qī zēng zhǎng le 20%。' WHERE chinese='利润' AND pinyin='lì rùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이자', example_zh='银行存款有利息，存款时间越长，利息越多。', example_ko='은행 예금에는 이자가 붙어서 예금 기간이 길수록 이자가 많아.', example_pinyin='yín háng cún kuǎn yǒu lì xī ， cún kuǎn shí jiān yuè zhǎng ， lì xī yuè duō 。' WHERE chinese='利息' AND pinyin='lì xī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이익, 이해관계', example_zh='这次合作对双方都有利益，大家都很满意。', example_ko='이번 협력은 양쪽 모두에게 이익이 있어서 다들 만족해.', example_pinyin='zhè cì hé zuò duì shuāng fāng dōu yǒu lì yì ， dà jiā dōu hěn mǎn yì 。' WHERE chinese='利益' AND pinyin='lì yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이용하다, 활용하다', example_zh='他善于利用碎片时间学习，每天进步一点点。', example_ko='그는 자투리 시간을 활용해서 공부하는 걸 잘해서 매일 조금씩 발전해.', example_pinyin='tā shàn yú lì yòng suì piàn shí jiān xué xí ， měi tiān jìn bù yì diǎn diǎn 。' WHERE chinese='利用' AND pinyin='lì yòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서둘러, 급히', example_zh='他连忙道歉，说不是故意的，请对方原谅。', example_ko='그는 서둘러 사과하며 의도한 게 아니라고 용서해달라고 했어.', example_pinyin='tā lián máng dào qiàn ， shuō bú shì gù yì de ， qǐng duì fāng yuán liàng 。' WHERE chinese='连忙' AND pinyin='lián máng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연속극, 드라마 시리즈', example_zh='她每天晚上都追一部连续剧，一口气看好几集。', example_ko='그녀는 매일 저녁 드라마를 보면서 한 번에 여러 편을 봐.', example_pinyin='tā měi tiān wǎn shàng dōu zhuī yī bù lián xù jù ， yì kǒu qì kàn hǎo jǐ jí 。' WHERE chinese='连续剧' AND pinyin='lián xù jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연합하다, 합치다', example_zh='两家公司联合起来，共同开拓新的市场。', example_ko='두 회사가 연합해서 함께 새로운 시장을 개척했어.', example_pinyin='liǎng jiā gōng sī lián hé qǐ lái ， gòng tóng kāi tuò xīn de shì chǎng 。' WHERE chinese='联合' AND pinyin='lián hé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사랑하다, 연애하다', example_zh='他们相识半年后开始恋爱，感情越来越好。', example_ko='그들은 알게 된 지 반 년 후 사귀기 시작했는데 사이가 점점 좋아졌어.', example_pinyin='tā men xiāng shí bàn nián hòu kāi shǐ liàn ài ， gǎn qíng yuè lái yuè hǎo 。' WHERE chinese='恋爱' AND pinyin='liàn ài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='양호하다, 좋다', example_zh='经过调养，他的身体状况已经恢复良好了。', example_ko='조양 끝에 그의 신체 상태가 이미 양호하게 회복됐어.', example_pinyin='jīng guò tiáo yǎng ， tā de shēn tǐ zhuàng kuàng yǐ jīng huī fù liáng hǎo le 。' WHERE chinese='良好' AND pinyin='liáng hǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='식량', example_zh='这次旱灾导致粮食减产，政府紧急调配物资援助。', example_ko='이번 가뭄으로 식량 생산이 줄어서 정부가 긴급히 물자를 배분해서 지원했어.', example_pinyin='zhè cì hàn zāi dǎo zhì liáng shí jiǎn chǎn ， zhèng fǔ jǐn jí diào pèi wù zī yuán zhù 。' WHERE chinese='粮食' AND pinyin='liáng shi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대단하다, 훌륭하다', example_zh='他一个人把这件事办成了，真是了不起！', example_ko='그가 혼자서 이 일을 해냈어, 정말 대단해!', example_pinyin='tā yí gè rén bǎ zhè jiàn shì bàn chéng le ， zhēn shì liǎo bù qǐ ！' WHERE chinese='了不起' AND pinyin='liǎo bu qǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='임시의, 그때그때의', example_zh='今天的司机请假了，临时找了个代驾，还好及时赶到了。', example_ko='오늘 기사가 휴가를 내서 임시로 대리기사를 구했는데 다행히 제때 도착했어.', example_pinyin='jīn tiān de sī jī qǐng jià le ， lín shí zhǎo le gè dài jià ， hái hǎo jí shí gǎn dào le 。' WHERE chinese='临时' AND pinyin='lín shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='벨, 방울', example_zh='上课铃响了，学生们迅速回到座位上坐好。', example_ko='수업 종이 울리자 학생들이 빠르게 자리로 돌아가서 앉았어.', example_pinyin='shàng kè líng xiǎng le ， xué shēng men xùn sù huí dào zuò wèi shàng zuò hǎo 。' WHERE chinese='铃' AND pinyin='líng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부품, 부속품', example_zh='这台机器坏了，需要更换一个零件才能修好。', example_ko='이 기계가 고장 났는데 부품 하나를 교체해야 수리할 수 있어.', example_pinyin='zhè tái jī qì huài le ， xū yào gēng huàn yí gè líng jiàn cái néng xiū hǎo 。' WHERE chinese='零件' AND pinyin='líng jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='잔돈, 동전', example_zh='请问你有没有零钱，我需要找一下。', example_ko='혹시 잔돈 있어? 내가 거슬러줘야 해서.', example_pinyin='qǐng wèn nǐ yǒu méi yǒu líng qián ， wǒ xū yào zhǎo yī xià 。' WHERE chinese='零钱' AND pinyin='líng qián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='간식', example_zh='她养成了少吃零食的习惯，有助于控制体重。', example_ko='그녀는 간식을 적게 먹는 습관을 들여서 체중 관리에 도움이 돼.', example_pinyin='tā yǎng chéng le shǎo chī líng shí de xí guàn ， yǒu zhù yú kòng zhì tǐ zhòng 。' WHERE chinese='零食' AND pinyin='líng shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유연하다, 융통성 있다', example_zh='他处理问题很灵活，能根据情况随时调整方案。', example_ko='그는 문제 처리가 유연해서 상황에 따라 방안을 수시로 조정할 수 있어.', example_pinyin='tā chǔ lǐ wèn tí hěn líng huó ， néng gēn jù qíng kuàng suí shí diào zhěng fāng àn 。' WHERE chinese='灵活' AND pinyin='líng huó' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='리더, 지도자; 이끌다', example_zh='她是团队的领导，大家都很信服她的决定。', example_ko='그녀는 팀의 리더야, 모두 그녀의 결정을 신뢰해.', example_pinyin='tā shì tuán duì de lǐng dǎo ， dà jiā dōu hěn xìn fú tā de jué dìng 。' WHERE chinese='领导' AND pinyin='lǐng dǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영역, 분야', example_zh='他在科技领域取得了很多重要的研究成果。', example_ko='그는 과학기술 분야에서 많은 중요한 연구 성과를 거뒀어.', example_pinyin='tā zài kē jì lǐng yù qǔ dé le hěn duō zhòng yào de yán jiū chéng guǒ 。' WHERE chinese='领域' AND pinyin='lǐng yù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전해지다, 유전하다', example_zh='这首民间故事流传了几百年，至今还有人传诵。', example_ko='이 민간 이야기는 수백 년간 전해져서 지금도 전하는 사람이 있어.', example_pinyin='zhè shǒu mín jiān gù shì liú chuán le jǐ bǎi nián ， zhì jīn hái yǒu rén chuán sòng 。' WHERE chinese='流传' AND pinyin='liú chuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='검색하다, 훑어보다', example_zh='他浏览了几个求职网站，找到了几个不错的职位。', example_ko='그는 취업 사이트 몇 개를 검색해서 괜찮은 직위를 몇 개 찾았어.', example_pinyin='tā liú lǎn le jǐ gè qiú zhí wǎng zhàn ， zhǎo dào le jǐ gè bù cuò de zhí wèi 。' WHERE chinese='浏览' AND pinyin='liú lǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='용', example_zh='龙在中国文化中象征着吉祥和力量，深受人们喜爱。', example_ko='용은 중국 문화에서 길상과 힘을 상징해서 사람들의 사랑을 많이 받아.', example_pinyin='lóng zài zhōng guó wén huà zhōng xiàng zhēng zhe jí xiáng hé lì liàng ， shēn shòu rén men xǐ ài 。' WHERE chinese='龙' AND pinyin='lóng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='새다, 누수하다', example_zh='水管漏了，地上积了一大滩水，要赶紧修。', example_ko='수도관이 새서 바닥에 물이 한 웅덩이 고였어, 빨리 수리해야 해.', example_pinyin='shuǐ guǎn lòu le ， dì shàng jī le yī dà tān shuǐ ， yào gǎn jǐn xiū 。' WHERE chinese='漏' AND pinyin='lòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='드러나다, 노출되다', example_zh='他试图隐瞒，但真相最终还是露出来了。', example_ko='그는 숨기려 했지만 진실은 결국 드러났어.', example_pinyin='tā shì tú yǐn mán ， dàn zhēn xiàng zuì zhōng hái shì lù chū lái le 。' WHERE chinese='露' AND pinyin='lù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='육지', example_zh='海龟每年都会回到陆地上产卵，然后再回到海洋。', example_ko='바다거북은 매년 육지로 돌아와 알을 낳고 나서 다시 바다로 돌아가.', example_pinyin='hǎi guī měi nián dū huì huí dào lù dì shàng chǎn luǎn ， rán hòu zài huí dào hǎi yáng 。' WHERE chinese='陆地' AND pinyin='lù dì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='잇달아, 차례로', example_zh='活动结束后，观众们陆续离开了会场。', example_ko='행사가 끝난 후 관람객들이 차례로 행사장을 떠났어.', example_pinyin='huó dòng jié shù hòu ， guān zhòng men lù xù lí kāi le huì chǎng 。' WHERE chinese='陆续' AND pinyin='lù xù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='합격 통보를 받다', example_zh='他收到了名牌大学的录取通知书，全家人都很高兴。', example_ko='그는 명문 대학의 합격 통지서를 받았는데 온 가족이 모두 기뻐했어.', example_pinyin='tā shōu dào le míng pái dà xué de lù qǔ tōng zhī shū ， quán jiā rén dōu hěn gāo xìng 。' WHERE chinese='录取' AND pinyin='lù qǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='녹음하다; 녹음', example_zh='他把这首歌录了音，发到了朋友圈，大家都很喜欢。', example_ko='그는 이 노래를 녹음해서 SNS에 올렸는데 다들 매우 좋아했어.', example_pinyin='tā bǎ zhè shǒu gē lù le yīn ， fā dào le péng yǒu quān ， dà jiā dōu hěn xǐ huān 。' WHERE chinese='录音' AND pinyin='lù yīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='번갈아 하다, 교대하다', example_zh='大家轮流发言，每个人都有机会表达自己的意见。', example_ko='모두 번갈아 발언해서 모든 사람이 자신의 의견을 표현할 기회가 있어.', example_pinyin='dà jiā lún liú fā yán ， měi gè rén dōu yǒu jī huì biǎo dá zì jǐ de yì jiàn 。' WHERE chinese='轮流' AND pinyin='lún liú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='논문', example_zh='他花了三年时间写完了自己的博士论文。', example_ko='그는 3년을 들여서 자신의 박사 논문을 완성했어.', example_pinyin='tā huā le sān nián shí jiān xiě wán le zì jǐ de bó shì lùn wén 。' WHERE chinese='论文' AND pinyin='lùn wén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='논리', example_zh='他说话的逻辑很清晰，大家都能很容易理解他的意思。', example_ko='그가 말하는 논리가 매우 명확해서 다들 그의 말을 쉽게 이해할 수 있어.', example_pinyin='tā shuō huà de luó jí hěn qīng xī ， dà jiā dōu néng hěn róng yì lǐ jiě tā de yì si 。' WHERE chinese='逻辑' AND pinyin='luó ji' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뒤처지다, 낙후하다', example_zh='这个地区在经济上比较落后，政府正在加大投入。', example_ko='이 지역은 경제적으로 비교적 뒤처져 있어서 정부가 투자를 늘리고 있어.', example_pinyin='zhè ge dì qū zài jīng jì shàng bǐ jiào luò hòu ， zhèng fǔ zhèng zài jiā dà tóu rù 。' WHERE chinese='落后' AND pinyin='luò hòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='욕하다, 꾸짖다', example_zh='他一生气就开始骂人，这个习惯真的很不好。', example_ko='그는 화가 나면 바로 욕을 해서 이 습관이 정말 별로야.', example_pinyin='tā yī shēng qì jiù kāi shǐ mà rén ， zhè ge xí guàn zhēn de hěn bù hǎo 。' WHERE chinese='骂' AND pinyin='mà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='마이크', example_zh='演讲时要靠近麦克风，这样声音才能清楚传出去。', example_ko='연설할 때 마이크에 가까이 해야 소리가 명확하게 전달돼.', example_pinyin='yǎn jiǎng shí yào kào jìn mài kè fēng ， zhè yàng shēng yīn cái néng qīng chǔ chuán chū qù 。' WHERE chinese='麦克风' AND pinyin='mài kè fēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만터우 (찐빵)', example_zh='他早餐喜欢吃馒头配咸菜，简单朴实。', example_ko='그는 아침에 만터우와 반찬을 즐겨 먹어, 간단하고 소박해.', example_pinyin='tā zǎo cān xǐ huān chī mán tou pèi xián cài ， jiǎn dān pǔ shí 。' WHERE chinese='馒头' AND pinyin='mán tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만족하다, 충족하다', example_zh='努力工作之后，她终于感到了满足，实现了自己的梦想。', example_ko='열심히 일한 끝에 그녀는 드디어 만족감을 느끼며 꿈을 이뤘어.', example_pinyin='nǔ lì gōng zuò zhī hòu ， tā zhōng yú gǎn dào le mǎn zú ， shí xiàn le zì jǐ de mèng xiǎng 。' WHERE chinese='满足' AND pinyin='mǎn zú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='털; 0.1위안', example_zh='他的猫掉了很多毛，家里到处都是猫毛。', example_ko='그의 고양이가 털이 많이 빠져서 집 안 곳곳에 고양이 털이 있어.', example_pinyin='tā de māo diào le hěn duō máo ， jiā lǐ dào chù dōu shì māo máo 。' WHERE chinese='毛' AND pinyin='máo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='결함, 흠; 고장', example_zh='这台电脑有点毛病，一直运行得很慢，需要检修。', example_ko='이 컴퓨터에 결함이 좀 있어서 계속 느리게 작동해, 점검이 필요해.', example_pinyin='zhè tái diàn nǎo yǒu diǎn máo bìng ， yì zhí yùn xíng dé hěn màn ， xū yào jiǎn xiū 。' WHERE chinese='毛病' AND pinyin='máo bìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모순, 갈등', example_zh='他们俩之间有一些矛盾，需要坐下来好好沟通。', example_ko='그들 사이에 갈등이 있어서 앉아서 잘 소통해야 해.', example_pinyin='tā men liǎ zhī jiān yǒu yī xiē máo dùn ， xū yào zuò xià lái hǎo hǎo gōu tōng 。' WHERE chinese='矛盾' AND pinyin='máo dùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모험하다; 모험', example_zh='他喜欢冒险，经常去陌生的地方探险。', example_ko='그는 모험을 좋아해서 자주 낯선 곳에 가서 탐험해.', example_pinyin='tā xǐ huān mào xiǎn ， jīng cháng qù mò shēng de dì fāng tàn xiǎn 。' WHERE chinese='冒险' AND pinyin='mào xiǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무역', example_zh='两国之间的贸易往来越来越频繁，关系日益密切。', example_ko='양국 간의 무역 교류가 점점 잦아지고 관계가 날로 긴밀해지고 있어.', example_pinyin='liǎng guó zhī jiān de mào yì wǎng lái yuè lái yuè pín fán ， guān xì rì yì mì qiè 。' WHERE chinese='贸易' AND pinyin='mào yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='눈썹', example_zh='她的眉毛很浓，整个人看起来很精神。', example_ko='그녀의 눈썹이 진해서 전체적으로 매우 생기 있어 보여.', example_pinyin='tā de méi máo hěn nóng ， zhěng gè rén kàn qǐ lái hěn jīng shén 。' WHERE chinese='眉毛' AND pinyin='méi mao' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='석탄', example_zh='煤炭是工业生产的重要燃料，但燃烧会造成污染。', example_ko='석탄은 공업 생산의 중요한 연료이지만 연소하면 오염을 일으켜.', example_pinyin='méi tàn shì gōng yè shēng chǎn de zhòng yào rán liào ， dàn rán shāo huì zào chéng wū rǎn 。' WHERE chinese='煤炭' AND pinyin='méi tàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미술, 예술', example_zh='她从小学习美术，现在已经是一名优秀的画家了。', example_ko='그녀는 어릴 때부터 미술을 배워서 지금은 훌륭한 화가가 됐어.', example_pinyin='tā cóng xiǎo xué xí měi shù ， xiàn zài yǐ jīng shì yī míng yōu xiù de huà jiā le 。' WHERE chinese='美术' AND pinyin='měi shù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='매력', example_zh='这个城市有独特的魅力，每年吸引大量游客前来参观。', example_ko='이 도시는 독특한 매력이 있어서 매년 많은 관광객을 끌어들여.', example_pinyin='zhè ge chéng shì yǒu dú tè de mèi lì ， měi nián xī yǐn dà liàng yóu kè qián lái cān guān 。' WHERE chinese='魅力' AND pinyin='mèi lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='길을 잃다', example_zh='第一次来这个城市，他迷路了，只好用手机导航。', example_ko='이 도시에 처음 와서 그는 길을 잃어서 스마트폰 내비를 쓸 수밖에 없었어.', example_pinyin='dì yī cì lái zhè ge chéng shì ， tā mí lù le ， zhǐ hǎo yòng shǒu jī dǎo háng 。' WHERE chinese='迷路' AND pinyin='mí lù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수수께끼', example_zh='孩子们喜欢猜谜语，锻炼思维能力。', example_ko='아이들은 수수께끼 맞히는 걸 좋아해서 사고 능력을 키워.', example_pinyin='hái zi men xǐ huān cāi mí yǔ ， duàn liàn sī wéi néng lì 。' WHERE chinese='谜语' AND pinyin='mí yǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='밀접하다, 긴밀하다', example_zh='这两件事联系密切，一件发生了就会影响另一件。', example_ko='이 두 가지 일은 밀접하게 연관되어 있어서 하나가 일어나면 다른 하나에 영향을 줘.', example_pinyin='zhè liǎng jiàn shì lián xì mì qiè ， yī jiàn fā shēng le jiù huì yǐng xiǎng lìng yī jiàn 。' WHERE chinese='密切' AND pinyin='mì qiè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='벌', example_zh='蜜蜂每天辛勤地采蜜，是大自然的小英雄。', example_ko='벌은 매일 열심히 꿀을 모아서 자연의 작은 영웅이야.', example_pinyin='mì fēng měi tiān xīn qín dì cǎi mì ， shì dà zì rán de xiǎo yīng xióng 。' WHERE chinese='蜜蜂' AND pinyin='mì fēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비밀', example_zh='这件事是他们之间的秘密，不能告诉任何人。', example_ko='이 일은 그들만의 비밀이야, 아무에게도 말하면 안 돼.', example_pinyin='zhè jiàn shì shì tā men zhī jiān de mì mì ， bù néng gào sù rèn hé rén 。' WHERE chinese='秘密' AND pinyin='mì mì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비서', example_zh='她是总经理的秘书，每天处理各种文件和会议安排。', example_ko='그녀는 총경리의 비서야, 매일 각종 서류와 회의 일정을 처리해.', example_pinyin='tā shì zǒng jīng lǐ de mì shū ， měi tiān chǔ lǐ gè zhǒng wén jiàn hé huì yì ān pái 。' WHERE chinese='秘书' AND pinyin='mì shū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='면화, 솜', example_zh='棉花是制作棉布的主要原料，广泛用于纺织业。', example_ko='면화는 면직물을 만드는 주요 원료야, 방직 산업에 널리 쓰여.', example_pinyin='mián huā shì zhì zuò mián bù de zhǔ yào yuán liào ， guǎng fàn yòng yú fǎng zhī yè 。' WHERE chinese='棉花' AND pinyin='mián hua' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='직면하다, 마주하다', example_zh='他勇敢地面对了自己的恐惧，终于克服了心理障碍。', example_ko='그는 용감하게 자신의 두려움과 마주해서 결국 심리적 장벽을 극복했어.', example_pinyin='tā yǒng gǎn dì miàn duì le zì jǐ de kǒng jù ， zhōng yú kè fú le xīn lǐ zhàng ài 。' WHERE chinese='面对' AND pinyin='miàn duì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='면적', example_zh='中国的国土面积居世界第三，地形多样。', example_ko='중국의 국토 면적은 세계 3위야, 지형이 다양해.', example_pinyin='zhōng guó de guó tǔ miàn jī jū shì jiè dì sān ， dì xíng duō yàng 。' WHERE chinese='面积' AND pinyin='miàn ji' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='직면하다, 처하다', example_zh='公司面临经营困难，管理层正在寻找解决办法。', example_ko='회사가 경영 어려움에 처해서 경영진이 해결 방법을 찾고 있어.', example_pinyin='gōng sī miàn lín jīng yíng kùn nán ， guǎn lǐ céng zhèng zài xún zhǎo jiě jué bàn fǎ 。' WHERE chinese='面临' AND pinyin='miàn lín' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='묘사하다', example_zh='他用生动的语言描写了家乡的美丽景色。', example_ko='그는 생생한 언어로 고향의 아름다운 경치를 묘사했어.', example_pinyin='tā yòng shēng dòng de yǔ yán miáo xiě le jiā xiāng de měi lì jǐng sè 。' WHERE chinese='描写' AND pinyin='miáo xiě' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='날씬하다, 몸매가 좋다', example_zh='她身材苗条，穿什么衣服都很好看。', example_ko='그녀는 몸매가 날씬해서 어떤 옷을 입어도 예뻐 보여.', example_pinyin='tā shēn cái miáo tiáo ， chuān shén me yī fú dōu hěn hǎo kàn 。' WHERE chinese='苗条' AND pinyin='miáo tiáo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='초 (시간 단위)', example_zh='百米短跑他只用了10秒，打破了校纪录。', example_ko='100미터 단거리를 그는 10초만에 달려서 학교 기록을 경신했어.', example_pinyin='bǎi mǐ duǎn pǎo tā zhǐ yòng le 10 miǎo ， dǎ pò le xiào jì lù 。' WHERE chinese='秒' AND pinyin='miǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='민주, 민주주의', example_zh='民主社会里，公民有权利参与政治，发表意见。', example_ko='민주 사회에서 시민은 정치에 참여하고 의견을 발표할 권리가 있어.', example_pinyin='mín zhǔ shè huì lǐ ， gōng mín yǒu quán lì cān yù zhèng zhì ， fā biǎo yì jiàn 。' WHERE chinese='民主' AND pinyin='mín zhǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='명확하다, 분명하다', example_zh='他表达的意思很明确，大家都清楚地理解了他的要求。', example_ko='그가 표현하는 의미가 매우 명확해서 모두 그의 요구를 분명하게 이해했어.', example_pinyin='tā biǎo dá de yì si hěn míng què ， dà jiā dōu qīng chǔ dì lǐ jiě le tā de yāo qiú 。' WHERE chinese='明确' AND pinyin='míng què' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뚜렷하다, 분명하다', example_zh='两种方案的区别很明显，一看就能看出来。', example_ko='두 방안의 차이가 뚜렷해서 한눈에 알아볼 수 있어.', example_pinyin='liǎng zhǒng fāng àn de qū bié hěn míng xiǎn ， yī kàn jiù néng kàn chū lái 。' WHERE chinese='明显' AND pinyin='míng xiǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='엽서', example_zh='她去旅游时买了很多明信片，寄给了远方的朋友。', example_ko='그녀는 여행 갔을 때 엽서를 많이 사서 멀리 있는 친구들에게 보냈어.', example_pinyin='tā qù lǚ yóu shí mǎi le hěn duō míng xìn piàn ， jì gěi le yuǎn fāng de péng yǒu 。' WHERE chinese='明信片' AND pinyin='míng xìn piàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='스타, 인기인', example_zh='她是中国著名的影视明星，拥有大量粉丝。', example_ko='그녀는 중국의 유명한 영화배우 스타야, 팬이 엄청 많아.', example_pinyin='tā shì zhōng guó zhù míng de yǐng shì míng xīng ， yōng yǒu dà liàng fěn sī 。' WHERE chinese='明星' AND pinyin='míng xīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='명품 브랜드', example_zh='他喜欢买名牌，认为质量和品位都有保障。', example_ko='그는 명품 사는 걸 좋아해서 품질과 품격이 보장된다고 생각해.', example_pinyin='tā xǐ huān mǎi míng pái ， rèn wéi zhì liàng hé pǐn wèi dōu yǒu bǎo zhàng 。' WHERE chinese='名牌' AND pinyin='míng pái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='명함', example_zh='初次见面时，他礼貌地递上了自己的名片。', example_ko='처음 만났을 때 그는 예의 바르게 자신의 명함을 건넸어.', example_pinyin='chū cì jiàn miàn shí ， tā lǐ mào dì dì shàng le zì jǐ de míng piàn 。' WHERE chinese='名片' AND pinyin='míng piàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='명승지, 유명 명소', example_zh='这座城市的名胜古迹很多，吸引了大量国内外游客。', example_ko='이 도시의 명승지가 많아서 국내외 관광객을 대거 끌어들여.', example_pinyin='zhè zuò chéng shì de míng shèng gǔ jì hěn duō ， xī yǐn le dà liàng guó nèi wài yóu kè 。' WHERE chinese='名胜' AND pinyin='míng shèng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='명령하다; 명령', example_zh='指挥官命令士兵原地待命，等待进一步指示。', example_ko='지휘관이 병사들에게 제자리에서 대기하며 추가 지시를 기다리라고 명령했어.', example_pinyin='zhǐ huī guān mìng lìng shì bīng yuán dì dài mìng ， děng dài jìn yí bù zhǐ shì 。' WHERE chinese='命令' AND pinyin='mìng lìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운명', example_zh='他相信命运是可以改变的，只要努力一切都有可能。', example_ko='그는 운명은 바꿀 수 있다고 믿어서 노력하면 모든 게 가능하다고 생각해.', example_pinyin='tā xiāng xìn mìng yùn shì kě yǐ gǎi biàn de ， zhǐ yào nǔ lì yī qiè dōu yǒu kě néng 。' WHERE chinese='命运' AND pinyin='mìng yùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만지다, 더듬다', example_zh='他在黑暗中摸索着找到了电灯开关，把灯打开了。', example_ko='그는 어둠 속에서 더듬어가며 전등 스위치를 찾아서 불을 켰어.', example_pinyin='tā zài hēi àn zhōng mō suǒ zhe zhǎo dào le diàn dēng kāi guān ， bǎ dēng dǎ kāi le 。' WHERE chinese='摸' AND pinyin='mō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오토바이', example_zh='他骑摩托车上班，速度快，但要注意安全。', example_ko='그는 오토바이를 타고 출근해서 빠르지만 안전에 주의해야 해.', example_pinyin='tā qí mó tuō chē shàng bān ， sù dù kuài ， dàn yào zhù yì ān quán 。' WHERE chinese='摩托车' AND pinyin='mó tuō chē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모방하다, 흉내 내다', example_zh='小孩子喜欢模仿大人的行为，所以家长要以身作则。', example_ko='아이들은 어른의 행동을 모방하기 좋아해서 부모는 솔선수범해야 해.', example_pinyin='xiǎo hái zi xǐ huān mó fǎng dà rén de xíng wéi ， suǒ yǐ jiā zhǎng yào yǐ shēn zuò zé 。' WHERE chinese='模仿' AND pinyin='mó fǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='흐릿하다, 모호하다', example_zh='他的记忆有些模糊，想不起来那天发生了什么事。', example_ko='그의 기억이 좀 모호해서 그날 무슨 일이 있었는지 생각이 안 나.', example_pinyin='tā de jì yì yǒu xiē mó hú ， xiǎng bù qǐ lái nà tiān fā shēng le shén me shì 。' WHERE chinese='模糊' AND pinyin='mó hu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='낯설다', example_zh='他搬到了一个陌生的城市，一切都需要重新开始。', example_ko='그는 낯선 도시로 이사해서 모든 걸 새로 시작해야 했어.', example_pinyin='tā bān dào le yí gè mò shēng de chéng shì ， yī qiè dōu xū yào chóng xīn kāi shǐ 。' WHERE chinese='陌生' AND pinyin='mò shēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어떤, 某某', example_zh='他说某某人告诉他这件事，但不肯透露名字。', example_ko='그는 어떤 사람이 이 일을 알려줬다고 했지만 이름을 밝히려 하지 않았어.', example_pinyin='tā shuō mǒu mǒu rén gào sù tā zhè jiàn shì ， dàn bù kěn tòu lù míng zì 。' WHERE chinese='某' AND pinyin='mǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='목표', example_zh='他给自己定下了一个明确的目标，然后一步一步地去实现。', example_ko='그는 스스로 명확한 목표를 세우고 한 걸음씩 실현해 나갔어.', example_pinyin='tā gěi zì jǐ dìng xià le yí gè míng què de mù biāo ， rán hòu yí bù yí bù dì qù shí xiàn 。' WHERE chinese='目标' AND pinyin='mù biāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='목차, 목록', example_zh='书的目录可以帮助读者快速找到自己需要的内容。', example_ko='책의 목차는 독자가 필요한 내용을 빠르게 찾는 데 도움이 돼.', example_pinyin='shū de mù lù kě yǐ bāng zhù dú zhě kuài sù zhǎo dào zì jǐ xū yào de nèi róng 。' WHERE chinese='目录' AND pinyin='mù lù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='현재, 지금', example_zh='目前公司的发展势头很好，业绩持续增长。', example_ko='현재 회사의 발전 기세가 좋아서 실적이 지속적으로 성장하고 있어.', example_pinyin='mù qián gōng sī de fā zhǎn shì tou hěn hǎo ， yè jì chí xù zēng zhǎng 。' WHERE chinese='目前' AND pinyin='mù qián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='나무', example_zh='他小时候喜欢爬木头做的树屋，那是他最美好的童年记忆。', example_ko='그는 어릴 때 나무로 만든 나무 집 오르는 걸 좋아했어, 가장 아름다운 어린 시절 추억이야.', example_pinyin='tā xiǎo shí hòu xǐ huān pá mù tou zuò de shù wū ， nà shì tā zuì měi hǎo de tóng nián jì yì 。' WHERE chinese='木头' AND pinyin='mù tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='설령 ~해도, 비록', example_zh='哪怕只有一点点希望，他也要坚持下去。', example_ko='설령 아주 조금의 희망만 있어도 그는 계속 버텨나가겠어.', example_pinyin='nǎ pà zhǐ yǒu yì diǎn diǎn xī wàng ， tā yě yào jiān chí xià qù 。' WHERE chinese='哪怕' AND pinyin='nǎ pà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어쩐지, 당연하다', example_zh='难怪他今天这么开心，原来是升职了。', example_ko='어쩐지 그가 오늘 이렇게 기쁘더라, 알고 보니 승진했네.', example_pinyin='nán guài tā jīn tiān zhè me kāi xīn ， yuán lái shì shēng zhí le 。' WHERE chinese='难怪' AND pinyin='nán guài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='못생기다, 보기 싫다', example_zh='他写的字太难看了，让他练习书法改善一下。', example_ko='그가 쓴 글씨가 너무 보기 싫어서 서예를 연습해서 개선하라고 했어.', example_pinyin='tā xiě de zì tài nán kàn le ， ràng tā liàn xí shū fǎ gǎi shàn yī xià 。' WHERE chinese='难看' AND pinyin='nán kàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='머리', example_zh='他摔了一跤，脑袋撞到了墙，头很痛。', example_ko='그는 넘어져서 머리가 벽에 부딪혀 머리가 매우 아파.', example_pinyin='tā shuāi le yī jiāo ， nǎo dài zhuàng dào le qiáng ， tóu hěn tòng 。' WHERE chinese='脑袋' AND pinyin='nǎo dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='내과', example_zh='他去了内科检查，医生说他需要做进一步检查。', example_ko='그는 내과에 가서 검진을 받았는데 의사가 추가 검사가 필요하다고 했어.', example_pinyin='tā qù le nèi kē jiǎn chá ， yī shēng shuō tā xū yào zuò jìn yí bù jiǎn chá 。' WHERE chinese='内科' AND pinyin='nèi kē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연하다, 부드럽다', example_zh='这块豆腐非常嫩，口感滑溜，入口即化。', example_ko='이 두부는 매우 부드럽고 감촉이 매끄러워서 입에 넣으면 바로 녹아.', example_pinyin='zhè kuài dòu fǔ fēi cháng nèn ， kǒu gǎn huá liū ， rù kǒu jí huà 。' WHERE chinese='嫩' AND pinyin='nèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='능력 있다, 유능하다', example_zh='她工作很能干，一个人顶两个人用，老板很器重她。', example_ko='그녀는 일을 유능하게 해서 혼자 두 사람 몫을 해서 사장이 매우 소중히 여겨.', example_pinyin='tā gōng zuò hěn néng gàn ， yí gè rén dǐng liǎng gè rén yòng ， lǎo bǎn hěn qì zhòng tā 。' WHERE chinese='能干' AND pinyin='néng gàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='에너지원, 자원', example_zh='太阳能是一种清洁的能源，对环境几乎没有污染。', example_ko='태양에너지는 청정 에너지야, 환경에 거의 오염을 일으키지 않아.', example_pinyin='tài yáng néng shì yī zhǒng qīng jié de néng yuán ， duì huán jìng jī hū méi yǒu wū rǎn 。' WHERE chinese='能源' AND pinyin='néng yuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연대, 시대', example_zh='20世纪90年代，中国经济开始快速发展。', example_ko='20세기 90년대에 중국 경제가 빠르게 발전하기 시작했어.', example_pinyin='20 shì jì 90 nián dài ， zhōng guó jīng jì kāi shǐ kuài sù fā zhǎn 。' WHERE chinese='年代' AND pinyin='nián dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='나이, 연령', example_zh='他年纪不小了，但一直保持着年轻的心态。', example_ko='그는 나이가 적지 않지만 항상 젊은 마음을 유지하고 있어.', example_pinyin='tā nián jì bù xiǎo le ， dàn yì zhí bǎo chí zhe nián qīng de xīn tài 。' WHERE chinese='年纪' AND pinyin='nián jì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='읽다, 생각하다', example_zh='她每天睡前都要念几页书，养成了很好的阅读习惯。', example_ko='그녀는 매일 자기 전에 책을 몇 쪽 읽어서 좋은 독서 습관을 길렀어.', example_pinyin='tā měi tiān shuì qián dōu yào niàn jǐ yè shū ， yǎng chéng le hěn hǎo de yuè dú xí guàn 。' WHERE chinese='念' AND pinyin='niàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='차라리 ~하겠다', example_zh='宁可少赚一点，也不愿意做违背良心的事。', example_ko='차라리 조금 덜 벌더라도 양심을 어기는 일은 하고 싶지 않아.', example_pinyin='nìng kě shǎo zhuàn yì diǎn ， yě bù yuàn yì zuò wéi bèi liáng xīn de shì 。' WHERE chinese='宁可' AND pinyin='nìng kě' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='청바지', example_zh='牛仔裤是全球最流行的裤子之一，男女老少都穿。', example_ko='청바지는 전 세계에서 가장 유행하는 바지 중 하나야, 남녀노소 모두 입어.', example_pinyin='niú zǎi kù shì quán qiú zuì liú xíng de kù zi zhī yī ， nán nǚ lǎo shào dōu chuān 。' WHERE chinese='牛仔裤' AND pinyin='niú zǎi kù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='짙다, 진하다', example_zh='这杯咖啡味道太浓了，再加点水稀释一下吧。', example_ko='이 커피가 너무 진해서 물을 조금 더 넣어서 희석해봐.', example_pinyin='zhè bēi kā fēi wèi dào tài nóng le ， zài jiā diǎn shuǐ xī shì yī xià ba 。' WHERE chinese='浓' AND pinyin='nóng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='농민', example_zh='农民们春天播种，秋天收获，辛勤劳作了一年。', example_ko='농민들은 봄에 씨를 뿌리고 가을에 수확해서 1년간 열심히 일했어.', example_pinyin='nóng mín men chūn tiān bō zhǒng ， qiū tiān shōu huò ， xīn qín láo zuò le yī nián 。' WHERE chinese='农民' AND pinyin='nóng mín' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='농업', example_zh='中国的农业历史悠久，水稻种植已有数千年历史。', example_ko='중국의 농업 역사는 유구해서 벼 재배가 수천 년의 역사를 갖고 있어.', example_pinyin='zhōng guó de nóng yè lì shǐ yōu jiǔ ， shuǐ dào zhǒng zhí yǐ yǒu shù qiān nián lì shǐ 。' WHERE chinese='农业' AND pinyin='nóng yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='여사, 여성분 (경칭)', example_zh='各位女士先生，欢迎来到今天的颁奖典礼。', example_ko='신사 숙녀 여러분, 오늘 시상식에 오신 것을 환영합니다.', example_pinyin='gè wèi nǚ shì xiān shēng ， huān yíng lái dào jīn tiān de bān jiǎng diǎn lǐ 。' WHERE chinese='女士' AND pinyin='nǚ shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='우연히, 뜻밖에', example_zh='他们在机场偶然相遇，没想到在异乡还能碰到老同学。', example_ko='그들은 공항에서 우연히 만났어, 타지에서 옛 동창을 만나게 될 줄 몰랐어.', example_pinyin='tā men zài jī chǎng ǒu rán xiāng yù ， méi xiǎng dào zài yì xiāng hái néng pèng dào lǎo tóng xué 。' WHERE chinese='偶然' AND pinyin='ǒu rán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='두드리다, 치다; 찍다', example_zh='他拍了很多照片，记录下了这次旅行的美好时光。', example_ko='그는 사진을 많이 찍어서 이번 여행의 아름다운 시간을 기록했어.', example_pinyin='tā pāi le hěn duō zhào piān ， jì lù xià le zhè cì lǚ xíng de měi hǎo shí guāng 。' WHERE chinese='拍' AND pinyin='pāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='줄 서다, 줄을 서다', example_zh='超市收银台前人很多，他排队等了将近半个小时。', example_ko='슈퍼마켓 계산대 앞에 사람이 많아서 그는 줄 서서 거의 30분을 기다렸어.', example_pinyin='chāo shì shōu yín tái qián rén hěn duō ， tā pái duì děng le jiāng jìn bàn gè xiǎo shí 。' WHERE chinese='排队' AND pinyin='pái duì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='배구', example_zh='她加入了学校的排球队，每天下午训练两个小时。', example_ko='그녀는 학교 배구팀에 들어가서 매일 오후 두 시간씩 훈련해.', example_pinyin='tā jiā rù le xué xiào de pái qiú duì ， měi tiān xià wǔ xùn liàn liǎng gè xiǎo shí 。' WHERE chinese='排球' AND pinyin='pái qiú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보내다, 파견하다', example_zh='公司派他去上海出差，谈一个重要的合作项目。', example_ko='회사에서 그를 상하이로 출장 보냈어, 중요한 협력 프로젝트를 협의하러.', example_pinyin='gōng sī pài tā qù shàng hǎi chū chāi ， tán yí gè zhòng yào de hé zuò xiàng mù 。' WHERE chinese='派' AND pinyin='pài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='갈망하다, 고대하다', example_zh='孩子们盼望已久的暑假终于来了，大家都非常开心。', example_ko='아이들이 오랫동안 고대하던 여름방학이 드디어 왔어, 모두 매우 기뻐.', example_pinyin='hái zi men pàn wàng yǐ jiǔ de shǔ jià zhōng yú lái le ， dà jiā dōu fēi cháng kāi xīn 。' WHERE chinese='盼望' AND pinyin='pàn wàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='배상하다, 보상하다', example_zh='因为工程延误，承包公司需要向客户赔偿损失。', example_ko='공사 지연으로 인해 도급 회사는 고객에게 손해를 배상해야 해.', example_pinyin='yīn wèi gōng chéng yán wù ， chéng bāo gōng sī xū yào xiàng kè hù péi cháng sǔn shī 。' WHERE chinese='赔偿' AND pinyin='péi cháng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='육성하다, 키우다', example_zh='公司注重培养年轻人才，每年都会提供大量培训机会。', example_ko='회사는 젊은 인재 육성을 중시해서 매년 많은 교육 기회를 제공해.', example_pinyin='gōng sī zhù zhòng péi yǎng nián qīng rén cái ， měi nián dū huì tí gōng dà liàng péi xùn jī huì 。' WHERE chinese='培养' AND pinyin='péi yǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='협조하다, 맞추다', example_zh='团队工作需要大家相互配合，才能提高效率。', example_ko='팀 업무는 모두가 서로 협조해야 효율을 높일 수 있어.', example_pinyin='tuán duì gōng zuò xū yào dà jiā xiāng hù pèi hé ， cái néng tí gāo xiào lǜ 。' WHERE chinese='配合' AND pinyin='pèi hé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감복하다, 탄복하다', example_zh='她的演讲技巧令人佩服，整个会场掌声不断。', example_ko='그녀의 연설 기술은 감탄스러워서 행사장 전체가 계속 박수갈채를 보냈어.', example_pinyin='tā de yǎn jiǎng jì qiǎo lìng rén pèi fú ， zhěng gè huì chǎng zhǎng shēng bù duàn 。' WHERE chinese='佩服' AND pinyin='pèi fú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대야, 화분', example_zh='她买了一盆小花放在窗台上，增添了一份生气。', example_ko='그녀는 화분을 하나 사서 창가에 놓았더니 생기가 더해졌어.', example_pinyin='tā mǎi le yī pén xiǎo huā fàng zài chuāng tái shàng ， zēng tiān le yī fèn shēng qì 。' WHERE chinese='盆' AND pinyin='pén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만나다, 우연히 보다', example_zh='在超市里他碰见了多年未见的老同学，两人聊了很久。', example_ko='슈퍼마켓에서 그는 수년간 못 본 옛 동창을 만나서 두 사람이 오랫동안 이야기했어.', example_pinyin='zài chāo shì lǐ tā pèng jiàn le duō nián wèi jiàn de lǎo tóng xué ， liǎng rén liáo le hěn jiǔ 。' WHERE chinese='碰见' AND pinyin='pèng jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='두르다, 걸치다', example_zh='天气变凉了，她随手披了一件外套出门。', example_ko='날씨가 선선해져서 그녀는 재킷을 걸치고 나갔어.', example_pinyin='tiān qì biàn liáng le ， tā suí shǒu pī le yī jiàn wài tào chū mén 。' WHERE chinese='披' AND pinyin='pī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비판하다; 비판 (양사)', example_zh='他写了一批评论文章，批评了当前的教育体制。', example_ko='그는 비평 글 여러 편을 써서 현재의 교육 체제를 비판했어.', example_pinyin='tā xiě le yī pī píng lùn wén zhāng ， pī píng liǎo dàng qián de jiào yù tǐ zhì 。' WHERE chinese='批' AND pinyin='pī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='승인하다, 허가하다', example_zh='他的申请终于被批准了，可以正式开始项目了。', example_ko='그의 신청이 드디어 승인됐어, 공식적으로 프로젝트를 시작할 수 있어.', example_pinyin='tā de shēn qǐng zhōng yú bèi pī zhǔn le ， kě yǐ zhèng shì kāi shǐ xiàng mù le 。' WHERE chinese='批准' AND pinyin='pī zhǔn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='피로하다, 지치다', example_zh='工作了一整天，他感到非常疲劳，需要好好休息。', example_ko='하루 종일 일해서 그는 매우 피로해서 잘 쉬어야 해.', example_pinyin='gōng zuò le yī zhěng tiān ， tā gǎn dào fēi cháng pí láo ， xū yào hǎo hǎo xiū xī 。' WHERE chinese='疲劳' AND pinyin='pí láo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가죽 구두', example_zh='他穿着一双锃亮的皮鞋去参加面试，显得很精神。', example_ko='그는 반짝반짝한 가죽 구두를 신고 면접에 갔는데 매우 단정해 보였어.', example_pinyin='tā chuān zhe yī shuāng zèng liàng de pí xié qù cān jiā miàn shì ， xiǎn de hěn jīng shén 。' WHERE chinese='皮鞋' AND pinyin='pí xié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='필 (양사, 말을 세는 단위)', example_zh='农场里有三匹马，平时用来耕地。', example_ko='농장에 말이 세 필 있어서 평소에 밭을 가는 데 써.', example_pinyin='nóng chǎng lǐ yǒu sān pǐ mǎ ， píng shí yòng lái gēng dì 。' WHERE chinese='匹' AND pinyin='pǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='편, 장 (양사)', example_zh='这部电影一共有三片，每片大概90分钟。', example_ko='이 영화는 총 세 편인데 각 편이 약 90분이야.', example_pinyin='zhè bù diàn yǐng yī gòng yǒu sān piàn ， měi piàn dà gài 90 fēn zhōng 。' WHERE chinese='片' AND pinyin='piàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='편파적이다, 일방적이다', example_zh='看问题不能片面，要从多个角度综合考虑。', example_ko='문제를 볼 때 편파적이면 안 돼, 여러 각도에서 종합적으로 고려해야 해.', example_pinyin='kàn wèn tí bù néng piàn miàn ， yào cóng duō gè jiǎo dù zōng hé kǎo lǜ 。' WHERE chinese='片面' AND pinyin='piàn miàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='날리다, 떠다니다', example_zh='风一吹，树上的花瓣飘落下来，非常美丽。', example_ko='바람이 불자 나무의 꽃잎이 날려 떨어져서 매우 아름다워.', example_pinyin='fēng yī chuī ， shù shàng de huā bàn piāo luò xià lái ， fēi cháng měi lì 。' WHERE chinese='飘' AND pinyin='piāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='채널', example_zh='他把电视换到了新闻频道，想了解一下最新动态。', example_ko='그는 TV를 뉴스 채널로 돌려서 최신 동향을 알고 싶었어.', example_pinyin='tā bǎ diàn shì huàn dào le xīn wén pín dào ， xiǎng liǎo jiě yī xià zuì xīn dòng tài 。' WHERE chinese='频道' AND pinyin='pín dào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='품종, 품목', example_zh='这家花店的花品种很多，颜色各异，非常好看。', example_ko='이 꽃집의 꽃은 품종이 많고 색깔이 다양해서 매우 예뻐.', example_pinyin='zhè jiā huā diàn de huā pǐn zhǒng hěn duō ， yán sè gè yì ， fēi cháng hǎo kàn 。' WHERE chinese='品种' AND pinyin='pǐn zhǒng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~에 의거하다, ~을 근거로', example_zh='凭他的实力，这次考试一定能考得很好。', example_ko='그의 실력에 의거하면 이번 시험을 반드시 잘 볼 수 있어.', example_pinyin='píng tā de shí lì ， zhè cì kǎo shì yí dìng néng kǎo dé hěn hǎo 。' WHERE chinese='凭' AND pinyin='píng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평평하다; 수평', example_zh='这条路不太平，有很多坑，开车要小心。', example_ko='이 길은 그다지 평평하지 않아서 구멍이 많아, 운전할 때 조심해야 해.', example_pinyin='zhè tiáo lù bù tài píng ， yǒu hěn duō kēng ， kāi chē yào xiǎo xīn 。' WHERE chinese='平' AND pinyin='píng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평소, 보통', example_zh='她平常不爱说话，但一旦开口就很有见地。', example_ko='그녀는 평소에 말하기를 즐기지 않지만 한번 입을 열면 매우 견식이 있어.', example_pinyin='tā píng cháng bù ài shuō huà ， dàn yí dàn kāi kǒu jiù hěn yǒu jiàn dì 。' WHERE chinese='平常' AND pinyin='píng cháng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평등하다', example_zh='法律面前人人平等，任何人都没有特权。', example_ko='법 앞에 모든 사람은 평등해서 누구도 특권이 없어.', example_pinyin='fǎ lǜ miàn qián rén rén píng děng ， rèn hé rén dōu méi yǒu tè quán 。' WHERE chinese='平等' AND pinyin='píng děng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평방, 제곱', example_zh='这套公寓面积是90平方米，对于三口之家来说刚好合适。', example_ko='이 아파트 면적은 90제곱미터야, 세 식구에게는 딱 적당해.', example_pinyin='zhè tào gōng yù miàn jī shì 90 píng fāng mǐ ， duì yú sān kǒu zhī jiā lái shuō gāng hǎo hé shì 。' WHERE chinese='平方' AND pinyin='píng fāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='균형', example_zh='他注重工作与生活的平衡，不让自己太过劳累。', example_ko='그는 업무와 생활의 균형을 중시해서 너무 지치지 않게 해.', example_pinyin='tā zhù zhòng gōng zuò yǔ shēng huó de píng héng ， bù ràng zì jǐ tài guò láo lèi 。' WHERE chinese='平衡' AND pinyin='píng héng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조용하다, 평온하다', example_zh='他深呼吸，让自己平静下来，再重新思考问题。', example_ko='그는 심호흡을 해서 자신을 진정시키고 다시 문제를 생각했어.', example_pinyin='tā shēn hū xī ， ràng zì jǐ píng jìng xià lái ， zài chóng xīn sī kǎo wèn tí 。' WHERE chinese='平静' AND pinyin='píng jìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평균', example_zh='班级的平均分是75分，他的成绩比平均分高出10分。', example_ko='반 평균 점수는 75점이야, 그의 성적은 평균보다 10점 높아.', example_pinyin='bān jí de píng jūn fēn shì 75 fēn ， tā de chéng jì bǐ píng jūn fēn gāo chū 10 fēn 。' WHERE chinese='平均' AND pinyin='píng jūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평가하다; 평가', example_zh='老师对他的表现给予了很高的评价。', example_ko='선생님은 그의 활약에 높은 평가를 내렸어.', example_pinyin='lǎo shī duì tā de biǎo xiàn jǐ yǔ le hěn gāo de píng jià 。' WHERE chinese='评价' AND pinyin='píng jià' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='파산하다', example_zh='因为经营不善，那家公司最终宣告破产。', example_ko='경영이 잘못되어 그 회사는 결국 파산을 선언했어.', example_pinyin='yīn wèi jīng yíng bù shàn ， nà jiā gōng sī zuì zhōng xuān gào pò chǎn 。' WHERE chinese='破产' AND pinyin='pò chǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='파괴하다, 훼손하다', example_zh='不能随意破坏公共设施，这是每个公民应有的素质。', example_ko='공공시설을 함부로 파괴해서는 안 돼, 이것은 모든 시민이 갖춰야 할 소양이야.', example_pinyin='bù néng suí yì pò huài gōng gòng shè shī ， zhè shì měi gè gōng mín yīng yǒu de sù zhì 。' WHERE chinese='破坏' AND pinyin='pò huài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='절박하다, 시급하다', example_zh='他迫切地希望找到一份稳定的工作，尽快独立生活。', example_ko='그는 안정적인 직장을 하루빨리 찾아서 빨리 독립하기를 절박하게 원해.', example_pinyin='tā pò qiè dì xī wàng zhǎo dào yī fèn wěn dìng de gōng zuò ， jǐn kuài dú lì shēng huó 。' WHERE chinese='迫切' AND pinyin='pò qiè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소박하다, 검소하다', example_zh='她穿着朴素，不追求名牌，但总是干净整洁。', example_ko='그녀는 차림새가 소박해서 명품을 추구하지 않지만 항상 깔끔하고 단정해.', example_pinyin='tā chuān zhe pǔ sù ， bù zhuī qiú míng pái ， dàn zǒng shì gān jìng zhěng jié 。' WHERE chinese='朴素' AND pinyin='pǔ sù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기대하다, 기다리다', example_zh='他满怀期待地等着结果，希望能有好消息传来。', example_ko='그는 기대를 품고 결과를 기다리며 좋은 소식이 오기를 바랐어.', example_pinyin='tā mǎn huái qī dài dì děng zhe jié guǒ ， xī wàng néng yǒu hǎo xiāo xī chuán lái 。' WHERE chinese='期待' AND pinyin='qī dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기간, 기간 중', example_zh='在学习期间，他结交了很多来自不同国家的朋友。', example_ko='공부하는 기간 동안 그는 다양한 나라에서 온 친구들을 많이 사귀었어.', example_pinyin='zài xué xí qī jiān ， tā jié jiāo le hěn duō lái zì bù tóng guó jiā de péng yǒu 。' WHERE chinese='期间' AND pinyin='qī jiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그 나머지', example_zh='主菜已经准备好了，其余的小菜等一下就好。', example_ko='메인 요리는 이미 준비됐어, 나머지 반찬은 잠깐 있으면 돼.', example_pinyin='zhǔ cài yǐ jīng zhǔn bèi hǎo le ， qí yú de xiǎo cài děng yí xià jiù hǎo 。' WHERE chinese='其余' AND pinyin='qí yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기적', example_zh='医生说他的康复简直是一个奇迹，大家都很惊喜。', example_ko='의사가 그의 회복이 정말 기적이라고 했어, 모두 매우 놀라워했어.', example_pinyin='yī shēng shuō tā de kāng fù jiǎn zhí shì yí gè qí jì ， dà jiā dōu hěn jīng xǐ 。' WHERE chinese='奇迹' AND pinyin='qí jì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영감을 주다, 계발하다', example_zh='这本书启发了他，让他重新思考自己的人生方向。', example_ko='이 책은 그에게 영감을 주어서 인생의 방향을 다시 생각하게 했어.', example_pinyin='zhè běn shū qǐ fā le tā ， ràng tā chóng xīn sī kǎo zì jǐ de rén shēng fāng xiàng 。' WHERE chinese='启发' AND pinyin='qǐ fā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='획책하다, 기도하다', example_zh='他企图逃避责任，但事实证明是他的过错。', example_ko='그는 책임을 회피하려 했지만 사실이 그의 잘못임을 증명했어.', example_pinyin='tā qǐ tú táo bì zé rèn ， dàn shì shí zhèng míng shì tā de guò cuò 。' WHERE chinese='企图' AND pinyin='qǐ tú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기업', example_zh='这家企业在全国有几十个分支机构，规模很大。', example_ko='이 기업은 전국에 수십 개의 지사가 있어서 규모가 매우 커.', example_pinyin='zhè jiā qǐ yè zài quán guó yǒu jǐ shí gè fēn zhī jī gòu ， guī mó hěn dà 。' WHERE chinese='企业' AND pinyin='qǐ yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='분위기', example_zh='今天的聚会气氛很热烈，大家都玩得很开心。', example_ko='오늘 모임의 분위기가 매우 활기찼어, 모두 즐겁게 놀았어.', example_pinyin='jīn tiān de jù huì qì fēn hěn rè liè ， dà jiā dōu wán dé hěn kāi xīn 。' WHERE chinese='气氛' AND pinyin='qì fēn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='휘발유, 가솔린', example_zh='油箱快没油了，需要去加油站加油了。', example_ko='연료 탱크 기름이 거의 떨어졌어, 주유소에 가서 기름을 넣어야 해.', example_pinyin='yóu xiāng kuài méi yóu le ， xū yào qù jiā yóu zhàn jiā yóu le 。' WHERE chinese='汽油' AND pinyin='qì yóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='끌다, 잡아당기다', example_zh='她牵着小孩的手过马路，确保孩子的安全。', example_ko='그녀는 아이의 손을 잡고 횡단보도를 건너서 아이의 안전을 확보했어.', example_pinyin='tā qiān zhe xiǎo hái de shǒu guò mǎ lù ， què bǎo hái zi de ān quán 。' WHERE chinese='牵' AND pinyin='qiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서명하다', example_zh='合同签字之前，请仔细阅读所有条款。', example_ko='계약서에 서명하기 전에 모든 조항을 꼼꼼히 읽어주세요.', example_pinyin='hé tóng qiān zì zhī qián ， qǐng zǐ xì yuè dú suǒ yǒu tiáo kuǎn 。' WHERE chinese='签字' AND pinyin='qiān zì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='겸손하다', example_zh='他虽然取得了很大的成功，但为人依然谦虚，从不自大。', example_ko='그는 큰 성공을 거뒀지만 여전히 겸손하고 결코 자만하지 않아.', example_pinyin='tā suī rán qǔ dé le hěn dà de chéng gōng ， dàn wéi rén yī rán qiān xū ， cóng bù zì dà 。' WHERE chinese='谦虚' AND pinyin='qiān xū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='앞길, 전망', example_zh='他的前途一片光明，大家都看好他的未来。', example_ko='그의 앞길은 밝아서 다들 그의 미래를 긍정적으로 봐.', example_pinyin='tā de qián tú yī piàn guāng míng ， dà jiā dōu kàn hǎo tā de wèi lái 。' WHERE chinese='前途' AND pinyin='qián tú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='얕다; 연하다', example_zh='这条河水很浅，站在水里只到膝盖。', example_ko='이 강은 물이 얕아서 물속에 서면 무릎까지밖에 안 와.', example_pinyin='zhè tiáo hé shuǐ hěn qiǎn ， zhàn zài shuǐ lǐ zhǐ dào xī gài 。' WHERE chinese='浅' AND pinyin='qiǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='빚지다, 모자라다', example_zh='他还欠着银行一笔贷款，每个月要还款。', example_ko='그는 아직 은행에 대출금을 빚지고 있어서 매달 상환해야 해.', example_pinyin='tā hái qiàn zhe yín háng yī bǐ dài kuǎn ， měi gè yuè yào hái kuǎn 。' WHERE chinese='欠' AND pinyin='qiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='총, 소총', example_zh='士兵们端着枪，严守着边境线。', example_ko='병사들은 총을 들고 국경선을 엄중하게 지키고 있어.', example_pinyin='shì bīng men duān zhe qiāng ， yán shǒu zhuó biān jìng xiàn 。' WHERE chinese='枪' AND pinyin='qiāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='강조하다', example_zh='老师一再强调基础知识的重要性，让学生打好基础。', example_ko='선생님은 기초 지식의 중요성을 거듭 강조하며 학생들이 기초를 잘 다지게 했어.', example_pinyin='lǎo shī yī zài qiáng diào jī chǔ zhī shí de zhòng yào xìng ， ràng xué shēng dǎ hǎo jī chǔ 。' WHERE chinese='强调' AND pinyin='qiáng diào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='강렬하다, 격렬하다', example_zh='他对音乐有强烈的热爱，每天练习好几个小时。', example_ko='그는 음악에 대한 강렬한 열정이 있어서 매일 몇 시간씩 연습해.', example_pinyin='tā duì yīn yuè yǒu qiáng liè de rè ài ， měi tiān liàn xí hǎo jǐ gè xiǎo shí 。' WHERE chinese='强烈' AND pinyin='qiáng liè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='빼앗다, 서둘러 하다', example_zh='他不顾危险，奋力从火场里抢出了重要文件。', example_ko='그는 위험을 무릅쓰고 화재 현장에서 중요한 서류를 빼냈어.', example_pinyin='tā bù gù wēi xiǎn ， fèn lì cóng huǒ chǎng lǐ qiǎng chū le zhòng yào wén jiàn 。' WHERE chinese='抢' AND pinyin='qiǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='살그머니, 조용히', example_zh='他悄悄地打开门，不想吵醒睡觉的孩子。', example_ko='그는 살그머니 문을 열어서 자고 있는 아이를 깨우고 싶지 않았어.', example_pinyin='tā qiāo qiāo dì dǎ kāi mén ， bù xiǎng chǎo xǐng shuì jiào de hái zi 。' WHERE chinese='悄悄' AND pinyin='qiāo qiāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보다, 쳐다보다', example_zh='她悄悄地瞧了他一眼，然后把头转开了。', example_ko='그녀는 살짝 그를 쳐다보고 나서 고개를 돌렸어.', example_pinyin='tā qiāo qiāo dì qiáo le tā yī yǎn ， rán hòu bǎ tóu zhuǎn kāi le 。' WHERE chinese='瞧' AND pinyin='qiáo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='교묘하다, 솜씨 좋다', example_zh='他处理这件事的方式非常巧妙，双方都很满意。', example_ko='그가 이 일을 처리하는 방식이 매우 교묘해서 양쪽 모두 만족해.', example_pinyin='tā chǔ lǐ zhè jiàn shì de fāng shì fēi cháng qiǎo miào ， shuāng fāng dōu hěn mǎn yì 。' WHERE chinese='巧妙' AND pinyin='qiǎo miào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자르다, 깎다', example_zh='她把蔬菜切成小块，然后放入锅中翻炒。', example_ko='그녀는 채소를 작게 잘라서 냄비에 넣고 볶았어.', example_pinyin='tā bǎ shū cài qiè chéng xiǎo kuài ， rán hòu fàng rù guō zhōng fān chǎo 。' WHERE chinese='切' AND pinyin='qiē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='친애하는', example_zh='亲爱的朋友们，感谢你们今天的到来，让我们一起庆祝。', example_ko='친애하는 친구들, 오늘 와주셔서 감사해요, 함께 축하합시다.', example_pinyin='qīn ài de péng yǒu men ， gǎn xiè nǐ men jīn tiān de dào lái ， ràng wǒ men yì qǐ qìng zhù 。' WHERE chinese='亲爱' AND pinyin='qīn ài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='친절하다, 따뜻하다', example_zh='她对客人非常亲切，让每个人都感到宾至如归。', example_ko='그녀는 손님에게 매우 친절해서 모든 사람이 집처럼 편안하게 느껴.', example_pinyin='tā duì kè rén fēi cháng qīn qiè ， ràng měi gè rén dōu gǎn dào bīn zhì rú guī 。' WHERE chinese='亲切' AND pinyin='qīn qiè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='직접, 몸소', example_zh='领导亲自来看望受伤的员工，表示了对他的关心。', example_ko='리더가 직접 다친 직원을 문병해서 관심을 표했어.', example_pinyin='lǐng dǎo qīn zì lái kàn wàng shòu shāng de yuán gōng ， biǎo shì le duì tā de guān xīn 。' WHERE chinese='亲自' AND pinyin='qīn zì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='침략하다; 침략', example_zh='历史上，侵略战争给人民带来了无尽的苦难。', example_ko='역사상 침략 전쟁은 인민에게 끝없는 고통을 가져다줬어.', example_pinyin='lì shǐ shàng ， qīn lüè zhàn zhēng gěi rén mín dài lái liǎo wú jǐn de kǔ nàn 。' WHERE chinese='侵略' AND pinyin='qīn lvè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부지런하다', example_zh='他学习非常勤奋，每天都要复习到深夜。', example_ko='그는 공부를 매우 부지런히 해서 매일 밤늦게까지 복습해.', example_pinyin='tā xué xí fēi cháng qín fèn ， měi tiān dōu yào fù xí dào shēn yè 。' WHERE chinese='勤奋' AND pinyin='qín fèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부지런하다, 근면하다', example_zh='中国人以勤劳著称，在世界各地都有出色的表现。', example_ko='중국 사람들은 근면함으로 유명해서 전 세계에서 뛰어난 면모를 보여.', example_pinyin='zhōng guó rén yǐ qín láo zhù chēng ， zài shì jiè gè dì dōu yǒu chū sè de biǎo xiàn 。' WHERE chinese='勤劳' AND pinyin='qín láo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='청색; 채소', example_zh='天空一片青，云一朵朵，令人心旷神怡。', example_ko='하늘이 청색으로 물들고 구름이 한 덩이씩 있어서 마음이 탁 트여.', example_pinyin='tiān kōng yī piàn qīng ， yún yī duǒ duǒ ， lìng rén xīn kuàng shén yí 。' WHERE chinese='青' AND pinyin='qīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='청춘, 젊음', example_zh='青春是人生中最美好的时光，要好好珍惜。', example_ko='청춘은 인생에서 가장 아름다운 시간이야, 소중히 여겨야 해.', example_pinyin='qīng chūn shì rén shēng zhōng zuì měi hǎo de shí guāng ， yào hǎo hǎo zhēn xī 。' WHERE chinese='青春' AND pinyin='qīng chūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='청소년', example_zh='青少年是国家的未来，社会应该为他们提供良好的成长环境。', example_ko='청소년은 나라의 미래야, 사회는 그들에게 좋은 성장 환경을 제공해야 해.', example_pinyin='qīng shào nián shì guó jiā de wèi lái ， shè huì yīng gāi wèi tā men tí gōng liáng hǎo de chéng zhǎng huán jìng 。' WHERE chinese='青少年' AND pinyin='qīng shào nián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가볍게 여기다, 무시하다', example_zh='不要轻视别人，每个人都有值得尊重的地方。', example_ko='남을 무시하지 마, 모든 사람에게는 존중받을 만한 면이 있어.', example_pinyin='bú yào qīng shì bié rén ， měi gè rén dōu yǒu zhí de zūn zhòng de dì fāng 。' WHERE chinese='轻视' AND pinyin='qīng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='담백하다, 기름기 없다', example_zh='生病后医生建议吃清淡的食物，少油少盐。', example_ko='아프고 나서 의사가 기름기 없는 음식을 먹으라고 권유했어, 기름도 소금도 적게.', example_pinyin='shēng bìng hòu yī shēng jiàn yì chī qīng dàn de shí wù ， shǎo yóu shǎo yán 。' WHERE chinese='清淡' AND pinyin='qīng dàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정경, 장면', example_zh='看到那幅温馨的家庭情景，他心里涌起了思乡之情。', example_ko='그 따뜻한 가정의 정경을 보자 그의 마음에 고향에 대한 그리움이 솟아났어.', example_pinyin='kàn dào nà fú wēn xīn de jiā tíng qíng jǐng ， tā xīn lǐ yǒng qǐ le sī xiāng zhī qíng 。' WHERE chinese='情景' AND pinyin='qíng jǐng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감정, 기분', example_zh='她情绪不太稳定，时好时坏，需要多关心一下。', example_ko='그녀는 감정이 그다지 안정적이지 않아서 좋았다가 나빴다가 해서 더 신경 써줘야 해.', example_pinyin='tā qíng xù bù tài wěn dìng ， shí hǎo shí huài ， xū yào duō guān xīn yī xià 。' WHERE chinese='情绪' AND pinyin='qíng xù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='요청하다; 요청', example_zh='他向老师请求延期提交作业，老师同意了。', example_ko='그는 선생님에게 과제 제출 연기를 요청했더니 선생님이 동의했어.', example_pinyin='tā xiàng lǎo shī qǐng qiú yán qī tí jiāo zuò yè ， lǎo shī tóng yì le 。' WHERE chinese='请求' AND pinyin='qǐng qiú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='축하하다', example_zh='大家聚在一起庆祝他的生日，气氛非常热闹。', example_ko='다들 모여서 그의 생일을 축하했는데 분위기가 매우 시끌벅적했어.', example_pinyin='dà jiā jù zài yì qǐ qìng zhù tā de shēng rì ， qì fēn fēi cháng rè nào 。' WHERE chinese='庆祝' AND pinyin='qìng zhù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='(스포츠) 팬', example_zh='他是一名铁杆球迷，无论多忙都不会错过比赛直播。', example_ko='그는 열혈 팬이어서 아무리 바빠도 경기 생방송을 놓치지 않아.', example_pinyin='tā shì yī míng tiě gǎn qiú mí ， wú lùn duō máng dōu bú huì cuò guò bǐ sài zhí bō 。' WHERE chinese='球迷' AND pinyin='qiú mí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='추세, 트렌드', example_zh='现在健康饮食成为一种趋势，越来越多的人开始注重营养。', example_ko='지금 건강식이 하나의 트렌드가 되어서 점점 더 많은 사람들이 영양을 중시하기 시작했어.', example_pinyin='xiàn zài jiàn kāng yǐn shí chéng wéi yī zhǒng qū shì ， yuè lái yuè duō de rén kāi shǐ zhù zhòng yíng yǎng 。' WHERE chinese='趋势' AND pinyin='qū shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='장가들다 (남성이 결혼)', example_zh='他在30岁时娶了一位善良的女孩，婚后生活幸福美满。', example_ko='그는 30살에 착한 여성과 결혼했는데 결혼 후 행복하고 풍요로운 생활을 하고 있어.', example_pinyin='tā zài 30 suì shí qǔ le yī wèi shàn liáng de nǚ hái ， hūn hòu shēng huó xìng fú měi mǎn 。' WHERE chinese='娶' AND pinyin='qǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='취소하다', example_zh='因为天气原因，这次户外活动被取消了。', example_ko='날씨 때문에 이번 야외 활동이 취소됐어.', example_pinyin='yīn wèi tiān qì yuán yīn ， zhè cì hù wài huó dòng bèi qǔ xiāo le 。' WHERE chinese='取消' AND pinyin='qǔ xiāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='돌아가시다, 세상을 뜨다', example_zh='他的爷爷昨天去世了，享年90岁，家人都很悲痛。', example_ko='그의 할아버지가 어제 돌아가셨어, 향년 90세야, 가족들 모두 슬퍼해.', example_pinyin='tā de yé yé zuó tiān qù shì le ， xiǎng nián 90 suì ， jiā rén dōu hěn bēi tòng 。' WHERE chinese='去世' AND pinyin='qù shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='원, 권; 그룹', example_zh='小朋友们围成一个圈，一起做游戏，玩得很开心。', example_ko='아이들이 원을 만들어 함께 게임을 하면서 즐겁게 놀았어.', example_pinyin='xiǎo péng yǒu men wéi chéng yí gè quān ， yì qǐ zuò yóu xì ， wán dé hěn kāi xīn 。' WHERE chinese='圈' AND pinyin='quān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전면적이다, 포괄적이다', example_zh='要全面了解一个问题，就要从多个角度来看。', example_ko='한 문제를 전면적으로 이해하려면 여러 각도에서 봐야 해.', example_pinyin='yào quán miàn liǎo jiě yí gè wèn tí ， jiù yào cóng duō gè jiǎo dù lái kàn 。' WHERE chinese='全面' AND pinyin='quán miàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='권력', example_zh='权力需要受到监督，不能被滥用。', example_ko='권력은 감독을 받아야 해서 남용될 수 없어.', example_pinyin='quán lì xū yào shòu dào jiān dū ， bù néng bèi làn yòng 。' WHERE chinese='权力' AND pinyin='quán lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='권리', example_zh='每个公民都有受教育的权利，这是法律保障的基本权益。', example_ko='모든 시민은 교육받을 권리가 있어서 법으로 보장된 기본 권익이야.', example_pinyin='měi gè gōng mín dōu yǒu shòu jiào yù de quán lì ， zhè shì fǎ lǜ bǎo zhàng de jī běn quán yì 。' WHERE chinese='权利' AND pinyin='quán lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='권하다, 설득하다', example_zh='朋友劝他不要冲动，先冷静下来再做决定。', example_ko='친구가 그에게 충동적으로 굴지 말고 먼저 냉정해진 후 결정하라고 권했어.', example_pinyin='péng yǒu quàn tā bú yào chōng dòng ， xiān lěng jìng xià lái zài zuò jué dìng 。' WHERE chinese='劝' AND pinyin='quàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부족하다, 결핍되다', example_zh='由于缺乏沟通，两人之间产生了很多误解。', example_ko='소통이 부족해서 두 사람 사이에 오해가 많이 생겼어.', example_pinyin='yóu yú quē fá gōu tōng ， liǎng rén zhī jiān chǎn shēng le hěn duō wù jiě 。' WHERE chinese='缺乏' AND pinyin='quē fá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='확정하다, 결정하다', example_zh='会议时间已经确定了，就在下周三下午两点。', example_ko='회의 시간이 이미 확정됐어, 다음 주 수요일 오후 2시야.', example_pinyin='huì yì shí jiān yǐ jīng què dìng le ， jiù zài xià zhōu sān xià wǔ liǎng diǎn 。' WHERE chinese='确定' AND pinyin='què dìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='확인하다, 승인하다', example_zh='请再次确认您的订单信息，然后点击提交。', example_ko='주문 정보를 다시 한번 확인한 후 제출 버튼을 클릭해주세요.', example_pinyin='qǐng zài cì què rèn nín de dìng dān xìn xī ， rán hòu diǎn jī tí jiāo 。' WHERE chinese='确认' AND pinyin='què rèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연소하다, 타다', example_zh='木头在燃烧时会产生大量烟雾，影响空气质量。', example_ko='나무가 탈 때 많은 연기가 발생해서 공기 질에 영향을 줘.', example_pinyin='mù tou zài rán shāo shí huì chǎn shēng dà liàng yān wù ， yǐng xiǎng kōng qì zhì liàng 。' WHERE chinese='燃烧' AND pinyin='rán shāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소리치다, 고함치다', example_zh='他生气了，对着电话大声嚷嚷，把旁边的人都吓了一跳。', example_ko='그가 화가 나서 전화에 대고 소리를 질러서 옆에 있던 사람들을 모두 깜짝 놀라게 했어.', example_pinyin='tā shēng qì le ， duì zhe diàn huà dà shēng rāng rang ， bǎ páng biān de rén dōu xià le yī tiào 。' WHERE chinese='嚷' AND pinyin='rǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='돌아서 가다, 우회하다', example_zh='前方道路施工，请绕道而行，谢谢配合。', example_ko='전방 도로 공사 중이니 우회해서 가주세요, 협조해주셔서 감사합니다.', example_pinyin='qián fāng dào lù shī gōng ， qǐng rào dào ér xíng ， xiè xiè pèi hé 。' WHERE chinese='绕' AND pinyin='rào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='열렬히 사랑하다', example_zh='他热爱自己的工作，每天都充满激情地去上班。', example_ko='그는 자신의 일을 열렬히 사랑해서 매일 열정 가득하게 출근해.', example_pinyin='tā rè ài zì jǐ de gōng zuò ， měi tiān dōu chōng mǎn jī qíng dì qù shàng bān 。' WHERE chinese='热爱' AND pinyin='rè ài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='열렬하다', example_zh='现场观众热烈鼓掌，为精彩的表演表达了赞赏。', example_ko='현장 관중이 열렬히 박수를 쳐서 훌륭한 공연에 찬사를 표했어.', example_pinyin='xiàn chǎng guān zhòng rè liè gǔ zhǎng ， wèi jīng cǎi de biǎo yǎn biǎo dá le zàn shǎng 。' WHERE chinese='热烈' AND pinyin='rè liè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='열심히 하다, 적극적이다', example_zh='她为人热心，总是主动帮助需要帮助的人。', example_ko='그녀는 사람이 적극적이어서 항상 도움이 필요한 사람을 먼저 도와.', example_pinyin='tā wéi rén rè xīn ， zǒng shì zhǔ dòng bāng zhù xū yào bāng zhù de rén 。' WHERE chinese='热心' AND pinyin='rè xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인재, 능력자', example_zh='公司广纳人才，希望吸引更多优秀的年轻人加入。', example_ko='회사는 인재를 널리 모집해서 더 많은 우수한 젊은이를 유치하고 싶어해.', example_pinyin='gōng sī guǎng nà rén cái ， xī wàng xī yǐn gèng duō yōu xiù de nián qīng rén jiā rù 。' WHERE chinese='人才' AND pinyin='rén cái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인구', example_zh='中国的人口众多，城市化进程加快了城市的发展。', example_ko='중국은 인구가 많아서 도시화 진행이 도시의 발전을 가속화했어.', example_pinyin='zhōng guó de rén kǒu zhòng duō ， chéng shì huà jìn chéng jiā kuài le chéng shì de fā zhǎn 。' WHERE chinese='人口' AND pinyin='rén kǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인류', example_zh='科技的发展推动了人类社会的进步，改善了生活质量。', example_ko='과학기술의 발전은 인류 사회의 진보를 촉진해서 생활 수준을 개선했어.', example_pinyin='kē jì de fā zhǎn tuī dòng le rén lèi shè huì de jìn bù ， gǎi shàn le shēng huó zhì liàng 。' WHERE chinese='人类' AND pinyin='rén lèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인생', example_zh='人生中总会遇到困难，重要的是保持积极的心态去面对。', example_ko='인생에서 항상 어려움을 만나게 돼, 중요한 건 긍정적인 마음을 유지하며 마주하는 거야.', example_pinyin='rén shēng zhōng zǒng huì yù dào kùn nán ， zhòng yào de shì bǎo chí jī jí de xīn tài qù miàn duì 。' WHERE chinese='人生' AND pinyin='rén shēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인사, 인재 관리', example_zh='公司的人事部门负责招聘和员工培训工作。', example_ko='회사의 인사 부서는 채용과 직원 교육 업무를 담당하고 있어.', example_pinyin='gōng sī de rén shì bù mén fù zé zhāo pìn hé yuán gōng péi xùn gōng zuò 。' WHERE chinese='人事' AND pinyin='rén shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인물, 캐릭터', example_zh='这部小说里的人物性格鲜明，给读者留下了深刻印象。', example_ko='이 소설 속 인물의 성격이 뚜렷해서 독자들에게 깊은 인상을 남겼어.', example_pinyin='zhè bù xiǎo shuō lǐ de rén wù xìng gé xiān míng ， gěi dú zhě liú xià le shēn kè yìn xiàng 。' WHERE chinese='人物' AND pinyin='rén wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인원, 직원', example_zh='这次活动需要增加人员，请大家积极报名参与。', example_ko='이번 행사는 인원이 더 필요해서 모두 적극적으로 신청해주세요.', example_pinyin='zhè cì huó dòng xū yào zēng jiā rén yuán ， qǐng dà jiā jī jí bào míng cān yù 。' WHERE chinese='人员' AND pinyin='rén yuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='참을 수 없다', example_zh='他太想笑了，忍不住噗嗤一声笑出来了。', example_ko='그는 너무 웃고 싶어서 참을 수 없어서 픽 웃음이 터져버렸어.', example_pinyin='tā tài xiǎng xiào le ， rěn bú zhù pū chī yī shēng xiào chū lái le 。' WHERE chinese='忍不住' AND pinyin='rěn bu zhù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일상적인', example_zh='日常生活中，要养成良好的生活习惯，保持身体健康。', example_ko='일상생활에서 좋은 생활 습관을 길러서 건강을 유지해야 해.', example_pinyin='rì cháng shēng huó zhōng ， yào yǎng chéng liáng hǎo de shēng huó xí guàn ， bǎo chí shēn tǐ jiàn kāng 。' WHERE chinese='日常' AND pinyin='rì cháng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일정, 스케줄', example_zh='这周的日程安排得很满，每天都有不同的会议和活动。', example_ko='이번 주 일정이 매우 빽빽해서 매일 다른 회의와 활동이 있어.', example_pinyin='zhè zhōu de rì chéng ān pái dé hěn mǎn ， měi tiān dōu yǒu bù tóng de huì yì hé huó dòng 。' WHERE chinese='日程' AND pinyin='rì chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='달력', example_zh='他在日历上记下了重要的约会和截止日期。', example_ko='그는 달력에 중요한 약속과 마감일을 기록해뒀어.', example_pinyin='tā zài rì lì shàng jì xià le zhòng yào de yuē huì hé jié zhǐ rì qī 。' WHERE chinese='日历' AND pinyin='rì lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='날짜', example_zh='请在表格上填写今天的日期和您的姓名。', example_ko='양식에 오늘 날짜와 성함을 기입해주세요.', example_pinyin='qǐng zài biǎo gé shàng tián xiě jīn tiān de rì qī hé nín de xìng míng 。' WHERE chinese='日期' AND pinyin='rì qī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일용품', example_zh='超市里的日用品很齐全，生活所需一站式购买。', example_ko='슈퍼마켓에 일용품이 매우 잘 갖춰져 있어서 생활 필수품을 원스톱으로 살 수 있어.', example_pinyin='chāo shì lǐ de rì yòng pǐn hěn qí quán ， shēng huó suǒ xū yī zhàn shì gòu mǎi 。' WHERE chinese='日用品' AND pinyin='rì yòng pǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='녹다, 융화되다', example_zh='春天来了，山上的积雪开始融化，小溪里的水多了起来。', example_ko='봄이 왔어서 산 위의 눈이 녹기 시작하고 시냇물이 많아졌어.', example_pinyin='chūn tiān lái le ， shān shàng de jī xuě kāi shǐ róng huà ， xiǎo xī lǐ de shuǐ duō le qǐ lái 。' WHERE chinese='融化' AND pinyin='róng huà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영광스럽다', example_zh='能参加这次比赛，他感到非常荣幸。', example_ko='이번 대회에 참가할 수 있어서 그는 매우 영광스럽게 느꼈어.', example_pinyin='néng cān jiā zhè cì bǐ sài ， tā gǎn dào fēi cháng róng xìng 。' WHERE chinese='荣幸' AND pinyin='róng xìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영예, 명예', example_zh='他为公司带来了很多荣誉，是大家学习的榜样。', example_ko='그는 회사에 많은 영예를 가져다줘서 모두의 학습 모범이 됐어.', example_pinyin='tā wèi gōng sī dài lái le hěn duō róng yù ， shì dà jiā xué xí de bǎng yàng 。' WHERE chinese='荣誉' AND pinyin='róng yù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어떻게, 어떤', example_zh='你觉得如何才能改善目前的状况？有什么好建议？', example_ko='현재 상황을 어떻게 개선할 수 있다고 생각해? 좋은 건의가 있어?', example_pinyin='nǐ jué de rú hé cái néng gǎi shàn mù qián de zhuàng kuàng ？ yǒu shén me hǎo jiàn yì ？' WHERE chinese='如何' AND pinyin='rú hé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오늘날, 지금', example_zh='如今的科技发展速度令人惊叹，十年前无法想象的事情已经成真。', example_ko='오늘날 과학기술 발전 속도가 놀라울 정도야, 10년 전엔 상상할 수 없던 일이 현실이 됐어.', example_pinyin='rú jīn de kē jì fā zhǎn sù dù lìng rén jīng tàn ， shí nián qián wú fǎ xiǎng xiàng de shì qíng yǐ jīng chéng zhēn 。' WHERE chinese='如今' AND pinyin='rú jīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소프트웨어', example_zh='他在学习一门新的编程语言，用来开发手机软件。', example_ko='그는 새로운 프로그래밍 언어를 배우고 있어서 스마트폰 소프트웨어를 개발하는 데 써.', example_pinyin='tā zài xué xí yī mén xīn de biān chéng yǔ yán ， yòng lái kāi fā shǒu jī ruǎn jiàn 。' WHERE chinese='软件' AND pinyin='ruǎn jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='약하다', example_zh='他生病后身体很弱，需要好好休养，慢慢恢复。', example_ko='그는 아프고 나서 몸이 매우 약해서 잘 요양하며 천천히 회복해야 해.', example_pinyin='tā shēng bìng hòu shēn tǐ hěn ruò ， xū yào hǎo hǎo xiū yǎng ， màn màn huī fù 。' WHERE chinese='弱' AND pinyin='ruò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뿌리다, 흘리다', example_zh='他洒了一杯水在地板上，赶紧拿毛巾擦干。', example_ko='그는 컵에 있던 물을 바닥에 엎질러서 얼른 수건으로 닦았어.', example_pinyin='tā sǎ le yī bēi shuǐ zài dì bǎn shàng ， gǎn jǐn ná máo jīn cā gàn 。' WHERE chinese='洒' AND pinyin='sǎ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='목', example_zh='他唱了一晚上的歌，嗓子都哑了，需要好好休息。', example_ko='그는 밤새 노래를 불렀더니 목이 쉬어서 잘 쉬어야 해.', example_pinyin='tā chàng le yī wǎn shàng de gē ， sǎng zi dōu yǎ le ， xū yào hǎo hǎo xiū xī 。' WHERE chinese='嗓子' AND pinyin='sǎng zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='죽이다', example_zh='这部电影里，主人公杀死了大反派，结局令人满意。', example_ko='이 영화에서 주인공이 대악당을 죽여서 결말이 만족스러워.', example_pinyin='zhè bù diàn yǐng lǐ ， zhǔ rén gōng shā sǐ le dà fǎn pài ， jié jú lìng rén mǎn yì 。' WHERE chinese='杀' AND pinyin='shā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사막', example_zh='撒哈拉沙漠是世界上最大的沙漠，气候极端干燥。', example_ko='사하라 사막은 세계에서 가장 큰 사막이야, 기후가 극도로 건조해.', example_pinyin='sā hā lā shā mò shì shì jiè shàng zuì dà de shā mò ， qì hòu jí duān gān zào 。' WHERE chinese='沙漠' AND pinyin='shā mò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모래사장, 해변', example_zh='夏天在沙滩上晒太阳、游泳，是很多人的休闲方式。', example_ko='여름에 모래사장에서 일광욕하고 수영하는 건 많은 사람들의 여가 방식이야.', example_pinyin='xià tiān zài shā tān shàng shài tài yáng 、 yóu yǒng ， shì hěn duō rén de xiū xián fāng shì 。' WHERE chinese='沙滩' AND pinyin='shā tān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='바보다, 멍청하다', example_zh='他当时太傻了，被人骗了还以为对方是在帮他。', example_ko='그는 그때 너무 멍청해서 사기를 당하고도 상대방이 도와준다고 생각했어.', example_pinyin='tā dāng shí tài shǎ le ， bèi rén piàn le hái yǐ wéi duì fāng shì zài bāng tā 。' WHERE chinese='傻' AND pinyin='shǎ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='햇볕에 말리다, 쬐다', example_zh='洗完衣服后，她把衣服晒在阳台上，让太阳晒干。', example_ko='빨래를 다 하고 나서 그녀는 옷을 베란다에 널어서 햇볕에 말렸어.', example_pinyin='xǐ wán yī fú hòu ， tā bǎ yī fú shài zài yáng tái shàng ， ràng tài yáng shài gàn 。' WHERE chinese='晒' AND pinyin='shài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='삭제하다', example_zh='他误删了重要文件，幸好有备份，可以恢复。', example_ko='그는 실수로 중요한 파일을 삭제했는데 다행히 백업이 있어서 복구할 수 있어.', example_pinyin='tā wù shān le zhòng yào wén jiàn ， xìng hǎo yǒu bèi fèn ， kě yǐ huī fù 。' WHERE chinese='删除' AND pinyin='shān chú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='번개', example_zh='打雷闪电，孩子们都躲进了屋子里，非常害怕。', example_ko='천둥 번개가 치자 아이들이 모두 집 안으로 숨었어, 매우 무서워했어.', example_pinyin='dǎ léi shǎn diàn ， hái zi men dōu duǒ jìn le wū zi lǐ ， fēi cháng hài pà 。' WHERE chinese='闪电' AND pinyin='shǎn diàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='착하다, 선량하다', example_zh='她是一个善良的人，从不计较别人的过错。', example_ko='그녀는 착한 사람이어서 다른 사람의 잘못을 따지지 않아.', example_pinyin='tā shì yí gè shàn liáng de rén ， cóng bù jì jiào bié rén de guò cuò 。' WHERE chinese='善良' AND pinyin='shàn liáng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~를 잘하다, 능하다', example_zh='他善于表达，无论什么事情都能清楚地解释给别人听。', example_ko='그는 표현을 잘해서 무슨 일이든 명확하게 설명할 수 있어.', example_pinyin='tā shàn yú biǎo dá ， wú lùn shén me shì qíng dōu néng qīng chǔ dì jiě shì gěi bié rén tīng 。' WHERE chinese='善于' AND pinyin='shàn yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부채', example_zh='夏天她喜欢用扇子扇风，觉得比空调更自然。', example_ko='여름에 그녀는 부채로 바람을 부치는 걸 좋아하는데 에어컨보다 더 자연스럽게 느껴.', example_pinyin='xià tiān tā xǐ huān yòng shàn zi shān fēng ， jué de bǐ kōng tiáo gèng zì rán 。' WHERE chinese='扇子' AND pinyin='shān zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상품', example_zh='这家商店的商品种类繁多，价格也很实惠。', example_ko='이 가게의 상품 종류가 매우 많고 가격도 실속 있어.', example_pinyin='zhè jiā shāng diàn de shāng pǐn zhǒng lèi fán duō ， jià gé yě hěn shí huì 。' WHERE chinese='商品' AND pinyin='shāng pǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상업, 비즈니스', example_zh='随着互联网的发展，网络商业模式越来越多样化。', example_ko='인터넷의 발전에 따라 인터넷 상업 모델이 점점 다양해지고 있어.', example_pinyin='suí zhe hù lián wǎng de fā zhǎn ， wǎng luò shāng yè mó shì yuè lái yuè duō yàng huà 。' WHERE chinese='商业' AND pinyin='shāng yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='속다, 당하다', example_zh='他在网上买东西上当了，付了钱却没收到货。', example_ko='그는 인터넷에서 물건을 사다가 속았어, 돈을 냈는데 물건을 못 받았어.', example_pinyin='tā zài wǎng shàng mǎi dōng xī shàng dàng le ， fù le qián què mò shōu dào huò 。' WHERE chinese='上当' AND pinyin='shàng dàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='국자', example_zh='她用勺子把汤盛到碗里，端给了老人。', example_ko='그녀는 국자로 국을 그릇에 퍼서 노인에게 가져다줬어.', example_pinyin='tā yòng sháo zi bǎ tāng shèng dào wǎn lǐ ， duān gěi le lǎo rén 。' WHERE chinese='勺子' AND pinyin='sháo zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뱀', example_zh='在野外遇到蛇时，要保持冷静，慢慢退开。', example_ko='야외에서 뱀을 만나면 침착하게 천천히 물러나야 해.', example_pinyin='zài yě wài yù dào shé shí ， yào bǎo chí lěng jìng ， màn màn tuì kāi 。' WHERE chinese='蛇' AND pinyin='shé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='혀', example_zh='他不小心咬到了舌头，痛了好一会儿。', example_ko='그는 실수로 혀를 깨물어서 한동안 아팠어.', example_pinyin='tā bù xiǎo xīn yǎo dào le shé tou ， tòng le hǎo yī huì er 。' WHERE chinese='舌头' AND pinyin='shé tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아깝다, 내키지 않다', example_zh='他舍不得扔掉那件旧外套，虽然已经穿了很多年了。', example_ko='그는 그 낡은 외투를 버리기 아까워서 오래 입었는데도 버리지 못해.', example_pinyin='tā shě bù dé rēng diào nà jiàn jiù wài tào ， suī rán yǐ jīng chuān le hěn duō nián le 。' WHERE chinese='舍不得' AND pinyin='shě bu de' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='설비, 장비', example_zh='这家医院的医疗设备非常先进，吸引了很多患者。', example_ko='이 병원의 의료 설비가 매우 첨단이어서 많은 환자를 유치해.', example_pinyin='zhè jiā yī yuàn de yī liáo shè bèi fēi cháng xiān jìn ， xī yǐn le hěn duō huàn zhě 。' WHERE chinese='设备' AND pinyin='shè bèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='설계하다; 설계', example_zh='这栋建筑由著名建筑师设计，融合了传统与现代风格。', example_ko='이 건물은 유명 건축가가 설계했어, 전통과 현대 스타일이 융합됐어.', example_pinyin='zhè dòng jiàn zhù yóu zhù míng jiàn zhù shī shè jì ， róng hé le chuán tǒng yǔ xiàn dài fēng gé 。' WHERE chinese='设计' AND pinyin='shè jì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시설', example_zh='这所学校的教学设施很完善，学生们学习条件很好。', example_ko='이 학교의 교육 시설이 매우 잘 갖춰져 있어서 학생들의 학습 환경이 좋아.', example_pinyin='zhè suǒ xué xiào de jiào xué shè shī hěn wán shàn ， xué shēng men xué xí tiáo jiàn hěn hǎo 。' WHERE chinese='设施' AND pinyin='shè shī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사격하다; 사격', example_zh='他参加了射击比赛，成绩非常优秀，获得了金牌。', example_ko='그는 사격 대회에 참가했는데 성적이 매우 우수해서 금메달을 획득했어.', example_pinyin='tā cān jiā le shè jī bǐ sài ， chéng jì fēi cháng yōu xiù ， huò dé le jīn pái 。' WHERE chinese='射击' AND pinyin='shè jī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사진을 찍다', example_zh='他爱好摄影，喜欢用相机记录生活中的美好瞬间。', example_ko='그는 사진 찍기를 즐겨해서 카메라로 삶의 아름다운 순간을 기록하는 걸 좋아해.', example_pinyin='tā ài hào shè yǐng ， xǐ huān yòng xiàng jī jì lù shēng huó zhōng de měi hǎo shùn jiān 。' WHERE chinese='摄影' AND pinyin='shè yǐng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뻗다, 내밀다', example_zh='她伸出手，接过了对方递来的礼物，表示感谢。', example_ko='그녀는 손을 내밀어 상대방이 건네준 선물을 받으며 감사를 표했어.', example_pinyin='tā shēn chū shǒu ， jiē guò le duì fāng dì lái de lǐ wù ， biǎo shì gǎn xiè 。' WHERE chinese='伸' AND pinyin='shēn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='깊다, 심오하다', example_zh='这本书给他带来了深刻的启发，改变了他的思维方式。', example_ko='이 책은 그에게 깊은 영감을 주어서 그의 사고 방식을 바꿨어.', example_pinyin='zhè běn shū gěi tā dài lái le shēn kè de qǐ fā ， gǎi biàn le tā de sī wéi fāng shì 。' WHERE chinese='深刻' AND pinyin='shēn kè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='몸매, 체형', example_zh='她经常健身，保持了很好的身材，看起来很健康。', example_ko='그녀는 자주 운동해서 좋은 몸매를 유지하고 있어서 건강해 보여.', example_pinyin='tā jīng cháng jiàn shēn ， bǎo chí le hěn hǎo de shēn cái ， kàn qǐ lái hěn jiàn kāng 。' WHERE chinese='身材' AND pinyin='shēn cái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신분, 정체', example_zh='入境时必须出示有效的身份证件，以核实身份。', example_ko='입국 시 유효한 신분증을 반드시 제시해야 해, 신분 확인을 위해서.', example_pinyin='rù jìng shí bì xū chū shì yǒu xiào de shēn fèn zhèng jiàn ， yǐ hé shí shēn fèn 。' WHERE chinese='身份' AND pinyin='shēn fèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신화', example_zh='古代神话故事中，常常有各种神奇的生物和英雄。', example_ko='고대 신화 이야기에는 자주 다양한 신기한 생물과 영웅이 등장해.', example_pinyin='gǔ dài shén huà gù shì zhōng ， cháng cháng yǒu gè zhǒng shén qí de shēng wù hé yīng xióng 。' WHERE chinese='神话' AND pinyin='shén huà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신경', example_zh='他的神经系统出了问题，需要做专业的检查和治疗。', example_ko='그의 신경계에 문제가 생겨서 전문 검사와 치료를 받아야 해.', example_pinyin='tā de shén jīng xì tǒng chū le wèn tí ， xū yào zuò zhuān yè de jiǎn chá hé zhì liáo 。' WHERE chinese='神经' AND pinyin='shén jīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신비하다', example_zh='宇宙充满了神秘，人类至今仍有很多未知的领域。', example_ko='우주는 신비로움으로 가득 차 있어서 인류는 지금도 미지의 영역이 많아.', example_pinyin='yǔ zhòu chōng mǎn le shén mì ， rén lèi zhì jīn réng yǒu hěn duō wèi zhī de lǐng yù 。' WHERE chinese='神秘' AND pinyin='shén mì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오르다, 상승하다; 리터', example_zh='今天油价又升了，加一箱油要多花几十块钱。', example_ko='오늘 기름값이 또 올랐어서 한 탱크 넣으려면 몇 십 위안이 더 들어.', example_pinyin='jīn tiān yóu jià yòu shēng le ， jiā yī xiāng yóu yào duō huā jǐ shí kuài qián 。' WHERE chinese='升' AND pinyin='shēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='생산하다; 생산', example_zh='这家工厂每天生产数千件产品，供应全国市场。', example_ko='이 공장은 매일 수천 개의 제품을 생산해서 전국 시장에 공급해.', example_pinyin='zhè jiā gōng chǎng měi tiān shēng chǎn shù qiān jiàn chǎn pǐn ， gōng yìng quán guó shì chǎng 。' WHERE chinese='生产' AND pinyin='shēng chǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='생생하다, 생동감 있다', example_zh='他的讲解非常生动，学生们听得津津有味。', example_ko='그의 강의는 매우 생동감 있어서 학생들이 매우 재미있게 들어.', example_pinyin='tā de jiǎng jiě fēi cháng shēng dòng ， xué shēng men tīng dé jīn jīn yǒu wèi 。' WHERE chinese='生动' AND pinyin='shēng dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성조', example_zh='学习普通话时，声调非常重要，不同声调意思完全不同。', example_ko='표준어를 배울 때 성조가 매우 중요해서 다른 성조는 의미가 완전히 달라.', example_pinyin='xué xí pǔ tōng huà shí ， shēng diào fēi cháng zhòng yào ， bù tóng shēng diào yì si wán quán bù tóng 。' WHERE chinese='声调' AND pinyin='shēng diào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='줄, 끈', example_zh='他用绳子把箱子绑好，防止运输途中散开。', example_ko='그는 끈으로 상자를 묶어서 운반 중 풀리지 않도록 했어.', example_pinyin='tā yòng shéng zi bǎ xiāng zi bǎng hǎo ， fáng zhǐ yùn shū tú zhōng sàn kāi 。' WHERE chinese='绳子' AND pinyin='shéng zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='생략하다', example_zh='这道题解答时可以省略中间步骤，直接写结果。', example_ko='이 문제를 풀 때 중간 단계를 생략하고 바로 결과를 적어도 돼.', example_pinyin='zhè dào tí jiě dá shí kě yǐ shěng lüè zhōng jiān bù zhòu ， zhí jiē xiě jié guǒ 。' WHERE chinese='省略' AND pinyin='shěng lvè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='승리하다; 승리', example_zh='他们队以三比零的比分取得了胜利，进入了决赛。', example_ko='그들 팀은 3대 0의 스코어로 승리해서 결승전에 진출했어.', example_pinyin='tā men duì yǐ sān bǐ líng de bǐ fēn qǔ dé le shèng lì ， jìn rù le jué sài 。' WHERE chinese='胜利' AND pinyin='shèng lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시, 시가', example_zh='他喜欢读唐诗，觉得古人的诗句充满了智慧与美感。', example_ko='그는 당시 읽는 걸 좋아해서 옛사람의 시구가 지혜와 아름다움으로 가득하다고 생각해.', example_pinyin='tā xǐ huān dú táng shī ， jué de gǔ rén de shī jù chōng mǎn le zhì huì yǔ měi gǎn 。' WHERE chinese='诗' AND pinyin='shī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='불면증', example_zh='他最近压力太大，经常失眠，睡不好觉。', example_ko='그는 최근 스트레스가 너무 커서 자주 불면증에 시달려, 잠을 잘 못 자.', example_pinyin='tā zuì jìn yā lì tài dà ， jīng cháng shī mián ， shuì bù hǎo jué 。' WHERE chinese='失眠' AND pinyin='shī mián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='잃다', example_zh='他在事故中失去了一条腿，但依然坚强地生活着。', example_ko='그는 사고에서 다리 하나를 잃었지만 여전히 강인하게 살아가고 있어.', example_pinyin='tā zài shì gù zhōng shī qù le yī tiáo tuǐ ， dàn yī rán jiān qiáng dì shēng huó zhe 。' WHERE chinese='失去' AND pinyin='shī qù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실직하다, 직업을 잃다', example_zh='工厂关闭后，很多工人失业了，生活陷入了困境。', example_ko='공장이 문을 닫은 후 많은 노동자가 실직해서 생활이 어려움에 빠졌어.', example_pinyin='gōng chǎng guān bì hòu ， hěn duō gōng rén shī yè le ， shēng huó xiàn rù le kùn jìng 。' WHERE chinese='失业' AND pinyin='shī yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시대', example_zh='这是一个信息爆炸的时代，获取知识比以前容易多了。', example_ko='이건 정보 폭발의 시대야, 지식을 얻는 게 예전보다 훨씬 쉬워졌어.', example_pinyin='zhè shì yí gè xìn xī bào zhà de shí dài ， huò qǔ zhī shí bǐ yǐ qián róng yì duō le 。' WHERE chinese='时代' AND pinyin='shí dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='순간, 시각', example_zh='在那个关键时刻，他做出了正确的决定，改变了命运。', example_ko='그 결정적인 순간에 그는 올바른 결정을 내려서 운명을 바꿨어.', example_pinyin='zài nà ge guān jiàn shí kè ， tā zuò chū le zhèng què de jué dìng ， gǎi biàn le mìng yùn 。' WHERE chinese='时刻' AND pinyin='shí kè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유행하다, 최신의', example_zh='这款衣服非常时髦，上市后立刻受到了年轻人的追捧。', example_ko='이 옷은 매우 유행이어서 출시되자마자 즉시 젊은이들의 선풍적인 인기를 얻었어.', example_pinyin='zhè kuǎn yī fú fēi cháng shí máo ， shàng shì hòu lì kè shòu dào le nián qīng rén de zhuī pěng 。' WHERE chinese='时髦' AND pinyin='shí máo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시기, 기간', example_zh='这是公司发展的关键时期，每个人都要全力以赴。', example_ko='이는 회사 발전의 핵심 시기야, 모두가 전력을 다해야 해.', example_pinyin='zhè shì gōng sī fā zhǎn de guān jiàn shí qī ， měi gè rén dōu yào quán lì yǐ fù 。' WHERE chinese='时期' AND pinyin='shí qī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='패션, 유행', example_zh='她很注重时尚，总是跟上最新的潮流趋势。', example_ko='그녀는 패션을 매우 중시해서 항상 최신 트렌드를 따라가.', example_pinyin='tā hěn zhù zhòng shí shàng ， zǒng shì gēn shàng zuì xīn de cháo liú qū shì 。' WHERE chinese='时尚' AND pinyin='shí shàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='솔직한 말', example_zh='跟朋友说实话，比说漂亮的谎话更有价值。', example_ko='친구에게 솔직한 말을 하는 게 그럴듯한 거짓말보다 더 가치 있어.', example_pinyin='gēn péng yǒu shuō shí huà ， bǐ shuō piào liàng de huǎng huà gèng yǒu jià zhí 。' WHERE chinese='实话' AND pinyin='shí huà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실천하다, 실행하다', example_zh='光有想法不够，还需要去实践，才能知道是否可行。', example_ko='생각만으로는 부족해서 실천해봐야 가능한지 알 수 있어.', example_pinyin='guāng yǒu xiǎng fǎ bù gòu ， hái xū yào qù shí jiàn ， cái néng zhī dào shì fǒu kě xíng 。' WHERE chinese='实践' AND pinyin='shí jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인턴십, 실습하다', example_zh='大学生在毕业前通常要到公司实习，积累工作经验。', example_ko='대학생은 졸업 전에 보통 회사에 인턴십을 나가서 업무 경험을 쌓아.', example_pinyin='dà xué shēng zài bì yè qián tōng cháng yào dào gōng sī shí xí ， jī lěi gōng zuò jīng yàn 。' WHERE chinese='实习' AND pinyin='shí xí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실현하다, 이루다', example_zh='经过多年的努力，他终于实现了自己的梦想。', example_ko='수년간의 노력 끝에 그는 드디어 자신의 꿈을 실현했어.', example_pinyin='jīng guò duō nián de nǔ lì ， tā zhōng yú shí xiàn le zì jǐ de mèng xiǎng 。' WHERE chinese='实现' AND pinyin='shí xiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실행하다, 시행하다', example_zh='新政策从下个月开始实行，所有员工必须遵守。', example_ko='새 정책은 다음 달부터 시행돼서 모든 직원이 반드시 지켜야 해.', example_pinyin='xīn zhèng cè cóng xià gè yuè kāi shǐ shí xíng ， suǒ yǒu yuán gōng bì xū zūn shǒu 。' WHERE chinese='实行' AND pinyin='shí xíng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실험하다; 실험', example_zh='科学家们通过大量实验，终于找到了治疗这种疾病的方法。', example_ko='과학자들은 대량의 실험을 통해서 드디어 이 질환을 치료하는 방법을 찾았어.', example_pinyin='kē xué jiā men tōng guò dà liàng shí yàn ， zhōng yú zhǎo dào le zhì liáo zhè zhǒng jí bìng de fāng fǎ 。' WHERE chinese='实验' AND pinyin='shí yàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='실용적이다, 실용', example_zh='这款包包既好看又实用，适合日常使用。', example_ko='이 가방은 예쁘고 실용적이어서 일상 사용에 적합해.', example_pinyin='zhè kuǎn bāo bāo jì hǎo kàn yòu shí yòng ， shì hé rì cháng shǐ yòng 。' WHERE chinese='实用' AND pinyin='shí yòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='음식, 먹을 것', example_zh='营养均衡的食物对保持健康非常重要。', example_ko='영양이 균형 잡힌 음식은 건강을 유지하는 데 매우 중요해.', example_pinyin='yíng yǎng jūn héng de shí wù duì bǎo chí jiàn kāng fēi cháng zhòng yào 。' WHERE chinese='食物' AND pinyin='shí wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='돌', example_zh='她在河边捡了几块漂亮的石头，带回家做纪念。', example_ko='그녀는 강가에서 예쁜 돌을 몇 개 주워서 집에 가져가 기념으로 삼았어.', example_pinyin='tā zài hé biān jiǎn le jǐ kuài piào liàng de shí tou ， dài huí jiā zuò jì niàn 。' WHERE chinese='石头' AND pinyin='shí tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='힘껏 하다', example_zh='他使劲儿推开了那扇沉重的门，终于进去了。', example_ko='그는 힘껏 그 무거운 문을 밀어서 드디어 들어갔어.', example_pinyin='tā shǐ jìn ér tuī kāi le nà shàn chén zhòng de mén ， zhōng yú jìn qù le 。' WHERE chinese='使劲儿' AND pinyin='shǐ jìn ér' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시종일관, 처음부터 끝까지', example_zh='他始终坚持自己的原则，不受外界的影响。', example_ko='그는 시종일관 자신의 원칙을 고수하며 외부 영향을 받지 않아.', example_pinyin='tā shǐ zhōng jiān chí zì jǐ de yuán zé ， bù shòu wài jiè de yǐng xiǎng 。' WHERE chinese='始终' AND pinyin='shǐ zhōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~인지 아닌지', example_zh='请确认一下是否已经收到了货物，如有问题请联系我们。', example_ko='화물을 이미 받았는지 확인해주세요, 문제가 있으면 연락 주세요.', example_pinyin='qǐng què rèn yī xià shì fǒu yǐ jīng shōu dào le huò wù ， rú yǒu wèn tí qǐng lián xì wǒ men 。' WHERE chinese='是否' AND pinyin='shì fǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시험지', example_zh='考试结束后，老师收走了所有学生的试卷。', example_ko='시험이 끝난 후 선생님이 모든 학생의 시험지를 거둬갔어.', example_pinyin='kǎo shì jié shù hòu ， lǎo shī shōu zǒu le suǒ yǒu xué shēng de shì juàn 。' WHERE chinese='试卷' AND pinyin='shì juàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='병사, 군인', example_zh='士兵们在恶劣的环境中坚守岗位，保卫国家安全。', example_ko='병사들이 열악한 환경에서 초소를 지키며 국가 안전을 지키고 있어.', example_pinyin='shì bīng men zài è liè de huán jìng zhōng jiān shǒu gǎng wèi ， bǎo wèi guó jiā ān quán 。' WHERE chinese='士兵' AND pinyin='shì bīng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~처럼, ~같이', example_zh='他跑起来似的，让人担心他是不是出了什么事。', example_ko='그가 달리는 것처럼 보여서 무슨 일이 생긴 게 아닌가 걱정됐어.', example_pinyin='tā pǎo qǐ lái shì de ， ràng rén dān xīn tā shì bú shì chū le shén me shì 。' WHERE chinese='似的' AND pinyin='shì de' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사실', example_zh='请说出事实，不要隐瞒任何重要的信息。', example_ko='사실을 말해주세요, 어떤 중요한 정보도 숨기지 마세요.', example_pinyin='qǐng shuō chū shì shí ， bú yào yǐn mán rèn hé zhòng yào de xìn xī 。' WHERE chinese='事实' AND pinyin='shì shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사물, 사항', example_zh='世界上的事物都在不断变化，没有什么是永恒的。', example_ko='세상의 사물은 모두 끊임없이 변화해서 영원한 건 없어.', example_pinyin='shì jiè shàng de shì wù dōu zài bù duàn biàn huà ， méi yǒu shén me shì yǒng héng de 。' WHERE chinese='事物' AND pinyin='shì wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미리, 사전에', example_zh='出发前要事先做好准备，不然到了会手忙脚乱。', example_ko='출발 전에 미리 준비해야 해, 그러지 않으면 도착해서 허둥댈 거야.', example_pinyin='chū fā qián yào shì xiān zuò hǎo zhǔn bèi ， bù rán dào le huì shǒu máng jiǎo luàn 。' WHERE chinese='事先' AND pinyin='shì xiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수확; 얻다', example_zh='经过一年的努力，他在工作上有了很大的收获。', example_ko='1년간의 노력 끝에 그는 업무에서 큰 수확을 얻었어.', example_pinyin='jīng guò yī nián de nǔ lì ， tā zài gōng zuò shàng yǒu le hěn dà de shōu huò 。' WHERE chinese='收获' AND pinyin='shōu huò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영수증', example_zh='购物后请保留好收据，如需退换货请出示。', example_ko='쇼핑 후 영수증을 잘 보관해주세요, 교환 반품 시 제시해야 해요.', example_pinyin='gòu wù hòu qǐng bǎo liú hǎo shōu jù ， rú xū tuì huàn huò qǐng chū shì 。' WHERE chinese='收据' AND pinyin='shōu jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수공예, 손으로 만들다', example_zh='她喜欢做手工，经常用废旧材料做出美丽的装饰品。', example_ko='그녀는 수공예를 좋아해서 자주 폐자재로 예쁜 장식품을 만들어.', example_pinyin='tā xǐ huān zuò shǒu gōng ， jīng cháng yòng fèi jiù cái liào zuò chū měi lì de zhuāng shì pǐn 。' WHERE chinese='手工' AND pinyin='shǒu gōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수술', example_zh='医生说他需要做手术，手术后要好好休养。', example_ko='의사가 수술이 필요하다고 했어, 수술 후에 잘 요양해야 해.', example_pinyin='yī shēng shuō tā xū yào zuò shǒu shù ， shǒu shù hòu yào hǎo hǎo xiū yǎng 。' WHERE chinese='手术' AND pinyin='shǒu shù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='장갑', example_zh='天气冷了，出门要戴手套，防止手被冻伤。', example_ko='날씨가 추워졌으니 외출할 때 장갑을 끼어야 해, 손이 동상에 걸리지 않게.', example_pinyin='tiān qì lěng le ， chū mén yào dài shǒu tào ， fáng zhǐ shǒu bèi dòng shāng 。' WHERE chinese='手套' AND pinyin='shǒu tào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수속, 절차', example_zh='办理登机手续需要出示护照和机票，提前一小时到机场。', example_ko='탑승 수속을 처리하려면 여권과 항공권을 제시해야 해, 한 시간 전에 공항에 도착해.', example_pinyin='bàn lǐ dēng jī shǒu xù xū yào chū shì hù zhào hé jī piào ， tí qián yī xiǎo shí dào jī chǎng 。' WHERE chinese='手续' AND pinyin='shǒu xù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='손가락', example_zh='他的手指很灵活，弹钢琴非常熟练。', example_ko='그의 손가락이 매우 유연해서 피아노를 매우 능숙하게 쳐.', example_pinyin='tā de shǒu zhǐ hěn líng huó ， tán gāng qín fēi cháng shú liàn 。' WHERE chinese='手指' AND pinyin='shǒu zhǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부상당하다', example_zh='他在比赛中受伤了，不得不退出了这次比赛。', example_ko='그는 경기 중 부상당해서 어쩔 수 없이 이번 경기에서 기권했어.', example_pinyin='tā zài bǐ sài zhōng shòu shāng le ， bù dé bù tuì chū le zhè cì bǐ sài 。' WHERE chinese='受伤' AND pinyin='shòu shāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수명, 생명', example_zh='健康的生活方式可以有效延长寿命，减少疾病。', example_ko='건강한 생활 방식은 효과적으로 수명을 연장하고 질병을 줄일 수 있어.', example_pinyin='jiàn kāng de shēng huó fāng shì kě yǐ yǒu xiào yán cháng shòu mìng ， jiǎn shǎo jí bìng 。' WHERE chinese='寿命' AND pinyin='shòu mìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='책장', example_zh='他的书架上摆满了各种书籍，涵盖了文学、历史和科学。', example_ko='그의 책장은 문학, 역사, 과학 등 다양한 서적으로 가득 차 있어.', example_pinyin='tā de shū jià shàng bǎi mǎn le gè zhǒng shū jí ， hán gài le wén xué 、 lì shǐ hé kē xué 。' WHERE chinese='书架' AND pinyin='shū jià' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='입력하다', example_zh='请把您的用户名和密码输入到登录框中。', example_ko='로그인 창에 사용자 이름과 비밀번호를 입력해주세요.', example_pinyin='qǐng bǎ nín de yòng hù míng hé mì mǎ shū rù dào dēng lù kuāng zhōng 。' WHERE chinese='输入' AND pinyin='shū rù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='채소', example_zh='每天吃新鲜的蔬菜对身体很好，营养丰富。', example_ko='매일 신선한 채소를 먹으면 몸에 좋고 영양도 풍부해.', example_pinyin='měi tiān chī xīn xiān de shū cài duì shēn tǐ hěn hǎo ， yíng yǎng fēng fù 。' WHERE chinese='蔬菜' AND pinyin='shū cài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='편안하다, 쾌적하다', example_zh='这把椅子坐起来非常舒适，长时间坐也不会腰酸。', example_ko='이 의자는 앉으면 매우 편안해서 오래 앉아도 허리가 아프지 않아.', example_pinyin='zhè bǎ yǐ zi zuò qǐ lái fēi cháng shū shì ， zhǎng shí jiān zuò yě bú huì yāo suān 。' WHERE chinese='舒适' AND pinyin='shū shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='빗', example_zh='她每天早上用梳子梳头，然后再出门。', example_ko='그녀는 매일 아침 빗으로 머리를 빗고 나서 외출해.', example_pinyin='tā měi tiān zǎo shàng yòng shū zi shū tóu ， rán hòu zài chū mén 。' WHERE chinese='梳子' AND pinyin='shū zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='능숙하다, 숙련되다', example_zh='他学了三年中文，现在口语已经非常熟练了。', example_ko='그는 3년간 중국어를 배워서 지금 구어가 이미 매우 능숙해졌어.', example_pinyin='tā xué le sān nián zhōng wén ， xiàn zài kǒu yǔ yǐ jīng fēi cháng shú liàn le 。' WHERE chinese='熟练' AND pinyin='shú liàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='마우스', example_zh='他换了一个新的无线鼠标，用起来更加方便。', example_ko='그는 새 무선 마우스로 바꿨는데 사용하기가 더 편리해.', example_pinyin='tā huàn le yí gè xīn de wú xiàn shǔ biāo ， yòng qǐ lái gèng jiā fāng biàn 。' WHERE chinese='鼠标' AND pinyin='shǔ biāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='속하다, ~에 해당하다', example_zh='这个部门属于公司的核心部门，工作非常重要。', example_ko='이 부서는 회사의 핵심 부서에 속해서 업무가 매우 중요해.', example_pinyin='zhè ge bù mén shǔ yú gōng sī de hé xīn bù mén ， gōng zuò fēi cháng zhòng yào 。' WHERE chinese='属于' AND pinyin='shǔ yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='데이터', example_zh='数据显示，这款产品的销售量持续增长。', example_ko='데이터에 따르면 이 제품의 판매량이 지속적으로 성장하고 있어.', example_pinyin='shù jù xiǎn shì ， zhè kuǎn chǎn pǐn de xiāo shòu liàng chí xù zēng zhǎng 。' WHERE chinese='数据' AND pinyin='shù jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='디지털', example_zh='数码相机的出现彻底改变了摄影行业。', example_ko='디지털 카메라의 등장은 사진 업계를 완전히 바꿔놓았어.', example_pinyin='shù mǎ xiàng jī de chū xiàn chè dǐ gǎi biàn le shè yǐng háng yè 。' WHERE chinese='数码' AND pinyin='shù mǎ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='넘어지다, 떨어지다', example_zh='地板太滑了，他不小心摔倒了，幸好没有受伤。', example_ko='바닥이 너무 미끄러워서 그는 실수로 넘어졌는데 다행히 다치지 않았어.', example_pinyin='dì bǎn tài huá le ， tā bù xiǎo xīn shuāi dǎo le ， xìng hǎo méi yǒu shòu shāng 。' WHERE chinese='摔' AND pinyin='shuāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='내동댕이치다; 뒤처지다', example_zh='他甩开对手，第一个冲过了终点线。', example_ko='그는 상대방을 뒤로 제치고 가장 먼저 결승선을 통과했어.', example_pinyin='tā shuǎi kāi duì shǒu ， dì yí gè chōng guò le zhōng diǎn xiàn 。' WHERE chinese='甩' AND pinyin='shuǎi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쌍방, 양쪽', example_zh='这次谈判双方都做出了让步，最终达成了协议。', example_ko='이번 협상에서 양측 모두 양보해서 결국 합의에 도달했어.', example_pinyin='zhè cì tán pàn shuāng fāng dōu zuò chū le ràng bù ， zuì zhōng dá chéng le xié yì 。' WHERE chinese='双方' AND pinyin='shuāng fāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세금', example_zh='按规定纳税是每个公民的义务，不能逃税漏税。', example_ko='규정에 따라 납세하는 것은 모든 시민의 의무야, 탈세를 해서는 안 돼.', example_pinyin='àn guī dìng nà shuì shì měi gè gōng mín de yì wù ， bù néng táo shuì lòu shuì 。' WHERE chinese='税' AND pinyin='shuì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아마도, 모를지도', example_zh='今晚说不定会下雨，最好带把伞出门。', example_ko='오늘 저녁 아마 비가 올지도 몰라, 우산을 챙겨 나가는 게 좋아.', example_pinyin='jīn wǎn shuō bù dìng huì xià yǔ ， zuì hǎo dài bǎ sǎn chū mén 。' WHERE chinese='说不定' AND pinyin='shuō bu dìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='설득하다', example_zh='他花了很长时间说服父母，让他们同意他出国留学。', example_ko='그는 오랫동안 부모를 설득해서 유학 허락을 받았어.', example_pinyin='tā huā le hěn zhǎng shí jiān shuō fú fù mǔ ， ràng tā men tóng yì tā chū guó liú xué 。' WHERE chinese='说服' AND pinyin='shuō fú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='찢다', example_zh='他生气地把那封信撕成了碎片，扔进了垃圾桶。', example_ko='그는 화가 나서 그 편지를 조각조각 찢어서 쓰레기통에 버렸어.', example_pinyin='tā shēng qì dì bǎ nà fēng xìn sī chéng le suì piàn ， rēng jìn le lā jī tǒng 。' WHERE chinese='撕' AND pinyin='sī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비단, 실크', example_zh='苏州的丝绸非常有名，质地光滑，色泽亮丽。', example_ko='쑤저우의 비단은 매우 유명해서 질감이 부드럽고 색택이 아름다워.', example_pinyin='sū zhōu de sī chóu fēi cháng yǒu míng ， zhì dì guāng huá ， sè zé liàng lì 。' WHERE chinese='丝绸' AND pinyin='sī chóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조금도, 전혀', example_zh='他对这件事丝毫没有察觉，完全被蒙在鼓里。', example_ko='그는 이 일에 대해 조금도 눈치채지 못했어, 완전히 아무것도 모른 채였어.', example_pinyin='tā duì zhè jiàn shì sī háo méi yǒu chá jué ， wán quán bèi méng zài gǔ lǐ 。' WHERE chinese='丝毫' AND pinyin='sī háo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='생각하다, 사고하다', example_zh='解决复杂问题时，要认真思考，找到最佳方案。', example_ko='복잡한 문제를 해결할 때 진지하게 생각해서 최선의 방안을 찾아야 해.', example_pinyin='jiě jué fù zá wèn tí shí ， yào rèn zhēn sī kǎo ， zhǎo dào zuì jiā fāng àn 。' WHERE chinese='思考' AND pinyin='sī kǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사상, 생각', example_zh='他的思想非常开放，能够接受不同文化的观点。', example_ko='그의 사상은 매우 개방적이어서 다른 문화의 관점을 받아들일 수 있어.', example_pinyin='tā de sī xiǎng fēi cháng kāi fàng ， néng gòu jiē shòu bù tóng wén huà de guān diǎn 。' WHERE chinese='思想' AND pinyin='sī xiǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='개인적인, 사적인', example_zh='这是他的私人事务，不方便向外人透露。', example_ko='이건 그의 사적인 사정이야, 외부인에게 알리기 불편해.', example_pinyin='zhè shì tā de sī rén shì wù ， bù fāng biàn xiàng wài rén tòu lù 。' WHERE chinese='私人' AND pinyin='sī rén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~인 듯하다, ~같다', example_zh='他似乎有些心事，一直沉默不语。', example_ko='그는 뭔가 마음에 걸리는 게 있는 듯해서 계속 침묵하고 있어.', example_pinyin='tā sì hū yǒu xiē xīn shì ， yì zhí chén mò bù yǔ 。' WHERE chinese='似乎' AND pinyin='sì hū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='절, 사원', example_zh='这座寺庙已有五百年历史，香火非常旺盛。', example_ko='이 절은 500년의 역사가 있어서 향불이 매우 왕성해.', example_pinyin='zhè zuò sì miào yǐ yǒu wǔ bǎi nián lì shǐ ， xiāng huǒ fēi cháng wàng shèng 。' WHERE chinese='寺庙' AND pinyin='sì miào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='기숙사', example_zh='大学的宿舍条件还不错，四人间，有独立卫生间。', example_ko='대학 기숙사 환경이 나쁘지 않아서 4인실이고 개인 화장실이 있어.', example_pinyin='dà xué de sù shè tiáo jiàn hái bú cuò ， sì rén jiān ， yǒu dú lì wèi shēng jiān 。' WHERE chinese='宿舍' AND pinyin='sù shè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수시로, 언제든지', example_zh='有任何问题可以随时联系我，我会尽快回复。', example_ko='어떤 문제든 수시로 연락해줘, 최대한 빨리 답할게.', example_pinyin='yǒu rèn hé wèn tí kě yǐ suí shí lián xì wǒ ， wǒ huì jǐn kuài huí fù 。' WHERE chinese='随时' AND pinyin='suí shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부서지다, 깨지다', example_zh='不小心把花瓶碰碎了，地上都是碎片，小心别踩到。', example_ko='실수로 꽃병을 건드려서 깨졌어, 바닥에 파편이 있으니 조심해서 밟지 마.', example_pinyin='bù xiǎo xīn bǎ huā píng pèng suì le ， dì shàng dōu shì suì piàn ， xiǎo xīn bié cǎi dào 。' WHERE chinese='碎' AND pinyin='suì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='손실, 손해', example_zh='这次投资失败造成了巨大的经济损失。', example_ko='이번 투자 실패로 큰 경제적 손실이 발생했어.', example_pinyin='zhè cì tóu zī shī bài zào chéng le jù dà de jīng jì sǔn shī 。' WHERE chinese='损失' AND pinyin='sǔn shī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단축하다', example_zh='新的交通方式大大缩短了两地之间的通勤时间。', example_ko='새로운 교통 방식이 두 지역 사이의 통근 시간을 크게 단축했어.', example_pinyin='xīn de jiāo tōng fāng shì dà dà suō duǎn le liǎng dì zhī jiān de tōng qín shí jiān 。' WHERE chinese='缩短' AND pinyin='suō duǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='축소하다', example_zh='设计时要注意把图片缩小到合适的尺寸，不要太大。', example_ko='디자인할 때 사진을 적합한 크기로 축소해야 해, 너무 크면 안 돼.', example_pinyin='shè jì shí yào zhù yì bǎ tú piàn suō xiǎo dào hé shì de chǐ cùn ， bú yào tài dà 。' WHERE chinese='缩小' AND pinyin='suō xiǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='잠그다, 자물쇠', example_zh='出门前记得把门锁好，防止有人闯入。', example_ko='외출 전에 문을 잘 잠가야 해, 누군가 침입하지 않도록.', example_pinyin='chū mén qián jì de bǎ mén suǒ hǎo ， fáng zhǐ yǒu rén chuǎng rù 。' WHERE chinese='锁' AND pinyin='suǒ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~이 있는 곳, 장소 (양사)', example_zh='他工作的那所学校是一所著名的大学。', example_ko='그가 일하는 그 학교는 유명한 대학이야.', example_pinyin='tā gōng zuò de nà suǒ xué xiào shì yī suǒ zhù míng de dà xué 。' WHERE chinese='所' AND pinyin='suǒ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이른바, 소위', example_zh='他所谓的计划其实很不切实际，需要重新调整。', example_ko='그가 이른바 계획이라고 하는 건 사실 매우 비현실적이어서 다시 조정해야 해.', example_pinyin='tā suǒ wèi de jì huà qí shí hěn bù qiē shí jì ， xū yào chóng xīn tiáo zhěng 。' WHERE chinese='所谓' AND pinyin='suǒ wèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='탑', example_zh='那座古塔已有千年历史，是当地的著名景点。', example_ko='저 고탑은 천 년의 역사가 있어서 현지의 유명한 명소야.', example_pinyin='nà zuò gǔ tǎ yǐ yǒu qiān nián lì shǐ ， shì dāng dì de zhù míng jǐng diǎn 。' WHERE chinese='塔' AND pinyin='tǎ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='계단', example_zh='他走下台阶时不小心滑了一下，幸好没有受伤。', example_ko='그는 계단을 내려올 때 실수로 미끄러졌는데 다행히 다치지 않았어.', example_pinyin='tā zǒu xià tái jiē shí bù xiǎo xīn huá le yī xià ， xìng hǎo méi yǒu shòu shāng 。' WHERE chinese='台阶' AND pinyin='tái jiē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='태극권', example_zh='他每天早上在公园打太极拳，保持身体健康。', example_ko='그는 매일 아침 공원에서 태극권을 해서 건강을 유지해.', example_pinyin='tā měi tiān zǎo shàng zài gōng yuán dǎ tài jí quán ， bǎo chí shēn tǐ jiàn kāng 。' WHERE chinese='太极拳' AND pinyin='tài jí quán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부인, 아내 (경칭)', example_zh='他带着太太一起参加了公司的年会，两人都打扮得很体面。', example_ko='그는 부인을 데리고 회사 연말 파티에 참석했는데 두 사람 모두 말끔하게 차려입었어.', example_pinyin='tā dài zhe tài tài yì qǐ cān jiā le gōng sī de nián huì ， liǎng rén dōu dǎ bàn dé hěn tǐ miàn 。' WHERE chinese='太太' AND pinyin='tài tai' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='협상하다; 협상', example_zh='两国代表经过多轮谈判，终于达成了贸易协议。', example_ko='양국 대표는 여러 차례 협상 끝에 드디어 무역 협정에 도달했어.', example_pinyin='liǎng guó dài biǎo jīng guò duō lún tán pàn ， zhōng yú dá chéng le mào yì xié yì 。' WHERE chinese='谈判' AND pinyin='tán pàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='솔직하다, 거침없다', example_zh='她为人坦率，有什么说什么，不喜欢拐弯抹角。', example_ko='그녀는 사람이 솔직해서 생각한 걸 바로 말하고 빙빙 돌려 말하는 걸 싫어해.', example_pinyin='tā wéi rén tǎn shuài ， yǒu shén me shuō shén me ， bù xǐ huān guǎi wān mò jiǎo 。' WHERE chinese='坦率' AND pinyin='tǎn shuài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뜨겁다, 덥다', example_zh='这碗汤很烫，小心别烫到嘴。', example_ko='이 국이 뜨거우니 입 데이지 않도록 조심해.', example_pinyin='zhè wǎn tāng hěn tàng ， xiǎo xīn bié tàng dào zuǐ 。' WHERE chinese='烫' AND pinyin='tàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='복숭아', example_zh='夏天的桃子又甜又多汁，是他最喜欢的水果之一。', example_ko='여름 복숭아는 달콤하고 즙이 많아서 그가 가장 좋아하는 과일 중 하나야.', example_pinyin='xià tiān de táo zi yòu tián yòu duō zhī ， shì tā zuì xǐ huān de shuǐ guǒ zhī yī 。' WHERE chinese='桃' AND pinyin='táo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='도망치다', example_zh='小偷被发现后，立刻拔腿就逃，警察追了上去。', example_ko='도둑이 발각된 후 즉시 줄행랑을 쳤는데 경찰이 뒤쫓아 갔어.', example_pinyin='xiǎo tōu bèi fā xiàn hòu ， lì kè bá tuǐ jiù táo ， jǐng chá zhuī le shàng qù 。' WHERE chinese='逃' AND pinyin='táo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='피하다, 회피하다', example_zh='他总是逃避困难，而不是面对并解决它们。', example_ko='그는 어려움을 직면하고 해결하지 않고 항상 피해.', example_pinyin='tā zǒng shì táo bì kùn nán ， ér bú shì miàn duì bìng jiě jué tā men 。' WHERE chinese='逃避' AND pinyin='táo bì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세트, 묶음; 씌우다', example_zh='这套茶具一共有六件，包括茶壶和茶杯。', example_ko='이 찻잔 세트는 총 6개야, 차 주전자와 찻잔을 포함해.', example_pinyin='zhè tào chá jù yī gòng yǒu liù jiàn ， bāo kuò chá hú hé chá bēi 。' WHERE chinese='套' AND pinyin='tào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='특수하다, 특별하다', example_zh='这个地区气候特殊，冬天非常冷，夏天非常热。', example_ko='이 지역은 기후가 특수해서 겨울은 매우 춥고 여름은 매우 더워.', example_pinyin='zhè ge dì qū qì hòu tè shū ， dōng tiān fēi cháng lěng ， xià tiān fēi cháng rè 。' WHERE chinese='特殊' AND pinyin='tè shū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='특별히, 일부러', example_zh='他特意早起，为了赶上第一班地铁去接她。', example_ko='그는 특별히 일찍 일어나서 첫 지하철을 타러 그녀를 맞이하러 갔어.', example_pinyin='tā tè yì zǎo qǐ ， wèi le gǎn shàng dì yī bān dì tiě qù jiē tā 。' WHERE chinese='特意' AND pinyin='tè yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='특징', example_zh='这种植物有一个显著的特征，就是叶子非常宽大。', example_ko='이 식물은 뚜렷한 특징이 있는데 잎이 매우 넓다는 거야.', example_pinyin='zhè zhòng zhí wù yǒu yí gè xiǎn zhù de tè zhēng ， jiù shì yè zi fēi cháng kuān dà 。' WHERE chinese='特征' AND pinyin='tè zhēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아끼다, 귀여워하다', example_zh='爷爷非常疼爱他的孙子，经常带他出去玩。', example_ko='할아버지는 손자를 매우 아껴서 자주 데리고 나가서 놀아.', example_pinyin='yé yé fēi cháng téng ài tā de sūn zi ， jīng cháng dài tā chū qù wán 。' WHERE chinese='疼爱' AND pinyin='téng ài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='들다, 올리다; 언급하다', example_zh='会议上他提出了几个改进方案，大家都表示赞同。', example_ko='회의에서 그는 몇 가지 개선 방안을 제시했는데 모두 찬성을 표했어.', example_pinyin='huì yì shàng tā tí chū le jǐ gè gǎi jìn fāng àn ， dà jiā dōu biǎo shì zàn tóng 。' WHERE chinese='提' AND pinyin='tí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='제창하다, 권장하다', example_zh='学校提倡学生积极参加体育锻炼，保持健康。', example_ko='학교는 학생들이 적극적으로 체육 운동에 참가해서 건강을 유지하기를 권장해.', example_pinyin='xué xiào tí chàng xué shēng jī jí cān jiā tǐ yù duàn liàn ， bǎo chí jiàn kāng 。' WHERE chinese='提倡' AND pinyin='tí chàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아웃라인, 요강', example_zh='写论文前先列好提纲，这样写起来更有条理。', example_ko='논문을 쓰기 전에 먼저 아웃라인을 잘 작성해야 써나가기가 더 체계적이야.', example_pinyin='xiě lùn wén qián xiān liè hǎo tí gāng ， zhè yàng xiě qǐ lái gèng yǒu tiáo lǐ 。' WHERE chinese='提纲' AND pinyin='tí gāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='질문하다', example_zh='老师鼓励学生积极提问，这样可以加深理解。', example_ko='선생님이 학생들의 적극적인 질문을 격려해서 이해를 깊게 할 수 있어.', example_pinyin='lǎo shī gǔ lì xué shēng jī jí tí wèn ， zhè yàng kě yǐ jiā shēn lǐ jiě 。' WHERE chinese='提问' AND pinyin='tí wèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='제목', example_zh='这篇文章的题目很吸引人，让人一看就想读下去。', example_ko='이 글의 제목이 매우 흥미로워서 한번 보면 계속 읽고 싶어져.', example_pinyin='zhè piān wén zhāng de tí mù hěn xī yǐn rén ， ràng rén yī kàn jiù xiǎng dú xià qù 。' WHERE chinese='题目' AND pinyin='tí mù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='체험하다, 이해하다; 체험', example_zh='通过实际操作，他深刻体会到了理论与实践的重要结合。', example_ko='실제 조작을 통해 그는 이론과 실천의 중요한 결합을 깊이 체험했어.', example_pinyin='tōng guò shí jì cāo zuò ， tā shēn kè tǐ huì dào le lǐ lùn yǔ shí jiàn de zhòng yào jié hé 。' WHERE chinese='体会' AND pinyin='tǐ huì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='부피, 체적', example_zh='这个箱子的体积太大了，放不进行李舱。', example_ko='이 상자는 부피가 너무 커서 수화물 칸에 넣을 수 없어.', example_pinyin='zhè ge xiāng zi de tǐ jī tài dà le ， fàng bù jìn xíng lǐ cāng 。' WHERE chinese='体积' AND pinyin='tǐ jī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세심하다, 배려하다', example_zh='他对妻子非常体贴，总是照顾好家里的大小事务。', example_ko='그는 아내에게 매우 세심해서 항상 집안 크고 작은 일을 잘 돌봐.', example_pinyin='tā duì qī zǐ fēi cháng tǐ tiē ， zǒng shì zhào gù hǎo jiā lǐ de dà xiǎo shì wù 。' WHERE chinese='体贴' AND pinyin='tǐ tiē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구현하다, 반영하다', example_zh='这次活动体现了公司对员工的关心和重视。', example_ko='이번 행사는 회사의 직원에 대한 관심과 중시를 구현했어.', example_pinyin='zhè cì huó dòng tǐ xiàn le gōng sī duì yuán gōng de guān xīn hé zhòng shì 。' WHERE chinese='体现' AND pinyin='tǐ xiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='체험하다; 경험', example_zh='他去农村体验了一周的农耕生活，感受了很多。', example_ko='그는 농촌에서 일주일간 농경 생활을 체험하며 많은 것을 느꼈어.', example_pinyin='tā qù nóng cūn tǐ yàn le yī zhōu de nóng gēng shēng huó ， gǎn shòu le hěn duō 。' WHERE chinese='体验' AND pinyin='tǐ yàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='하늘', example_zh='今天天空湛蓝，一点云都没有，真是个好天气。', example_ko='오늘 하늘이 짙푸르고 구름 한 점 없어서 정말 좋은 날씨야.', example_pinyin='jīn tiān tiān kōng zhàn lán ， yì diǎn yún dōu méi yǒu ， zhēn shì gè hǎo tiān qì 。' WHERE chinese='天空' AND pinyin='tiān kōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='순진하다, 천진하다', example_zh='她的笑容非常天真，像一个没有烦恼的孩子。', example_ko='그녀의 미소가 매우 천진해서 근심 없는 아이 같아.', example_pinyin='tā de xiào róng fēi cháng tiān zhēn ， xiàng yí gè méi yǒu fán nǎo de hái zi 。' WHERE chinese='天真' AND pinyin='tiān zhēn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='들판, 전원', example_zh='春天来了，田野里开满了各种颜色的野花，非常美丽。', example_ko='봄이 왔어서 들판에 다양한 색의 들꽃이 가득 피었어, 매우 아름다워.', example_pinyin='chūn tiān lái le ， tián yě lǐ kāi mǎn le gè zhǒng yán sè de yě huā ， fēi cháng měi lì 。' WHERE chinese='田野' AND pinyin='tián yě' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='장난꾸러기다, 개구지다', example_zh='这个小孩非常调皮，总是惹麻烦，让父母头疼。', example_ko='이 아이는 매우 개구져서 항상 말썽을 피워서 부모를 골치 아프게 해.', example_pinyin='zhè ge xiǎo hái fēi cháng tiáo pí ， zǒng shì rě má fán ， ràng fù mǔ tóu téng 。' WHERE chinese='调皮' AND pinyin='tiáo pí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조정하다, 조절하다', example_zh='根据实际情况，他们对计划做了一些调整。', example_ko='실제 상황에 따라 그들은 계획에 약간의 조정을 했어.', example_pinyin='gēn jù shí jì qíng kuàng ， tā men duì jì huà zuò le yī xiē tiáo zhěng 。' WHERE chinese='调整' AND pinyin='tiáo zhěng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='도전하다; 도전', example_zh='他勇于挑战自我，不断突破自己的极限。', example_ko='그는 자신에게 도전하는 걸 좋아해서 끊임없이 자신의 한계를 돌파해.', example_pinyin='tā yǒng yú tiǎo zhàn zì wǒ ， bù duàn tū pò zì jǐ de jí xiàn 。' WHERE chinese='挑战' AND pinyin='tiǎo zhàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보통, 일반적으로', example_zh='通常来说，这种工作需要三年以上的工作经验。', example_ko='보통 이런 업무는 3년 이상의 업무 경험이 필요해.', example_pinyin='tōng cháng lái shuō ， zhè zhǒng gōng zuò xū yào sān nián yǐ shàng de gōng zuò jīng yàn 。' WHERE chinese='通常' AND pinyin='tōng cháng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='통신, 통신망', example_zh='现代通讯技术的发展使人们能够随时随地保持联系。', example_ko='현대 통신 기술의 발전으로 사람들이 언제 어디서나 연락을 유지할 수 있게 됐어.', example_pinyin='xiàn dài tōng xùn jì shù de fā zhǎn shǐ rén men néng gòu suí shí suí dì bǎo chí lián xì 。' WHERE chinese='通讯' AND pinyin='tōng xùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구리', example_zh='这个古老的铜器已经有两千年历史，非常珍贵。', example_ko='이 고대 구리 기물은 2000년의 역사가 있어서 매우 귀중해.', example_pinyin='zhè ge gǔ lǎo de tóng qì yǐ jīng yǒu liǎng qiān nián lì shǐ ， fēi cháng zhēn guì 。' WHERE chinese='铜' AND pinyin='tóng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='동시에, 동시의', example_zh='他同时负责三个项目，压力很大，但表现得很出色。', example_ko='그는 동시에 세 개의 프로젝트를 담당해서 스트레스가 크지만 훌륭하게 해내고 있어.', example_pinyin='tā tóng shí fù zé sān gè xiàng mù ， yā lì hěn dà ， dàn biǎo xiàn dé hěn chū sè 。' WHERE chinese='同时' AND pinyin='tóng shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='통일하다; 통일', example_zh='公司统一了所有部门的工作流程，提高了整体效率。', example_ko='회사는 모든 부서의 업무 프로세스를 통일해서 전체 효율을 높였어.', example_pinyin='gōng sī tǒng yī liǎo suǒ yǒu bù mén de gōng zuò liú chéng ， tí gāo le zhěng tǐ xiào lǜ 。' WHERE chinese='统一' AND pinyin='tǒng yī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='통치하다; 통치', example_zh='历史上，许多帝王靠武力统治国家，但最终都走向了衰落。', example_ko='역사상 많은 제왕이 무력으로 나라를 통치했지만 결국 모두 쇠락의 길을 걸었어.', example_pinyin='lì shǐ shàng ， xǔ duō dì wáng kào wǔ lì tǒng zhì guó jiā ， dàn zuì zhōng dōu zǒu xiàng le shuāi luò 。' WHERE chinese='统治' AND pinyin='tǒng zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='고통스럽다, 괴롭다', example_zh='失去亲人的痛苦是难以言说的，需要时间慢慢愈合。', example_ko='가족을 잃는 고통은 말로 표현하기 어려워서 천천히 회복하는 데 시간이 필요해.', example_pinyin='shī qù qīn rén de tòng kǔ shì nán yǐ yán shuō de ， xū yào shí jiān màn màn yù hé 。' WHERE chinese='痛苦' AND pinyin='tòng kǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시원하다, 유쾌하다', example_zh='打完球后喝一杯冰水，感觉真是痛快！', example_ko='공을 치고 나서 얼음물 한 잔 마시니 정말 시원해!', example_pinyin='dǎ wán qiú hòu hē yī bēi bīng shuǐ ， gǎn jué zhēn shì tòng kuài ！' WHERE chinese='痛快' AND pinyin='tòng kuài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='투자하다; 투자', example_zh='他把大部分积蓄都投资了这家公司，希望能获得高回报。', example_ko='그는 저축의 대부분을 이 회사에 투자해서 높은 수익을 얻기를 기대해.', example_pinyin='tā bǎ dà bù fèn jī xù dōu tóu zī le zhè jiā gōng sī ， xī wàng néng huò dé gāo huí bào 。' WHERE chinese='投资' AND pinyin='tóu zī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='투명하다', example_zh='这家公司的财务信息非常透明，定期向公众公开。', example_ko='이 회사의 재무 정보는 매우 투명해서 정기적으로 대중에게 공개해.', example_pinyin='zhè jiā gōng sī de cái wù xìn xī fēi cháng tòu míng ， dìng qī xiàng gōng zhòng gōng kāi 。' WHERE chinese='透明' AND pinyin='tòu míng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='두드러지다, 뛰어나다; 돌출하다', example_zh='他在这次活动中突出的表现获得了领导的高度赞扬。', example_ko='그는 이번 행사에서 두드러진 활약으로 리더의 높은 칭찬을 받았어.', example_pinyin='tā zài zhè cì huó dòng zhōng tū chū de biǎo xiàn huò dé le lǐng dǎo de gāo dù zàn yáng 。' WHERE chinese='突出' AND pinyin='tū chū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='토지, 땅', example_zh='这片土地非常肥沃，适合种植各种农作物。', example_ko='이 토지는 매우 비옥해서 다양한 농작물 재배에 적합해.', example_pinyin='zhè piàn tǔ dì fēi cháng féi wò ， shì hé zhòng zhí gè zhǒng nóng zuò wù 。' WHERE chinese='土地' AND pinyin='tǔ dì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감자', example_zh='他最喜欢吃土豆，无论是炒还是炖，都很香。', example_ko='그는 감자를 가장 좋아해서 볶든 삶든 다 맛있어.', example_pinyin='tā zuì xǐ huān chī tǔ dòu ， wú lùn shì chǎo hái shì dùn ， dōu hěn xiāng 。' WHERE chinese='土豆' AND pinyin='tǔ dòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='토하다, 내뱉다', example_zh='他喝酒太多，最后吐了，被朋友送回家休息。', example_ko='그는 술을 너무 많이 마셔서 결국 토하고 친구가 집에 데려다줬어.', example_pinyin='tā hē jiǔ tài duō ， zuì hòu tǔ le ， bèi péng yǒu sòng huí jiā xiū xī 。' WHERE chinese='吐' AND pinyin='tù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='토끼', example_zh='小女孩把兔子抱在怀里，轻轻抚摸着，兔子很乖。', example_ko='어린 여자아이가 토끼를 품에 안고 살살 쓰다듬었는데 토끼가 매우 순했어.', example_pinyin='xiǎo nǚ hái bǎ tù zi bào zài huái lǐ ， qīng qīng fǔ mō zhe ， tù zi hěn guāi 。' WHERE chinese='兔子' AND pinyin='tù zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단체, 그룹', example_zh='他们组成了一个团，一起去演出，获得了很多好评。', example_ko='그들은 팀을 구성해서 함께 공연하러 갔는데 많은 호평을 받았어.', example_pinyin='tā men zǔ chéng le yí gè tuán ， yì qǐ qù yǎn chū ， huò dé le hěn duō hǎo píng 。' WHERE chinese='团' AND pinyin='tuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사양하다, 거절하다', example_zh='他推辞了那份高薪工作，因为不符合自己的职业规划。', example_ko='그는 그 고연봉 직장을 사양했어, 자신의 직업 계획에 맞지 않아서.', example_pinyin='tā tuī cí le nà fèn gāo xīn gōng zuò ， yīn wèi bù fú hé zì jǐ de zhí yè guī huà 。' WHERE chinese='推辞' AND pinyin='tuī cí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보급하다, 확산하다', example_zh='政府积极推广新能源汽车，以减少碳排放。', example_ko='정부는 탄소 배출을 줄이기 위해 신에너지 자동차 보급을 적극 추진하고 있어.', example_pinyin='zhèng fǔ jī jí tuī guǎng xīn néng yuán qì chē ， yǐ jiǎn shǎo tàn pái fàng 。' WHERE chinese='推广' AND pinyin='tuī guǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='추천하다', example_zh='朋友向他推荐了一家非常好吃的餐厅，他去了之后果然没失望。', example_ko='친구가 그에게 매우 맛있는 식당을 추천해줬는데 가보니 역시 실망하지 않았어.', example_pinyin='péng yǒu xiàng tā tuī jiàn le yī jiā fēi cháng hǎo chī de cān tīng ， tā qù le zhī hòu guǒ rán méi shī wàng 。' WHERE chinese='推荐' AND pinyin='tuī jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='물러나다, 돌려주다', example_zh='衣服买回来不合适，退了吧，可以换一件。', example_ko='옷을 샀는데 맞지 않으면 반품해, 다른 걸로 교환할 수 있어.', example_pinyin='yī fú mǎi huí lái bù hé shì ， tuì le ba ， kě yǐ huàn yī jiàn 。' WHERE chinese='退' AND pinyin='tuì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='퇴보하다, 후퇴하다', example_zh='如果不持续学习，技能会逐渐退步，跟不上时代。', example_ko='지속적으로 배우지 않으면 기술이 점점 퇴보해서 시대를 따라가지 못해.', example_pinyin='rú guǒ bù chí xù xué xí ， jì néng huì zhú jiàn tuì bù ， gēn bù shàng shí dài 。' WHERE chinese='退步' AND pinyin='tuì bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='퇴직하다, 은퇴하다', example_zh='她工作了三十五年后退休了，开始享受悠闲的生活。', example_ko='그녀는 35년간 일하고 퇴직해서 한가로운 생활을 즐기기 시작했어.', example_pinyin='tā gōng zuò le sān shí wǔ nián hòu tuì xiū le ， kāi shǐ xiǎng shòu yōu xián de shēng huó 。' WHERE chinese='退休' AND pinyin='tuì xiū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비뚤다, 바르지 않다', example_zh='那幅画挂歪了，帮我扶正一下吧。', example_ko='저 그림이 비뚤게 걸렸어, 바로잡아줘.', example_pinyin='nà fú huà guà wāi le ， bāng wǒ fú zhèng yī xià ba 。' WHERE chinese='歪' AND pinyin='wāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='외교', example_zh='这次外交访问对促进两国关系有重要意义。', example_ko='이번 외교 방문은 양국 관계 증진에 중요한 의미가 있어.', example_pinyin='zhè cì wài jiāo fǎng wèn duì cù jìn liǎng guó guān xì yǒu zhòng yào yì yì 。' WHERE chinese='外交' AND pinyin='wài jiāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='굽다, 구부러지다', example_zh='山路很弯，开车时要减速慢行，注意安全。', example_ko='산길이 굽이가 많아서 운전할 때 속도를 줄이고 천천히 가며 안전에 주의해야 해.', example_pinyin='shān lù hěn wān ， kāi chē shí yào jiǎn sù màn xíng ， zhù yì ān quán 。' WHERE chinese='弯' AND pinyin='wān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='완벽하다', example_zh='他对工作要求完美，每一个细节都不放过。', example_ko='그는 업무에 완벽함을 요구해서 모든 세부 사항을 빠뜨리지 않아.', example_pinyin='tā duì gōng zuò yāo qiú wán měi ， měi yí gè xì jié dōu bù fàng guò 。' WHERE chinese='完美' AND pinyin='wán měi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='완선하다, 개선하다', example_zh='公司正在完善服务体系，以提高客户满意度。', example_ko='회사는 고객 만족도를 높이기 위해 서비스 체계를 개선하고 있어.', example_pinyin='gōng sī zhèng zài wán shàn fú wù tǐ xì ， yǐ tí gāo kè hù mǎn yì dù 。' WHERE chinese='完善' AND pinyin='wán shàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='완전하다, 완벽하다', example_zh='这份报告内容完整，涵盖了所有需要讨论的问题。', example_ko='이 보고서는 내용이 완전해서 토론해야 할 모든 문제를 포함했어.', example_pinyin='zhè fèn bào gào nèi róng wán zhěng ， hán gài le suǒ yǒu xū yào tǎo lùn de wèn tí 。' WHERE chinese='完整' AND pinyin='wán zhěng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='장난감', example_zh='他给孩子买了很多玩具，但孩子最喜欢的还是那辆小汽车。', example_ko='그는 아이에게 장난감을 많이 사줬는데 아이가 가장 좋아하는 건 여전히 그 작은 자동차야.', example_pinyin='tā gěi hái zi mǎi le hěn duō wán jù ， dàn hái zi zuì xǐ huān de hái shì nà liàng xiǎo qì chē 。' WHERE chinese='玩具' AND pinyin='wán jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만일, 만약', example_zh='万一他不来，我们应该如何处理这个问题？', example_ko='만일 그가 오지 않으면 우리는 이 문제를 어떻게 처리해야 할까?', example_pinyin='wàn yī tā bù lái ， wǒ men yīng gāi rú hé chǔ lǐ zhè ge wèn tí ？' WHERE chinese='万一' AND pinyin='wàn yī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='왕자', example_zh='故事里的王子勇敢地打败了恶龙，救出了公主。', example_ko='이야기 속 왕자는 용감하게 악룡을 물리치고 공주를 구해냈어.', example_pinyin='gù shì lǐ de wáng zǐ yǒng gǎn dì dǎ bài le è lóng ， jiù chū le gōng zhǔ 。' WHERE chinese='王子' AND pinyin='wáng zǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='왕복하다, 오가다', example_zh='她每天往返于家和公司之间，单程需要一个小时。', example_ko='그녀는 매일 집과 회사를 오가는데 편도에 한 시간이 필요해.', example_pinyin='tā měi tiān wǎng fǎn yú jiā hé gōng sī zhī jiān ， dān chéng xū yào yí gè xiǎo shí 。' WHERE chinese='往返' AND pinyin='wǎng fǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미소 짓다; 미소', example_zh='她甜甜地微笑着，让周围的人都感到很温暖。', example_ko='그녀가 환하게 미소 지어서 주변 사람들을 모두 따뜻하게 만들어.', example_pinyin='tā tián tián dì wēi xiào zhe ， ràng zhōu wéi de rén dōu gǎn dào hěn wēn nuǎn 。' WHERE chinese='微笑' AND pinyin='wēi xiào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='위협하다; 위협', example_zh='黑客威胁说如果不付钱，就公开公司的机密数据。', example_ko='해커가 돈을 내지 않으면 회사의 기밀 데이터를 공개하겠다고 위협했어.', example_pinyin='hēi kè wēi xié shuō rú guǒ bù fù qián ， jiù gōng kāi gōng sī de jī mì shù jù 。' WHERE chinese='威胁' AND pinyin='wēi xié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='해치다, 해를 끼치다', example_zh='长期熬夜会危害健康，要注意调整作息。', example_ko='장기적인 야행은 건강을 해쳐서 생활 리듬을 조정해야 해.', example_pinyin='cháng qī áo yè huì wēi hài jiàn kāng ， yào zhù yì tiáo zhěng zuò xī 。' WHERE chinese='危害' AND pinyin='wēi hài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='위반하다', example_zh='他违反了交通规则，被警察罚款了。', example_ko='그는 교통 규칙을 위반해서 경찰에게 벌금을 받았어.', example_pinyin='tā wéi fǎn le jiāo tōng guī zé ， bèi jǐng chá fá kuǎn le 。' WHERE chinese='违反' AND pinyin='wéi fǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유지하다, 보호하다', example_zh='公司致力于维护良好的客户关系，确保长期合作。', example_ko='회사는 좋은 고객 관계 유지에 힘써서 장기 협력을 확보하고 있어.', example_pinyin='gōng sī zhì lì yú wéi hù liáng hǎo de kè hù guān xì ， què bǎo zhǎng qī hé zuò 。' WHERE chinese='维护' AND pinyin='wéi hù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='목도리, 스카프', example_zh='冬天出门时她总会戴上围巾，既保暖又好看。', example_ko='겨울에 외출할 때 그녀는 항상 목도리를 해서 따뜻하기도 하고 예뻐 보이기도 해.', example_pinyin='dōng tiān chū mén shí tā zǒng huì dài shàng wéi jīn ， jì bǎo nuǎn yòu hǎo kàn 。' WHERE chinese='围巾' AND pinyin='wéi jīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~을 중심으로, 둘러싸다', example_zh='这次讨论围绕着如何提高工作效率展开了热烈的交流。', example_ko='이번 토론은 업무 효율을 어떻게 높일지를 중심으로 열띤 교류가 이루어졌어.', example_pinyin='zhè cì tǎo lùn wéi rào zhe rú hé tí gāo gōng zuò xiào lǜ zhǎn kāi le rè liè de jiāo liú 。' WHERE chinese='围绕' AND pinyin='wéi rào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유일하다', example_zh='她是家里唯一的孩子，父母对她非常疼爱。', example_ko='그녀는 집에서 유일한 자녀야, 부모님이 그녀를 매우 아껴.', example_pinyin='tā shì jiā lǐ wéi yī de hái zi ， fù mǔ duì tā fēi cháng téng ài 。' WHERE chinese='唯一' AND pinyin='wéi yī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='꼬리', example_zh='那只小狗摇着尾巴，欢迎主人回家。', example_ko='그 강아지가 꼬리를 흔들면서 주인이 귀가하는 걸 반겼어.', example_pinyin='nà zhǐ xiǎo gǒu yáo zhe wěi ba ， huān yíng zhǔ rén huí jiā 。' WHERE chinese='尾巴' AND pinyin='wěi ba' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='위대하다', example_zh='他是一位伟大的科学家，为人类的发展做出了巨大贡献。', example_ko='그는 위대한 과학자야, 인류의 발전에 엄청난 기여를 했어.', example_pinyin='tā shì yī wèi wěi dà de kē xué jiā ， wéi rén lèi de fā zhǎn zuò chū le jù dà gòng xiàn 。' WHERE chinese='伟大' AND pinyin='wěi dà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='억울하다, 서럽다', example_zh='她被误会了，感到很委屈，忍不住流下了眼泪。', example_ko='그녀는 오해를 받아서 매우 억울하게 느껴서 참지 못하고 눈물을 흘렸어.', example_pinyin='tā bèi wù huì le ， gǎn dào hěn wěi qū ， rěn bú zhù liú xià le yǎn lèi 。' WHERE chinese='委屈' AND pinyin='wěi qu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='위탁하다, 맡기다', example_zh='他委托律师代理自己的案件，全权处理法律事务。', example_ko='그는 변호사에게 자신의 사건을 위탁해서 법률 사무를 전권 처리하게 했어.', example_pinyin='tā wěi tuō lǜ shī dài lǐ zì jǐ de àn jiàn ， quán quán chǔ lǐ fǎ lǜ shì wù 。' WHERE chinese='委托' AND pinyin='wěi tuō' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='위, 위장', example_zh='他的胃不太好，平时要注意饮食，少吃刺激性食物。', example_ko='그는 위가 별로 좋지 않아서 평소에 식단에 주의하고 자극적인 음식을 적게 먹어야 해.', example_pinyin='tā de wèi bù tài hǎo ， píng shí yào zhù yì yǐn shí ， shǎo chī cì jī xìng shí wù 。' WHERE chinese='胃' AND pinyin='wèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='위치, 자리', example_zh='请找好自己的位置，然后坐下，活动马上开始。', example_ko='자신의 자리를 찾은 다음 앉아주세요, 행사가 곧 시작돼요.', example_pinyin='qǐng zhǎo hǎo zì jǐ de wèi zhì ， rán hòu zuò xià ， huó dòng mǎ shàng kāi shǐ 。' WHERE chinese='位置' AND pinyin='wèi zhi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='반드시 ~한 건 아니다', example_zh='贵的东西未必好用，有时候实惠的选择更合适。', example_ko='비싼 게 반드시 잘 쓰이는 건 아니야, 때로는 실속 있는 선택이 더 적합해.', example_pinyin='guì de dōng xī wèi bì hǎo yòng ， yǒu shí hòu shí huì de xuǎn zé gèng hé shì 。' WHERE chinese='未必' AND pinyin='wèi bì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='미래', example_zh='他对未来充满了希望，相信只要努力就能成功。', example_ko='그는 미래에 대한 희망으로 가득 차 있어서 노력하면 성공할 수 있다고 믿어.', example_pinyin='tā duì wèi lái chōng mǎn le xī wàng ， xiāng xìn zhǐ yào nǔ lì jiù néng chéng gōng 。' WHERE chinese='未来' AND pinyin='wèi lái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='화장실', example_zh='请问卫生间在哪里？我需要洗手。', example_ko='화장실이 어디 있나요? 손을 씻어야 해서요.', example_pinyin='qǐng wèn wèi shēng jiān zài nǎ lǐ ？ wǒ xū yào xǐ shǒu 。' WHERE chinese='卫生间' AND pinyin='wèi shēng jiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='따뜻하다', example_zh='春天的阳光温暖而柔和，让人感到非常舒适。', example_ko='봄 햇살이 따뜻하고 부드러워서 매우 편안하게 느껴져.', example_pinyin='chūn tiān de yáng guāng wēn nuǎn ér róu hé ， ràng rén gǎn dào fēi cháng shū shì 。' WHERE chinese='温暖' AND pinyin='wēn nuǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='온화하다, 부드럽다', example_zh='她性格温柔，说话轻声细语，让人感到很舒服。', example_ko='그녀는 성격이 온화해서 말을 조용하고 부드럽게 해서 편안하게 느껴져.', example_pinyin='tā xìng gé wēn róu ， shuō huà qīng shēng xì yǔ ， ràng rén gǎn dào hěn shū fú 。' WHERE chinese='温柔' AND pinyin='wēn róu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='냄새를 맡다', example_zh='他一进厨房就闻到了饭菜的香味，肚子开始饿了。', example_ko='그는 주방에 들어가자마자 밥과 반찬의 향기를 맡아서 배가 고파지기 시작했어.', example_pinyin='tā yī jìn chú fáng jiù wén dào le fàn cài de xiāng wèi ， dǔ zi kāi shǐ è le 。' WHERE chinese='闻' AND pinyin='wén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서류, 파일', example_zh='请把所有相关文件发给我，我需要仔细审查。', example_ko='관련 서류를 모두 보내줘, 꼼꼼히 검토해야 해.', example_pinyin='qǐng bǎ suǒ yǒu xiāng guān wén jiàn fā gěi wǒ ， wǒ xū yào zǐ xì shěn chá 。' WHERE chinese='文件' AND pinyin='wén jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='문구, 학용품', example_zh='她去文具店买了一些笔和本子，准备开学用。', example_ko='그녀는 문구점에 가서 펜과 공책을 좀 사서 개학 준비를 했어.', example_pinyin='tā qù wén jù diàn mǎi le yī xiē bǐ hé běn zi ， zhǔn bèi kāi xué yòng 。' WHERE chinese='文具' AND pinyin='wén jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='문명, 문명화된', example_zh='文明社会要求公民遵守公共秩序，互相尊重。', example_ko='문명 사회는 시민들이 공중 질서를 지키고 서로 존중하기를 요구해.', example_pinyin='wén míng shè huì yāo qiú gōng mín zūn shǒu gōng gòng zhì xù ， hù xiāng zūn zhòng 。' WHERE chinese='文明' AND pinyin='wén míng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='문학', example_zh='她从小热爱文学，长大后成为了一名作家。', example_ko='그녀는 어릴 때부터 문학을 좋아해서 자라서 작가가 됐어.', example_pinyin='tā cóng xiǎo rè ài wén xué ， zhǎng dà hòu chéng wéi le yī míng zuò jiā 。' WHERE chinese='文学' AND pinyin='wén xué' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='키스하다; 키스', example_zh='他轻轻地吻了她的额头，表达了自己的深情。', example_ko='그는 그녀의 이마에 살며시 키스해서 자신의 깊은 정을 표현했어.', example_pinyin='tā qīng qīng dì wěn le tā de é tóu ， biǎo dá le zì jǐ de shēn qíng 。' WHERE chinese='吻' AND pinyin='wěn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='안정적이다', example_zh='他找到了一份稳定的工作，生活逐渐步入了正轨。', example_ko='그는 안정적인 직장을 찾아서 생활이 점차 정상 궤도에 올랐어.', example_pinyin='tā zhǎo dào le yī fèn wěn dìng de gōng zuò ， shēng huó zhú jiàn bù rù le zhèng guǐ 。' WHERE chinese='稳定' AND pinyin='wěn dìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='안부를 묻다, 인사하다', example_zh='出差回来后，他给同事们带了礼物，还向大家问候了一番。', example_ko='출장에서 돌아온 후 그는 동료들에게 선물을 사오고 모두에게 안부를 물었어.', example_pinyin='chū chāi huí lái hòu ， tā gěi tóng shì men dài le lǐ wù ， hái xiàng dà jiā wèn hòu le yī fān 。' WHERE chinese='问候' AND pinyin='wèn hòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='침실', example_zh='她把卧室装饰得很温馨，挂了很多照片和小摆件。', example_ko='그녀는 침실을 아늑하게 꾸며서 사진과 작은 장식품을 많이 걸었어.', example_pinyin='tā bǎ wò shì zhuāng shì dé hěn wēn xīn ， guà le hěn duō zhào piān hé xiǎo bǎi jiàn 。' WHERE chinese='卧室' AND pinyin='wò shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='방', example_zh='他住的屋子虽然小，但收拾得非常干净整洁。', example_ko='그가 사는 방은 작지만 매우 깔끔하게 정리되어 있어.', example_pinyin='tā zhù de wū zi suī rán xiǎo ， dàn shōu shí dé fēi cháng gān jìng zhěng jié 。' WHERE chinese='屋子' AND pinyin='wū zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어쩔 수 없다, 무력하다', example_zh='他无奈地接受了这个结果，虽然不甘心，但没有办法。', example_ko='그는 어쩔 수 없이 이 결과를 받아들였어, 억울하지만 방법이 없었어.', example_pinyin='tā wú nài dì jiē shòu le zhè ge jié guǒ ， suī rán bù gān xīn ， dàn méi yǒu bàn fǎ 。' WHERE chinese='无奈' AND pinyin='wú nài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='셀 수 없다, 무수히 많다', example_zh='夜空中有无数颗星星，让人心旷神怡。', example_ko='밤하늘에 셀 수 없이 많은 별이 있어서 마음이 탁 트여.', example_pinyin='yè kōng zhōng yǒu wú shù kē xīng xīng ， ràng rén xīn kuàng shén yí 。' WHERE chinese='无数' AND pinyin='wú shù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무기', example_zh='历史上，武器的发展改变了战争的面貌。', example_ko='역사상 무기의 발전은 전쟁의 양상을 바꿔놓았어.', example_pinyin='lì shǐ shàng ， wǔ qì de fā zhǎn gǎi biàn le zhàn zhēng de miàn mào 。' WHERE chinese='武器' AND pinyin='wǔ qì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무술', example_zh='中国武术历史悠久，是传统文化的重要组成部分。', example_ko='중국 무술은 역사가 유구해서 전통 문화의 중요한 구성 요소야.', example_pinyin='zhōng guó wǔ shù lì shǐ yōu jiǔ ， shì chuán tǒng wén huà de zhòng yào zǔ chéng bù fèn 。' WHERE chinese='武术' AND pinyin='wǔ shù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='안개', example_zh='今天早上雾很大，能见度非常低，开车要特别小心。', example_ko='오늘 아침 안개가 짙어서 시야가 매우 좋지 않아, 운전할 때 특히 조심해야 해.', example_pinyin='jīn tiān zǎo shàng wù hěn dà ， néng jiàn dù fēi cháng dī ， kāi chē yào tè bié xiǎo xīn 。' WHERE chinese='雾' AND pinyin='wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='물리학', example_zh='学好物理可以帮助理解自然界的各种现象。', example_ko='물리학을 잘 배우면 자연계의 다양한 현상을 이해하는 데 도움이 돼.', example_pinyin='xué hǎo wù lǐ kě yǐ bāng zhù lǐ jiě zì rán jiè de gè zhǒng xiàn xiàng 。' WHERE chinese='物理' AND pinyin='wù lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='물질', example_zh='物质生活的改善固然重要，但精神生活也不容忽视。', example_ko='물질 생활의 개선도 물론 중요하지만 정신 생활도 소홀히 해서는 안 돼.', example_pinyin='wù zhì shēng huó de gǎi shàn gù rán zhòng yào ， dàn jīng shén shēng huó yě bù róng hū shì 。' WHERE chinese='物质' AND pinyin='wù zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='흡수하다, 받아들이다', example_zh='他学习能力很强，能快速吸收新知识。', example_ko='그는 학습 능력이 강해서 새로운 지식을 빠르게 흡수할 수 있어.', example_pinyin='tā xué xí néng lì hěn qiáng ， néng kuài sù xī shōu xīn zhī shí 。' WHERE chinese='吸收' AND pinyin='xī shōu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='묶다; 계열, 학과', example_zh='他毕业于计算机系，现在在一家科技公司工作。', example_ko='그는 컴퓨터 학과를 졸업했어, 지금은 IT 회사에서 일해.', example_pinyin='tā bì yè yú jì suàn jī xì ， xiàn zài zài yī jiā kē jì gōng sī gōng zuò 。' WHERE chinese='系' AND pinyin='xì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시스템, 체계', example_zh='公司的管理系统需要升级，以提高效率和安全性。', example_ko='회사의 관리 시스템을 업그레이드해야 해서 효율과 보안을 높여야 해.', example_pinyin='gōng sī de guǎn lǐ xì tǒng xū yào shēng jí ， yǐ tí gāo xiào lǜ hé ān quán xìng 。' WHERE chinese='系统' AND pinyin='xì tǒng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='세부 사항, 디테일', example_zh='他做事非常注重细节，每一个小地方都处理得很好。', example_ko='그는 일할 때 세부 사항을 매우 중시해서 모든 작은 부분을 잘 처리해.', example_pinyin='tā zuò shì fēi cháng zhù zhòng xì jié ， měi yí gè xiǎo dì fāng dōu chǔ lǐ dé hěn hǎo 。' WHERE chinese='细节' AND pinyin='xì jié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연극, 드라마', example_zh='他很喜欢戏剧，周末经常去剧院看话剧。', example_ko='그는 연극을 매우 좋아해서 주말에 자주 극장에 가서 연극을 봐.', example_pinyin='tā hěn xǐ huān xì jù ， zhōu mò jīng cháng qù jù yuàn kàn huà jù 。' WHERE chinese='戏剧' AND pinyin='xì jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='눈이 멀다, 무턱대고', example_zh='不要瞎说，没有证据就不能随便指责别人。', example_ko='함부로 말하지 마, 증거도 없이 마음대로 다른 사람을 비난하면 안 돼.', example_pinyin='bú yào xiā shuō ， méi yǒu zhèng jù jiù bù néng suí biàn zhǐ zé bié rén 。' WHERE chinese='瞎' AND pinyin='xiā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='놀라다, 겁주다', example_zh='他突然出现在门口，吓了她一跳，她的心跳加速了。', example_ko='그가 갑자기 문 앞에 나타나서 그녀를 깜짝 놀라게 했어, 심장이 빨리 뛰었어.', example_pinyin='tā tū rán chū xiàn zài mén kǒu ， xià le tā yī tiào ， tā de xīn tiào jiā sù le 。' WHERE chinese='吓' AND pinyin='xià' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='내려받다, 다운로드하다', example_zh='请从官网下载最新版本的软件，以获得最佳体验。', example_ko='최상의 경험을 위해 공식 사이트에서 최신 버전의 소프트웨어를 다운로드해주세요.', example_pinyin='qǐng cóng guān wǎng xià zài zuì xīn bǎn běn de ruǎn jiàn ， yǐ huò dé zuì jiā tǐ yàn 。' WHERE chinese='下载' AND pinyin='xià zǎi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='선명하다, 밝다', example_zh='这件衣服的颜色非常鲜艳，在人群中很显眼。', example_ko='이 옷의 색이 매우 선명해서 군중 속에서 눈에 잘 띄어.', example_pinyin='zhè jiàn yī fú de yán sè fēi cháng xiān yàn ， zài rén qún zhōng hěn xiǎn yǎn 。' WHERE chinese='鲜艳' AND pinyin='xiān yàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~처럼 보이다', example_zh='他换了个发型，整个人显得年轻了很多。', example_ko='그는 헤어스타일을 바꾸니 전체적으로 훨씬 젊어 보여.', example_pinyin='tā huàn le gè fà xíng ， zhěng gè rén xiǎn de nián qīng le hěn duō 。' WHERE chinese='显得' AND pinyin='xiǎn de' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='명백하다, 분명하다', example_zh='显然，这个方案存在很多问题，需要进一步修改。', example_ko='명백히 이 방안에는 많은 문제가 있어서 더 수정해야 해.', example_pinyin='xiǎn rán ， zhè ge fāng àn cún zài hěn duō wèn tí ， xū yào jìn yí bù xiū gǎi 。' WHERE chinese='显然' AND pinyin='xiǎn rán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='표시하다, 보여주다', example_zh='屏幕上显示出了错误信息，系统需要重启。', example_ko='화면에 오류 메시지가 표시됐어, 시스템을 재부팅해야 해.', example_pinyin='píng mù shàng xiǎn shì chū le cuò wù xìn xī ， xì tǒng xū yào chóng qǐ 。' WHERE chinese='显示' AND pinyin='xiǎn shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='현, 군 (행정 구역)', example_zh='他的老家在一个偏远的县，交通不太方便。', example_ko='그의 고향은 외진 군에 있어서 교통이 그다지 편리하지 않아.', example_pinyin='tā de lǎo jiā zài yí gè piān yuǎn de xiàn ， jiāo tōng bù tài fāng biàn 。' WHERE chinese='县' AND pinyin='xiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='현금', example_zh='这家店只收现金，不支持刷卡或移动支付。', example_ko='이 가게는 현금만 받아서 카드나 모바일 결제를 지원하지 않아.', example_pinyin='zhè jiā diàn zhǐ shōu xiàn jīn ， bù zhī chí shuā kǎ huò yí dòng zhī fù 。' WHERE chinese='现金' AND pinyin='xiàn jīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='현실', example_zh='理想很美好，但现实往往是残酷的，需要脚踏实地。', example_ko='이상은 아름답지만 현실은 종종 냉혹해서 발을 땅에 딛고 있어야 해.', example_pinyin='lǐ xiǎng hěn měi hǎo ， dàn xiàn shí wǎng wǎng shì cán kù de ， xū yào jiǎo tà shí dì 。' WHERE chinese='现实' AND pinyin='xiàn shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='현상', example_zh='这是一个普遍的社会现象，很多国家都面临同样的问题。', example_ko='이건 보편적인 사회 현상이야, 많은 나라가 같은 문제를 안고 있어.', example_pinyin='zhè shì yí gè pǔ biàn de shè huì xiàn xiàng ， hěn duō guó jiā dōu miàn lín tóng yàng de wèn tí 。' WHERE chinese='现象' AND pinyin='xiàn xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='함께 지내다, 사귀다', example_zh='他们在一起相处了很多年，彼此非常了解。', example_ko='그들은 오랫동안 함께 지내서 서로를 매우 잘 알아.', example_pinyin='tā men zài yì qǐ xiāng chǔ le hěn duō nián ， bǐ cǐ fēi cháng liǎo jiě 。' WHERE chinese='相处' AND pinyin='xiāng chǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상당히, 꽤; 맞다', example_zh='这道菜的味道相当不错，值得再来吃一次。', example_ko='이 음식의 맛이 상당히 괜찮아서 또 먹으러 올 만해.', example_pinyin='zhè dào cài de wèi dào xiāng dāng bù cuò ， zhí de zài lái chī yī cì 。' WHERE chinese='相当' AND pinyin='xiāng dāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상대적이다', example_zh='这件事的难度是相对的，对他来说难，对我来说可能简单。', example_ko='이 일의 난이도는 상대적이야, 그에게는 어렵지만 나에게는 쉬울 수도 있어.', example_pinyin='zhè jiàn shì de nán dù shì xiāng duì de ， duì tā lái shuō nán ， duì wǒ lái shuō kě néng jiǎn dān 。' WHERE chinese='相对' AND pinyin='xiāng duì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='관련되다', example_zh='这件事与他相关，请通知他参加这次会议。', example_ko='이 일은 그와 관련이 있어서 그에게 이번 회의에 참가하라고 통보해줘.', example_pinyin='zhè jiàn shì yǔ tā xiāng guān ， qǐng tōng zhī tā cān jiā zhè cì huì yì 。' WHERE chinese='相关' AND pinyin='xiāng guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비슷하다, 유사하다', example_zh='这两件衣服款式相似，但价格差了很多。', example_ko='이 두 옷은 스타일이 비슷하지만 가격 차이가 많이 나.', example_pinyin='zhè liǎng jiàn yī fú kuǎn shì xiāng sì ， dàn jià gé chà le hěn duō 。' WHERE chinese='相似' AND pinyin='xiāng sì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그리워하다, 보고 싶다', example_zh='他在外地工作，非常想念家人，每周都要打电话报平安。', example_ko='그는 타지에서 일하면서 가족이 매우 보고 싶어서 매주 전화해서 안부를 전해.', example_pinyin='tā zài wài dì gōng zuò ， fēi cháng xiǎng niàn jiā rén ， měi zhōu dōu yào dǎ diàn huà bào píng ān 。' WHERE chinese='想念' AND pinyin='xiǎng niàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상상하다', example_zh='他脑子里有很强的想象力，总是能想出别人想不到的方案。', example_ko='그는 상상력이 매우 풍부해서 항상 다른 사람이 생각하지 못하는 방안을 생각해내.', example_pinyin='tā nǎo zi lǐ yǒu hěn qiáng de xiǎng xiàng lì ， zǒng shì néng xiǎng chū bié rén xiǎng bú dào de fāng àn 。' WHERE chinese='想象' AND pinyin='xiǎng xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='즐기다, 누리다', example_zh='退休后，他每天享受着悠闲的生活，非常开心。', example_ko='퇴직 후 그는 매일 한가로운 생활을 즐기며 매우 기뻐해.', example_pinyin='tuì xiū hòu ， tā měi tiān xiǎng shòu zhe yōu xián de shēng huó ， fēi cháng kāi xīn 。' WHERE chinese='享受' AND pinyin='xiǎng shòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='항목, 조항 (양사)', example_zh='这份合同共有十项条款，每一项都需要仔细阅读。', example_ko='이 계약서에는 총 10개 조항이 있어서 모든 항목을 꼼꼼히 읽어야 해.', example_pinyin='zhè fèn hé tóng gòng yǒu shí xiàng tiáo kuǎn ， měi yī xiàng dōu xū yào zǐ xì yuè dú 。' WHERE chinese='项' AND pinyin='xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='목걸이', example_zh='她戴着一条精美的项链，在阳光下闪闪发光。', example_ko='그녀는 정교한 목걸이를 하고 있는데 햇빛 아래 반짝반짝 빛나.', example_pinyin='tā dài zhe yī tiáo jīng měi de xiàng liàn ， zài yáng guāng xià shǎn shǎn fā guāng 。' WHERE chinese='项链' AND pinyin='xiàng liàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='프로젝트, 항목', example_zh='这个项目需要三个部门合作，预计三个月完成。', example_ko='이 프로젝트는 세 부서가 협력해야 하는데 3개월 안에 완성될 예정이야.', example_pinyin='zhè ge xiàng mù xū yào sān gè bù mén hé zuò ， yù jì sān gè yuè wán chéng 。' WHERE chinese='项目' AND pinyin='xiàng mù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지우개', example_zh='他用橡皮把写错的字擦掉，重新写了一遍。', example_ko='그는 지우개로 잘못 쓴 글자를 지우고 다시 한번 썼어.', example_pinyin='tā yòng xiàng pí bǎ xiě cuò de zì cā diào ， chóng xīn xiě le yī biàn 。' WHERE chinese='橡皮' AND pinyin='xiàng pí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='장기 (보드게임)', example_zh='他的爷爷很喜欢下象棋，每天和邻居对弈两局。', example_ko='그의 할아버지는 장기 두는 걸 매우 좋아해서 매일 이웃과 두 판을 둬.', example_pinyin='tā de yé yé hěn xǐ huān xià xiàng qí ， měi tiān hé lín jū duì yì liǎng jú 。' WHERE chinese='象棋' AND pinyin='xiàng qí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상징하다; 상징', example_zh='龙在中国文化中象征着力量和好运。', example_ko='용은 중국 문화에서 힘과 행운을 상징해.', example_pinyin='lóng zài zhōng guó wén huà zhōng xiàng zhēng zhuó lì liàng hé hǎo yùn 。' WHERE chinese='象征' AND pinyin='xiàng zhēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소비하다; 소비', example_zh='年轻人消费能力越来越强，推动了市场的繁荣。', example_ko='젊은이들의 소비 능력이 점점 강해져서 시장의 번영을 촉진해.', example_pinyin='nián qīng rén xiāo fèi néng lì yuè lái yuè qiáng ， tuī dòng le shì chǎng de fán róng 。' WHERE chinese='消费' AND pinyin='xiāo fèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소화하다', example_zh='饭后适当散步有助于消化，对胃肠道有好处。', example_ko='식사 후 적당히 산책하면 소화를 돕고 소화기관에 좋아.', example_pinyin='fàn hòu shì dàng sàn bù yǒu zhù yú xiāo huà ， duì wèi cháng dào yǒu hǎo chù 。' WHERE chinese='消化' AND pinyin='xiāo huà' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소멸하다, 없애다', example_zh='新技术的出现消灭了很多传统行业，但也创造了新的机会。', example_ko='새로운 기술의 등장은 많은 전통 업계를 소멸시켰지만 새로운 기회도 만들었어.', example_pinyin='xīn jì shù de chū xiàn xiāo miè le hěn duō chuán tǒng háng yè ， dàn yě chuàng zào le xīn de jī huì 。' WHERE chinese='消灭' AND pinyin='xiāo miè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='사라지다', example_zh='那辆车拐过街角，慢慢消失在人群中。', example_ko='그 차가 길모퉁이를 돌아서 천천히 사람들 사이로 사라졌어.', example_pinyin='nà liàng chē guǎi guò jiē jiǎo ， màn màn xiāo shī zài rén qún zhōng 。' WHERE chinese='消失' AND pinyin='xiāo shī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='판매하다; 판매', example_zh='公司决定扩大销售网络，进入更多城市的市场。', example_ko='회사는 판매망을 확대해서 더 많은 도시 시장에 진출하기로 결정했어.', example_pinyin='gōng sī jué dìng kuò dà xiāo shòu wǎng luò ， jìn rù gèng duō chéng shì de shì chǎng 。' WHERE chinese='销售' AND pinyin='xiāo shòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='길거리 음식, 간식', example_zh='他特别喜欢吃小吃，每到一个新城市都要尝当地的美食。', example_ko='그는 길거리 음식을 특히 좋아해서 새로운 도시에 갈 때마다 현지 음식을 맛봐.', example_pinyin='tā tè bié xǐ huān chī xiǎo chī ， měi dào yí gè xīn chéng shì dōu yào cháng dāng dì de měi shí 。' WHERE chinese='小吃' AND pinyin='xiǎo chī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='젊은 남자, 청년', example_zh='那个小伙子很有礼貌，主动帮老人搬行李。', example_ko='그 젊은 남자는 예의가 바라서 먼저 나서서 노인의 짐을 옮겨줬어.', example_pinyin='nà ge xiǎo huǒ zi hěn yǒu lǐ mào ， zhǔ dòng bāng lǎo rén bān xíng lǐ 。' WHERE chinese='小伙子' AND pinyin='xiǎo huǒ zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='밀', example_zh='中国北方以小麦为主要粮食，南方以水稻为主。', example_ko='중국 북부는 밀이 주요 식량이고 남부는 쌀이 주요 식량이야.', example_pinyin='zhōng guó běi fāng yǐ xiǎo mài wéi zhǔ yào liáng shí ， nán fāng yǐ shuǐ dào wéi zhǔ 。' WHERE chinese='小麦' AND pinyin='xiǎo mài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='인색하다, 소심하다', example_zh='他很小气，从来不肯请朋友吃饭，大家都不喜欢他。', example_ko='그는 인색해서 친구에게 밥을 사주는 법이 없어서 다들 그를 좋아하지 않아.', example_pinyin='tā hěn xiǎo qì ， cóng lái bù kěn qǐng péng yǒu chī fàn ， dà jiā dōu bù xǐ huān tā 。' WHERE chinese='小气' AND pinyin='xiǎo qì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='도둑', example_zh='小偷在拥挤的地铁里偷了他的钱包，他没有注意到。', example_ko='도둑이 붐비는 지하철에서 그의 지갑을 훔쳤는데 그는 눈치채지 못했어.', example_pinyin='xiǎo tōu zài yōng jǐ de dì tiě lǐ tōu le tā de qián bāo ， tā méi yǒu zhù yì dào 。' WHERE chinese='小偷' AND pinyin='xiǎo tōu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='효율', example_zh='合理安排时间可以大幅提高工作效率。', example_ko='시간을 합리적으로 배분하면 업무 효율을 크게 높일 수 있어.', example_pinyin='hé lǐ ān pái shí jiān kě yǐ dà fú tí gāo gōng zuò xiào lǜ 。' WHERE chinese='效率' AND pinyin='xiào lǜ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='효도하다, 부모님께 잘 하다', example_zh='他非常孝顺，每逢节假日都会回家陪父母。', example_ko='그는 매우 효성스러워서 명절마다 집에 돌아가서 부모님 곁에 있어.', example_pinyin='tā fēi cháng xiào shùn ， měi féng jié jià rì dū huì huí jiā péi fù mǔ 。' WHERE chinese='孝顺' AND pinyin='xiào shùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쉬다, 잠시 멈추다', example_zh='工作了三个小时，他出去歇了一会儿，喝了杯咖啡。', example_ko='3시간을 일하고 나서 그는 잠깐 쉬러 나갔다가 커피 한 잔을 마셨어.', example_pinyin='gōng zuò le sān gè xiǎo shí ， tā chū qù xiē le yī huì er ， hē le bēi kā fēi 。' WHERE chinese='歇' AND pinyin='xiē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='비스듬하다, 기울다', example_zh='那棵大树因为风吹得有些斜，需要加固支撑。', example_ko='그 큰 나무가 바람에 좀 기울어서 지지대를 보강해야 해.', example_pinyin='nà kē dà shù yīn wèi fēng chuī dé yǒu xiē xié ， xū yào jiā gù zhī chēng 。' WHERE chinese='斜' AND pinyin='xié' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='협조하다, 조화를 이루다', example_zh='各部门需要相互协调，才能保证项目按时完成。', example_ko='각 부서가 서로 협조해야 프로젝트가 제때 완성될 수 있어.', example_pinyin='gè bù mén xū yào xiāng hù xié tiáo ， cái néng bǎo zhèng xiàng mù àn shí wán chéng 。' WHERE chinese='协调' AND pinyin='xié tiáo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='심리', example_zh='他的心理状态很好，面对压力时总是保持冷静。', example_ko='그의 심리 상태는 좋아서 압박을 받을 때 항상 침착함을 유지해.', example_pinyin='tā de xīn lǐ zhuàng tài hěn hǎo ， miàn duì yā lì shí zǒng shì bǎo chí lěng jìng 。' WHERE chinese='心理' AND pinyin='xīn lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='심장', example_zh='心脏是人体最重要的器官之一，要注意保护心脏健康。', example_ko='심장은 인체에서 가장 중요한 기관 중 하나야, 심장 건강 보호에 주의해야 해.', example_pinyin='xīn zàng shì rén tǐ zuì zhòng yào de qì guān zhī yī ， yào zhù yì bǎo hù xīn zàng jiàn kāng 。' WHERE chinese='心脏' AND pinyin='xīn zàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감상하다, 즐기다', example_zh='他喜欢在周末欣赏音乐会，陶冶情操。', example_ko='그는 주말에 음악회를 감상하는 걸 좋아해서 정서를 함양해.', example_pinyin='tā xǐ huān zài zhōu mò xīn shǎng yīn yuè huì ， táo yě qíng cāo 。' WHERE chinese='欣赏' AND pinyin='xīn shǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='봉투', example_zh='他把信放进信封里，写好地址，然后寄了出去。', example_ko='그는 편지를 봉투에 넣고 주소를 적은 다음 부쳤어.', example_pinyin='tā bǎ xìn fàng jìn xìn fēng lǐ ， xiě hǎo dì zhǐ ， rán hòu jì le chū qù 。' WHERE chinese='信封' AND pinyin='xìn fēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신호', example_zh='红绿灯是交通信号，所有司机都必须遵守。', example_ko='신호등은 교통 신호야, 모든 운전자는 반드시 지켜야 해.', example_pinyin='hóng lǜ dēng shì jiāo tōng xìn hào ， suǒ yǒu sī jī dōu bì xū zūn shǒu 。' WHERE chinese='信号' AND pinyin='xìn hào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정보, 소식', example_zh='现代社会信息传递非常快，任何新闻几乎都是实时更新的。', example_ko='현대 사회에서 정보 전달이 매우 빨라서 어떤 뉴스든 거의 실시간으로 업데이트돼.', example_pinyin='xiàn dài shè huì xìn xī chuán dì fēi cháng kuài ， rèn hé xīn wén jī hū dōu shì shí shí gēng xīn de 。' WHERE chinese='信息' AND pinyin='xìn xī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='행동, 활동하다', example_zh='紧急情况下，要迅速行动，不能犹豫不决。', example_ko='긴급 상황에서는 신속하게 행동해야 해, 우물쭈물하면 안 돼.', example_pinyin='jǐn jí qíng kuàng xià ， yào xùn sù xíng dòng ， bù néng yóu yù bù jué 。' WHERE chinese='行动' AND pinyin='xíng dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보행자', example_zh='请注意行人，在人行横道前要礼让行人通过。', example_ko='보행자에 주의해주세요, 횡단보도 앞에서는 보행자를 먼저 지나가게 해야 해.', example_pinyin='qǐng zhù yì xíng rén ， zài rén xíng héng dào qián yào lǐ ràng xíng rén tōng guò 。' WHERE chinese='行人' AND pinyin='xíng rén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='행위, 행동', example_zh='他的行为影响了整个团队，大家对此非常不满。', example_ko='그의 행위가 팀 전체에 영향을 줘서 모두 이에 매우 불만을 가지고 있어.', example_pinyin='tā de xíng wéi yǐng xiǎng le zhěng gè tuán duì ， dà jiā duì cǐ fēi cháng bù mǎn 。' WHERE chinese='行为' AND pinyin='xíng wéi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='형성하다', example_zh='良好的学习习惯需要从小开始培养，逐渐形成。', example_ko='좋은 학습 습관은 어릴 때부터 길러서 점차 형성해야 해.', example_pinyin='liáng hǎo de xué xí xí guàn xū yào cóng xiǎo kāi shǐ péi yǎng ， zhú jiàn xíng chéng 。' WHERE chinese='形成' AND pinyin='xíng chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='형용하다, 묘사하다', example_zh='他用"美丽"来形容那片风景，但感觉还不够贴切。', example_ko='그는 "아름답다"는 말로 그 경치를 묘사했는데 딱 들어맞지 않는 것 같기도 해.', example_pinyin='tā yòng " měi lì " lái xíng róng nà piàn fēng jǐng ， dàn gǎn jué hái bù gòu tiē qiè 。' WHERE chinese='形容' AND pinyin='xíng róng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='형식', example_zh='这次会议的形式是小组讨论，每组五人。', example_ko='이번 회의의 형식은 소그룹 토론이야, 각 그룹이 5명이야.', example_pinyin='zhè cì huì yì de xíng shì shì xiǎo zǔ tǎo lùn ， měi zǔ wǔ rén 。' WHERE chinese='形式' AND pinyin='xíng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정세, 형세', example_zh='目前的形势对我们有利，要抓住机会大胆行动。', example_ko='현재의 정세는 우리에게 유리해서 기회를 잡고 과감하게 행동해야 해.', example_pinyin='mù qián de xíng shì duì wǒ men yǒu lì ， yào zhuā zhù jī huì dà dǎn xíng dòng 。' WHERE chinese='形势' AND pinyin='xíng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='형상, 이미지', example_zh='这个品牌的形象一直很正面，深受消费者的信赖。', example_ko='이 브랜드의 이미지는 항상 긍정적이어서 소비자들의 신뢰를 많이 받아.', example_pinyin='zhè ge pǐn pái de xíng xiàng yì zhí hěn zhèng miàn ， shēn shòu xiāo fèi zhě de xìn lài 。' WHERE chinese='形象' AND pinyin='xíng xiàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='모양, 형태', example_zh='这块石头的形状很特别，像一只正在飞翔的鸟。', example_ko='이 돌의 모양이 특별해서 날아오르는 새처럼 생겼어.', example_pinyin='zhè kuài shí tou de xíng zhuàng hěn tè bié ， xiàng yī zhī zhèng zài fēi xiáng de niǎo 。' WHERE chinese='形状' AND pinyin='xíng zhuàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='성질, 성격', example_zh='这件事的性质很严重，需要认真对待，不能马虎。', example_ko='이 일의 성질이 매우 심각해서 진지하게 대처해야 해, 대충 해서는 안 돼.', example_pinyin='zhè jiàn shì de xìng zhì hěn yán zhòng ， xū yào rèn zhēn duì dài ， bù néng mǎ hǔ 。' WHERE chinese='性质' AND pinyin='xìng zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='다행히', example_zh='幸亏他提醒了我，不然我就忘了带证件。', example_ko='다행히 그가 나에게 알려줘서 안 그랬으면 증명서 챙기는 걸 잊어버릴 뻔했어.', example_pinyin='xìng kuī tā tí xǐng le wǒ ， bù rán wǒ jiù wàng le dài zhèng jiàn 。' WHERE chinese='幸亏' AND pinyin='xìng kuī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운이 좋다', example_zh='他很幸运，在关键时刻遇到了贵人相助。', example_ko='그는 운이 좋아서 결정적인 순간에 좋은 사람의 도움을 만났어.', example_pinyin='tā hěn xìng yùn ， zài guān jiàn shí kè yù dào le guì rén xiāng zhù 。' WHERE chinese='幸运' AND pinyin='xìng yùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가슴', example_zh='他深吸一口气，感到胸口舒畅多了。', example_ko='그는 심호흡을 한 번 하고 나니 가슴이 훨씬 시원해졌어.', example_pinyin='tā shēn xī yì kǒu qì ， gǎn dào xiōng kǒu shū chàng duō le 。' WHERE chinese='胸' AND pinyin='xiōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='형제', example_zh='他们兄弟俩感情很好，无论发生什么都互相支持。', example_ko='그들 형제는 사이가 정말 좋아서 무슨 일이 있어도 서로 지지해.', example_pinyin='tā men xiōng dì liǎ gǎn qíng hěn hǎo ， wú lùn fā shēng shén me dōu hù xiāng zhī chí 。' WHERE chinese='兄弟' AND pinyin='xiōng dì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='웅장하다, 우뚝 서다', example_zh='这座山雄伟壮观，山顶终年积雪，吸引了无数登山者。', example_ko='이 산은 웅장하고 장관이야, 산꼭대기에 일 년 내내 눈이 쌓여 있어서 수많은 등산객을 끌어들여.', example_pinyin='zhè zuò shān xióng wěi zhuàng guān ， shān dǐng zhōng nián jī xuě ， xī yǐn liǎo wú shù dēng shān zhě 。' WHERE chinese='雄伟' AND pinyin='xióng wěi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수정하다, 고치다', example_zh='他仔细修改了报告，删去了一些不必要的内容。', example_ko='그는 보고서를 꼼꼼히 수정해서 불필요한 내용 일부를 삭제했어.', example_pinyin='tā zǐ xì xiū gǎi le bào gào ， shān qù le yī xiē bù bì yào de nèi róng 。' WHERE chinese='修改' AND pinyin='xiū gǎi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='여가를 즐기다', example_zh='他平时喜欢休闲活动，比如钓鱼和爬山。', example_ko='그는 평소에 여가 활동을 좋아해서 낚시나 등산 같은 거야.', example_pinyin='tā píng shí xǐ huān xiū xián huó dòng ， bǐ rú diào yú hé pá shān 。' WHERE chinese='休闲' AND pinyin='xiū xián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='겸손하다, 열린 마음으로 배우다', example_zh='学习时要保持虚心的态度，不耻下问。', example_ko='공부할 때 겸손한 태도를 유지해야 해, 아랫사람에게 배우기를 부끄러워해서는 안 돼.', example_pinyin='xué xí shí yào bǎo chí xū xīn de tài dù ， bù chǐ xià wèn 。' WHERE chinese='虚心' AND pinyin='xū xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='서술하다, 이야기하다', example_zh='他详细叙述了事情的经过，让大家明白了发生了什么。', example_ko='그는 사건의 경위를 자세히 서술해서 모두가 무슨 일이 있었는지 이해하게 했어.', example_pinyin='tā xiáng xì xù shù liǎo shì qíng de jīng guò ， ràng dà jiā míng bái le fā shēng le shén me 。' WHERE chinese='叙述' AND pinyin='xù shù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='선포하다, 발표하다', example_zh='公司宣布了新的合并计划，消息一出，股价立刻上涨。', example_ko='회사가 새로운 합병 계획을 선포했는데 소식이 나오자마자 주가가 즉시 올랐어.', example_pinyin='gōng sī xuān bù le xīn de hé bìng jì huà ， xiāo xī yī chū ， gǔ jià lì kè shàng zhǎng 。' WHERE chinese='宣布' AND pinyin='xuān bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='홍보하다, 선전하다', example_zh='他们通过社交媒体宣传产品，吸引了大量年轻用户。', example_ko='그들은 소셜 미디어를 통해 제품을 홍보해서 많은 젊은 이용자를 유치했어.', example_pinyin='tā men tōng guò shè jiāo méi tǐ xuān chuán chǎn pǐn ， xī yǐn le dà liàng nián qīng yòng hù 。' WHERE chinese='宣传' AND pinyin='xuān chuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='선거하다; 선거', example_zh='民主国家的政府是由公民通过选举产生的。', example_ko='민주 국가의 정부는 시민들이 선거를 통해 만들어.', example_pinyin='mín zhǔ guó jiā de zhèng fǔ shì yóu gōng mín tōng guò xuǎn jǔ chǎn shēng de 。' WHERE chinese='选举' AND pinyin='xuǎn jǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='학기', example_zh='这个学期他选了五门课，每天都很忙。', example_ko='이번 학기에 그는 다섯 과목을 수강해서 매일 매우 바빠.', example_pinyin='zhè ge xué qī tā xuǎn le wǔ mén kè ， měi tiān dōu hěn máng 。' WHERE chinese='学期' AND pinyin='xué qī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='학술적인', example_zh='他参加了多次国际学术会议，与世界各地的专家交流。', example_ko='그는 여러 차례 국제 학술 회의에 참가해서 세계 각지의 전문가들과 교류했어.', example_pinyin='tā cān jiā le duō cì guó jì xué shù huì yì ， yǔ shì jiè gè dì de zhuān jiā jiāo liú 。' WHERE chinese='学术' AND pinyin='xué shù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='학문, 지식', example_zh='他学问渊博，无论什么领域都有深入的研究。', example_ko='그는 학문이 해박해서 어떤 분야든 깊이 연구하고 있어.', example_pinyin='tā xué wèn yuān bó ， wú lùn shén me lǐng yù dōu yǒu shēn rù de yán jiū 。' WHERE chinese='学问' AND pinyin='xué wèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='찾다, 구하다', example_zh='他在图书馆寻找关于这个课题的参考资料。', example_ko='그는 도서관에서 이 주제에 관한 참고 자료를 찾고 있어.', example_pinyin='tā zài tú shū guǎn xún zhǎo guān yú zhè ge kè tí de cān kǎo zī liào 。' WHERE chinese='寻找' AND pinyin='xún zhǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='문의하다', example_zh='如果有任何疑问，请随时向我们的客服人员询问。', example_ko='어떤 궁금한 점이 있으시면 언제든지 고객 서비스 담당자에게 문의하세요.', example_pinyin='rú guǒ yǒu rèn hé yí wèn ， qǐng suí shí xiàng wǒ men de kè fú rén yuán xún wèn 。' WHERE chinese='询问' AND pinyin='xún wèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='훈련하다; 훈련', example_zh='他每天坚持训练，体能和技巧都有了很大提升。', example_ko='그는 매일 꾸준히 훈련해서 체력과 기술이 크게 향상됐어.', example_pinyin='tā měi tiān jiān chí xùn liàn ， tǐ néng hé jì qiǎo dōu yǒu le hěn dà tí shēng 。' WHERE chinese='训练' AND pinyin='xùn liàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='신속하다, 빠르다', example_zh='他迅速做出了判断，避免了更大的损失。', example_ko='그는 신속하게 판단을 내려서 더 큰 손실을 막았어.', example_pinyin='tā xùn sù zuò chū le pàn duàn ， bì miǎn le gèng dà de sǔn shī 。' WHERE chinese='迅速' AND pinyin='xùn sù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연장하다', example_zh='由于特殊情况，这次展览的时间延长了一个星期。', example_ko='특수한 상황으로 인해 이번 전시 기간이 일주일 연장됐어.', example_pinyin='yóu yú tè shū qíng kuàng ， zhè cì zhǎn lǎn de shí jiān yán cháng le yí gè xīng qī 。' WHERE chinese='延长' AND pinyin='yán cháng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='엄숙하다, 진지하다', example_zh='他的表情非常严肃，让大家知道这件事情很重要。', example_ko='그의 표정이 매우 엄숙해서 모두 이 일이 중요하다는 걸 알았어.', example_pinyin='tā de biǎo qíng fēi cháng yán sù ， ràng dà jiā zhī dào zhè jiàn shì qíng hěn zhòng yào 。' WHERE chinese='严肃' AND pinyin='yán sù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='연회, 파티', example_zh='公司每年都会举办年终宴会，庆祝一年来的成就。', example_ko='회사는 매년 연말 연회를 열어서 한 해의 성취를 축하해.', example_pinyin='gōng sī měi nián dū huì jǔ bàn nián zhōng yàn huì ， qìng zhù yī nián lái de chéng jiù 。' WHERE chinese='宴会' AND pinyin='yàn huì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='베란다, 발코니', example_zh='她喜欢在阳台上种花，每天给它们浇水。', example_ko='그녀는 베란다에서 꽃을 키우는 걸 좋아해서 매일 물을 줘.', example_pinyin='tā xǐ huān zài yáng tái shàng zhòng huā ， měi tiān gěi tā men jiāo shuǐ 。' WHERE chinese='阳台' AND pinyin='yáng tái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가렵다', example_zh='被蚊子咬了之后，皮肤一直很痒，忍不住想抓。', example_ko='모기에 물린 후 피부가 계속 가려워서 참지 못하고 긁고 싶어.', example_pinyin='bèi wén zi yǎo le zhī hòu ， pí fū yì zhí hěn yǎng ， rěn bú zhù xiǎng zhuā 。' WHERE chinese='痒' AND pinyin='yǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='스타일, 형태', example_zh='这款手机有多种颜色和样式，你可以根据喜好选择。', example_ko='이 스마트폰은 다양한 색상과 스타일이 있어서 좋아하는 걸 골라.', example_pinyin='zhè kuǎn shǒu jī yǒu duō zhǒng yán sè hé yàng shì ， nǐ kě yǐ gēn jù xǐ hào xuǎn zé 。' WHERE chinese='样式' AND pinyin='yàng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='허리', example_zh='他长时间坐在电脑前，腰疼得很厉害，需要多休息。', example_ko='그는 오랫동안 컴퓨터 앞에 앉아서 허리가 많이 아파서 더 쉬어야 해.', example_pinyin='tā zhǎng shí jiān zuò zài diàn nǎo qián ， yāo téng dé hěn lì hài ， xū yào duō xiū xī 。' WHERE chinese='腰' AND pinyin='yāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='흔들다, 흔들리다', example_zh='地震时，地面和建筑物都在剧烈摇晃。', example_ko='지진이 일어날 때 지면과 건물이 모두 격렬하게 흔들렸어.', example_pinyin='dì zhèn shí ， dì miàn hé jiàn zhù wù dōu zài jù liè yáo huàng 。' WHERE chinese='摇' AND pinyin='yáo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='물다, 깨물다', example_zh='那条狗咬了他的脚踝，他立刻去医院处理伤口。', example_ko='그 개가 그의 발목을 물어서 그는 즉시 병원에 가서 상처를 처리했어.', example_pinyin='nà tiáo gǒu yǎo le tā de jiǎo huái ， tā lì kè qù yī yuàn chǔ lǐ shāng kǒu 。' WHERE chinese='咬' AND pinyin='yǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~하지 않으면; 아니면', example_zh='你要么现在去，要不就明天再说吧。', example_ko='지금 가든지 아니면 내일 다시 얘기하자.', example_pinyin='nǐ yào me xiàn zài qù ， yào bù jiù míng tiān zài shuō ba 。' WHERE chinese='要不' AND pinyin='yào bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='만약, 만일', example_zh='要是明天天气好，我们就去郊外野餐。', example_ko='만약 내일 날씨가 좋으면 우리는 교외로 소풍 가자.', example_pinyin='yào shì míng tiān tiān qì hǎo ， wǒ men jiù qù jiāo wài yě cān 。' WHERE chinese='要是' AND pinyin='yào shi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='밤', example_zh='深夜里，他还在努力工作，准备明天的演讲。', example_ko='깊은 밤에도 그는 열심히 일하면서 내일 연설을 준비하고 있었어.', example_pinyin='shēn yè lǐ ， tā hái zài nǔ lì gōng zuò ， zhǔn bèi míng tiān de yǎn jiǎng 。' WHERE chinese='夜' AND pinyin='yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='액체', example_zh='在化学实验中，液体的体积用量筒来测量。', example_ko='화학 실험에서 액체의 부피는 메스실린더로 측정해.', example_pinyin='zài huà xué shí yàn zhōng ， yè tǐ de tǐ jī yòng liáng tǒng lái cè liáng 。' WHERE chinese='液体' AND pinyin='yè tǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='업무, 비즈니스', example_zh='他的工作业务范围很广，包括市场调研和客户管理。', example_ko='그의 업무 범위가 매우 넓어서 시장 조사와 고객 관리를 포함해.', example_pinyin='tā de gōng zuò yè wù fàn wéi hěn guǎng ， bāo kuò shì chǎng diào yán hé kè hù guǎn lǐ 。' WHERE chinese='业务' AND pinyin='yè wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아마추어의, 여가의', example_zh='她是个业余画家，画画只是她的爱好，不是职业。', example_ko='그녀는 아마추어 화가야, 그림 그리기는 그녀의 취미일 뿐이고 직업이 아니야.', example_pinyin='tā shì gè yè yú huà jiā ， huà huà zhǐ shì tā de ài hào ， bú shì zhí yè 。' WHERE chinese='业余' AND pinyin='yè yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='여전히, 여전하다', example_zh='虽然分开了很多年，他们依然保持着联系。', example_ko='비록 수년간 떨어져 있었지만 그들은 여전히 연락을 유지하고 있어.', example_pinyin='suī rán fēn kāi le hěn duō nián ， tā men yī rán bǎo chí zhe lián xì 。' WHERE chinese='依然' AND pinyin='yī rán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평생, 일생', example_zh='他把一辈子的时间都花在了研究上，取得了很多成就。', example_ko='그는 평생의 시간을 연구에 쏟아서 많은 성과를 거뒀어.', example_pinyin='tā bǎ yī bèi zi de shí jiān dōu huā zài le yán jiū shàng ， qǔ dé le hěn duō chéng jiù 。' WHERE chinese='一辈子' AND pinyin='yī bèi zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일단, 한번', example_zh='一旦做了决定，就要坚持下去，不要轻易放弃。', example_ko='일단 결정을 내리면 끝까지 밀고 나가야 해, 쉽게 포기하면 안 돼.', example_pinyin='yí dàn zuò le jué dìng ， jiù yào jiān chí xià qù ， bú yào qīng yì fàng qì 。' WHERE chinese='一旦' AND pinyin='yī dàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='내내, 쭉', example_zh='他一路上都很沉默，让大家很担心他的状态。', example_ko='그는 내내 침묵해서 모두 그의 상태를 걱정했어.', example_pinyin='tā yī lù shàng dōu hěn chén mò ， ràng dà jiā hěn dān xīn tā de zhuàng tài 。' WHERE chinese='一路' AND pinyin='yī lù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='일치하다, 통일되다', example_zh='团队成员要意见一致，才能高效地合作。', example_ko='팀원들이 의견이 일치해야 효율적으로 협력할 수 있어.', example_pinyin='tuán duì chéng yuán yào yì jiàn yí zhì ， cái néng gāo xiào dì hé zuò 。' WHERE chinese='一致' AND pinyin='yī zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유감이다, 아쉽다', example_zh='他没能参加这次活动，感到非常遗憾。', example_ko='그는 이번 행사에 참가하지 못해서 매우 유감스럽게 느꼈어.', example_pinyin='tā méi néng cān jiā zhè cì huó dòng ， gǎn dào fēi cháng yí hàn 。' WHERE chinese='遗憾' AND pinyin='yí hàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이동하다', example_zh='手机让我们可以随时随地移动，保持联系。', example_ko='스마트폰 덕분에 우리는 언제 어디서나 이동하면서 연락을 유지할 수 있어.', example_pinyin='shǒu jī ràng wǒ men kě yǐ suí shí suí dì yí dòng ， bǎo chí lián xì 。' WHERE chinese='移动' AND pinyin='yí dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이민하다; 이민자', example_zh='他的父母三十年前移民到了美国，现在他在那里出生长大。', example_ko='그의 부모님이 30년 전에 미국으로 이민 가서 그는 거기서 태어나고 자랐어.', example_pinyin='tā de fù mǔ sān shí nián qián yí mín dào le měi guó ， xiàn zài tā zài nà lǐ chū shēng zhǎng dà 。' WHERE chinese='移民' AND pinyin='yí mín' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='의문, 의혹', example_zh='他对这件事有很多疑问，希望得到详细的解释。', example_ko='그는 이 일에 의문이 많아서 자세한 설명을 받기를 바랐어.', example_pinyin='tā duì zhè jiàn shì yǒu hěn duō yí wèn ， xī wàng dé dào xiáng xì de jiě shì 。' WHERE chinese='疑问' AND pinyin='yí wèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='둘째 천간; 을', example_zh='按甲乙丙丁，乙排在第二位。', example_ko='갑을병정 순서에서 을은 두 번째야.', example_pinyin='àn jiǎ yǐ bǐng dīng ， yǐ pái zài dì èr wèi 。' WHERE chinese='乙' AND pinyin='yǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~및, ~와 더불어', example_zh='他的团队以及合作伙伴共同完成了这次任务。', example_ko='그의 팀 및 협력 파트너가 함께 이번 임무를 완수했어.', example_pinyin='tā de tuán duì yǐ jí hé zuò huǒ bàn gòng tóng wán chéng le zhè cì rèn wù 。' WHERE chinese='以及' AND pinyin='yǐ jí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~이래, ~이후로', example_zh='自从他换了工作以来，心情好多了，工作也更顺利了。', example_ko='그가 직장을 바꾼 이래 기분이 훨씬 나아지고 일도 더 순조로워졌어.', example_pinyin='zì cóng tā huàn le gōng zuò yǐ lái ， xīn qíng hǎo duō le ， gōng zuò yě gèng shùn lì le 。' WHERE chinese='以来' AND pinyin='yǐ lái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='뜻밖에, 예상치 못하다; 사고', example_zh='他在途中遇到了意外，所以比预定时间晚到了。', example_ko='그는 도중에 사고를 만나서 예정 시간보다 늦게 도착했어.', example_pinyin='tā zài tú zhōng yù dào le yì wài ， suǒ yǐ bǐ yù dìng shí jiān wǎn dào le 。' WHERE chinese='意外' AND pinyin='yì wài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='의의, 의미', example_zh='这项研究的意义非常重大，对人类的健康有很大影响。', example_ko='이 연구의 의의는 매우 중대해서 인류의 건강에 큰 영향을 미쳐.', example_pinyin='zhè xiàng yán jiū de yì yì fēi cháng zhòng dà ， duì rén lèi de jiàn kāng yǒu hěn dà yǐng xiǎng 。' WHERE chinese='意义' AND pinyin='yì yì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='논의하다, 비판하다', example_zh='大家对这个问题议论纷纷，各自发表了不同的看法。', example_ko='다들 이 문제에 대해 여러 가지 논의를 하며 각각 다른 견해를 발표했어.', example_pinyin='dà jiā duì zhè ge wèn tí yì lùn fēn fēn ， gè zì fā biǎo le bù tóng de kàn fǎ 。' WHERE chinese='议论' AND pinyin='yì lùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='의무', example_zh='纳税是每个公民的义务，不能逃避。', example_ko='납세는 모든 시민의 의무야, 회피할 수 없어.', example_pinyin='nà shuì shì měi gè gōng mín de yì wù ， bù néng táo bì 。' WHERE chinese='义务' AND pinyin='yì wù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='따라서, 그러므로', example_zh='他努力学习，因而取得了优异的成绩。', example_ko='그는 열심히 공부해서 따라서 우수한 성적을 거뒀어.', example_pinyin='tā nǔ lì xué xí ， yīn ér qǔ dé le yōu yì de chéng jì 。' WHERE chinese='因而' AND pinyin='yīn ér' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='요소, 원인', example_zh='成功的因素有很多，包括努力、天赋和运气。', example_ko='성공의 요소는 많아서 노력, 재능, 운이 포함돼.', example_pinyin='chéng gōng de yīn sù yǒu hěn duō ， bāo kuò nǔ lì 、 tiān fù hé yùn qì 。' WHERE chinese='因素' AND pinyin='yīn sù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='은; 은빛', example_zh='她戴着一只银戒指，在阳光下闪闪发光。', example_ko='그녀는 은반지를 끼고 있는데 햇빛 아래 반짝반짝 빛나.', example_pinyin='tā dài zhe yī zhī yín jiè zhǐ ， zài yáng guāng xià shǎn shǎn fā guāng 。' WHERE chinese='银' AND pinyin='yín' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='잘생기다, 준수하다', example_zh='他长得非常英俊，在公司里很受女同事欢迎。', example_ko='그는 매우 잘생겨서 회사에서 여자 동료들에게 인기가 많아.', example_pinyin='tā zhǎng dé fēi cháng yīng jùn ， zài gōng sī lǐ hěn shòu nǚ tóng shì huān yíng 。' WHERE chinese='英俊' AND pinyin='yīng jùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영웅', example_zh='消防员是现代社会的英雄，他们冒着生命危险保护大家。', example_ko='소방관은 현대 사회의 영웅이야, 그들은 목숨의 위험을 무릅쓰고 모두를 보호해.', example_pinyin='xiāo fáng yuán shì xiàn dài shè huì de yīng xióng ， tā men mào zhe shēng mìng wēi xiǎn bǎo hù dà jiā 。' WHERE chinese='英雄' AND pinyin='yīng xióng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='맞이하다, 환영하다', example_zh='公司特别派人到机场迎接贵宾的到来。', example_ko='회사는 특별히 공항에 사람을 보내서 귀빈을 맞이했어.', example_pinyin='gōng sī tè bié pài rén dào jī chǎng yíng jiē guì bīn de dào lái 。' WHERE chinese='迎接' AND pinyin='yíng jiē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영양', example_zh='均衡的营养对儿童的健康成长至关重要。', example_ko='균형 잡힌 영양은 아이들의 건강한 성장에 매우 중요해.', example_pinyin='jūn héng de yíng yǎng duì ér tóng de jiàn kāng chéng zhǎng zhì guān zhòng yào 。' WHERE chinese='营养' AND pinyin='yíng yǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='영업하다, 운영하다', example_zh='这家店每天营业到晚上十点，非常方便。', example_ko='이 가게는 매일 저녁 10시까지 영업해서 매우 편리해.', example_pinyin='zhè jiā diàn měi tiān yíng yè dào wǎn shàng shí diǎn ， fēi cháng fāng biàn 。' WHERE chinese='营业' AND pinyin='yíng yè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='그림자, 흔적', example_zh='傍晚时分，他的影子被夕阳拉得很长，投在地上。', example_ko='저녁 무렵 그의 그림자가 석양에 길게 늘어져서 바닥에 드리워졌어.', example_pinyin='bàng wǎn shí fēn ， tā de yǐng zi bèi xī yáng lā dé hěn zhǎng ， tóu zài dì shàng 。' WHERE chinese='影子' AND pinyin='yǐng zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='동전', example_zh='他口袋里只剩下几枚硬币，不够买一杯水。', example_ko='그의 주머니에 동전 몇 개만 남아서 물 한 잔을 살 돈도 부족해.', example_pinyin='tā kǒu dài lǐ zhǐ shèng xià jǐ méi yìng bì ， bù gòu mǎi yī bēi shuǐ 。' WHERE chinese='硬币' AND pinyin='yìng bì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='하드웨어', example_zh='电脑的硬件出了故障，需要请专业人士来修理。', example_ko='컴퓨터의 하드웨어가 고장 났어서 전문가를 불러 수리해야 해.', example_pinyin='diàn nǎo de yìng jiàn chū le gù zhàng ， xū yào qǐng zhuān yè rén shì lái xiū lǐ 。' WHERE chinese='硬件' AND pinyin='yìng jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='적당히 처리하다, 대처하다', example_zh='他有时候处理问题的方式有些应付，不够认真。', example_ko='그는 때때로 문제 처리 방식이 좀 대충이어서 충분히 진지하지 않아.', example_pinyin='tā yǒu shí hòu chǔ lǐ wèn tí de fāng shì yǒu xiē yìng fù ， bù gòu rèn zhēn 。' WHERE chinese='应付' AND pinyin='yìng fu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지원하다, 응시하다', example_zh='他应聘了几家公司，最后选择了待遇最好的那家。', example_ko='그는 몇 개 회사에 지원해서 결국 대우가 가장 좋은 곳을 선택했어.', example_pinyin='tā yìng pìn le jǐ jiā gōng sī ， zuì hòu xuǎn zé le dài yù zuì hǎo de nà jiā 。' WHERE chinese='应聘' AND pinyin='yìng pìn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='응용하다, 적용하다', example_zh='他把学到的知识应用到实际工作中，取得了很好的效果。', example_ko='그는 배운 지식을 실제 업무에 응용해서 좋은 효과를 거뒀어.', example_pinyin='tā bǎ xué dào de zhī shí yìng yòng dào shí jì gōng zuò zhōng ， qǔ dé le hěn hǎo de xiào guǒ 。' WHERE chinese='应用' AND pinyin='yìng yòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='포옹하다', example_zh='久别重逢后，他们紧紧地拥抱在一起，激动不已。', example_ko='오랫동안 헤어졌다가 다시 만나서 그들은 꼭 껴안았어, 감격스러워했어.', example_pinyin='jiǔ bié chóng féng hòu ， tā men jǐn jǐn dì yōng bào zài yì qǐ ， jī dòng bù yǐ 。' WHERE chinese='拥抱' AND pinyin='yōng bào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='붐비다, 복잡하다', example_zh='早高峰时地铁非常拥挤，乘客们紧紧挤在一起。', example_ko='아침 출근 시간에 지하철이 매우 붐벼서 승객들이 빽빽하게 붙어 있어.', example_pinyin='zǎo gāo fēng shí dì tiě fēi cháng yōng jǐ ， chéng kè men jǐn jǐn jǐ zài yì qǐ 。' WHERE chinese='拥挤' AND pinyin='yōng jǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='용기', example_zh='他鼓起勇气向她表白，虽然被拒绝了，但他不后悔。', example_ko='그는 용기를 내서 그녀에게 고백했는데 거절당했지만 후회하지 않아.', example_pinyin='tā gǔ qǐ yǒng qì xiàng tā biǎo bái ， suī rán bèi jù jué le ， dàn tā bù hòu huǐ 。' WHERE chinese='勇气' AND pinyin='yǒng qì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='용도, 쓰임새', example_zh='这个工具的用途很广，可以用来切割、钻孔等。', example_ko='이 도구의 용도가 매우 광범위해서 절단, 드릴링 등에 쓸 수 있어.', example_pinyin='zhè ge gōng jù de yòng tú hěn guǎng ， kě yǐ yòng lái qiē gē 、 zuān kǒng děng 。' WHERE chinese='用途' AND pinyin='yòng tú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='혜택, 우대하다', example_zh='学生凭学生证可以享受票价优惠，半价进入。', example_ko='학생은 학생증으로 가격 혜택을 누릴 수 있어서 반값으로 입장할 수 있어.', example_pinyin='xué shēng píng xué shēng zhèng kě yǐ xiǎng shòu piào jià yōu huì ， bàn jià jìn rù 。' WHERE chinese='优惠' AND pinyin='yōu huì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아름답다, 우아하다', example_zh='这段音乐非常优美，让人听了心情愉快。', example_ko='이 음악은 매우 아름다워서 들으면 기분이 좋아져.', example_pinyin='zhè duàn yīn yuè fēi cháng yōu měi ， ràng rén tīng le xīn qíng yú kuài 。' WHERE chinese='优美' AND pinyin='yōu měi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='우세, 강점', example_zh='我们的产品在价格和质量上都有优势，竞争力很强。', example_ko='우리 제품은 가격과 품질 모두 우세가 있어서 경쟁력이 강해.', example_pinyin='wǒ men de chǎn pǐn zài jià gé hé zhì liàng shàng dōu yǒu yōu shì ， jìng zhēng lì hěn qiáng 。' WHERE chinese='优势' AND pinyin='yōu shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유구하다, 오래되다', example_zh='中国有着悠久的历史，文化积淀非常深厚。', example_ko='중국은 유구한 역사를 갖고 있어서 문화적 축적이 매우 깊어.', example_pinyin='zhōng guó yǒu zhe yōu jiǔ de lì shǐ ， wén huà jī diàn fēi cháng shēn hòu 。' WHERE chinese='悠久' AND pinyin='yōu jiǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='우체국', example_zh='他去邮局寄了一个包裹给远在外地的朋友。', example_ko='그는 우체국에 가서 멀리 타지에 있는 친구에게 소포를 보냈어.', example_pinyin='tā qù yóu jú jì le yí gè bāo guǒ gěi yuǎn zài wài dì de péng yǒu 。' WHERE chinese='邮局' AND pinyin='yóu jú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유람하다, 관광하다', example_zh='他们乘船游览了漓江，欣赏了美丽的山水风光。', example_ko='그들은 배를 타고 리장강을 유람하며 아름다운 산수 경관을 감상했어.', example_pinyin='tā men chéng chuán yóu lǎn le lí jiāng ， xīn shǎng le měi lì de shān shuǐ fēng guāng 。' WHERE chinese='游览' AND pinyin='yóu lǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='튀기다, 기름에 볶다', example_zh='油炸食物虽然好吃，但热量太高，不适合经常吃。', example_ko='튀긴 음식은 맛있지만 열량이 너무 높아서 자주 먹기에 적합하지 않아.', example_pinyin='yóu zhá shí wù suī rán hǎo chī ， dàn rè liàng tài gāo ， bú shì hé jīng cháng chī 。' WHERE chinese='油炸' AND pinyin='yóu zhá' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주저하다, 망설이다', example_zh='他犹豫了很久，最终还是决定接受那份工作。', example_ko='그는 오랫동안 망설이다가 결국 그 직장을 수락하기로 결정했어.', example_pinyin='tā yóu yù le hěn jiǔ ， zuì zhōng hái shì jué dìng jiē shòu nà fèn gōng zuò 。' WHERE chinese='犹豫' AND pinyin='yóu yù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유리하다, 이롭다', example_zh='良好的沟通对解决问题非常有利，大家应该多交流。', example_ko='좋은 소통은 문제 해결에 매우 유리해서 모두 더 많이 교류해야 해.', example_pinyin='liáng hǎo de gōu tōng duì jiě jué wèn tí fēi cháng yǒu lì ， dà jiā yīng gāi duō jiāo liú 。' WHERE chinese='有利' AND pinyin='yǒu lì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='유치원', example_zh='她的孩子今年开始上幼儿园，适应得很快。', example_ko='그녀의 아이가 올해 유치원에 다니기 시작했는데 적응이 빨라.', example_pinyin='tā de hái zi jīn nián kāi shǐ shàng yòu ér yuán ， shì yìng dé hěn kuài 。' WHERE chinese='幼儿园' AND pinyin='yòu ér yuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오락, 즐거움', example_zh='工作之余，他喜欢各种娱乐活动，比如看电影和玩游戏。', example_ko='업무 외에 그는 다양한 오락 활동을 좋아해서 영화 보기와 게임 등이야.', example_pinyin='gōng zuò zhī yú ， tā xǐ huān gè zhǒng yú lè huó dòng ， bǐ rú kàn diàn yǐng hé wán yóu xì 。' WHERE chinese='娱乐' AND pinyin='yú lè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~보다는, ~하는 것보다', example_zh='与其在这里发愁，不如积极行动去解决问题。', example_ko='여기서 걱정하는 것보다는 적극적으로 행동해서 문제를 해결하는 게 나아.', example_pinyin='yǔ qí zài zhè lǐ fā chóu ， bù rú jī jí xíng dòng qù jiě jué wèn tí 。' WHERE chinese='与其' AND pinyin='yǔ qí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어조, 말투', example_zh='他说话的语气很强硬，让对方感到很有压力。', example_ko='그가 말하는 어조가 매우 강경해서 상대방이 매우 압박감을 느꼈어.', example_pinyin='tā shuō huà de yǔ qì hěn qiáng yìng ， ràng duì fāng gǎn dào hěn yǒu yā lì 。' WHERE chinese='语气' AND pinyin='yǔ qì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='우주', example_zh='科学家们一直在探索宇宙的奥秘，希望发现外星生命。', example_ko='과학자들은 우주의 신비를 계속 탐구하며 외계 생명체를 발견하기를 바라고 있어.', example_pinyin='kē xué jiā men yì zhí zài tàn suǒ yǔ zhòu de ào mì ， xī wàng fā xiàn wài xīng shēng mìng 。' WHERE chinese='宇宙' AND pinyin='yǔ zhòu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='예보하다; 예보', example_zh='天气预报说明天会有大雨，记得带伞出门。', example_ko='일기 예보에 내일 큰 비가 온다고 해서 우산을 챙겨 나가야 해.', example_pinyin='tiān qì yù bào shuō míng tiān huì yǒu dà yǔ ， jì de dài sǎn chū mén 。' WHERE chinese='预报' AND pinyin='yù bào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='예약하다', example_zh='他提前预订了餐厅，免得到时候没有位置。', example_ko='그는 미리 식당을 예약했어, 그때 자리가 없을 수도 있어서.', example_pinyin='tā tí qián yù dìng le cān tīng ， miǎn de dào shí hòu méi yǒu wèi zhì 。' WHERE chinese='预订' AND pinyin='yù dìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='예방하다', example_zh='定期接种疫苗可以有效预防多种疾病。', example_ko='정기적으로 백신을 접종하면 다양한 질병을 효과적으로 예방할 수 있어.', example_pinyin='dìng qī jiē zhǒng yì miáo kě yǐ yǒu xiào yù fáng duō zhǒng jí bìng 。' WHERE chinese='预防' AND pinyin='yù fáng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='옥수수', example_zh='他喜欢在夏天烤玉米吃，香甜可口，非常美味。', example_ko='그는 여름에 옥수수를 구워 먹는 걸 좋아해서 달콤하고 맛있어.', example_pinyin='tā xǐ huān zài xià tiān kǎo yù mǐ chī ， xiāng tián kě kǒu ， fēi cháng měi wèi 。' WHERE chinese='玉米' AND pinyin='yù mǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='원단 (1월 1일)', example_zh='元旦是一月一日，很多人会举行庆祝活动。', example_ko='원단은 1월 1일이야, 많은 사람들이 축하 행사를 열어.', example_pinyin='yuán dàn shì yí yuè yī rì ， hěn duō rén huì jǔ xíng qìng zhù huó dòng 。' WHERE chinese='元旦' AND pinyin='yuán dàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='원료, 재료', example_zh='这款产品使用的原料都是天然的，对环境友好。', example_ko='이 제품에 사용된 원료는 모두 천연이어서 환경 친화적이야.', example_pinyin='zhè kuǎn chǎn pǐn shǐ yòng de yuán liào dōu shì tiān rán de ， duì huán jìng yǒu hǎo 。' WHERE chinese='原料' AND pinyin='yuán liào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='원칙', example_zh='他做事坚守原则，从不为了私利而妥协。', example_ko='그는 일 처리에 원칙을 고수하며 사리사욕을 위해 타협하지 않아.', example_pinyin='tā zuò shì jiān shǒu yuán zé ， cóng bù wèi le sī lì ér tuǒ xié 。' WHERE chinese='原则' AND pinyin='yuán zé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='원인, 까닭', example_zh='他迟到是有缘故的，路上发生了交通事故。', example_ko='그가 늦은 데는 이유가 있어서 길에서 교통사고가 났어.', example_pinyin='tā chí dào shì yǒu yuán gù de ， lù shàng fā shēng le jiāo tōng shì gù 。' WHERE chinese='缘故' AND pinyin='yuán gù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소원, 바람', example_zh='她的愿望是环游世界，体验不同国家的文化。', example_ko='그녀의 소원은 세계 일주를 해서 다양한 나라의 문화를 체험하는 거야.', example_pinyin='tā de yuàn wàng shì huán yóu shì jiè ， tǐ yàn bù tóng guó jiā de wén huà 。' WHERE chinese='愿望' AND pinyin='yuàn wàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='어지럽다, 멀미나다', example_zh='坐了很长时间的船，他感到头晕，需要休息一下。', example_ko='배를 오래 타서 그는 어지러워서 좀 쉬어야 해.', example_pinyin='zuò le hěn zhǎng shí jiān de chuán ， tā gǎn dào tóu yūn ， xū yào xiū xī yī xià 。' WHERE chinese='晕' AND pinyin='yūn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운, 운수', example_zh='他今天运气很好，找到了停车位，还遇到了老朋友。', example_ko='그는 오늘 운이 좋아서 주차 자리를 찾고 옛 친구도 만났어.', example_pinyin='tā jīn tiān yùn qì hěn hǎo ， zhǎo dào le tíng chē wèi ， hái yù dào le lǎo péng yǒu 。' WHERE chinese='运气' AND pinyin='yùn qi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운송하다, 수송하다', example_zh='这批货物需要通过海运来运输，预计十天后到达。', example_ko='이 화물은 해운으로 운송해야 해서 10일 후에 도착할 예정이야.', example_pinyin='zhè pī huò wù xū yào tōng guò hǎi yùn lái yùn shū ， yù jì shí tiān hòu dào dá 。' WHERE chinese='运输' AND pinyin='yùn shū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='운용하다, 활용하다', example_zh='他善于运用各种工具和方法来提高工作效率。', example_ko='그는 다양한 도구와 방법을 활용해서 업무 효율을 높이는 걸 잘해.', example_pinyin='tā shàn yú yùn yòng gè zhǒng gōng jù hé fāng fǎ lái tí gāo gōng zuò xiào lǜ 。' WHERE chinese='运用' AND pinyin='yùn yòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='재해, 재난', example_zh='洪水是一种常见的自然灾害，给人们带来很大的损失。', example_ko='홍수는 흔한 자연재해야, 사람들에게 큰 손실을 가져다줘.', example_pinyin='hóng shuǐ shì yī zhǒng cháng jiàn de zì rán zāi hài ， gěi rén men dài lái hěn dà de sǔn shī 。' WHERE chinese='灾害' AND pinyin='zāi hài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='거듭, 여러 번', example_zh='她再三叮嘱他出门要带钥匙，但他还是忘了。', example_ko='그녀는 외출할 때 열쇠를 챙기라고 거듭 당부했는데 그는 여전히 잊어버렸어.', example_pinyin='tā zài sān dīng zhǔ tā chū mén yào dài yào shi ， dàn tā hái shì wàng le 。' WHERE chinese='再三' AND pinyin='zài sān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='찬성하다, 동의하다', example_zh='大多数人赞成这个提议，少数人持反对意见。', example_ko='대부분의 사람들이 이 제안에 찬성하고 소수가 반대 의견을 지지해.', example_pinyin='dà duō shù rén zàn chéng zhè ge tí yì ， shǎo shù rén chí fǎn duì yì jiàn 。' WHERE chinese='赞成' AND pinyin='zàn chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='칭찬하다, 찬미하다', example_zh='她用诗歌赞美大自然的美丽，感动了很多读者。', example_ko='그녀는 시로 대자연의 아름다움을 찬미해서 많은 독자를 감동시켰어.', example_pinyin='tā yòng shī gē zàn měi dà zì rán de měi lì ， gǎn dòng le hěn duō dú zhě 。' WHERE chinese='赞美' AND pinyin='zàn měi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='엉망이다, 망쳤다', example_zh='今天真糟糕，什么事情都不顺利，希望明天会更好。', example_ko='오늘 정말 엉망이야, 무슨 일도 잘 안 됐어, 내일은 더 나아지기를 바라.', example_pinyin='jīn tiān zhēn zāo gāo ， shén me shì qíng dōu bù shùn lì ， xī wàng míng tiān huì gèng hǎo 。' WHERE chinese='糟糕' AND pinyin='zāo gāo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='초래하다, 일으키다', example_zh='这次失误造成了很大的损失，需要认真总结教训。', example_ko='이번 실수가 큰 손실을 초래했어서 교훈을 진지하게 정리해야 해.', example_pinyin='zhè cì shī wù zào chéng le hěn dà de sǔn shī ， xū yào rèn zhēn zǒng jié jiào xùn 。' WHERE chinese='造成' AND pinyin='zào chéng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='즉, 그러면 (접속사)', example_zh='若犯了错，则要勇于承认并改正。', example_ko='잘못을 저질렀으면 용감하게 인정하고 수정해야 해.', example_pinyin='ruò fàn le cuò ， zé yào yǒng yú chéng rèn bìng gǎi zhèng 。' WHERE chinese='则' AND pinyin='zé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='책망하다, 나무라다', example_zh='她责备了他一顿，因为他没有事先通知就缺席了会议。', example_ko='그녀는 그를 한바탕 책망했어, 그가 사전 통보 없이 회의에 빠져서.', example_pinyin='tā zé bèi le tā yī dùn ， yīn wèi tā méi yǒu shì xiān tōng zhī jiù quē xí le huì yì 。' WHERE chinese='责备' AND pinyin='zé bèi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='따다, 뽑다', example_zh='她在花园里摘了一朵玫瑰，送给了妈妈。', example_ko='그녀는 정원에서 장미 한 송이를 따서 엄마에게 드렸어.', example_pinyin='tā zài huā yuán lǐ zhāi le yī duǒ méi guī ， sòng gěi le mā mā 。' WHERE chinese='摘' AND pinyin='zhāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='붙이다, 붙다', example_zh='她把照片粘贴在日记本上，留作美好的回忆。', example_ko='그녀는 사진을 일기장에 붙여서 아름다운 추억으로 남겼어.', example_pinyin='tā bǎ zhào piān zhān tiē zài rì jì běn shàng ， liú zuò měi hǎo de huí yì 。' WHERE chinese='粘贴' AND pinyin='zhān tiē' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='펼치다, 전개하다', example_zh='随着活动展开，越来越多的人开始参与进来。', example_ko='행사가 전개되면서 점점 더 많은 사람들이 참여하기 시작했어.', example_pinyin='suí zhe huó dòng zhǎn kāi ， yuè lái yuè duō de rén kāi shǐ cān yù jìn lái 。' WHERE chinese='展开' AND pinyin='zhǎn kāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전람회, 전시', example_zh='他参观了一场现代艺术展览，被那些创意作品深深吸引。', example_ko='그는 현대 예술 전시회를 관람해서 그 창의적인 작품들에 깊이 끌렸어.', example_pinyin='tā cān guān le yī cháng xiàn dài yì shù zhǎn lǎn ， bèi nà xiē chuàng yì zuò pǐn shēn shēn xī yǐn 。' WHERE chinese='展览' AND pinyin='zhǎn lǎn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전쟁', example_zh='战争带来了无尽的苦难，和平才是人类最大的愿望。', example_ko='전쟁은 끝없는 고통을 가져다주니 평화야말로 인류 최대의 소망이야.', example_pinyin='zhàn zhēng dài lái liǎo wú jǐn de kǔ nàn ， hé píng cái shì rén lèi zuì dà de yuàn wàng 。' WHERE chinese='战争' AND pinyin='zhàn zhēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='(전화가) 통화 중이다', example_zh='我给他打电话，一直占线，可能他在和别人通话。', example_ko='그에게 전화했는데 계속 통화 중이야, 다른 사람과 통화 중인 것 같아.', example_pinyin='wǒ gěi tā dǎ diàn huà ， yì zhí zhàn xiàn ， kě néng tā zài hé bié rén tōng huà 。' WHERE chinese='占线' AND pinyin='zhàn xiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='오르다, 상승하다', example_zh='最近蔬菜价格上涨，让很多家庭感到压力增加。', example_ko='최근 채소 가격이 올라서 많은 가정이 압박감이 늘었어.', example_pinyin='zuì jìn shū cài jià gé shàng zhǎng ， ràng hěn duō jiā tíng gǎn dào yā lì zēng jiā 。' WHERE chinese='涨' AND pinyin='zhǎng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='파악하다, 장악하다', example_zh='学习语言最重要的是掌握基础语法和常用词汇。', example_ko='언어를 배울 때 가장 중요한 건 기초 문법과 상용 어휘를 파악하는 거야.', example_pinyin='xué xí yǔ yán zuì zhòng yào de shì zhǎng wò jī chǔ yǔ fǎ hé cháng yòng cí huì 。' WHERE chinese='掌握' AND pinyin='zhǎng wò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='계좌', example_zh='他在网上银行开通了一个账户，方便日常转账和支付。', example_ko='그는 인터넷 은행에 계좌를 개설해서 일상 이체와 결제를 편리하게 했어.', example_pinyin='tā zài wǎng shàng yín háng kāi tōng le yí gè zhàng hù ， fāng biàn rì cháng zhuǎn zhàng hé zhī fù 。' WHERE chinese='账户' AND pinyin='zhàng hù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='접대하다, 환대하다', example_zh='他们热情地招待了从远方来的客人，安排了丰盛的晚宴。', example_ko='그들은 멀리서 온 손님을 열정적으로 접대해서 풍성한 저녁 만찬을 준비했어.', example_pinyin='tā men rè qíng dì zhāo dài le cóng yuǎn fāng lái de kè rén ， ān pái le fēng shèng de wǎn yàn 。' WHERE chinese='招待' AND pinyin='zhāo dài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='감기 들다', example_zh='昨天没注意保暖，今天着凉了，头疼鼻塞。', example_ko='어제 보온에 신경 쓰지 않아서 오늘 감기 들었어, 머리 아프고 코 막혀.', example_pinyin='zuó tiān méi zhù yì bǎo nuǎn ， jīn tiān zháo liáng le ， tóu téng bí sè 。' WHERE chinese='着凉' AND pinyin='zháo liáng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='평소대로, 여전히', example_zh='虽然下大雨，但商店还是照常营业，没有关门。', example_ko='큰 비가 내렸지만 가게는 여전히 평소대로 영업하며 문을 닫지 않았어.', example_pinyin='suī rán xià dà yǔ ， dàn shāng diàn hái shì zhào cháng yíng yè ， méi yǒu guān mén 。' WHERE chinese='照常' AND pinyin='zhào cháng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소집하다, 개최하다', example_zh='公司明天召开全体员工大会，讨论新的发展计划。', example_ko='회사가 내일 전 직원 대회를 소집해서 새로운 발전 계획을 논의해.', example_pinyin='gōng sī míng tiān zhào kāi quán tǐ yuán gōng dà huì ， tǎo lùn xīn de fā zhǎn jì huà 。' WHERE chinese='召开' AND pinyin='zhào kāi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='철학', example_zh='他喜欢研究哲学，认为它能帮助理解人生的意义。', example_ko='그는 철학 연구를 좋아해서 인생의 의미를 이해하는 데 도움이 된다고 생각해.', example_pinyin='tā xǐ huān yán jiū zhé xué ， rèn wéi tā néng bāng zhù lǐ jiě rén shēng de yì yì 。' WHERE chinese='哲学' AND pinyin='zhé xué' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='진리', example_zh='科学研究的目的是探索真理，揭示自然规律。', example_ko='과학 연구의 목적은 진리를 탐구해서 자연 법칙을 밝히는 거야.', example_pinyin='kē xué yán jiū de mù dì shì tàn suǒ zhēn lǐ ， jiē shì zì rán guī lǜ 。' WHERE chinese='真理' AND pinyin='zhēn lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='진실하다, 사실에 맞다', example_zh='报道应该真实客观，不能虚假或夸大事实。', example_ko='보도는 진실하고 객관적이어야 해, 거짓이거나 사실을 과장해서는 안 돼.', example_pinyin='bào dào yīng gāi zhēn shí kè guān ， bù néng xū jiǎ huò kuā dà shì shí 。' WHERE chinese='真实' AND pinyin='zhēn shí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~을 겨냥하다, 针对', example_zh='他的批评是针对这件事本身，不是针对任何人。', example_ko='그의 비판은 이 일 자체를 겨냥한 거야, 어느 사람을 겨냥한 게 아니야.', example_pinyin='tā de pī píng shì zhēn duì zhè jiàn shì běn shēn ， bú shì zhēn duì rèn hé rén 。' WHERE chinese='针对' AND pinyin='zhēn duì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='소중히 여기다, 아끼다', example_zh='要珍惜每一段缘分，因为相遇是很难得的事。', example_ko='모든 인연을 소중히 여겨야 해, 만남이란 매우 귀한 일이니까.', example_pinyin='yào zhēn xī měi yī duàn yuán fēn ， yīn wèi xiāng yù shì hěn nán dé de shì 。' WHERE chinese='珍惜' AND pinyin='zhēn xī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='진단하다; 진단', example_zh='经过仔细检查，医生诊断他患了轻微的肺炎。', example_ko='꼼꼼한 검사 끝에 의사는 그가 가벼운 폐렴에 걸렸다고 진단했어.', example_pinyin='jīng guò zǐ xì jiǎn chá ， yī shēng zhěn duàn tā huàn le qīng wēi de fèi yán 。' WHERE chinese='诊断' AND pinyin='zhěn duàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='베개', example_zh='她换了一个更软的枕头，睡觉的时候脖子不再酸了。', example_ko='그녀는 더 부드러운 베개로 바꾸니 잘 때 목이 더 이상 결리지 않아.', example_pinyin='tā huàn le yí gè gèng ruǎn de zhěn tou ， shuì jiào de shí hòu bó zi bù zài suān le 。' WHERE chinese='枕头' AND pinyin='zhěn tou' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='진, 부대 (양사)', example_zh='外面下了一阵大雨，一下子就停了。', example_ko='밖에 한바탕 큰 비가 내렸다가 금방 그쳤어.', example_pinyin='wài miàn xià le yī zhèn dà yǔ ， yī xià zi jiù tíng le 。' WHERE chinese='阵' AND pinyin='zhèn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='진동하다', example_zh='地震时，建筑物剧烈振动，让人们非常恐慌。', example_ko='지진 시 건물이 격렬하게 진동해서 사람들을 매우 공황 상태로 만들었어.', example_pinyin='dì zhèn shí ， jiàn zhù wù jù liè zhèn dòng ， ràng rén men fēi cháng kǒng huāng 。' WHERE chinese='振动' AND pinyin='zhèn dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='눈을 뜨다', example_zh='他睁开眼睛，发现自己已经到了目的地。', example_ko='그는 눈을 떴는데 이미 목적지에 도착해 있었어.', example_pinyin='tā zhēng kāi yǎn jīng ， fā xiàn zì jǐ yǐ jīng dào le mù dì dì 。' WHERE chinese='睁' AND pinyin='zhēng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='논쟁하다; 논쟁', example_zh='两人在这个问题上争论了很久，谁也说服不了谁。', example_ko='두 사람은 이 문제에 대해 오랫동안 논쟁했는데 아무도 상대방을 설득하지 못했어.', example_pinyin='liǎng rén zài zhè ge wèn tí shàng zhēng lùn le hěn jiǔ ， shuí yě shuō fú bù liǎo shuí 。' WHERE chinese='争论' AND pinyin='zhēng lùn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='쟁취하다, 얻으려 노력하다', example_zh='她努力工作，争取在三年内升职加薪。', example_ko='그녀는 열심히 일해서 3년 안에 승진과 급여 인상을 쟁취하려고 해.', example_pinyin='tā nǔ lì gōng zuò ， zhēng qǔ zài sān nián nèi shēng zhí jiā xīn 。' WHERE chinese='争取' AND pinyin='zhēng qǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='구하다, 수렴하다', example_zh='在做出决定之前，他广泛征求了同事的意见。', example_ko='결정을 내리기 전에 그는 동료들의 의견을 광범위하게 수렴했어.', example_pinyin='zài zuò chū jué dìng zhī qián ， tā guǎng fàn zhēng qiú le tóng shì de yì jiàn 。' WHERE chinese='征求' AND pinyin='zhēng qiú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전체의', example_zh='整个会议下来，他一直保持着专注，没有分心。', example_ko='회의 전체 내내 그는 계속 집중을 유지하며 딴생각을 하지 않았어.', example_pinyin='zhěng gè huì yì xià lái ， tā yì zhí bǎo chí zhe zhuān zhù ， méi yǒu fēn xīn 。' WHERE chinese='整个' AND pinyin='zhěng gè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전체, 총체', example_zh='要从整体上看问题，不能只关注某一个方面。', example_ko='문제를 전체적으로 봐야 해, 어느 한 측면만 집중해서는 안 돼.', example_pinyin='yào cóng zhěng tǐ shàng kàn wèn tí ， bù néng zhǐ guān zhù mǒu yí gè fāng miàn 。' WHERE chinese='整体' AND pinyin='zhěng tǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='바로, 마침', example_zh='他正在睡觉，突然接到了紧急电话，不得不起床。', example_ko='그가 자고 있는데 갑자기 긴급 전화가 와서 어쩔 수 없이 일어났어.', example_pinyin='tā zhèng zài shuì jiào ， tū rán jiē dào le jǐn jí diàn huà ， bù dé bù qǐ chuáng 。' WHERE chinese='正' AND pinyin='zhèng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정책', example_zh='政府出台了一系列新政策，支持科技创新和创业。', example_ko='정부는 과학기술 혁신과 창업을 지원하는 일련의 새 정책을 내놓았어.', example_pinyin='zhèng fǔ chū tái le yī xì liè xīn zhèng cè ， zhī chí kē jì chuàng xīn hé chuàng yè 。' WHERE chinese='政策' AND pinyin='zhèng cè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정부', example_zh='政府的职责是保障公民的基本权利和公共利益。', example_ko='정부의 직책은 시민의 기본 권리와 공공 이익을 보장하는 거야.', example_pinyin='zhèng fǔ de zhí zé shì bǎo zhàng gōng mín de jī běn quán lì hé gōng gòng lì yì 。' WHERE chinese='政府' AND pinyin='zhèng fǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='정치', example_zh='政治与每个人的生活都密切相关，公民要关心时事。', example_ko='정치는 모든 사람의 생활과 밀접하게 관련돼서 시민들은 시사에 관심을 가져야 해.', example_pinyin='zhèng zhì yǔ měi gè rén de shēng huó dōu mì qiè xiāng guān ， gōng mín yào guān xīn shí shì 。' WHERE chinese='政治' AND pinyin='zhèng zhì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='증명서, 신분증', example_zh='进入大楼需要出示有效的证件，无证人员不得入内。', example_ko='건물 입장 시 유효한 증명서를 제시해야 해, 증명서 없는 사람은 입장할 수 없어.', example_pinyin='jìn rù dà lóu xū yào chū shì yǒu xiào de zhèng jiàn ， wú zhèng rén yuán bù dé rù nèi 。' WHERE chinese='证件' AND pinyin='zhèng jiàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='증거', example_zh='在法庭上，没有充分的证据是无法定罪的。', example_ko='법정에서 충분한 증거 없이는 유죄 판결을 내릴 수 없어.', example_pinyin='zài fǎ tíng shàng ， méi yǒu chōng fèn de zhèng jù shì wú fǎ dìng zuì de 。' WHERE chinese='证据' AND pinyin='zhèng jù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='돈을 벌다', example_zh='他努力工作挣钱，为的是给孩子更好的生活。', example_ko='그는 열심히 일해서 돈을 벌어서 아이에게 더 좋은 생활을 주기 위한 거야.', example_pinyin='tā nǔ lì gōng zuò zhèng qián ， wèi de shì gěi hái zi gèng hǎo de shēng huó 。' WHERE chinese='挣钱' AND pinyin='zhèng qián' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='가지 (양사); 지원하다', example_zh='这支队伍在训练上付出了很多，赢得了比赛。', example_ko='이 팀은 훈련에 많은 노력을 기울여서 경기에서 이겼어.', example_pinyin='zhè zhī duì wǔ zài xùn liàn shàng fù chū le hěn duō ， yíng dé le bǐ sài 。' WHERE chinese='支' AND pinyin='zhī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='수표', example_zh='他开了一张支票，支付了这个月的房租。', example_ko='그는 수표를 끊어서 이번 달 월세를 지불했어.', example_pinyin='tā kāi le yī zhāng zhī piào ， zhī fù le zhè ge yuè de fáng zū 。' WHERE chinese='支票' AND pinyin='zhī piào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='곧다, 직접적이다', example_zh='他说话很直，有什么说什么，从不拐弯抹角。', example_ko='그는 말이 곧아서 생각한 걸 바로 말하고 돌려 말하지 않아.', example_pinyin='tā shuō huà hěn zhí ， yǒu shén me shuō shén me ， cóng bù guǎi wān mò jiǎo 。' WHERE chinese='直' AND pinyin='zhí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집행하다', example_zh='任务已经分配好了，现在需要大家认真执行。', example_ko='임무가 이미 분배됐으니 이제 모두 진지하게 집행해야 해.', example_pinyin='rèn wù yǐ jīng fēn pèi hǎo le ， xiàn zài xū yào dà jiā rèn zhēn zhí xíng 。' WHERE chinese='执行' AND pinyin='zhí xíng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='면허증, 허가증', example_zh='他刚考取了驾驶执照，可以正式上路开车了。', example_ko='그는 막 운전 면허증을 따서 정식으로 도로를 운전할 수 있게 됐어.', example_pinyin='tā gāng kǎo qǔ le jià shǐ zhí zhào ， kě yǐ zhèng shì shàng lù kāi chē le 。' WHERE chinese='执照' AND pinyin='zhí zhào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지도하다, 안내하다', example_zh='导师一直在指导他的研究方向，给予了很多建议。', example_ko='지도교수가 계속 그의 연구 방향을 지도하며 많은 건의를 줬어.', example_pinyin='dǎo shī yì zhí zài zhǐ dǎo tā de yán jiū fāng xiàng ， jǐ yǔ le hěn duō jiàn yì 。' WHERE chinese='指导' AND pinyin='zhǐ dǎo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지휘하다', example_zh='他指挥乐团演奏了一首美丽的交响乐，台下掌声雷动。', example_ko='그는 오케스트라를 지휘해서 아름다운 교향곡을 연주했는데 객석에서 우레 같은 박수가 쏟아졌어.', example_pinyin='tā zhǐ huī yuè tuán yǎn zòu le yī shǒu měi lì de jiāo xiǎng yuè ， tái xià zhǎng shēng léi dòng 。' WHERE chinese='指挥' AND pinyin='zhǐ huī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='제정하다, 결정하다', example_zh='公司制定了新的规章制度，所有员工必须严格遵守。', example_ko='회사가 새로운 규정을 제정해서 모든 직원이 반드시 엄격히 지켜야 해.', example_pinyin='gōng sī zhì dìng le xīn de guī zhāng zhì dù ， suǒ yǒu yuán gōng bì xū yán gé zūn shǒu 。' WHERE chinese='制定' AND pinyin='zhì dìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='제도, 규정', example_zh='完善的制度是保证公平竞争的基础。', example_ko='완벽한 제도는 공정한 경쟁을 보장하는 기초야.', example_pinyin='wán shàn de zhì dù shì bǎo zhèng gōng píng jìng zhēng de jī chǔ 。' WHERE chinese='制度' AND pinyin='zhì dù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='제작하다, 만들다', example_zh='他们花了两年时间制作这部电影，终于上映了。', example_ko='그들은 2년을 들여서 이 영화를 제작했는데 드디어 개봉됐어.', example_pinyin='tā men huā le liǎng nián shí jiān zhì zuò zhè bù diàn yǐng ， zhōng yú shàng yìng le 。' WHERE chinese='制作' AND pinyin='zhì zuò' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지혜', example_zh='他用自己的智慧解决了这个困扰大家多年的难题。', example_ko='그는 자신의 지혜로 모두를 수년간 괴롭혔던 난제를 해결했어.', example_pinyin='tā yòng zì jǐ de zhì huì jiě jué le zhè ge kùn rǎo dà jiā duō nián de nán tí 。' WHERE chinese='智慧' AND pinyin='zhì huì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='지금까지', example_zh='这个问题至今仍没有得到解决，需要继续研究。', example_ko='이 문제는 지금까지도 해결되지 않았어서 계속 연구해야 해.', example_pinyin='zhè ge wèn tí zhì jīn réng méi yǒu dé dào jiě jué ， xū yào jì xù yán jiū 。' WHERE chinese='至今' AND pinyin='zhì jīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~에 대해서는, ~에 있어서는', example_zh='至于下一步的计划，大家可以在会议上再讨论。', example_ko='다음 단계 계획에 대해서는 회의에서 다시 토론할 수 있어.', example_pinyin='zhì yú xià yī bù de jì huà ， dà jiā kě yǐ zài huì yì shàng zài tǎo lùn 。' WHERE chinese='至于' AND pinyin='zhì yú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='치료하다', example_zh='他生病了，医生给他开了药，让他好好治疗。', example_ko='그가 아파서 의사가 약을 처방해줬어, 잘 치료하라고 했어.', example_pinyin='tā shēng bìng le ， yī shēng gěi tā kāi le yào ， ràng tā hǎo hǎo zhì liáo 。' WHERE chinese='治疗' AND pinyin='zhì liáo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자원봉사자', example_zh='她是一名热心的志愿者，经常去养老院帮助老人。', example_ko='그녀는 열심인 자원봉사자야, 자주 노인 요양원에 가서 노인들을 도와.', example_pinyin='tā shì yī míng rè xīn de zhì yuàn zhě ， jīng cháng qù yǎng lǎo yuàn bāng zhù lǎo rén 。' WHERE chinese='志愿者' AND pinyin='zhì yuàn zhě' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='질서', example_zh='维护公共秩序是每个公民的责任，不能随意破坏。', example_ko='공공 질서 유지는 모든 시민의 책임이야, 함부로 파괴해서는 안 돼.', example_pinyin='wéi hù gōng gòng zhì xù shì měi gè gōng mín de zé rèn ， bù néng suí yì pò huài 。' WHERE chinese='秩序' AND pinyin='zhì xù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='시계; 종', example_zh='墙上的钟坏了，不知道现在几点了，需要换一个。', example_ko='벽의 시계가 고장 났어서 지금 몇 시인지 모르겠어, 새것으로 바꿔야 해.', example_pinyin='qiáng shàng de zhōng huài le ， bù zhī dào xiàn zài jǐ diǎn le ， xū yào huàn yí gè 。' WHERE chinese='钟' AND pinyin='zhōng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='중개, 중매', example_zh='他通过中介找到了一套合适的房子，省了很多时间。', example_ko='그는 중개인을 통해 적합한 집을 찾아서 시간이 많이 절약됐어.', example_pinyin='tā tōng guò zhōng jiè zhǎo dào le yī tào hé shì de fáng zi ， shěng le hěn duō shí jiān 。' WHERE chinese='中介' AND pinyin='zhōng jiè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='중심, 센터', example_zh='购物中心里有很多商店和餐厅，非常热闹。', example_ko='쇼핑센터에 가게와 식당이 많아서 매우 시끌벅적해.', example_pinyin='gòu wù zhōng xīn lǐ yǒu hěn duō shāng diàn hé cān tīng ， fēi cháng rè nào 。' WHERE chinese='中心' AND pinyin='zhōng xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='중순 (한 달의 11-20일)', example_zh='他计划在七月中旬出发，避开最热的时期。', example_ko='그는 7월 중순에 출발할 계획이야, 가장 더운 시기를 피해서.', example_pinyin='tā jì huà zài qī yuè zhōng xún chū fā ， bì kāi zuì rè de shí qī 。' WHERE chinese='中旬' AND pinyin='zhōng xún' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무거운; 재차', example_zh='这个行李箱太重了，我一个人搬不动，需要帮忙。', example_ko='이 여행 가방이 너무 무거워서 나 혼자 못 들어서 도움이 필요해.', example_pinyin='zhè ge xíng lǐ xiāng tài zhòng le ， wǒ yí gè rén bān bù dòng ， xū yào bāng máng 。' WHERE chinese='重' AND pinyin='zhòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='무게', example_zh='这块石头的重量超过了50公斤，非常沉。', example_ko='이 돌의 무게가 50킬로그램을 넘어서 매우 무거워.', example_pinyin='zhè kuài shí tou de zhòng liàng chāo guò le 50 gōng jīn ， fēi cháng chén 。' WHERE chinese='重量' AND pinyin='zhòng liàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주도면밀하다, 배려가 깊다', example_zh='她服务非常周到，客人的每一个需求都被满足了。', example_ko='그녀의 서비스는 매우 주도면밀해서 손님의 모든 수요가 충족됐어.', example_pinyin='tā fú wù fēi cháng zhōu dào ， kè rén de měi yí gè xū qiú dōu bèi mǎn zú le 。' WHERE chinese='周到' AND pinyin='zhōu dao' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='점진적으로, 차차', example_zh='他的病情逐步好转，医生说再过两周就可以出院了。', example_ko='그의 병세가 점진적으로 호전되고 있어서 의사가 2주 후면 퇴원할 수 있다고 했어.', example_pinyin='tā de bìng qíng zhú bù hǎo zhuǎn ， yī shēng shuō zài guò liǎng zhōu jiù kě yǐ chū yuàn le 。' WHERE chinese='逐步' AND pinyin='zhú bù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대나무', example_zh='熊猫最喜欢吃竹子，一天可以吃掉几十公斤。', example_ko='판다는 대나무를 가장 좋아해서 하루에 수십 킬로그램을 먹을 수 있어.', example_pinyin='xióng māo zuì xǐ huān chī zhú zi ， yī tiān kě yǐ chī diào jǐ shí gōng jīn 。' WHERE chinese='竹子' AND pinyin='zhú zi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='삶다, 끓이다', example_zh='她把鸡蛋煮熟后剥壳，做成了一道简单的早餐。', example_ko='그녀는 계란을 삶아서 껍질을 까고 간단한 아침 식사를 만들었어.', example_pinyin='tā bǎ jī dàn zhǔ shú hòu bāo ké ， zuò chéng le yī dào jiǎn dān de zǎo cān 。' WHERE chinese='煮' AND pinyin='zhǔ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주관하다, 사회를 보다', example_zh='她主持了这次颁奖典礼，表现得非常专业大方。', example_ko='그녀는 이번 시상식을 진행했는데 매우 전문적이고 당당하게 해냈어.', example_pinyin='tā zhǔ chí le zhè cì bān jiǎng diǎn lǐ ， biǎo xiàn dé fēi cháng zhuān yè dà fāng 。' WHERE chinese='主持' AND pinyin='zhǔ chí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주관적이다', example_zh='评价艺术作品时，主观感受和客观标准都很重要。', example_ko='예술 작품을 평가할 때 주관적인 느낌과 객관적인 기준 모두 중요해.', example_pinyin='píng jià yì shù zuò pǐn shí ， zhǔ guān gǎn shòu hé kè guān biāo zhǔn dōu hěn zhòng yào 。' WHERE chinese='主观' AND pinyin='zhǔ guān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주인, 집주인', example_zh='他是这家餐厅的主人，从服务到菜品都亲自把关。', example_ko='그는 이 식당의 주인이야, 서비스부터 요리까지 직접 관리해.', example_pinyin='tā shì zhè jiā cān tīng de zhǔ rén ， cóng fú wù dào cài pǐn dōu qīn zì bǎ guān 。' WHERE chinese='主人' AND pinyin='zhǔ rén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주석, 의장', example_zh='公司董事会主席在年会上发表了重要讲话。', example_ko='회사 이사회 의장이 연차 총회에서 중요한 연설을 했어.', example_pinyin='gōng sī dǒng shì huì zhǔ xí zài nián huì shàng fā biǎo le zhòng yào jiǎng huà 。' WHERE chinese='主席' AND pinyin='zhǔ xí' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='주장하다; 주장', example_zh='他一直主张以和平方式解决争端，反对武力冲突。', example_ko='그는 항상 평화적인 방식으로 분쟁을 해결하자고 주장하며 무력 충돌에 반대해.', example_pinyin='tā yì zhí zhǔ zhāng yǐ hé píng fāng shì jiě jué zhēng duān ， fǎn duì wǔ lì chōng tū 。' WHERE chinese='主张' AND pinyin='zhǔ zhāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='당부하다, 부탁하다', example_zh='出发前，妈妈一再嘱咐他注意安全，多联系。', example_ko='출발 전에 엄마가 거듭 안전에 주의하고 자주 연락하라고 당부했어.', example_pinyin='chū fā qián ， mā mā yī zài zhǔ fù tā zhù yì ān quán ， duō lián xì 。' WHERE chinese='嘱咐' AND pinyin='zhǔ fù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='축복하다; 축복', example_zh='朋友们在婚礼上送来了最真诚的祝福，让他们很感动。', example_ko='친구들이 결혼식에서 가장 진심 어린 축복을 보내줘서 그들이 감동받았어.', example_pinyin='péng yǒu men zài hūn lǐ shàng sòng lái le zuì zhēn chéng de zhù fú ， ràng tā men hěn gǎn dòng 。' WHERE chinese='祝福' AND pinyin='zhù fú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='등록하다, 가입하다', example_zh='他注册了一个新的账号，开始使用这款软件。', example_ko='그는 새 계정을 등록해서 이 소프트웨어를 사용하기 시작했어.', example_pinyin='tā zhù cè le yí gè xīn de zhàng hào ， kāi shǐ shǐ yòng zhè kuǎn ruǎn jiàn 。' WHERE chinese='注册' AND pinyin='zhù cè' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='단단히 잡다, 서두르다', example_zh='时间不多了，大家抓紧时间，加快进度。', example_ko='시간이 많지 않아서 모두 시간을 단단히 잡고 진도를 앞당겨야 해.', example_pinyin='shí jiān bù duō le ， dà jiā zhuā jǐn shí jiān ， jiā kuài jìn dù 。' WHERE chinese='抓紧' AND pinyin='zhuā jǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전문가', example_zh='他是这个领域的专家，大家都来向他请教。', example_ko='그는 이 분야의 전문가야, 모두 그에게 물어보러 와.', example_pinyin='tā shì zhè ge lǐng yù de zhuān jiā ， dà jiā dōu lái xiàng tā qǐng jiào 。' WHERE chinese='专家' AND pinyin='zhuān jiā' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='집중하다', example_zh='做作业的时候要专心，不能一边玩手机一边写作业。', example_ko='숙제할 때는 집중해야 해, 스마트폰 하면서 숙제하면 안 돼.', example_pinyin='zuò zuò yè de shí hòu yào zhuān xīn ， bù néng yī biān wán shǒu jī yī biān xiě zuò yè 。' WHERE chinese='专心' AND pinyin='zhuān xīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='변화하다, 바뀌다', example_zh='随着时代变化，传统观念也需要不断转变。', example_ko='시대의 변화에 따라 전통적인 관념도 끊임없이 변화해야 해.', example_pinyin='suí zhe shí dài biàn huà ， chuán tǒng guān niàn yě xū yào bù duàn zhuǎn biàn 。' WHERE chinese='转变' AND pinyin='zhuǎn biàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='전달하다, 전하다', example_zh='请帮我转告他，明天的会议改到下午三点了。', example_ko='그에게 전달해줘, 내일 회의가 오후 3시로 바뀌었다고.', example_pinyin='qǐng bāng wǒ zhuǎn gào tā ， míng tiān de huì yì gǎi dào xià wǔ sān diǎn le 。' WHERE chinese='转告' AND pinyin='zhuǎn gào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='입다, 차리다; 장치', example_zh='他装作不知道，实际上他已经知道了一切。', example_ko='그는 모르는 척했는데 실제로 이미 모든 걸 알고 있었어.', example_pinyin='tā zhuāng zuò bù zhī dào ， shí jì shàng tā yǐ jīng zhī dào le yī qiè 。' WHERE chinese='装' AND pinyin='zhuāng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='장식하다; 장식', example_zh='她精心装饰了家里，把房间布置得非常温馨。', example_ko='그녀는 집을 정성껏 꾸며서 방을 매우 아늑하게 만들었어.', example_pinyin='tā jīng xīn zhuāng shì le jiā lǐ ， bǎ fáng jiān bù zhì dé fēi cháng wēn xīn 。' WHERE chinese='装饰' AND pinyin='zhuāng shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상황, 상태', example_zh='目前公司的运营状况良好，各项指标都在预期范围内。', example_ko='현재 회사의 운영 상황이 양호해서 각 지표가 모두 예상 범위 안에 있어.', example_pinyin='mù qián gōng sī de yùn yíng zhuàng kuàng liáng hǎo ， gè xiàng zhǐ biāo dōu zài yù qī fàn wéi nèi 。' WHERE chinese='状况' AND pinyin='zhuàng kuàng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상태, 컨디션', example_zh='他今天状态很好，精力充沛，工作效率特别高。', example_ko='그는 오늘 컨디션이 좋아서 활기 넘치고 업무 효율이 특히 높아.', example_pinyin='tā jīn tiān zhuàng tài hěn hǎo ， jīng lì chōng pèi ， gōng zuò xiào lǜ tè bié gāo 。' WHERE chinese='状态' AND pinyin='zhuàng tài' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='추구하다', example_zh='他一生都在追求真理和知识，从未停止学习。', example_ko='그는 평생 진리와 지식을 추구하며 배움을 멈추지 않았어.', example_pinyin='tā yī shēng dōu zài zhuī qiú zhēn lǐ hé zhī shí ， cóng wèi tíng zhǐ xué xí 。' WHERE chinese='追求' AND pinyin='zhuī qiú' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자격', example_zh='参加这次考试需要具备相关资格，请提前确认。', example_ko='이번 시험에 참가하려면 관련 자격을 갖춰야 해서 미리 확인해주세요.', example_pinyin='cān jiā zhè cì kǎo shì xū yào jù bèi xiāng guān zī gé ， qǐng tí qián què rèn 。' WHERE chinese='资格' AND pinyin='zī gé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자금', example_zh='这个项目需要大量的资金支持，我们需要找到投资者。', example_ko='이 프로젝트는 많은 자금 지원이 필요해서 투자자를 찾아야 해.', example_pinyin='zhè ge xiàng mù xū yào dà liàng de zī jīn zhī chí ， wǒ men xū yào zhǎo dào tóu zī zhě 。' WHERE chinese='资金' AND pinyin='zī jīn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자료, 데이터', example_zh='他整理了大量的历史资料，为研究提供了重要的依据。', example_ko='그는 대량의 역사 자료를 정리해서 연구에 중요한 근거를 제공했어.', example_pinyin='tā zhěng lǐ le dà liàng de lì shǐ zī liào ， wèi yán jiū tí gōng le zhòng yào de yī jù 。' WHERE chinese='资料' AND pinyin='zī liào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자원', example_zh='地球上的自然资源是有限的，需要合理利用和保护。', example_ko='지구의 자연 자원은 한정적이어서 합리적으로 이용하고 보호해야 해.', example_pinyin='dì qiú shàng de zì rán zī yuán shì yǒu xiàn de ， xū yào hé lǐ lì yòng hé bǎo hù 。' WHERE chinese='资源' AND pinyin='zī yuán' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자세, 포즈', example_zh='瑜伽需要保持正确的姿势，否则会对身体造成伤害。', example_ko='요가는 올바른 자세를 유지해야 해, 그러지 않으면 몸에 상처를 줄 수 있어.', example_pinyin='yú jiā xū yào bǎo chí zhèng què de zī shì ， fǒu zé huì duì shēn tǐ zào chéng shāng hài 。' WHERE chinese='姿势' AND pinyin='zī shì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='상담하다, 문의하다', example_zh='他去银行咨询了贷款相关的事宜，了解了贷款的条件。', example_ko='그는 은행에 가서 대출 관련 사항을 상담해서 대출 조건을 이해했어.', example_pinyin='tā qù yín háng zī xún le dài kuǎn xiāng guān de shì yí ， liǎo jiě le dài kuǎn de tiáo jiàn 。' WHERE chinese='咨询' AND pinyin='zī xún' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='보라색', example_zh='她喜欢紫色，家里的很多装饰品都是紫色的。', example_ko='그녀는 보라색을 좋아해서 집의 많은 장식품이 보라색이야.', example_pinyin='tā xǐ huān zǐ sè ， jiā lǐ de hěn duō zhuāng shì pǐn dōu shì zǐ sè de 。' WHERE chinese='紫' AND pinyin='zǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자막', example_zh='这部外国电影有中文字幕，帮助观众理解对话内容。', example_ko='이 외국 영화에는 중국어 자막이 있어서 관객이 대화 내용을 이해하는 데 도움이 돼.', example_pinyin='zhè bù wài guó diàn yǐng yǒu zhōng wén zì mù ， bāng zhù guān zhòng lǐ jiě duì huà nèi róng 。' WHERE chinese='字幕' AND pinyin='zì mù' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~이후로, ~부터', example_zh='自从他戒烟以后，身体明显好多了。', example_ko='담배를 끊은 이후로 그의 몸이 뚜렷이 많이 좋아졌어.', example_pinyin='zì cóng tā jiè yān yǐ hòu ， shēn tǐ míng xiǎn hǎo duō le 。' WHERE chinese='自从' AND pinyin='zì cóng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자동', example_zh='这台洗碗机是自动的，不需要手动清洗，很方便。', example_ko='이 식기세척기는 자동이어서 손으로 씻을 필요가 없어서 매우 편리해.', example_pinyin='zhè tái xǐ wǎn jī shì zì dòng de ， bù xū yào shǒu dòng qīng xǐ ， hěn fāng biàn 。' WHERE chinese='自动' AND pinyin='zì dòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자부심을 느끼다, 자랑스럽다', example_zh='他为自己的国家感到自豪，努力为国家做贡献。', example_ko='그는 자신의 나라에 대해 자부심을 느껴서 나라를 위해 기여하려 노력해.', example_pinyin='tā wèi zì jǐ de guó jiā gǎn dào zì háo ， nǔ lì wèi guó jiā zuò gòng xiàn 。' WHERE chinese='自豪' AND pinyin='zì háo' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자각하다, 의식하다', example_zh='员工要自觉遵守公司规定，不需要每次都被提醒。', example_ko='직원들은 자각적으로 회사 규정을 지켜야 해, 매번 상기시켜줄 필요가 없어야 해.', example_pinyin='yuán gōng yào zì jué zūn shǒu gōng sī guī dìng ， bù xū yào měi cì dōu bèi tí xǐng 。' WHERE chinese='自觉' AND pinyin='zì jué' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='이기적이다', example_zh='他为人自私，只考虑自己的利益，不顾及别人的感受。', example_ko='그는 이기적이어서 자신의 이익만 생각하고 다른 사람의 감정을 배려하지 않아.', example_pinyin='tā wéi rén zì sī ， zhǐ kǎo lǜ zì jǐ de lì yì ， bù gù jí bié rén de gǎn shòu 。' WHERE chinese='自私' AND pinyin='zì sī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자신감이 있다', example_zh='她非常自信，不管什么场合都能从容应对。', example_ko='그녀는 자신감이 넘쳐서 어떤 상황에서도 여유 있게 대처할 수 있어.', example_pinyin='tā fēi cháng zì xìn ， bù guǎn shén me chǎng hé dōu néng cóng róng yìng duì 。' WHERE chinese='自信' AND pinyin='zì xìn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자유', example_zh='言论自由是民主社会的基本权利之一。', example_ko='언론의 자유는 민주 사회의 기본 권리 중 하나야.', example_pinyin='yán lùn zì yóu shì mín zhǔ shè huì de jī běn quán lì zhī yī 。' WHERE chinese='自由' AND pinyin='zì yóu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='자원하다, 자발적으로 하다', example_zh='他自愿报名参加了这次志愿活动，帮助有需要的人。', example_ko='그는 자원해서 이번 봉사 활동에 신청했어서 도움이 필요한 사람을 도왔어.', example_pinyin='tā zì yuàn bào míng cān jiā le zhè cì zhì yuàn huó dòng ， bāng zhù yǒu xū yào de rén 。' WHERE chinese='自愿' AND pinyin='zì yuàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='종합하다', example_zh='这本书综合了多位专家的观点，内容非常全面。', example_ko='이 책은 여러 전문가의 견해를 종합해서 내용이 매우 전면적이야.', example_pinyin='zhè běn shū zōng hé le duō wèi zhuān jiā de guān diǎn ， nèi róng fēi cháng quán miàn 。' WHERE chinese='综合' AND pinyin='zōng hé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='종교', example_zh='宗教信仰是个人的事情，每个人都有自由选择的权利。', example_ko='종교 신앙은 개인적인 일이야, 모든 사람이 자유롭게 선택할 권리가 있어.', example_pinyin='zōng jiào xìn yǎng shì gè rén de shì qíng ， měi gè rén dōu yǒu zì yóu xuǎn zé de quán lì 。' WHERE chinese='宗教' AND pinyin='zōng jiào' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='총재, CEO', example_zh='新任总裁上任后，对公司进行了多项改革，成效显著。', example_ko='새 CEO가 취임한 후 회사에 여러 개혁을 진행했는데 성과가 뚜렷해.', example_pinyin='xīn rèn zǒng cái shàng rèn hòu ， duì gōng sī jìn xíng le duō xiàng gǎi gé ， chéng xiào xiǎn zhù 。' WHERE chinese='总裁' AND pinyin='zǒng cái' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='도합, 합계', example_zh='这次旅行总共花了五千元，比预算少了很多。', example_ko='이번 여행에 합계 5000위안을 썼어서 예산보다 많이 적었어.', example_pinyin='zhè cì lǚ xíng zǒng gòng huā le wǔ qiān yuán ， bǐ yù suàn shǎo le hěn duō 。' WHERE chinese='总共' AND pinyin='zǒng gòng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='총리', example_zh='总理在国会发表了年度工作报告，提出了新的发展目标。', example_ko='총리가 국회에서 연간 업무 보고를 발표하며 새로운 발전 목표를 제시했어.', example_pinyin='zǒng lǐ zài guó huì fā biǎo le nián dù gōng zuò bào gào ， tí chū le xīn de fā zhǎn mù biāo 。' WHERE chinese='总理' AND pinyin='zǒng lǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='드디어, 마침내', example_zh='经过多年的努力，他总算实现了自己的目标。', example_ko='수년간의 노력 끝에 그는 드디어 자신의 목표를 이루었어.', example_pinyin='jīng guò duō nián de nǔ lì ， tā zǒng suàn shí xiàn le zì jǐ de mù biāo 。' WHERE chinese='总算' AND pinyin='zǒng suàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='대통령', example_zh='总统在新年前夕发表了讲话，对全国人民送上了祝福。', example_ko='대통령이 새해 전날 연설을 발표하며 전국 인민에게 축복을 전했어.', example_pinyin='zǒng tǒng zài xīn nián qián xī fā biǎo le jiǎng huà ， duì quán guó rén mín sòng shàng le zhù fú 。' WHERE chinese='总统' AND pinyin='zǒng tǒng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='요컨대, 결국', example_zh='总之，这件事需要大家团结合作，才能顺利解决。', example_ko='요컨대 이 일은 모두가 단결해서 협력해야 순조롭게 해결할 수 있어.', example_pinyin='zǒng zhī ， zhè jiàn shì xū yào dà jiā tuán jié hé zuò ， cái néng shùn lì jiě jué 。' WHERE chinese='总之' AND pinyin='zǒng zhī' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조합하다, 결합하다', example_zh='这两种颜色组合在一起很好看，设计很有创意。', example_ko='이 두 색을 조합하면 보기 좋아서 디자인이 매우 창의적이야.', example_pinyin='zhè liǎng zhǒng yán sè zǔ hé zài yì qǐ hěn hǎo kàn ， shè jì hěn yǒu chuàng yì 。' WHERE chinese='组合' AND pinyin='zǔ hé' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='막다, 저지하다', example_zh='警察及时阻止了一场严重的交通事故的发生。', example_ko='경찰이 적시에 심각한 교통사고 발생을 저지했어.', example_pinyin='jǐng chá jí shí zǔ zhǐ le yī cháng yán zhòng de jiāo tōng shì gù de fā shēng 。' WHERE chinese='阻止' AND pinyin='zǔ zhǐ' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조국, 모국', example_zh='他虽然在海外生活多年，但始终心系祖国，时刻关注国内动态。', example_ko='그는 해외에서 수년간 살았지만 항상 조국을 마음에 두고 시시각각 국내 동향을 주시해.', example_pinyin='tā suī rán zài hǎi wài shēng huó duō nián ， dàn shǐ zhōng xīn xì zǔ guó ， shí kè guān zhù guó nèi dòng tài 。' WHERE chinese='祖国' AND pinyin='zǔ guó' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='조상, 선조', example_zh='他的祖先是从中国来的移民，在这里生活了好几代人。', example_ko='그의 조상은 중국에서 온 이민자야, 여기서 여러 세대를 살아왔어.', example_pinyin='tā de zǔ xiān shì cóng zhōng guó lái de yí mín ， zài zhè lǐ shēng huó le hǎo jǐ dài rén 。' WHERE chinese='祖先' AND pinyin='zǔ xiān' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='술에 취하다', example_zh='他喝多了，醉得连路都走不稳，朋友扶着他回家了。', example_ko='그는 너무 많이 마셔서 취해서 걸음도 제대로 못 걸었어, 친구가 부축해서 집에 데려다줬어.', example_pinyin='tā hē duō le ， zuì dé lián lù dōu zǒu bù wěn ， péng yǒu fú zhe tā huí jiā le 。' WHERE chinese='醉' AND pinyin='zuì' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='최초, 처음', example_zh='他最初的想法很简单，只是想帮助身边的人。', example_ko='그의 처음 생각은 매우 간단했어, 그냥 주변 사람들을 도우려는 거였어.', example_pinyin='tā zuì chū de xiǎng fǎ hěn jiǎn dān ， zhǐ shì xiǎng bāng zhù shēn biān de rén 。' WHERE chinese='最初' AND pinyin='zuì chū' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='범죄자', example_zh='警察经过长时间的调查，终于抓获了那名罪犯。', example_ko='경찰이 오랫동안 수사한 끝에 드디어 그 범죄자를 체포했어.', example_pinyin='jǐng chá jīng guò zhǎng shí jiān de diào chá ， zhōng yú zhuā huò le nà míng zuì fàn 。' WHERE chinese='罪犯' AND pinyin='zuì fàn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='존경하다', example_zh='他尊敬每一位老人，总是主动让座或帮助他们。', example_ko='그는 모든 노인을 존경해서 항상 먼저 나서서 자리를 양보하거나 도와줘.', example_pinyin='tā zūn jìng měi yī wèi lǎo rén ， zǒng shì zhǔ dòng ràng zuò huò bāng zhù tā men 。' WHERE chinese='尊敬' AND pinyin='zūn jìng' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='준수하다, 지키다', example_zh='每个人都应该遵守法律，维护社会的公平与正义。', example_ko='모든 사람은 법을 준수해서 사회의 공평과 정의를 지켜야 해.', example_pinyin='měi gè rén dōu yīng gāi zūn shǒu fǎ lǜ ， wéi hù shè huì de gōng píng yǔ zhèng yì 。' WHERE chinese='遵守' AND pinyin='zūn shǒu' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='작품', example_zh='她的最新作品在艺术展上获得了广泛好评。', example_ko='그녀의 최신 작품이 예술 전시회에서 광범위한 호평을 받았어.', example_pinyin='tā de zuì xīn zuò pǐn zài yì shù zhǎn shàng huò dé le guǎng fàn hǎo píng 。' WHERE chinese='作品' AND pinyin='zuò pǐn' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='~으로서, ~의 입장에서', example_zh='作为团队领导，他有责任带领大家共同前进。', example_ko='팀 리더로서 그는 모두를 이끌고 함께 나아갈 책임이 있어.', example_pinyin='zuò wéi tuán duì lǐng dǎo ， tā yǒu zé rèn dài lǐng dà jiā gòng tóng qián jìn 。' WHERE chinese='作为' AND pinyin='zuò wéi' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='작문', example_zh='老师让同学们写一篇关于环境保护的作文。', example_ko='선생님이 학생들에게 환경보호에 관한 작문을 쓰라고 했어.', example_pinyin='lǎo shī ràng tóng xué men xiě yī piān guān yú huán jìng bǎo hù de zuò wén 。' WHERE chinese='作文' AND pinyin='zuò wén' AND hsk_level IN (3,5,6);
UPDATE words SET meaning='아이고, 아야', example_zh='哎哟，我的脚被踩了！', example_ko='아이고, 발을 밟혔어!', example_pinyin='' WHERE chinese='哎哟' AND pinyin='āi yō' AND hsk_level IN (3,5,6);
